import React, { createContext, useContext, useState, ReactNode, useEffect, useCallback, useRef } from 'react';
import { User, Account, Transaction, Company, AppNotification, Product, Employee, Card, Contact, TaxConfig, ShareRequest, LootBox, LootItem, CardDesign, ApiUsageLog, PayrollHistory } from '../types';
import { jsPDF } from 'jspdf';
import 'jspdf-autotable';

interface BankContextType {
  currentUser: User | null;
  userAccounts: Account[];
  transactions: Transaction[];
  notifications: AppNotification[];
  companies: Company[];
  cards: Card[];
  contacts: Contact[];
  shareRequests: ShareRequest[];
  lootBoxes: LootBox[];
  marketDesigns: { store: CardDesign[], inventory: CardDesign[] };
  taxConfig: TaxConfig;
  login: (dip: string, pass: string) => Promise<{ success: boolean; error?: string }>;
  loginWithPlacetaID: (userData: any) => Promise<{ success: boolean; error?: string }>;
  logout: () => void;
  fetchData: (userId: string) => Promise<void>;
  transfer: (fromIban: string, toIban: string, amount: number, description: string, type?: string) => Promise<void>;
  requestCard: (accountId: string, holderName: string, design: string, pin: string) => Promise<void>;
  toggleCardStatus: (cardId: string, status: 'ACTIVE' | 'FROZEN') => Promise<void>;
  updateCardPin: (cardId: string, newPin: string) => Promise<void>;
  payWithCard: (cardData: {pan: string, cvv: string, pin: string}, amount: number, companyId: string, description: string) => Promise<void>;
  getApiUsageLogs: (companyId: string) => Promise<ApiUsageLog[]>;
  addNotification: (message: string, type: 'success' | 'error' | 'info') => void;
  generatePDF: (type: string, data: any) => void;
  getAge: (birthDate?: string) => number;
  saveContact: (name: string, iban: string) => Promise<void>;
  deleteContact: (id: string) => Promise<void>;
  buyStock: (companyId: string, accountId: string, amount: number) => Promise<void>;
  sellStock: (companyId: string, accountId: string, amount: number) => Promise<void>;
  payCitizenTax: (accountId: string, amount: number, description: string) => Promise<void>;
  getFiscalProjection: (month: number, year: number) => Promise<any[]>;
  respondShareRequest: (id: string, status: 'ACCEPTED' | 'REJECTED') => Promise<void>;
  requestShareAccount: (accountId: string, toDip: string, accessLevel: string) => Promise<void>;
  adminGetState: () => Promise<any>;
  adminRevertTransaction: (id: string) => Promise<void>;
  adminUpdateUserStatus: (userId: string, isBlocked: boolean) => Promise<void>;
  adminMint: (amount: number, reason: string) => Promise<void>;
  adminCreateUser: (user: any) => Promise<void>;
  adminGenerateMonthlyTaxes: (month: number, year: number) => Promise<any>;
  adminProcessTaxCollection: () => Promise<any>;
  buyLootBox: (boxId: string, accountId: string) => Promise<{ success: boolean; wonItem?: LootItem }>;
  redeemCode: (code: string) => Promise<void>;
  buyDesign: (designId: string, accountId: string) => Promise<void>;
  listDesign: (designId: string, price: number) => Promise<void>;
  deleteDesign: (designId: string) => Promise<void>;
  payPayroll: (companyId: string, month: string, year: string) => Promise<void>;
  updateEmployees: (companyId: string, employees: Employee[]) => Promise<void>;
  updateCatalog: (companyId: string, products: Product[]) => Promise<void>;
  rotateApiKey: (companyId: string) => Promise<{apiKey: string}>;
  createSubaccount: (companyId: string, alias: string) => Promise<void>;
  createLottery: (lotteryData: any) => Promise<void>;
  approveLottery: (id: string) => Promise<void>;
  deleteLottery: (id: string) => Promise<void>;
  getPayrollHistory: (companyId: string) => Promise<PayrollHistory[]>;
  triggerHaptic: (pattern?: 'light' | 'medium' | 'heavy' | 'success' | 'error') => void;
}

const BankContext = createContext<BankContextType | undefined>(undefined);

export const BankProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [userAccounts, setUserAccounts] = useState<Account[]>([]);
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [notifications, setNotifications] = useState<AppNotification[]>([]);
  const [companies, setCompanies] = useState<Company[]>([]);
  const [cards, setCards] = useState<Card[]>([]);
  const [contacts, setContacts] = useState<Contact[]>([]);
  const [shareRequests, setShareRequests] = useState<ShareRequest[]>([]);
  const [lootBoxes, setLootBoxes] = useState<LootBox[]>([]);
  const [marketDesigns, setMarketDesigns] = useState<{ store: CardDesign[], inventory: CardDesign[] }>({ store: [], inventory: [] });
  const [taxConfig, setTaxConfig] = useState<TaxConfig>({
      vatRate: 12,
      transferRate: 1,
      companyTaxRate: 25,
      lotteryRate: 20
  });

  const lastTxIdRef = useRef<string | null>(null);

  // Solicitar permiso de notificaciones al montar
  useEffect(() => {
    if ('Notification' in window && Notification.permission !== 'granted') {
      Notification.requestPermission();
    }
  }, []);

  // Monitorizar transacciones para notificaciones push
  useEffect(() => {
    if (transactions.length > 0) {
      const latestTx = transactions[0]; // Asumiendo que están ordenadas por fecha

      // Si es una nueva transacción y no la hemos notificado
      if (lastTxIdRef.current && lastTxIdRef.current !== latestTx.id) {
        // Verificar si es un ingreso para el usuario actual
        const myIbans = userAccounts.map(a => a.iban);
        const isIncoming = myIbans.includes(latestTx.receiverIban);

        if (isIncoming && document.hidden && Notification.permission === 'granted') {
           new Notification('Banco de La Placeta', {
             body: `Recibiste ${latestTx.amount.toLocaleString()} Pts de ${latestTx.senderIban ? 'una transferencia' : 'Sistema'}`,
             icon: 'https://i.postimg.cc/5t0S5t3p/BANCO-DE.png'
           });
        }
      }
      lastTxIdRef.current = latestTx.id;
    }
  }, [transactions, userAccounts]);

  const triggerHaptic = (pattern: 'light' | 'medium' | 'heavy' | 'success' | 'error' = 'light') => {
    if (typeof navigator !== 'undefined' && navigator.vibrate) {
        switch (pattern) {
            case 'light': navigator.vibrate(5); break;
            case 'medium': navigator.vibrate(15); break;
            case 'heavy': navigator.vibrate(30); break;
            case 'success': navigator.vibrate([10, 30, 10]); break;
            case 'error': navigator.vibrate([30, 50, 30, 50, 30]); break;
        }
    }
  };

  const apiCall = async (body: any) => {
    const res = await fetch('/api', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(body)
    });
    const data = await res.json();
    if (!res.ok) throw new Error(data.error || 'Error de Nodo');
    return data;
  };

  const fetchData = useCallback(async (userId: string) => {
    try {
      const data = await apiCall({ action: 'GET_INITIAL_DATA', userId });
      setUserAccounts(data.accounts || []);
      setTransactions(data.transactions || []);
      setCompanies(data.companies || []);
      setCards(data.cards || []);
      setContacts(data.contacts || []);
      setShareRequests(data.shareRequests || []);
      setLootBoxes(data.lootBoxes || []);
      setMarketDesigns(data.marketDesigns || { store: [], inventory: [] });
      if (data.taxConfig) setTaxConfig(data.taxConfig);
    } catch (e: any) {
      console.error("Fetch Data Error:", e.message);
    }
  }, []);

  const login = async (dip: string, pass: string) => {
    try {
      const data = await apiCall({ action: 'AUTH', dip, password: pass });
      setCurrentUser(data.user);
      await fetchData(data.user.id);
      triggerHaptic('success');
      return { success: true, user: data.user };
    } catch (e: any) { 
      triggerHaptic('error');
      return { success: false, error: e.message }; 
    }
  };

  const loginWithPlacetaID = async (userData: any) => {
    try {
      const data = await apiCall({ action: 'AUTH_PLACETAID', userData });
      setCurrentUser(data.user);
      await fetchData(data.user.id);
      triggerHaptic('success');
      return { success: true };
    } catch (e: any) {
      triggerHaptic('error');
      return { success: false, error: e.message };
    }
  };

  const logout = () => {
    setCurrentUser(null);
    setUserAccounts([]);
    setTransactions([]);
    triggerHaptic('medium');
  };

  const transfer = async (fromIban: string, toIban: string, amount: number, description: string, type = 'TRANSFER') => {
    await apiCall({ action: 'TRANSFER', fromIban, toIban, amount, description, type });
    if (currentUser) await fetchData(currentUser.id);
    addNotification(`Operación completada: ${amount} Pts`, "success");
    triggerHaptic('success');
  };

  const requestCard = async (accountId: string, holderName: string, design: string, pin: string) => {
      await apiCall({ action: 'REQUEST_CARD', accountId, holderName, design, pin });
      if (currentUser) await fetchData(currentUser.id);
      addNotification("Tarjeta SIDS emitida correctamente", "success");
      triggerHaptic('success');
  };

  const toggleCardStatus = async (cardId: string, status: 'ACTIVE' | 'FROZEN') => {
      await apiCall({ action: 'TOGGLE_CARD_STATUS', cardId, status });
      if (currentUser) await fetchData(currentUser.id);
      addNotification(status === 'ACTIVE' ? "Tarjeta reactivada" : "Tarjeta bloqueada", "info");
      triggerHaptic('medium');
  };

  const updateCardPin = async (cardId: string, newPin: string) => {
      await apiCall({ action: 'UPDATE_CARD_PIN', cardId, newPin });
      addNotification("PIN actualizado correctamente", "success");
      triggerHaptic('success');
  };

  const payWithCard = async (cardData: any, amount: number, companyId: string, description: string) => {
      await apiCall({ action: 'PAY_WITH_CARD', ...cardData, amount, companyId, description });
      if (currentUser) await fetchData(currentUser.id);
      addNotification("Pago con tarjeta autorizado", "success");
      triggerHaptic('success');
  };

  const getApiUsageLogs = async (companyId: string) => {
      const data = await apiCall({ action: 'GET_API_USAGE_LOGS', companyId });
      return data;
  };

  const getAge = (birthDate?: string) => {
    if (!birthDate) return 0;
    const today = new Date();
    const birth = new Date(birthDate);
    let age = today.getFullYear() - birth.getFullYear();
    const m = today.getMonth() - birth.getMonth();
    if (m < 0 || (m === 0 && today.getDate() < birth.getDate())) {
        age--;
    }
    return age;
  };

  const saveContact = async (name: string, iban: string) => {
    if (!currentUser) return;
    await apiCall({ action: 'SAVE_CONTACT', userId: currentUser.id, name, iban });
    await fetchData(currentUser.id);
    addNotification("Contacto guardado", "success");
  };

  const deleteContact = async (id: string) => {
    if (!currentUser) return;
    await apiCall({ action: 'DELETE_CONTACT', contactId: id });
    await fetchData(currentUser.id);
    addNotification("Contacto eliminado", "info");
  };

  const buyStock = async (companyId: string, accountId: string, amount: number) => {
    await apiCall({ action: 'BUY_STOCK', companyId, accountId, amount });
    if (currentUser) await fetchData(currentUser.id);
    addNotification("Acciones adquiridas", "success");
    triggerHaptic('success');
  };

  const sellStock = async (companyId: string, accountId: string, amount: number) => {
    await apiCall({ action: 'SELL_STOCK', companyId, accountId, amount });
    if (currentUser) await fetchData(currentUser.id);
    addNotification("Venta de acciones completada", "success");
    triggerHaptic('success');
  };

  const payCitizenTax = async (accountId: string, amount: number, description: string) => {
    await apiCall({ action: 'PAY_TAX', accountId, amount, description });
    if (currentUser) await fetchData(currentUser.id);
    triggerHaptic('success');
  };

  const getFiscalProjection = async (month: number, year: number) => {
    if (!currentUser) return [];
    return await apiCall({ action: 'GET_FISCAL_PROJECTION', userId: currentUser.id, month, year });
  };

  const respondShareRequest = async (id: string, status: 'ACCEPTED' | 'REJECTED') => {
    await apiCall({ action: 'RESPOND_SHARE_REQUEST', requestId: id, status });
    if (currentUser) await fetchData(currentUser.id);
    addNotification(`Solicitud ${status === 'ACCEPTED' ? 'aceptada' : 'rechazada'}`, "info");
    triggerHaptic('medium');
  };

  const requestShareAccount = async (accountId: string, toDip: string, accessLevel: string) => {
    await apiCall({ action: 'REQUEST_SHARE_ACCOUNT', accountId, toDip, accessLevel });
    if (currentUser) await fetchData(currentUser.id);
    addNotification("Solicitud de cuenta compartida enviada", "success");
    triggerHaptic('success');
  };

  const adminGetState = async () => {
    return await apiCall({ action: 'ADMIN_GET_STATE' });
  };

  const adminRevertTransaction = async (id: string) => {
    await apiCall({ action: 'ADMIN_REVERT_TX', transactionId: id });
    addNotification("Transacción revertida", "success");
    triggerHaptic('medium');
  };

  const adminUpdateUserStatus = async (userId: string, isBlocked: boolean) => {
    await apiCall({ action: 'ADMIN_UPDATE_USER_STATUS', userId, isBlocked });
    if(currentUser) await fetchData(currentUser.id);
    addNotification(`Usuario ${isBlocked ? 'bloqueado' : 'desbloqueado'}`, "info");
  };

  const adminMint = async (amount: number, reason: string) => {
    await apiCall({ action: 'ADMIN_MINT', amount, reason });
    addNotification("Emisión monetaria completada", "success");
    triggerHaptic('success');
  };

  const adminCreateUser = async (user: any) => {
    await apiCall({ action: 'ADMIN_CREATE_USER', user });
    addNotification("Ciudadano creado correctamente", "success");
  };

  const adminGenerateMonthlyTaxes = async (month: number, year: number) => {
    return await apiCall({ action: 'ADMIN_GEN_TAXES', month, year });
  };

  const adminProcessTaxCollection = async () => {
    return await apiCall({ action: 'ADMIN_PROCESS_TAX_COLLECTION' });
  };

  const buyLootBox = async (boxId: string, accountId: string) => {
    const res = await apiCall({ action: 'BUY_LOOTBOX', boxId, accountId });
    if (currentUser) await fetchData(currentUser.id);
    if(res.success) triggerHaptic('success');
    return res;
  };

  const redeemCode = async (code: string) => {
    await apiCall({ action: 'REDEEM_CODE', code });
    if (currentUser) await fetchData(currentUser.id);
    addNotification("Código canjeado", "success");
    triggerHaptic('success');
  };

  const buyDesign = async (designId: string, accountId: string) => {
    await apiCall({ action: 'BUY_DESIGN', designId, accountId });
    if (currentUser) await fetchData(currentUser.id);
    addNotification("Diseño adquirido", "success");
    triggerHaptic('success');
  };

  const listDesign = async (designId: string, price: number) => {
    await apiCall({ action: 'LIST_DESIGN', designId, price });
    if (currentUser) await fetchData(currentUser.id);
    addNotification("Diseño puesto a la venta", "success");
  };

  const deleteDesign = async (designId: string) => {
    await apiCall({ action: 'DELETE_DESIGN', designId });
    if (currentUser) await fetchData(currentUser.id);
    addNotification("Diseño eliminado de la tienda", "info");
  };

  const payPayroll = async (companyId: string, month: string, year: string) => {
    await apiCall({ action: 'PAY_PAYROLL', companyId, month, year });
    if (currentUser) await fetchData(currentUser.id);
    addNotification("Nóminas procesadas", "success");
    triggerHaptic('success');
  };

  const updateEmployees = async (companyId: string, employees: Employee[]) => {
    await apiCall({ action: 'UPDATE_EMPLOYEES', companyId, employees });
    if (currentUser) await fetchData(currentUser.id);
    addNotification("Lista de empleados actualizada", "success");
  };

  const updateCatalog = async (companyId: string, products: Product[]) => {
    await apiCall({ action: 'UPDATE_CATALOG', companyId, products });
    if (currentUser) await fetchData(currentUser.id);
    addNotification("Catálogo actualizado", "success");
  };

  const rotateApiKey = async (companyId: string) => {
    const data = await apiCall({ action: 'COMPANY_ROTATE_KEY', companyId });
    if (currentUser) await fetchData(currentUser.id);
    addNotification("Clave de API regenerada", "info");
    return data;
  };

  const createSubaccount = async (companyId: string, alias: string) => {
      await apiCall({ action: 'CREATE_SUBACCOUNT', companyId, alias });
      if (currentUser) await fetchData(currentUser.id);
      addNotification("Subcuenta creada correctamente", "success");
      triggerHaptic('success');
  };

  const createLottery = async (lotteryData: any) => {
      await apiCall({ action: 'CREATE_LOTTERY', ...lotteryData });
      if (currentUser) await fetchData(currentUser.id);
  };

  const approveLottery = async (id: string) => {
      await apiCall({ action: 'APPROVE_LOTTERY', lotteryId: id });
      if (currentUser) await fetchData(currentUser.id);
      addNotification("Sorteo aprobado y publicado", "success");
  };

  const deleteLottery = async (id: string) => {
      await apiCall({ action: 'DELETE_LOTTERY', lotteryId: id });
      if (currentUser) await fetchData(currentUser.id);
      addNotification("Sorteo eliminado", "info");
  };

  const getPayrollHistory = async (companyId: string): Promise<PayrollHistory[]> => {
      return await apiCall({ action: 'GET_PAYROLL_HISTORY', companyId });
  };

  const addNotification = (message: string, type: any) => {
    const id = Date.now().toString();
    setNotifications(prev => [...prev, { id, message, type }]);
    // Si la app está visible, también vibra
    if(!document.hidden) triggerHaptic(type === 'error' ? 'error' : 'light');
    setTimeout(() => setNotifications(prev => prev.filter(n => n.id !== id)), 4000);
  };

  const generatePDF = (type: string, data: any) => {
      const doc = new jsPDF() as any;
      doc.setFont("helvetica");
      doc.setFontSize(22);
      doc.setTextColor(30, 41, 59);
      doc.text("BANCO DE LA PLACETA", 20, 25);

      doc.setFontSize(10);
      doc.setTextColor(100, 116, 139);
      doc.text("SIDS JUNTA DE ADMINISTRACIÓN", 20, 32);
      doc.text(`FECHA: ${new Date().toLocaleDateString()}`, 150, 25);

      if (type === 'INVOICE') {
          doc.setFontSize(16);
          doc.setTextColor(30, 41, 59);
          doc.text("FACTURA ELECTRÓNICA", 20, 50);

          doc.setFontSize(10);
          doc.text(`CLIENTE: ${data.client || 'CONSUMIDOR FINAL'}`, 20, 60);
          doc.text(`NIF/DIP: ${data.nif || 'N/A'}`, 20, 65);

          doc.autoTable({
              startY: 75,
              head: [['Concepto', 'Base Imponible', 'IVA (12%)', 'Total']],
              body: [[
                  data.description || 'Operación SIDS', 
                  (data.amount / 1.12).toFixed(2) + ' Pts', 
                  (data.amount - (data.amount / 1.12)).toFixed(2) + ' Pts', 
                  data.amount.toFixed(2) + ' Pts'
              ]],
              theme: 'grid',
              headStyles: { fillColor: [94, 23, 235] }
          });
      }
      doc.save(`SIDS_OFFICIAL_${type}_${Date.now()}.pdf`);
  };

  return (
    <BankContext.Provider value={{
      currentUser, userAccounts, transactions, notifications, companies, cards, contacts, shareRequests, lootBoxes, marketDesigns, taxConfig,
      login, loginWithPlacetaID, logout, fetchData, transfer, requestCard, toggleCardStatus, updateCardPin, payWithCard, getApiUsageLogs, addNotification, generatePDF, getAge,
      saveContact, deleteContact, buyStock, sellStock, payCitizenTax, getFiscalProjection, respondShareRequest, requestShareAccount,
      adminGetState, adminRevertTransaction, adminUpdateUserStatus, adminMint, adminCreateUser, adminGenerateMonthlyTaxes, adminProcessTaxCollection,
      buyLootBox, redeemCode, buyDesign, listDesign, deleteDesign, payPayroll, updateEmployees, updateCatalog, rotateApiKey,
      createSubaccount, createLottery, approveLottery, deleteLottery, getPayrollHistory, triggerHaptic
    }}>
      {children}
    </BankContext.Provider>
  );
};

export const useBank = () => {
  const context = useContext(BankContext);
  if (!context) throw new Error('BankContext missing');
  return context;
};

import React from 'react';
import { LayoutDashboard, ArrowRightLeft, TrendingUp, FileText, LogOut, Gift, Zap, Palette, Wallet, Users, Shield } from 'lucide-react';
import { useBank } from '../context/BankContext';

interface SidebarProps {
  currentView: string;
  setView: (view: string) => void;
  onLogout: () => void;
}

export const Sidebar: React.FC<SidebarProps> = ({ currentView, setView, onLogout }) => {
  const { currentUser, getAge, triggerHaptic } = useBank();
  const age = currentUser ? getAge(currentUser.birthDate) : 0;
  const isTeen = age >= 14; 

  let menuItems = [
    { id: 'dashboard', label: 'Inicio', icon: LayoutDashboard },
    { id: 'accounts', label: 'Cartera', icon: Wallet },
    { id: 'transfers', label: 'Enviar', icon: ArrowRightLeft },
  ];

  if (isTeen) {
      menuItems = [
        ...menuItems,
        { id: 'payments', label: 'Pagos', icon: Zap },
        { id: 'lottery', label: 'Sorteos', icon: Gift },
        { id: 'market', label: 'Market', icon: Palette },
        { id: 'investments', label: 'Inversión', icon: TrendingUp },
        { id: 'taxes', label: 'Hacienda', icon: FileText },
        { id: 'family', label: 'Vínculos', icon: Users },
      ];
  }

  if (currentUser?.role === 'ADMIN') {
      menuItems.push({ id: 'admin', label: 'Junta Admin', icon: Shield });
  }

  const handleNav = (id: string) => {
    triggerHaptic('light');
    setView(id);
  }

  return (
    <div className="hidden md:flex w-64 bg-[#f8fafc] h-screen fixed left-0 top-0 flex-col z-50 border-r border-slate-200/60 font-sans">
      <div className="p-6">
        <div className="flex items-center gap-3 mb-8">
            <div className="w-10 h-10 bg-brand-600 rounded-xl flex items-center justify-center text-white shadow-glow">
                <img src="https://i.postimg.cc/5t0S5t3p/BANCO-DE.png" alt="Logo" className="w-6 h-6 object-contain brightness-0 invert" />
            </div>
            <span className="font-extrabold text-lg tracking-tight text-slate-900">La Placeta</span>
        </div>

        <div className="flex items-center gap-3 p-3 bg-white rounded-2xl border border-slate-100 shadow-sm mb-4">
            <img src={currentUser?.avatarUrl} alt="User" className="w-10 h-10 rounded-xl bg-slate-200 object-cover" />
            <div className="overflow-hidden">
                <p className="text-sm font-bold truncate text-slate-900">{currentUser?.name.split(' ')[0]}</p>
                <p className="text-[10px] text-slate-400 font-bold font-mono truncate">{currentUser?.dip}</p>
            </div>
        </div>
      </div>

      <nav className="flex-1 px-3 space-y-1 overflow-y-auto custom-scrollbar pb-4">
        <p className="px-4 mb-2 text-[10px] font-extrabold text-slate-400 uppercase tracking-widest">Menú</p>
        {menuItems.map((item) => {
          const isActive = currentView === item.id;
          return (
            <button
              key={item.id}
              onClick={() => handleNav(item.id)}
              className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl transition-all duration-200 group text-sm font-bold btn-press ${
                isActive
                  ? 'bg-brand-600 text-white shadow-lg shadow-brand-500/30'
                  : 'text-slate-500 hover:text-slate-900 hover:bg-white'
              }`}
            >
              <item.icon size={18} className={isActive ? 'text-white' : 'text-slate-400 group-hover:text-brand-600 transition-colors'} strokeWidth={2.5} />
              <span>{item.label}</span>
            </button>
          )
        })}
      </nav>

      <div className="p-4 border-t border-slate-200">
        <button 
          onClick={onLogout}
          className="w-full flex items-center gap-3 px-4 py-3 text-slate-400 hover:text-red-600 hover:bg-red-50 rounded-xl transition-all text-sm font-bold group btn-press"
        >
          <LogOut size={18} className="group-hover:-translate-x-1 transition-transform"/>
          <span>Salir</span>
        </button>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { LayoutDashboard, ArrowRightLeft, Wallet, Landmark, Menu, X, TrendingUp, Palette, FileText, Users, Gift, Shield, Zap, LogOut } from 'lucide-react';
import { useBank } from '../context/BankContext';

interface MobileNavbarProps {
  currentView: string;
  setView: (view: string) => void;
}

export const MobileNavbar: React.FC<MobileNavbarProps> = ({ currentView, setView }) => {
  const { currentUser, logout, getAge, triggerHaptic } = useBank();
  const [isMenuOpen, setIsMenuOpen] = useState(false);

  const isTeen = currentUser ? getAge(currentUser.birthDate) >= 14 : false;

  const dockItems = [
    { id: 'dashboard', icon: LayoutDashboard },
    { id: 'accounts', icon: Wallet },
    { id: 'transfers', icon: ArrowRightLeft }, 
    { id: 'sede', icon: Landmark },
  ];

  let drawerItems = [];
  if (isTeen) {
      drawerItems = [
        { id: 'payments', icon: Zap, label: 'Pagos', color: 'bg-brand-50 text-brand-600' },
        { id: 'investments', icon: TrendingUp, label: 'Mercado', color: 'bg-emerald-50 text-emerald-600' },
        { id: 'market', icon: Palette, label: 'Diseños', color: 'bg-indigo-50 text-indigo-600' },
        { id: 'taxes', icon: FileText, label: 'Hacienda', color: 'bg-orange-50 text-orange-600' },
        { id: 'family', icon: Users, label: 'Familia', color: 'bg-blue-50 text-blue-600' },
        { id: 'lottery', icon: Gift, label: 'Sorteos', color: 'bg-purple-50 text-purple-600' },
      ];
  }
  if (currentUser?.role === 'ADMIN') {
      drawerItems.push({ id: 'admin', icon: Shield, label: 'Gobierno', color: 'bg-slate-900 text-white' });
  }

  const handleNavigate = (viewId: string) => { 
      triggerHaptic('light');
      setView(viewId); 
      setIsMenuOpen(false); 
  };

  return (
    <>
        {/* Drawer Overlay */}
        {isMenuOpen && (
            <div className="md:hidden fixed inset-0 z-[110] flex flex-col justify-end">
                <div className="absolute inset-0 bg-slate-900/60 backdrop-blur-md animate-fade-in" onClick={() => setIsMenuOpen(false)}></div>
                <div className="relative bg-[#f8fafc] rounded-t-[2rem] p-6 pb-safe shadow-[0_-10px_40px_rgba(0,0,0,0.2)] animate-slide-up max-h-[85vh] overflow-y-auto border-t border-white/50">
                    <div className="w-12 h-1.5 bg-slate-300 rounded-full mx-auto mb-8 opacity-50"></div>
                    <h3 className="text-xl font-black text-slate-900 mb-6 px-2 tracking-tight">Menú Extendido</h3>
                    <div className="grid grid-cols-4 gap-4 mb-8">
                        {drawerItems.map((item) => (
                            <button key={item.id} onClick={() => handleNavigate(item.id)} className="flex flex-col items-center gap-2 group active:scale-95 transition-transform">
                                <div className={`w-14 h-14 rounded-2xl flex items-center justify-center shadow-sm ${item.color}`}>
                                    <item.icon size={24} strokeWidth={2.5} />
                                </div>
                                <span className="text-[10px] font-bold text-slate-500 uppercase tracking-wide truncate w-full text-center">{item.label}</span>
                            </button>
                        ))}
                    </div>
                    <button onClick={() => { triggerHaptic('medium'); logout(); }} className="w-full py-4 bg-white border border-slate-200 text-slate-600 rounded-2xl font-bold text-xs uppercase tracking-widest flex items-center justify-center gap-2 active:scale-95 transition-transform shadow-sm">
                        <LogOut size={16} /> Cerrar Sesión
                    </button>
                </div>
            </div>
        )}

        {/* Floating Dock Compacto */}
        <div className="md:hidden fixed bottom-6 left-0 w-full z-[100] pointer-events-none pb-safe px-6">
            <div className="glass-dark backdrop-blur-xl pointer-events-auto rounded-full p-2 shadow-2xl flex justify-around items-center max-w-[320px] mx-auto border border-white/10 ring-1 ring-white/5">
                {dockItems.map((item) => { 
                    const isActive = currentView === item.id && !isMenuOpen;
                    return (
                    <button key={item.id} onClick={() => { handleNavigate(item.id); }}
                        className={`w-12 h-12 rounded-full flex items-center justify-center transition-all duration-300 ${isActive ? 'bg-white text-slate-900 shadow-[0_0_15px_rgba(255,255,255,0.3)] scale-110' : 'text-slate-400 hover:text-white active:scale-90'}`}>
                        <item.icon size={20} strokeWidth={isActive ? 3 : 2.5}/>
                    </button>
                )})}
                <div className="w-px h-6 bg-white/10 mx-1"></div>
                <button onClick={() => { triggerHaptic('medium'); setIsMenuOpen(!isMenuOpen); }}
                    className={`w-12 h-12 rounded-full flex items-center justify-center transition-all duration-300 ${isMenuOpen ? 'bg-brand-600 text-white shadow-glow scale-110' : 'text-slate-400 hover:text-white active:scale-90'}`}>
                    {isMenuOpen ? <X size={20} strokeWidth={3}/> : <Menu size={20} strokeWidth={3}/>}
                </button>
            </div>
        </div>
    </>
  );
};

