import React, { useState, useRef } from 'react';
import { useBank } from '../context/BankContext';
import { SECURITY_THRESHOLD_AMOUNT } from '../constants';
import { Send, ChevronDown, X, CheckCircle2, ShieldCheck, Fingerprint, AlertTriangle, ArrowRight, BookOpen, Info, HelpCircle, BookUser, Star, Trash, Delete } from 'lucide-react';

interface TransfersProps {
  addNotification: (msg: string, type: 'success' | 'error' | 'info') => void;
}

type TransferStep = 'IDLE' | 'SECURITY' | 'CONFIRM' | 'PROCESSING' | 'SUCCESS';

// Modern Keypad Button
const KeypadButton: React.FC<{ val: string; onClick: () => void; icon?: React.ReactNode; primary?: boolean }> = ({ val, onClick, icon, primary }) => (
  <button 
    onClick={(e) => {
        // Simple haptic feedback simulation via button press visual
        const btn = e.currentTarget;
        btn.classList.add('scale-90');
        setTimeout(() => btn.classList.remove('scale-90'), 100);
        onClick();
    }}
    className={`h-16 w-full rounded-2xl transition-all duration-150 text-2xl font-semibold flex items-center justify-center select-none active:scale-95 ${primary ? 'bg-brand-600 text-white shadow-lg shadow-brand-500/30' : 'bg-slate-50 text-slate-900 hover:bg-slate-100'}`}
  >
      {icon ? icon : val}
  </button>
);

export const Transfers: React.FC<TransfersProps> = ({ addNotification }) => {
  const { userAccounts, transfer, taxConfig, contacts, saveContact, deleteContact, triggerHaptic } = useBank();

  const [selectedAccountIndex, setSelectedAccountIndex] = useState(0);
  const [showAccountMenu, setShowAccountMenu] = useState(false); 
  const [recipientBody, setRecipientBody] = useState(''); 
  const [amount, setAmount] = useState('');
  const [transferStep, setTransferStep] = useState<TransferStep>('IDLE');
  const [pin, setPin] = useState('');
  const [showContactsModal, setShowContactsModal] = useState(false);
  const [savingContact, setSavingContact] = useState(false);
  const [newContactName, setNewContactName] = useState('');

  const currentAccount = userAccounts[selectedAccountIndex];
  const currentTax = taxConfig.transferRate;
  const fullRecipient = 'PL' + recipientBody;

  const handleKeypad = (val: string) => {
      triggerHaptic('light');
      if (val === 'DEL') {
          setAmount(prev => prev.slice(0, -1));
      } else if (val === '.') {
          if (!amount.includes('.')) setAmount(prev => prev + '.');
      } else {
          if (amount.length < 9) setAmount(prev => prev + val);
      }
  };

  const handleVerify = () => {
    triggerHaptic('medium');
    if (recipientBody.length !== 22) {
      addNotification("Formato incorrecto: PL + 22 dígitos", 'error');
      return;
    }
    const numericAmount = Number(amount);
    if (numericAmount <= 0 || numericAmount > currentAccount.balance) {
      addNotification("Saldo insuficiente", 'error');
      return;
    }

    if (numericAmount > SECURITY_THRESHOLD_AMOUNT) {
      setTransferStep('SECURITY');
    } else {
      setTransferStep('CONFIRM');
    }
  };

  const handleConfirm = async () => {
    triggerHaptic('medium');
    setTransferStep('PROCESSING');
    await new Promise(r => setTimeout(r, 1500)); // Simular red
    await transfer(currentAccount.iban, fullRecipient, Number(amount), 'Transferencia Móvil');
    triggerHaptic('success');
    setTransferStep('SUCCESS');
  };

  const handleSelectContact = (iban: string) => {
      triggerHaptic('light');
      const cleanIban = iban.startsWith('PL') ? iban.substring(2) : iban;
      setRecipientBody(cleanIban);
      setShowContactsModal(false);
  };

  const resetFlow = () => {
      setTransferStep('IDLE');
      setAmount('');
      setRecipientBody('');
      setPin('');
  };

  if (!currentAccount) return <div className="p-8 text-center text-slate-400">Cargando cuentas...</div>;

  return (
    <div className="pb-safe-nav h-full flex flex-col max-w-lg mx-auto relative animate-fade-in pt-safe px-4">

      {/* Header */}
      <div className="flex justify-between items-center mb-6">
            <h2 className="text-2xl font-black text-slate-900 tracking-tight">Enviar Dinero</h2>
            <button onClick={() => setShowContactsModal(true)} className="p-3 bg-white border border-slate-200 rounded-full text-slate-600 hover:text-brand-600 transition-colors shadow-sm active:scale-95">
                <BookUser size={20} />
            </button>
      </div>

      {/* Account Selector */}
      <div className="relative mb-8 z-20">
             <div 
                className="p-4 bg-white border border-slate-200 rounded-2xl flex items-center justify-between shadow-sm cursor-pointer hover:border-brand-300 transition-all active:scale-[0.99]"
                onClick={() => setShowAccountMenu(!showAccountMenu)}
             >
                <div className="flex items-center gap-3">
                    <div className="w-10 h-10 bg-slate-900 rounded-xl flex items-center justify-center text-white font-bold text-sm shadow-md">
                        {selectedAccountIndex + 1}
                    </div>
                    <div className="text-left">
                        <p className="text-[10px] text-slate-400 font-bold uppercase tracking-wider">Origen</p>
                        <p className="font-bold text-slate-900 text-sm">{currentAccount.alias}</p>
                    </div>
                </div>
                <div className="text-right">
                    <p className="text-sm font-black text-slate-900">{currentAccount.balance.toLocaleString()} Pts</p>
                </div>
            </div>

            {showAccountMenu && (
                <div className="absolute top-full left-0 right-0 mt-2 bg-white rounded-2xl shadow-xl border border-slate-100 overflow-hidden animate-slide-up">
                    {userAccounts.map((acc, idx) => (
                        <button 
                            key={acc.id}
                            onClick={() => { setSelectedAccountIndex(idx); setShowAccountMenu(false); }}
                            className="w-full p-4 flex items-center justify-between hover:bg-slate-50 transition-colors border-b border-slate-50 last:border-0"
                        >
                            <span className="font-bold text-sm text-slate-900">{acc.alias}</span>
                            <span className="font-mono text-xs text-slate-500">{acc.balance.toLocaleString()} Pts</span>
                        </button>
                    ))}
                </div>
            )}
      </div>

      {/* Amount Display */}
      <div className="flex-1 flex flex-col items-center justify-center min-h-[160px] mb-6">
            <div className="flex items-baseline gap-1 animate-scale-up">
                 <span className={`text-6xl font-black tracking-tighter ${amount ? 'text-slate-900' : 'text-slate-300'}`}>
                    {amount || '0'}
                 </span>
                 <span className="text-2xl text-slate-400 font-bold">Pts</span>
            </div>
            {Number(amount) > SECURITY_THRESHOLD_AMOUNT && (
                <div className="flex items-center gap-2 mt-2 text-xs font-bold text-orange-600 bg-orange-50 px-3 py-1 rounded-full animate-fade-in">
                    <AlertTriangle size={12} /> Verificación Requerida
                </div>
            )}
      </div>

      {/* Recipient Input */}
      <div className="bg-white p-2 rounded-2xl border border-slate-200 mb-6 flex items-center shadow-sm focus-within:ring-2 focus-within:ring-brand-500/20 transition-all">
          <div className="bg-slate-100 px-3 py-2 rounded-xl text-slate-500 font-bold text-xs select-none">PL</div>
          <input 
              type="text" 
              value={recipientBody}
              onChange={(e) => {
                  const val = e.target.value.replace(/[^0-9]/g, '');
                  if(val.length <= 22) setRecipientBody(val);
              }}
              className="flex-1 bg-transparent px-3 py-2 font-mono text-lg font-bold outline-none text-slate-900 placeholder:text-slate-300 tracking-widest"
              placeholder="0000..."
              inputMode="numeric"
          />
          <div className="text-[10px] font-bold text-slate-400 px-3">{22 - recipientBody.length}</div>
      </div>

      {/* Keypad */}
      <div className="grid grid-cols-3 gap-3">
          {[1,2,3,4,5,6,7,8,9].map(n => (
              <KeypadButton key={n} val={n.toString()} onClick={() => handleKeypad(n.toString())} />
          ))}
          <KeypadButton val="." onClick={() => handleKeypad('.')} />
          <KeypadButton val="0" onClick={() => handleKeypad('0')} />
          <KeypadButton val="DEL" onClick={() => handleKeypad('DEL')} icon={<Delete size={24} className="text-slate-400"/>} />
      </div>

      <button
          onClick={handleVerify}
          disabled={!amount || recipientBody.length !== 22}
          className="w-full mt-6 py-4 bg-brand-600 text-white rounded-2xl font-black text-lg shadow-lg shadow-brand-500/30 active:scale-95 transition-all disabled:opacity-50 disabled:shadow-none flex items-center justify-center gap-2"
        >
          Continuar <ArrowRight size={20} strokeWidth={3} />
      </button>

      {/* Modals */}
      {transferStep === 'CONFIRM' && (
           <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-md z-50 flex items-center justify-center p-6 animate-fade-in">
                <div className="bg-white w-full max-w-sm rounded-[2.5rem] p-8 shadow-2xl animate-scale-up relative">
                    <button onClick={resetFlow} className="absolute top-6 right-6 p-2 bg-slate-50 rounded-full hover:bg-slate-100"><X size={20}/></button>
                    <h3 className="text-2xl font-black text-slate-900 mb-6 text-center">Confirmar</h3>

                    <div className="text-center mb-8">
                        <p className="text-slate-400 font-bold text-xs uppercase tracking-widest mb-1">Monto Total</p>
                        <p className="text-4xl font-black text-slate-900 tracking-tighter">{Number(amount).toLocaleString()} Pts</p>
                        <div className="mt-2 inline-block bg-blue-50 text-blue-600 px-3 py-1 rounded-lg text-[10px] font-bold uppercase">
                            + {(Number(amount) * (currentTax/100)).toFixed(1)} Pts Tasa
                        </div>
                    </div>

                    <div className="space-y-4 mb-8">
                        <div className="flex justify-between border-b border-slate-50 pb-3">
                            <span className="text-slate-500 font-bold text-xs">Para</span>
                            <span className="font-mono font-bold text-sm text-slate-900">{fullRecipient}</span>
                        </div>
                        <div className="flex justify-between border-b border-slate-50 pb-3">
                            <span className="text-slate-500 font-bold text-xs">Desde</span>
                            <span className="font-bold text-sm text-slate-900">{currentAccount.alias}</span>
                        </div>
