                    <button onClick={handleConfirm} className="w-full py-4 bg-brand-600 text-white rounded-2xl font-black uppercase text-xs tracking-widest shadow-xl hover:bg-brand-500 transition-all active:scale-95">
                        Enviar Ahora
                    </button>
                </div>
           </div>
      )}

      {transferStep === 'SUCCESS' && (
