               <p className="text-slate-500 font-bold mb-10">La transacción se ha completado.</p>

               <button onClick={resetFlow} className="px-10 py-4 bg-slate-900 text-white rounded-full font-black text-sm uppercase tracking-widest shadow-xl active:scale-95 transition-all">
                   Realizar otro envío
               </button>
           </div>
      )}

      {/* Contacts Modal */}
      {showContactsModal && (
          <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-md z-50 flex flex-col justify-end" onClick={() => setShowContactsModal(false)}>
              <div className="bg-white rounded-t-[2.5rem] p-6 pb-safe h-[80vh] animate-slide-up" onClick={e => e.stopPropagation()}>
                  <div className="w-12 h-1.5 bg-slate-200 rounded-full mx-auto mb-6"></div>
                  <h3 className="text-xl font-black text-slate-900 mb-6">Contactos</h3>
                  <div className="space-y-2 overflow-y-auto h-full pb-20">
                      {contacts.length === 0 ? (
                          <p className="text-center text-slate-400 py-10 font-bold text-sm">No tienes contactos guardados.</p>
                      ) : (
                          contacts.map(c => (
                              <div key={c.id} onClick={() => handleSelectContact(c.iban)} className="flex items-center justify-between p-4 hover:bg-slate-50 rounded-2xl cursor-pointer active:scale-95 transition-all">
                                  <div className="flex items-center gap-4">
                                      <div className="w-10 h-10 bg-brand-100 text-brand-600 rounded-full flex items-center justify-center font-bold">{c.name.charAt(0)}</div>
                                      <div>
                                          <p className="font-bold text-slate-900">{c.name}</p>
                                          <p className="text-xs text-slate-400 font-mono">{c.iban}</p>
                                      </div>
                                  </div>
                              </div>
                          ))
                      )}
                  </div>
              </div>
          </div>
      )}
    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { useBank } from '../context/BankContext';
import { BusinessSidebar } from '../components/BusinessSidebar';
import { BusinessMobileNavbar } from '../components/BusinessMobileNavbar';
import { 
  LayoutDashboard, Wallet, FileText, Users, ShoppingCart, 
  MessageCircle, PieChart, Code, DollarSign, UserPlus, 
  Edit2, Trash2, History, Download, Plus, Building2, 
  CreditCard, ArrowRightLeft, TrendingUp, Search, CheckCircle2,
  AlertCircle, ChevronRight, X, Save
} from 'lucide-react';
import { Company, Employee, PayrollHistory } from '../types';
import { AreaChart, Area, ResponsiveContainer, Tooltip, CartesianGrid, XAxis, YAxis } from 'recharts';

interface BusinessDashboardProps {
  onSwitchView: () => void;
}

export const BusinessDashboard: React.FC<BusinessDashboardProps> = ({ onSwitchView }) => {
  const { 
    currentUser, companies, payPayroll, updateEmployees, 
    generatePDF, getPayrollHistory, createSubaccount, 
    addNotification, rotateApiKey, getApiUsageLogs, updateCatalog
  } = useBank();

  const [selectedCompanyId, setSelectedCompanyId] = useState<string | null>(null);
  const [currentView, setCurrentView] = useState('OVERVIEW');

  // Modal States
  const [showPayrollModal, setShowPayrollModal] = useState(false);
  const [showEmployeeModal, setShowEmployeeModal] = useState(false);
  const [editingEmployee, setEditingEmployee] = useState<Employee | null>(null);

  // Data States
  const [payrollHistory, setPayrollHistory] = useState<PayrollHistory[]>([]);
  const [apiLogs, setApiLogs] = useState<any[]>([]);

  // Form States
  const [newEmpName, setNewEmpName] = useState('');
  const [newEmpDip, setNewEmpDip] = useState('');
  const [newEmpSalary, setNewEmpSalary] = useState('');
  const [newEmpRole, setNewEmpRole] = useState('');
  const [newEmpIban, setNewEmpIban] = useState('');

  // Auto-select first company
  useEffect(() => {
    if (companies.length > 0 && !selectedCompanyId) {
        // Filter companies owned by user if needed, or just take the first one available
        const myCompanies = companies.filter(c => c.ownerId === currentUser?.id);
        if(myCompanies.length > 0) setSelectedCompanyId(myCompanies[0].id);
    }
  }, [companies, currentUser]);

  const selectedCompany = useMemo(() => 
    companies.find(c => c.id === selectedCompanyId), 
    [companies, selectedCompanyId]
  );

  // Fetch company specific data when view or company changes
  useEffect(() => {
    if (selectedCompanyId) {
        if (currentView === 'EMPLOYEES') {
            getPayrollHistory(selectedCompanyId).then(setPayrollHistory);
        }
        if (currentView === 'DEVELOPERS') {
            getApiUsageLogs(selectedCompanyId).then(setApiLogs);
        }
    }
  }, [selectedCompanyId, currentView, getPayrollHistory, getApiUsageLogs]);

  // Handlers
  const handlePayrollProcess = async () => {
    if (!selectedCompany) return;
    const now = new Date();
    try {
        await payPayroll(selectedCompany.id, (now.getMonth() + 1).toString(), now.getFullYear().toString());
        setShowPayrollModal(false);
        // Refresh history
        const h = await getPayrollHistory(selectedCompany.id);
        setPayrollHistory(h);
    } catch (e: any) {
        addNotification(e.message, 'error');
    }
  };

  const handleSaveEmployee = async () => {
      if (!selectedCompany) return;
      const salary = parseFloat(newEmpSalary);
      if (!newEmpName || !newEmpDip || isNaN(salary)) {
          addNotification("Datos inválidos", "error");
          return;
      }

      const updatedEmployees = [...selectedCompany.employees];

      if (editingEmployee) {
          const idx = updatedEmployees.findIndex(e => e.id === editingEmployee.id);
          if (idx !== -1) {
              updatedEmployees[idx] = { 
                  ...editingEmployee, 
                  name: newEmpName, 
                  dip: newEmpDip, 
                  salary, 
                  role: newEmpRole,
                  iban: newEmpIban
              };
          }
      } else {
          updatedEmployees.push({
              id: `emp-${Date.now()}`,
              name: newEmpName,
              dip: newEmpDip,
              salary,
              role: newEmpRole,
              iban: newEmpIban,
              hireDate: new Date().toISOString(),
              status: 'ACTIVE'
          });
      }

      await updateEmployees(selectedCompany.id, updatedEmployees);
      setShowEmployeeModal(false);
      setEditingEmployee(null);
      resetEmpForm();
  };

  const handleDeleteEmployee = async (id: string) => {
      if (!selectedCompany || !confirm("¿Despedir empleado?")) return;
      const updatedEmployees = selectedCompany.employees.filter(e => e.id !== id);
      await updateEmployees(selectedCompany.id, updatedEmployees);
  };

  const handleEditEmployeeClick = (emp: Employee) => {
      setEditingEmployee(emp);
      setNewEmpName(emp.name);
      setNewEmpDip(emp.dip);
      setNewEmpSalary(emp.salary.toString());
      setNewEmpRole(emp.role);
      setNewEmpIban(emp.iban);
      setShowEmployeeModal(true);
  };

  const resetEmpForm = () => {
      setNewEmpName('');
      setNewEmpDip('');
      setNewEmpSalary('');
      setNewEmpRole('');
      setNewEmpIban('');
  };

  const handleRotateKey = async () => {
      if (!selectedCompany || !confirm("¿Regenerar API Key? La anterior dejará de funcionar.")) return;
      await rotateApiKey(selectedCompany.id);
  };

  if (!selectedCompany) {
      return (
          <div className="min-h-screen flex items-center justify-center bg-slate-50">
              <div className="text-center">
                  <Building2 size={48} className="mx-auto text-slate-300 mb-4"/>
                  <h2 className="text-xl font-bold text-slate-900">No hay sociedades activas</h2>
                  <button onClick={onSwitchView} className="mt-4 text-brand-600 font-bold hover:underline">Volver a vista personal</button>
              </div>
          </div>
      );
