                            <p className="text-slate-400 text-xs font-bold mt-1 uppercase tracking-widest">Resumen Ejecutivo</p>
                        </div>
                        <div className="px-4 py-2 bg-white rounded-xl border border-slate-200 text-xs font-bold text-slate-500 shadow-sm">
                            Capital: {selectedCompany.capital.toLocaleString()} Pts
                        </div>
                    </header>

                    <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                        <div className="bg-slate-900 text-white p-8 rounded-[2.5rem] relative overflow-hidden shadow-xl">
                            <div className="absolute top-0 right-0 w-32 h-32 bg-brand-500/20 rounded-full blur-3xl"></div>
                            <p className="text-[10px] font-black uppercase tracking-widest opacity-60 mb-2">Valoración Bursátil</p>
                            <div className="flex items-baseline gap-2">
                                <span className="text-4xl font-black tracking-tighter">{selectedCompany.stockValue.toLocaleString()}</span>
                                <span className="text-sm font-bold opacity-50">Pts/Acción</span>
                            </div>
                        </div>
                        <div className="bg-white p-8 rounded-[2.5rem] border border-slate-100 shadow-soft">
                             <p className="text-[10px] font-black uppercase tracking-widest text-slate-400 mb-2">Empleados Activos</p>
                             <div className="flex items-center gap-4">
                                <span className="text-4xl font-black text-slate-900 tracking-tighter">{selectedCompany.employees.length}</span>
                                <Users size={24} className="text-indigo-500"/>
                             </div>
                        </div>
                        <div className="bg-white p-8 rounded-[2.5rem] border border-slate-100 shadow-soft">
                             <p className="text-[10px] font-black uppercase tracking-widest text-slate-400 mb-2">Productos en Catálogo</p>
                             <div className="flex items-center gap-4">
                                <span className="text-4xl font-black text-slate-900 tracking-tighter">{selectedCompany.catalog.products.length}</span>
                                <ShoppingCart size={24} className="text-emerald-500"/>
                             </div>
                        </div>
                    </div>
                </div>
            )}

            {/* EMPLOYEES (From user snippet) */}
            {currentView === 'EMPLOYEES' && (
                <div className="space-y-8 animate-slide-up">
                    <div className="flex justify-between items-center flex-wrap gap-4">
                        <div>
                            <h3 className="text-3xl font-black text-slate-900 tracking-tight">Recursos Humanos</h3>
                            <p className="text-slate-400 text-xs font-bold mt-1">Gestión de plantilla y nóminas</p>
                        </div>
                        <div className="flex gap-3">
                            <button onClick={() => setShowPayrollModal(true)} className="px-6 py-3 bg-emerald-600 text-white rounded-2xl font-black text-[10px] uppercase tracking-widest shadow-xl hover:bg-emerald-500 transition-all flex items-center gap-3 active:scale-95">
                                <DollarSign size={18}/> Procesar Nóminas
                            </button>
                            <button onClick={() => { resetEmpForm(); setShowEmployeeModal(true); }} className="px-6 py-3 bg-slate-900 text-white rounded-2xl font-black text-[10px] uppercase tracking-widest shadow-xl hover:bg-brand-600 transition-all flex items-center gap-3 active:scale-95">
                                <UserPlus size={18}/> Contratar
                            </button>
                        </div>
                    </div>

                    <div className="bg-white rounded-3xl border border-slate-100 shadow-soft overflow-hidden">
