interface TransfersProps {
  addNotification: (msg: string, type: 'success' | 'error' | 'info') => void;
}

type TransferStep = 'IDLE' | 'SECURITY' | 'CONFIRM' | 'PROCESSING' | 'SUCCESS';

// Modern Keypad Button
const KeypadButton: React.FC<{ val: string; onClick: () => void; icon?: React.ReactNode; primary?: boolean }> = ({ val, onClick, icon, primary }) => (
  <button 
    onClick={(e) => {
        // Simple haptic feedback simulation via button press visual
        const btn = e.currentTarget;
        btn.classList.add('scale-90');
        setTimeout(() => btn.classList.remove('scale-90'), 100);
        onClick();
    }}
    className={`h-16 w-full rounded-2xl transition-all duration-150 text-2xl font-semibold flex items-center justify-center select-none active:scale-95 ${primary ? 'bg-brand-600 text-white shadow-lg shadow-brand-500/30' : 'bg-slate-50 text-slate-900 hover:bg-slate-100'}`}
  >
      {icon ? icon : val}
  </button>
);

