import { Pool } from '@neondatabase/serverless';

let pool: any = null;
const getPool = () => {
  if (!pool) {
    if (!process.env.DATABASE_URL) throw new Error('DATABASE_URL is missing');
    pool = new (Pool as any)({ connectionString: process.env.DATABASE_URL });
  }
  return pool;
};

// Formateador robusto para asegurar compatibilidad con el frontend
const formatResponse = (obj: any): any => {
    if (obj === null || obj === undefined) return obj;
    if (obj instanceof Date) return obj.toISOString();
    if (Array.isArray(obj)) return obj.map(formatResponse);
    if (typeof obj !== 'object') return obj;

    const newObj: any = {};
    for (const key in obj) {
        const newKey = key.replace(/_([a-z])/g, (g) => g[1].toUpperCase());
        let value = obj[key];

        const numericFields = ['balance', 'amount', 'price', 'capital', 'stockValue', 'salary', 'tax', 'prizeValue'];
        if (numericFields.includes(newKey) && (typeof value === 'string' || value === null)) {
            value = parseFloat(value || '0');
        }
        newObj[newKey] = formatResponse(value);
    }
    return newObj;
};

const logAction = async (client: any, companyId: string, action: string, status: 'SUCCESS' | 'ERROR', metadata: object = {}) => {
    try {
        const logId = `log-${Date.now()}-${Math.random().toString(36).substr(2, 9)}`;
        await client.query(
            `INSERT INTO api_usage_logs (id, company_id, action, status, metadata) VALUES ($1, $2, $3, $4, $5)`,
            [logId, companyId, action, status, JSON.stringify(metadata)]
        );
    } catch (e) {
        console.error("Failed to log action:", e); // Don't let logging fail the main request
    }
};

const ensureSchema = async (client: any) => {
    // 1. Tablas Core
    await client.query(`
        CREATE TABLE IF NOT EXISTS users (
            id TEXT PRIMARY KEY,
            name TEXT NOT NULL,
            dip TEXT UNIQUE NOT NULL,
            password_hash TEXT NOT NULL,
            role TEXT DEFAULT 'CITIZEN',
            verified BOOLEAN DEFAULT FALSE,
            avatar_url TEXT,
            birth_date DATE,
            created_at TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP
        );
        CREATE TABLE IF NOT EXISTS accounts (
            id TEXT PRIMARY KEY,
            owner_id TEXT NOT NULL,
            alias TEXT NOT NULL,
            iban TEXT UNIQUE NOT NULL,
            balance DECIMAL(15,2) DEFAULT 0,
            type TEXT NOT NULL,
            shared_with TEXT[] DEFAULT '{}'
        );
        CREATE TABLE IF NOT EXISTS transactions (
            id TEXT PRIMARY KEY,
            amount DECIMAL(15,2) NOT NULL,
            sender_iban TEXT,
            receiver_iban TEXT NOT NULL,
            description TEXT,
            type TEXT NOT NULL,
            tax DECIMAL(15,2) DEFAULT 0,
            status TEXT DEFAULT 'COMPLETED',
            date TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP
        );
        CREATE TABLE IF NOT EXISTS companies (
            id TEXT PRIMARY KEY,
            owner_id TEXT NOT NULL,
            name TEXT NOT NULL,
            nif TEXT UNIQUE NOT NULL,
            iban TEXT NOT NULL,
            capital DECIMAL(15,2) DEFAULT 0,
            is_public BOOLEAN DEFAULT FALSE,
            stock_value DECIMAL(15,2) DEFAULT 100,
            api_key TEXT,
            employees JSONB DEFAULT '[]'::jsonb,
            catalog JSONB DEFAULT '{"active": true, "products": []}'::jsonb
        );
        CREATE TABLE IF NOT EXISTS cards (
            id TEXT PRIMARY KEY,
            account_id TEXT NOT NULL,
            pan TEXT UNIQUE NOT NULL,
            expiry_date TEXT NOT NULL,
            cvv TEXT NOT NULL,
            pin TEXT NOT NULL,
            holder_name TEXT NOT NULL,
            type TEXT DEFAULT 'DEBIT',
            status TEXT DEFAULT 'ACTIVE',
            design TEXT,
            format TEXT DEFAULT 'VIRTUAL',
            created_at TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP
        );
        CREATE TABLE IF NOT EXISTS api_usage_logs (
            id TEXT PRIMARY KEY,
            company_id TEXT NOT NULL,
            action TEXT NOT NULL,
            timestamp TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP,
            status TEXT NOT NULL,
            metadata JSONB DEFAULT '{}'::jsonb
        );
        CREATE TABLE IF NOT EXISTS contacts (
            id TEXT PRIMARY KEY,
            user_id TEXT NOT NULL,
            name TEXT NOT NULL,
            iban TEXT NOT NULL
        );

        -- Módulos Adicionales
        CREATE TABLE IF NOT EXISTS share_requests (
            id TEXT PRIMARY KEY,
            from_user_id TEXT NOT NULL,
            to_user_dip TEXT NOT NULL,
            account_id TEXT NOT NULL,
            access_level TEXT DEFAULT 'READ_ONLY',
            status TEXT DEFAULT 'PENDING'
        );
        CREATE TABLE IF NOT EXISTS loot_boxes (
            id TEXT PRIMARY KEY,
            owner_id TEXT,
            name TEXT NOT NULL,
            description TEXT,
            price DECIMAL(15,2),
            prize_value DECIMAL(15,2),
            status TEXT DEFAULT 'PENDING',
            color TEXT
        );
        CREATE TABLE IF NOT EXISTS card_designs (
            id TEXT PRIMARY KEY,
            name TEXT,
            image_url TEXT,
            rarity TEXT,
            price DECIMAL(15,2),
            owner_id TEXT,
            is_listed BOOLEAN DEFAULT FALSE,
            seller_name TEXT
        );
        CREATE TABLE IF NOT EXISTS payroll_history (
            id TEXT PRIMARY KEY,
            company_id TEXT NOT NULL,
            month TEXT NOT NULL,
            year TEXT NOT NULL,
            total_amount DECIMAL(15,2) NOT NULL,
            employee_count INT NOT NULL,
            processed_at TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP,
            total_taxes DECIMAL(15,2)
        );
    `);

    // Patch columns if missing
    try {
        await client.query(`ALTER TABLE contacts ADD COLUMN IF NOT EXISTS user_id TEXT;`);
        await client.query(`ALTER TABLE cards ADD COLUMN IF NOT EXISTS format TEXT DEFAULT 'VIRTUAL';`);
        await client.query(`ALTER TABLE accounts ADD COLUMN IF NOT EXISTS company_id TEXT;`);
        await client.query(`ALTER TABLE payroll_history ADD COLUMN IF NOT EXISTS total_taxes DECIMAL(15,2);`);
    } catch (e) { /* ignore */ }
};

export default async function handler(req: any, res: any) {
    let client: any;
    res.setHeader('Content-Type', 'application/json');
    res.setHeader('Access-Control-Allow-Origin', '*');
    res.setHeader('Access-Control-Allow-Methods', 'POST, OPTIONS');
    res.setHeader('Access-Control-Allow-Headers', 'Content-Type, x-api-key');

    if (req.method === 'OPTIONS') return res.status(200).end();

    try {
        const { action, ...params } = req.body || {};
        client = await getPool().connect();
        await ensureSchema(client);

        // --- AUTH & DATA LOADING ---

        if (action === 'AUTH') {
            const { dip, password } = params;
            const userRes = await client.query(
                "SELECT * FROM users WHERE UPPER(dip) = $1 AND password_hash = $2", 
                [dip.toUpperCase().trim(), password]
            );
            if (userRes.rows.length === 0) return res.status(401).json({ error: "Credenciales no encontradas en el Ledger." });
            return res.status(200).json({ success: true, user: formatResponse(userRes.rows[0]) });
        }

        if (action === 'AUTH_PLACETAID') {
            const { userData } = params;
            const dip = (userData.dni || userData.dip || userData.id || userData.username || '').toUpperCase().trim();
            if (!dip) return res.status(400).json({ error: "Identidad externa no válida." });

            const userRes = await client.query("SELECT * FROM users WHERE UPPER(dip) = $1", [dip]);
            if (userRes.rows.length === 0) return res.status(404).json({ error: "Usuario validado por la Junta, pero no tiene cuenta bancaria activa." });

            return res.status(200).json({ success: true, user: formatResponse(userRes.rows[0]) });
        }

        if (action === 'GET_INITIAL_DATA') {
            const { userId } = params;
            const accounts = (await client.query("SELECT * FROM accounts WHERE owner_id = $1 OR $1 = ANY(shared_with)", [userId])).rows;
            const companies = (await client.query("SELECT * FROM companies")).rows;
            const cards = (await client.query("SELECT * FROM cards WHERE account_id IN (SELECT id FROM accounts WHERE owner_id = $1)", [userId])).rows;
            const contacts = (await client.query("SELECT * FROM contacts WHERE user_id = $1", [userId])).rows;

            const shareRequests = (await client.query(`
                SELECT sr.*, u1.name as from_user_name, u2.name as to_user_name
                FROM share_requests sr 
                LEFT JOIN users u1 ON sr.from_user_id = u1.id
                LEFT JOIN users u2 ON sr.to_user_dip = u2.dip
                WHERE sr.from_user_id = $1 OR sr.to_user_dip = (SELECT dip FROM users WHERE id = $1)
            `, [userId])).rows;

            const lootBoxes = (await client.query("SELECT * FROM loot_boxes")).rows;

            const allDesigns = (await client.query("SELECT * FROM card_designs")).rows;
            const storeDesigns = allDesigns.filter((d: any) => !d.owner_id || d.is_listed);
            const inventoryDesigns = allDesigns.filter((d: any) => d.owner_id === userId);

            const ibans = accounts.map((a: any) => a.iban);
            let txs = [];
            if (ibans.length > 0) {
                const placeholders = ibans.map((_, i) => `$${i + 1}`).join(',');
                txs = (await client.query(
                    `SELECT * FROM transactions WHERE sender_iban IN (${placeholders}) OR receiver_iban IN (${placeholders}) ORDER BY date DESC LIMIT 50`, 
                    ibans
                )).rows;
            }

            return res.status(200).json(formatResponse({ 
                accounts, 
                companies, 
                cards, 
                transactions: txs, 
                contacts,
                shareRequests,
                lootBoxes,
                marketDesigns: { store: storeDesigns, inventory: inventoryDesigns }
            }));
        }

        // --- COMMON ACTIONS ---

        if (action === 'GET_API_USAGE_LOGS') {
            const { companyId } = params;
            const logs = await client.query("SELECT * FROM api_usage_logs WHERE company_id = $1 ORDER BY timestamp DESC LIMIT 100", [companyId]);
            return res.status(200).json(formatResponse(logs.rows));
        }

        if (action === 'TRANSFER') {
            const { fromIban, toIban, amount, description, type } = params;
            const taxRate = 0.01; // 1% Transfer Rate
            const taxAmount = amount * taxRate;
            const totalDeduction = amount + taxAmount;
            const stateIban = 'PL0000000000000000000000';

            await client.query("BEGIN");
            const senderRes = await client.query("SELECT balance FROM accounts WHERE iban = $1 FOR UPDATE", [fromIban]);

            if (senderRes.rows.length === 0 || parseFloat(senderRes.rows[0].balance) < totalDeduction) {
                await client.query("ROLLBACK");
                return res.status(400).json({ error: "Saldo insuficiente para transferencia + tasa" });
            }

            const receiverRes = await client.query("SELECT iban FROM accounts WHERE iban = $1", [toIban]);
            const compRes = await client.query("SELECT iban FROM companies WHERE iban = $1", [toIban]);

            const targetExists = receiverRes.rows.length > 0 || compRes.rows.length > 0;

            if (!targetExists) {
                 await client.query("ROLLBACK");
                 return res.status(404).json({ error: "Destinatario no encontrado" });
            }

            // Deduct total from Sender
            await client.query("UPDATE accounts SET balance = balance - $1 WHERE iban = $2", [totalDeduction, fromIban]);

            // Add net amount to Receiver
            if (receiverRes.rows.length > 0) {
                await client.query("UPDATE accounts SET balance = balance + $1 WHERE iban = $2", [amount, toIban]);
            } else {
                const anyAccRes = await client.query("SELECT iban FROM accounts WHERE iban = $1", [toIban]);
                if (anyAccRes.rows.length > 0) {
                     await client.query("UPDATE accounts SET balance = balance + $1 WHERE iban = $2", [amount, toIban]);
                }
            }

            // Add tax to State
            const stateAccRes = await client.query("SELECT iban FROM accounts WHERE iban = $1", [stateIban]);
            if (stateAccRes.rows.length > 0) {
                await client.query("UPDATE accounts SET balance = balance + $1 WHERE iban = $2", [taxAmount, stateIban]);
            }

            const txId = `tx-${Date.now()}-${Math.random().toString(36).substr(2, 9)}`;
            await client.query(`INSERT INTO transactions (id, amount, sender_iban, receiver_iban, description, type, tax, status, date) 
                VALUES ($1, $2, $3, $4, $5, $6, $7, 'COMPLETED', NOW())`, 
                [txId, amount, fromIban, toIban, description, type || 'TRANSFER', taxAmount]);

            await client.query("COMMIT");
            return res.status(200).json({ success: true });
        }

        // --- BUSINESS ACTIONS ---

        if (action === 'GET_PAYROLL_HISTORY') {
            const { companyId } = params;
            const historyRes = await client.query("SELECT * FROM payroll_history WHERE company_id = $1 ORDER BY processed_at DESC LIMIT 12", [companyId]);
            return res.status(200).json(formatResponse(historyRes.rows));
        }

        if (action === 'PAY_PAYROLL') {
            const { companyId, month, year } = params;
            const payrollTaxRate = 0.075;
            const stateIban = 'PL0000000000000000000000'; // Hardcoded state treasury IBAN

            const compRes = await client.query("SELECT * FROM companies WHERE id = $1", [companyId]);
            if (compRes.rows.length === 0) return res.status(404).json({ error: "Empresa no encontrada" });

            const company = compRes.rows[0];
            const employees = company.employees || [];
            if (employees.length === 0) return res.status(400).json({ error: "No hay empleados registrados" });

            const totalGrossSalaries = employees.reduce((sum: number, emp: any) => sum + Number(emp.salary), 0);
            const totalEmployerTaxes = totalGrossSalaries * payrollTaxRate;
            const totalEmployeeTaxes = totalGrossSalaries * payrollTaxRate;
            const totalCostForCompany = totalGrossSalaries + totalEmployerTaxes;
            const totalTaxesToState = totalEmployerTaxes + totalEmployeeTaxes;

            await client.query("BEGIN");

            const compAccRes = await client.query("SELECT * FROM accounts WHERE iban = $1 FOR UPDATE", [company.iban]);
            if (compAccRes.rows.length === 0 || parseFloat(compAccRes.rows[0].balance) < totalCostForCompany) {
                await client.query("ROLLBACK");
                return res.status(400).json({ error: "Fondos insuficientes para nóminas e impuestos" });
            }

            await client.query("UPDATE accounts SET balance = balance - $1 WHERE iban = $2", [totalCostForCompany, company.iban]);

            for (const emp of employees) {
                const empAccRes = await client.query("SELECT iban FROM accounts WHERE iban = $1", [emp.iban]);
                if (empAccRes.rows.length > 0) {
                     const netSalary = Number(emp.salary) * (1 - payrollTaxRate);
                     await client.query("UPDATE accounts SET balance = balance + $1 WHERE iban = $2", [netSalary, emp.iban]);

                     const txId = `pay-${Date.now()}-${Math.random().toString(36).substr(2, 5)}`;
                     await client.query(`INSERT INTO transactions (id, amount, sender_iban, receiver_iban, description, type, status, date) 
                        VALUES ($1, $2, $3, $4, $5, 'PAYROLL', 'COMPLETED', NOW())`, 
                        [txId, netSalary, company.iban, emp.iban, `Nómina (Neto) ${month}/${year}`]);
                }
            }

            // Pay taxes to state account
            const stateAccRes = await client.query("SELECT iban FROM accounts WHERE iban = $1", [stateIban]);
            if (stateAccRes.rows.length > 0) {
                 await client.query("UPDATE accounts SET balance = balance + $1 WHERE iban = $2", [totalTaxesToState, stateIban]);
                 const taxTxId = `tax-${Date.now()}-${Math.random().toString(36).substr(2, 9)}`;
                 await client.query(`INSERT INTO transactions (id, amount, sender_iban, receiver_iban, description, type, status, date)
                    VALUES ($1, $2, $3, $4, $5, 'TAX', 'COMPLETED', NOW())`,
                    [taxTxId, totalTaxesToState, company.iban, stateIban, `Impuestos s/ Nóminas ${month}/${year} - ${company.name}`]);
            } else {
                console.warn(`State account with IBAN ${stateIban} not found. Taxes not paid.`);
            }

            const historyId = `ph-${Date.now()}`;
            await client.query(
                `INSERT INTO payroll_history (id, company_id, month, year, total_amount, employee_count, total_taxes) VALUES ($1, $2, $3, $4, $5, $6, $7)`,
                [historyId, companyId, month, year, totalGrossSalaries, employees.length, totalTaxesToState]
            );

            await client.query("COMMIT");
            await logAction(client, companyId, 'PAY_PAYROLL', 'SUCCESS', { month, year, totalCostForCompany });
            return res.status(200).json({ success: true });
        }

        if (action === 'UPDATE_EMPLOYEES') {
            const { companyId, employees } = params;
            await client.query("UPDATE companies SET employees = $1 WHERE id = $2", [JSON.stringify(employees), companyId]);
            await logAction(client, companyId, 'UPDATE_EMPLOYEES', 'SUCCESS', { employeeCount: employees.length });
            return res.status(200).json({ success: true });
        }

        if (action === 'UPDATE_CATALOG') {
            const { companyId, products } = params;
            const current = (await client.query("SELECT catalog FROM companies WHERE id = $1", [companyId])).rows[0].catalog;
            const newCatalog = { ...current, products: products };

            await client.query("UPDATE companies SET catalog = $1 WHERE id = $2", [JSON.stringify(newCatalog), companyId]);
            await logAction(client, companyId, 'UPDATE_CATALOG', 'SUCCESS', { productCount: products.length });
            return res.status(200).json({ success: true });
        }

        if (action === 'COMPANY_ROTATE_KEY') {
            const { companyId } = params;
            const newKey = `sk_live_${Math.random().toString(36).substr(2, 16)}`;
            await client.query("UPDATE companies SET api_key = $1 WHERE id = $2", [newKey, companyId]);
            await logAction(client, companyId, 'ROTATE_API_KEY', 'SUCCESS');
            return res.status(200).json({ apiKey: newKey });
        }

        if (action === 'CREATE_SUBACCOUNT') {
            const { companyId, alias } = params;
            const compRes = await client.query("SELECT owner_id FROM companies WHERE id = $1", [companyId]);
            if (compRes.rows.length === 0) return res.status(404).json({ error: "Empresa no encontrada" });

            const ownerId = compRes.rows[0].owner_id;
            const iban = 'PL' + Math.floor(Math.random() * 1000000000000000000000).toString().padStart(22, '0');
            const id = `acc-${Date.now()}`;

            await client.query(
                "INSERT INTO accounts (id, owner_id, alias, iban, balance, type, company_id) VALUES ($1, $2, $3, $4, 0, 'BUSINESS', $5)", 
                [id, ownerId, alias, iban, companyId]
            );
            await logAction(client, companyId, 'CREATE_SUBACCOUNT', 'SUCCESS', { alias });
            return res.status(200).json({ success: true });
        }

        // --- MARKETING / LOTTERY ACTIONS ---

        if (action === 'CREATE_LOTTERY') {
            const { name, description, price, prizeValue, color, companyId, emissionFee } = params;
            const id = `lb-${Date.now()}`;

            if (emissionFee > 0 && companyId) {
                const compRes = await client.query("SELECT iban FROM companies WHERE id = $1", [companyId]);
                if (compRes.rows.length > 0) {
                     const iban = compRes.rows[0].iban;
                     await client.query("UPDATE accounts SET balance = balance - $1 WHERE iban = $2", [emissionFee, iban]);
                }
            }

            await client.query(
                "INSERT INTO loot_boxes (id, owner_id, name, description, price, prize_value, status, color) VALUES ($1, $2, $3, $4, $5, $6, 'PENDING', $7)",
                [id, companyId, name, description, price, prizeValue, color]
            );
            return res.status(200).json({ success: true });
        }

        if (action === 'APPROVE_LOTTERY') {
            const { lotteryId } = params;
            await client.query("UPDATE loot_boxes SET status = 'APPROVED' WHERE id = $1", [lotteryId]);
            return res.status(200).json({ success: true });
        }

        if (action === 'DELETE_LOTTERY') {
             const { lotteryId } = params;
             await client.query("DELETE FROM loot_boxes WHERE id = $1", [lotteryId]);
             return res.status(200).json({ success: true });
        }

        // --- ADMIN ACTIONS ---

        if (action === 'ADMIN_GET_STATE') {
             const users = (await client.query("SELECT * FROM users ORDER BY created_at DESC")).rows;
             const txs = (await client.query("SELECT * FROM transactions ORDER BY date DESC LIMIT 200")).rows;
             const accounts = (await client.query("SELECT * FROM accounts")).rows;

             const m0 = accounts.reduce((acc: number, curr: any) => acc + parseFloat(curr.balance), 0);

             return res.status(200).json(formatResponse({
                 users,
                 transactions: txs,
                 allAccounts: accounts,
                 m0,
                 config: {}
             }));
        }

        if (action === 'ADMIN_CREATE_USER') {
            const { user } = params;
            const id = `user-${Date.now()}`;
            await client.query(
                "INSERT INTO users (id, name, dip, password_hash, role, verified) VALUES ($1, $2, $3, $4, $5, $6)",
                [id, user.name, user.dip, user.password, user.role, true]
            );
            const iban = 'PL' + Math.floor(Math.random() * 1000000000000000000000).toString().padStart(22, '0');
            await client.query(
                "INSERT INTO accounts (id, owner_id, alias, iban, balance, type) VALUES ($1, $2, 'Cuenta Principal', $3, 1000, 'PERSONAL')",
                [`acc-${Date.now()}`, id, iban]
            );
            return res.status(200).json({ success: true });
        }

        // --- OTHER ACTIONS ---

        if (action === 'SAVE_CONTACT') {
            const { userId, name, iban } = params;
            const id = `contact-${Date.now()}`;
            await client.query("INSERT INTO contacts (id, user_id, name, iban) VALUES ($1, $2, $3, $4)", [id, userId, name, iban]);
            return res.status(200).json({ success: true });
        }

        if (action === 'DELETE_CONTACT') {
            const { contactId } = params;
            await client.query("DELETE FROM contacts WHERE id = $1", [contactId]);
            return res.status(200).json({ success: true });
        }

        if (action === 'REQUEST_CARD') {
            const { accountId, holderName, design, pin } = params;
            const pan = '4' + Math.floor(Math.random() * 1000000000000000).toString().padStart(15, '0');
            const cvv = Math.floor(Math.random() * 900 + 100).toString();
            const id = `card-${Date.now()}`;
            await client.query(`
                INSERT INTO cards (id, account_id, pan, expiry_date, cvv, pin, holder_name, design, status, type)
                VALUES ($1, $2, $3, '12/30', $4, $5, $6, $7, 'ACTIVE', 'DEBIT')
            `, [id, accountId, pan, cvv, pin, holderName, design]);
            return res.status(200).json({ success: true });
        }

        if (action === 'TOGGLE_CARD_STATUS') {
            const { cardId, status } = params;
            await client.query("UPDATE cards SET status = $1 WHERE id = $2", [status, cardId]);
            return res.status(200).json({ success: true });
        }

        // Mocks
        if ([
            'UPDATE_CARD_PIN', 'PAY_WITH_CARD', 'BUY_STOCK', 'SELL_STOCK', 'PAY_TAX', 
            'GET_FISCAL_PROJECTION', 'RESPOND_SHARE_REQUEST', 'REQUEST_SHARE_ACCOUNT', 
            'REDEEM_CODE', 'BUY_DESIGN', 'LIST_DESIGN', 'DELETE_DESIGN'
        ].includes(action)) {
            return res.status(200).json({ success: true, message: "Operación simulada (Mock)" });
        }

        return res.status(400).json({ error: `Operación no definida: ${action}` });

    } catch (e: any) {
        console.error("API Error:", e);
        return res.status(500).json({ error: "Fallo en el Nodo Central: " + e.message });
    } finally {
        if (client) client.release();
    }
}

import { Pool } from '@neondatabase/serverless';

let pool: any = null;
const getPool = () => {
  if (!pool) {
    if (!process.env.DATABASE_URL) throw new Error('DATABASE_URL is missing');
    pool = new (Pool as any)({ connectionString: process.env.DATABASE_URL });
  }
  return pool;
};

const BANK_IBAN = 'PL0000000000000000000000'; // Cuenta del Banco de La Placeta

// Formateador robusto para asegurar compatibilidad con el frontend
const formatResponse = (obj: any): any => {
    if (obj === null || obj === undefined) return obj;
    if (obj instanceof Date) return obj.toISOString();
    if (Array.isArray(obj)) return obj.map(formatResponse);
    if (typeof obj !== 'object') return obj;

    const newObj: any = {};
    for (const key in obj) {
        const newKey = key.replace(/_([a-z])/g, (g) => g[1].toUpperCase());
        let value = obj[key];

        const numericFields = ['balance', 'amount', 'price', 'capital', 'stockValue', 'salary', 'tax', 'prizeValue'];
        if (numericFields.includes(newKey) && (typeof value === 'string' || value === null)) {
            value = parseFloat(value || '0');
        }
        newObj[newKey] = formatResponse(value);
    }
    return newObj;
};

const logAction = async (client: any, companyId: string, action: string, status: 'SUCCESS' | 'ERROR', metadata: object = {}) => {
    try {
        const logId = `log-${Date.now()}-${Math.random().toString(36).substr(2, 9)}`;
        await client.query(
            `INSERT INTO api_usage_logs (id, company_id, action, status, metadata) VALUES ($1, $2, $3, $4, $5)`,
            [logId, companyId, action, status, JSON.stringify(metadata)]
        );
    } catch (e) {
        console.error("Failed to log action:", e);
    }
};

