import { BusinessMobileNavbar } from '../components/BusinessMobileNavbar';
import { 
  LayoutDashboard, Wallet, FileText, Users, ShoppingCart, 
  DollarSign, UserPlus, Edit2, Trash2, History, Download, 
  ArrowRightLeft, TrendingUp, ArrowUpRight, ArrowDownLeft,
  Package, Plus, Save, X, Search, CreditCard
} from 'lucide-react';
import { Company, Employee, PayrollHistory, Product } from '../types';
import { AreaChart, Area, ResponsiveContainer, Tooltip, CartesianGrid } from 'recharts';

interface BusinessDashboardProps {
  onSwitchView: () => void;
}

export const BusinessDashboard: React.FC<BusinessDashboardProps> = ({ onSwitchView }) => {
  const { 
    currentUser, companies, payPayroll, updateEmployees, 
    generatePDF, getPayrollHistory, companyTransfer, 
    addNotification, updateCatalog, userAccounts 
  } = useBank();

  const [selectedCompanyId, setSelectedCompanyId] = useState<string | null>(null);
  const [currentView, setCurrentView] = useState('OVERVIEW');

  // States for Modals/Forms
  const [showPayrollModal, setShowPayrollModal] = useState(false);
  const [showEmployeeModal, setShowEmployeeModal] = useState(false);
  const [showProductModal, setShowProductModal] = useState(false);
  const [showTransferModal, setShowTransferModal] = useState(false);

  // Data States
  const [payrollHistory, setPayrollHistory] = useState<PayrollHistory[]>([]);
  const [searchTerm, setSearchTerm] = useState('');

  // Forms
  const [editingEmployee, setEditingEmployee] = useState<Employee | null>(null);
  const [empForm, setEmpForm] = useState({ name: '', dip: '', salary: '', role: '', iban: '' });

  const [editingProduct, setEditingProduct] = useState<Product | null>(null);
  const [prodForm, setProdForm] = useState({ name: '', price: '', description: '' });

  const [transferForm, setTransferForm] = useState({ destIban: '', amount: '', concept: '' });

  // Init
  useEffect(() => {
    if (companies.length > 0 && !selectedCompanyId) {
        const myCompanies = companies.filter(c => c.ownerId === currentUser?.id);
        if(myCompanies.length > 0) setSelectedCompanyId(myCompanies[0].id);
    }
  }, [companies, currentUser]);

  const selectedCompany = useMemo(() => companies.find(c => c.id === selectedCompanyId), [companies, selectedCompanyId]);

  // Accounts Balance Check (Company Account is virtual in DB but represented here)
  const companyBalance = useMemo(() => {
      // Find the account linked to this company IBAN if it exists in userAccounts context, or rely on company prop
      const acc = userAccounts.find(a => a.iban === selectedCompany?.iban);
      return acc ? acc.balance : (selectedCompany?.capital || 0); // Fallback to capital if no explicit account loaded
  }, [selectedCompany, userAccounts]);

  useEffect(() => {
    if (selectedCompanyId && currentView === 'EMPLOYEES') {
        getPayrollHistory(selectedCompanyId).then(setPayrollHistory);
    }
  }, [selectedCompanyId, currentView]);

  // --- HANDLERS ---

  const handleTransfer = async () => {
      if(!selectedCompany || !transferForm.destIban || !transferForm.amount) return;
      try {
          await companyTransfer(selectedCompany.id, transferForm.destIban, Number(transferForm.amount), transferForm.concept || 'Transferencia Corporativa');
          setShowTransferModal(false);
          setTransferForm({ destIban: '', amount: '', concept: '' });
      } catch(e: any) {
          addNotification(e.message, 'error');
      }
  };

  const handlePayrollProcess = async () => {
    if (!selectedCompany) return;
    const now = new Date();
    try {
        await payPayroll(selectedCompany.id, (now.getMonth() + 1).toString(), now.getFullYear().toString());
        setShowPayrollModal(false);
        const h = await getPayrollHistory(selectedCompany.id);
        setPayrollHistory(h);
    } catch (e: any) {
        addNotification(e.message, 'error');
    }
  };

  const handleEmployeeSave = async () => {
      if (!selectedCompany) return;
      const salary = parseFloat(empForm.salary);
      if (!empForm.name || !empForm.dip || isNaN(salary)) { addNotification("Datos inválidos", "error"); return; }

      const updatedEmployees = [...selectedCompany.employees];
      if (editingEmployee) {
          const idx = updatedEmployees.findIndex(e => e.id === editingEmployee.id);
          if (idx !== -1) updatedEmployees[idx] = { ...editingEmployee, ...empForm, salary };
      } else {
          updatedEmployees.push({
              id: `emp-${Date.now()}`,
              ...empForm,
              salary,
              hireDate: new Date().toISOString(),
              status: 'ACTIVE'
          });
      }
      await updateEmployees(selectedCompany.id, updatedEmployees);
      setShowEmployeeModal(false);
      setEmpForm({ name: '', dip: '', salary: '', role: '', iban: '' });
  };

  const handleProductSave = async () => {
      if(!selectedCompany) return;
      const price = parseFloat(prodForm.price);
      if(!prodForm.name || isNaN(price)) { addNotification("Producto inválido", "error"); return; }

      const currentCatalog = selectedCompany.catalog?.products || [];
      let newProducts = [...currentCatalog];

      if(editingProduct) {
          const idx = newProducts.findIndex(p => p.id === editingProduct.id);
          if(idx !== -1) newProducts[idx] = { ...editingProduct, ...prodForm, price };
      } else {
          newProducts.push({
              id: `prod-${Date.now()}`,
              ...prodForm,
              price
          });
      }
      await updateCatalog(selectedCompany.id, newProducts);
      setShowProductModal(false);
      setProdForm({ name: '', price: '', description: '' });
  };

