export default async function handler(req: any, res: any) {
    let client: any;
    res.setHeader('Content-Type', 'application/json');
    res.setHeader('Access-Control-Allow-Origin', '*');
    res.setHeader('Access-Control-Allow-Methods', 'POST, OPTIONS');
    res.setHeader('Access-Control-Allow-Headers', 'Content-Type, x-api-key');

    if (req.method === 'OPTIONS') return res.status(200).end();

    try {
        const { action, ...params } = req.body || {};
        client = await getPool().connect();

        // --- AUTH & DATA LOADING ---

        if (action === 'AUTH') {
            const { dip, password } = params;
            const userRes = await client.query(
                "SELECT * FROM users WHERE UPPER(dip) = $1 AND password_hash = $2", 
                [dip.toUpperCase().trim(), password]
            );
            if (userRes.rows.length === 0) return res.status(401).json({ error: "Credenciales no encontradas en el Ledger." });
            return res.status(200).json({ success: true, user: formatResponse(userRes.rows[0]) });
        }

        if (action === 'AUTH_PLACETAID') {
            const { userData } = params;
            const dip = (userData.dni || userData.dip || userData.id || userData.username || '').toUpperCase().trim();
            if (!dip) return res.status(400).json({ error: "Identidad externa no válida." });

            const userRes = await client.query("SELECT * FROM users WHERE UPPER(dip) = $1", [dip]);
            if (userRes.rows.length === 0) return res.status(404).json({ error: "Usuario validado por la Junta, pero no tiene cuenta bancaria activa." });

            return res.status(200).json({ success: true, user: formatResponse(userRes.rows[0]) });
        }

        if (action === 'GET_INITIAL_DATA') {
            const { userId } = params;
            const accounts = (await client.query("SELECT * FROM accounts WHERE owner_id = $1 OR $1 = ANY(shared_with)", [userId])).rows;
            const companies = (await client.query("SELECT * FROM companies")).rows;
            const cards = (await client.query("SELECT * FROM cards WHERE account_id IN (SELECT id FROM accounts WHERE owner_id = $1)", [userId])).rows;
            const contacts = (await client.query("SELECT * FROM contacts WHERE user_id = $1", [userId])).rows;

            const shareRequests = (await client.query(`
                SELECT sr.*, u1.name as from_user_name, u2.name as to_user_name
                FROM share_requests sr 
                LEFT JOIN users u1 ON sr.from_user_id = u1.id
                LEFT JOIN users u2 ON sr.to_user_dip = u2.dip
                WHERE sr.from_user_id = $1 OR sr.to_user_dip = (SELECT dip FROM users WHERE id = $1)
            `, [userId])).rows;

            const lootBoxes = (await client.query("SELECT * FROM loot_boxes")).rows;

            const allDesigns = (await client.query("SELECT * FROM card_designs")).rows;
            const storeDesigns = allDesigns.filter((d: any) => !d.owner_id || d.is_listed);
            const inventoryDesigns = allDesigns.filter((d: any) => d.owner_id === userId);

            const ibans = accounts.map((a: any) => a.iban);
            let txs = [];
            if (ibans.length > 0) {
                const placeholders = ibans.map((_, i) => `$${i + 1}`).join(',');
                txs = (await client.query(
                    `SELECT * FROM transactions WHERE sender_iban IN (${placeholders}) OR receiver_iban IN (${placeholders}) ORDER BY date DESC LIMIT 50`, 
                    ibans
                )).rows;
            }

            return res.status(200).json(formatResponse({ 
                accounts, 
                companies, 
                cards, 
                transactions: txs, 
                contacts,
                shareRequests,
                lootBoxes,
                marketDesigns: { store: storeDesigns, inventory: inventoryDesigns },
                taxConfig: { vatRate: 12, transferRate: 1, companyTaxRate: 25, lotteryRate: 20 }
            }));
        }

        // --- TRANSFERS ---

        if (action === 'TRANSFER') {
            const { fromIban, toIban, amount, description, type } = params;
            const taxRate = 0.01; // 1% Comisión
            const taxAmount = amount * taxRate;
            const totalDeduction = amount + taxAmount;

            await client.query("BEGIN");
            const senderRes = await client.query("SELECT balance FROM accounts WHERE iban = $1 FOR UPDATE", [fromIban]);

            if (senderRes.rows.length === 0 || parseFloat(senderRes.rows[0].balance) < totalDeduction) {
                await client.query("ROLLBACK");
                return res.status(400).json({ error: "Saldo insuficiente para transferencia + comisión" });
            }

            const receiverRes = await client.query("SELECT iban FROM accounts WHERE iban = $1", [toIban]);
            const compRes = await client.query("SELECT iban FROM companies WHERE iban = $1", [toIban]);

            if (receiverRes.rows.length === 0 && compRes.rows.length === 0) {
                 await client.query("ROLLBACK");
                 return res.status(404).json({ error: "Destinatario no encontrado" });
            }

            // 1. Descontar del emisor
            await client.query("UPDATE accounts SET balance = balance - $1 WHERE iban = $2", [totalDeduction, fromIban]);

            // 2. Ingresar neto al receptor
            const updateRes = await client.query("UPDATE accounts SET balance = balance + $1 WHERE iban = $2", [amount, toIban]);
            if (updateRes.rowCount === 0) {
                // Fallback para empresas que usan su IBAN principal
                await client.query("ROLLBACK");
                return res.status(404).json({ error: "Cuenta de destino no accesible" });
            }

            // 3. Ingresar comisión al Banco
            await client.query("UPDATE accounts SET balance = balance + $1 WHERE iban = $2", [taxAmount, BANK_IBAN]);

            const txId = `tx-${Date.now()}-${Math.random().toString(36).substr(2, 9)}`;
            await client.query(`INSERT INTO transactions (id, amount, sender_iban, receiver_iban, description, type, tax, status, date) 
                VALUES ($1, $2, $3, $4, $5, $6, $7, 'COMPLETED', NOW())`, 
                [txId, amount, fromIban, toIban, description, type || 'TRANSFER', taxAmount]);

            await client.query("COMMIT");
            return res.status(200).json({ success: true });
        }

        if (action === 'COMPANY_TRANSFER') {
            const { companyId, toIban, amount, description } = params;
            const taxRate = 0.01; 
            const taxAmount = amount * taxRate;
            const totalDeduction = amount + taxAmount;

            await client.query("BEGIN");

            const compRes = await client.query("SELECT iban FROM companies WHERE id = $1", [companyId]);
            if (compRes.rows.length === 0) throw new Error("Empresa no encontrada");
            const fromIban = compRes.rows[0].iban;

            const senderRes = await client.query("SELECT balance FROM accounts WHERE iban = $1 FOR UPDATE", [fromIban]);
            if (senderRes.rows.length === 0 || parseFloat(senderRes.rows[0].balance) < totalDeduction) {
                await client.query("ROLLBACK");
                return res.status(400).json({ error: "Fondos corporativos insuficientes" });
            }

            await client.query("UPDATE accounts SET balance = balance - $1 WHERE iban = $2", [totalDeduction, fromIban]);
            await client.query("UPDATE accounts SET balance = balance + $1 WHERE iban = $2", [amount, toIban]);
            await client.query("UPDATE accounts SET balance = balance + $1 WHERE iban = $2", [taxAmount, BANK_IBAN]);

            const txId = `ctx-${Date.now()}`;
            await client.query(`INSERT INTO transactions (id, amount, sender_iban, receiver_iban, description, type, tax, status, date) 
                VALUES ($1, $2, $3, $4, $5, 'TRANSFER', $6, 'COMPLETED', NOW())`, 
                [txId, amount, fromIban, toIban, description || 'Gasto Corporativo', taxAmount]);

            await client.query("COMMIT");
            await logAction(client, companyId, 'TRANSFER_OUT', 'SUCCESS', { amount, toIban });
            return res.status(200).json({ success: true });
        }

        // --- BUSINESS ACTIONS ---

        if (action === 'GET_PAYROLL_HISTORY') {
            const { companyId } = params;
            const historyRes = await client.query("SELECT * FROM payroll_history WHERE company_id = $1 ORDER BY processed_at DESC LIMIT 12", [companyId]);
            return res.status(200).json(formatResponse(historyRes.rows));
        }

        if (action === 'PAY_PAYROLL') {
            const { companyId, month, year } = params;
            // NORMATIVA: 
            // 1. Empleado: IRPF 7.5% sobre el Bruto (Se resta del sueldo).
            // 2. Empresa: Cuota Patronal 7.5% sobre el Bruto (Se paga EXTRA).
            const taxRate = 0.075; 

            const compRes = await client.query("SELECT * FROM companies WHERE id = $1", [companyId]);
            if (compRes.rows.length === 0) return res.status(404).json({ error: "Empresa no encontrada" });
            const company = compRes.rows[0];
            const employees = company.employees || [];
            if (employees.length === 0) return res.status(400).json({ error: "No hay empleados registrados" });

            // Calcular totales
            let totalGross = 0;
            let totalEmployerTax = 0; // Lo que paga la empresa extra
            let totalWorkerTax = 0; // Lo que se le retiene al empleado

            for (const emp of employees) {
                const gross = Number(emp.salary);
                totalGross += gross;
                totalEmployerTax += (gross * taxRate);
                totalWorkerTax += (gross * taxRate);
            }

            // Coste TOTAL para la empresa = Salarios Brutos + Cuota Patronal
            const totalCostForCompany = totalGross + totalEmployerTax;

            // Total a ingresar al estado = Cuota Patronal + Retención Trabajador
            const totalTaxToState = totalEmployerTax + totalWorkerTax;

            await client.query("BEGIN");

            const compAccRes = await client.query("SELECT * FROM accounts WHERE iban = $1 FOR UPDATE", [company.iban]);
            if (compAccRes.rows.length === 0 || parseFloat(compAccRes.rows[0].balance) < totalCostForCompany) {
                await client.query("ROLLBACK");
                return res.status(400).json({ error: "Fondos insuficientes para nóminas + cuota patronal" });
            }

            // 1. Descontar COSTE TOTAL de la empresa
            await client.query("UPDATE accounts SET balance = balance - $1 WHERE iban = $2", [totalCostForCompany, company.iban]);

            // 2. Procesar cada empleado
            for (const emp of employees) {
                const gross = Number(emp.salary);
                const retention = gross * taxRate; // 7.5%
                const net = gross - retention;

                // Ingresar NETO al empleado
                await client.query("UPDATE accounts SET balance = balance + $1 WHERE iban = $2", [net, emp.iban]);

                // Registrar Transacción Nómina
                await client.query(`INSERT INTO transactions (id, amount, sender_iban, receiver_iban, description, type, tax, status, date) 
                   VALUES ($1, $2, $3, $4, $5, 'PAYROLL', $6, 'COMPLETED', NOW())`, 
                   [`pay-${Date.now()}-${Math.random().toString(36).substr(2,5)}`, net, company.iban, emp.iban, `Nómina ${month}/${year}`, retention]);
            }

            // 3. Ingresar el total de impuestos al Estado
            await client.query("UPDATE accounts SET balance = balance + $1 WHERE iban = $2", [totalTaxToState, BANK_IBAN]);

            // Registrar Transacción Impuestos Global (Patronal + Obrero)
            await client.query(`INSERT INTO transactions (id, amount, sender_iban, receiver_iban, description, type, status, date)
               VALUES ($1, $2, $3, $4, $5, 'TAX', 'COMPLETED', NOW())`,
               [`tax-${Date.now()}`, totalTaxToState, company.iban, BANK_IBAN, `Impuestos Nóminas (Total 15%) ${month}/${year}`]);

            // Guardar Histórico
            const historyId = `ph-${Date.now()}`;
            await client.query(
                `INSERT INTO payroll_history (id, company_id, month, year, total_amount, employee_count, total_taxes) VALUES ($1, $2, $3, $4, $5, $6, $7)`,
                [historyId, companyId, month, year, totalGross, employees.length, totalTaxToState]
            );

            await client.query("COMMIT");
            await logAction(client, companyId, 'PAY_PAYROLL', 'SUCCESS', { month, totalCostForCompany });
            return res.status(200).json({ success: true });
        }

        if (action === 'UPDATE_CATALOG') {
            const { companyId, products } = params;
            const catalog = { active: true, products: products };
            await client.query("UPDATE companies SET catalog = $1 WHERE id = $2", [JSON.stringify(catalog), companyId]);
            await logAction(client, companyId, 'UPDATE_CATALOG', 'SUCCESS');
            return res.status(200).json({ success: true });
        }

        if (action === 'GET_API_USAGE_LOGS') {
            const { companyId } = params;
            const logs = await client.query("SELECT * FROM api_usage_logs WHERE company_id = $1 ORDER BY timestamp DESC LIMIT 50", [companyId]);
            return res.status(200).json(formatResponse(logs.rows));
        }

        // --- ADMIN TAXES ---

        if (action === 'ADMIN_GENERATE_MONTHLY_TAXES') {
            const { month, year } = params;

            await client.query("BEGIN");

            // 1. Obtener todas las cuentas (excepto la del banco)
            const accountsRes = await client.query("SELECT * FROM accounts WHERE type != 'STATE' AND iban != $1", [BANK_IBAN]);
            const accounts = accountsRes.rows;
            let totalCollected = 0;
            let countProcessed = 0;

            for (const acc of accounts) {
                // 2. Calcular Ingresos y Gastos del mes seleccionado para esta cuenta
                // Nota: Postgres usa EXTRACT(MONTH FROM date)
                const txRes = await client.query(`
                    SELECT * FROM transactions 
                    WHERE (sender_iban = $1 OR receiver_iban = $1)
                    AND EXTRACT(MONTH FROM date) = $2
                    AND EXTRACT(YEAR FROM date) = $3
                `, [acc.iban, month, year]);

                let income = 0;
                let expenses = 0;

                txRes.rows.forEach((tx: any) => {
                    const amt = parseFloat(tx.amount);
                    if (tx.receiver_iban === acc.iban) income += amt;
                    if (tx.sender_iban === acc.iban) expenses += amt;
                });

                // 3. Calcular IA (Índice de Acumulación)
                // IA = (Ingresos - Gastos) / Saldo Actual (Simplificado para el cierre de mes)
                const currentBalance = parseFloat(acc.balance);
                const netFlow = income - expenses;

                // Si el balance es muy bajo, ignorar para evitar división por cero o IA infinito
                if (currentBalance < 100) continue;

                let ia = 0;
                if (netFlow > 0) {
                    ia = netFlow / currentBalance;
                }

                // 4. Determinar Tasa según Normativa
                // IA > 0.30 -> 15% (Acumulación Alta)
                // IA > 0.10 -> 5% (Acumulación Media)
                // IA <= 0.10 -> 1% (Mantenimiento)
                let taxRate = 0.01;
                if (ia > 0.30) taxRate = 0.15;
                else if (ia > 0.10) taxRate = 0.05;

                const taxAmount = currentBalance * taxRate;

                if (taxAmount > 0 && currentBalance >= taxAmount) {
                    // Cobrar Impuesto
                    await client.query("UPDATE accounts SET balance = balance - $1 WHERE id = $2", [taxAmount, acc.id]);
                    await client.query("UPDATE accounts SET balance = balance + $1 WHERE iban = $2", [taxAmount, BANK_IBAN]);

                    const txId = `tax-${year}-${month}-${acc.id.substr(-4)}`;
                    await client.query(`
                        INSERT INTO transactions (id, amount, sender_iban, receiver_iban, description, type, status, date)
                        VALUES ($1, $2, $3, $4, $5, 'IRM_TAX', 'COMPLETED', NOW())
                    `, [txId, taxAmount, acc.iban, BANK_IBAN, `Impuesto Mensual (IA: ${ia.toFixed(2)}) - ${month}/${year}`]);

                    totalCollected += taxAmount;
                    countProcessed++;
                }
            }

            await client.query("COMMIT");
            return res.status(200).json({ success: true, processed: countProcessed, total: totalCollected });
        }

        if (action === 'ADMIN_GET_STATE') {
             const users = (await client.query("SELECT * FROM users ORDER BY created_at DESC")).rows;
             const txs = (await client.query("SELECT * FROM transactions ORDER BY date DESC LIMIT 200")).rows;
             const accounts = (await client.query("SELECT * FROM accounts")).rows;
             const m0 = accounts.reduce((acc: number, curr: any) => acc + parseFloat(curr.balance), 0);
             return res.status(200).json(formatResponse({ users, transactions: txs, allAccounts: accounts, m0, config: {} }));
        }

        // Mocks for other actions to ensure compatibility
        if (['ADMIN_REVERT_TX', 'ADMIN_UPDATE_USER_STATUS', 'ADMIN_MINT', 'ADMIN_CREATE_USER', 'ADMIN_PROCESS_TAX_COLLECTION', 
             'BUY_LOOTBOX', 'REDEEM_CODE', 'BUY_DESIGN', 'LIST_DESIGN', 'DELETE_DESIGN', 
             'COMPANY_ROTATE_KEY', 'CREATE_SUBACCOUNT', 'CREATE_LOTTERY', 'APPROVE_LOTTERY', 'DELETE_LOTTERY',
             'SAVE_CONTACT', 'DELETE_CONTACT', 'REQUEST_CARD', 'TOGGLE_CARD_STATUS', 'UPDATE_CARD_PIN', 'PAY_WITH_CARD',
             'BUY_STOCK', 'SELL_STOCK', 'PAY_TAX', 'GET_FISCAL_PROJECTION', 'RESPOND_SHARE_REQUEST', 'REQUEST_SHARE_ACCOUNT'
            ].includes(action)) {
             return res.status(200).json({ success: true });
        }

        return res.status(400).json({ error: `Operación no soportada: ${action}` });

    } catch (e: any) {
        console.error("API Error:", e);
        return res.status(500).json({ error: "Error interno del servidor: " + e.message });
    } finally {
        if (client) client.release();
    }
}

