import React, { useState, useMemo } from 'react';
import { useBank } from '../context/BankContext';
import { SECURITY_THRESHOLD_AMOUNT } from '../constants';
import { Send, ChevronDown, X, CheckCircle2, ShieldCheck, User, Search, BookUser, ArrowRight, Wallet, Check, Users, ScanLine } from 'lucide-react';

interface TransfersProps {
  addNotification: (msg: string, type: 'success' | 'error' | 'info') => void;
}

type TransferStep = 'IDLE' | 'SECURITY' | 'CONFIRM' | 'PROCESSING' | 'SUCCESS';

const KeypadButton: React.FC<{ val: string; onClick: () => void; icon?: React.ReactNode; primary?: boolean }> = ({ val, onClick, icon, primary }) => (
  <button 
    onClick={(e) => {
        const btn = e.currentTarget;
        btn.classList.add('scale-90', 'bg-slate-200');
        setTimeout(() => btn.classList.remove('scale-90', 'bg-slate-200'), 100);
        onClick();
    }}
    className={`h-14 w-full rounded-2xl transition-all duration-150 text-xl font-bold flex items-center justify-center select-none ${primary ? 'bg-brand-600 text-white shadow-lg shadow-brand-500/30 hover:bg-brand-700' : 'bg-white border border-slate-200 text-slate-900 hover:bg-slate-50 shadow-sm'}`}
  >
      {icon ? icon : val}
  </button>
);

export const Transfers: React.FC<TransfersProps> = ({ addNotification }) => {
  const { userAccounts, transfer, taxConfig, contacts, triggerHaptic } = useBank();

  const [selectedAccountIndex, setSelectedAccountIndex] = useState(0);
  const [showAccountDrawer, setShowAccountDrawer] = useState(false); 
  const [showContactDrawer, setShowContactDrawer] = useState(false);

  const [recipientBody, setRecipientBody] = useState(''); 
  const [showSuggestions, setShowSuggestions] = useState(false);

  const [amount, setAmount] = useState('');
  const [transferStep, setTransferStep] = useState<TransferStep>('IDLE');

  const currentAccount = userAccounts[selectedAccountIndex];
  const currentTaxRate = taxConfig.transferRate;
  const fullRecipient = 'PL' + recipientBody;

  // Filter contacts based on input
  const filteredContacts = useMemo(() => {
      if (!recipientBody) return contacts; 
      return contacts.filter(c => 
          c.name.toLowerCase().includes(recipientBody.toLowerCase()) || 
          c.iban.includes(recipientBody)
      );
  }, [contacts, recipientBody]);

  const suggestions = useMemo(() => {
      return filteredContacts.slice(0, 3);
  }, [filteredContacts]);

  const handleKeypad = (val: string) => {
      triggerHaptic('light');
      if (val === 'DEL') {
          setAmount(prev => prev.slice(0, -1));
      } else if (val === '.') {
          if (!amount.includes('.')) setAmount(prev => prev + '.');
      } else {
          if (amount.length < 9) setAmount(prev => prev + val);
      }
  };

  const handleRecipientChange = (e: React.ChangeEvent<HTMLInputElement>) => {
      let val = e.target.value.toUpperCase().replace(/[^A-Z0-9]/g, '');
      if (val.startsWith('PL')) val = val.substring(2);
      if (val.length <= 22) setRecipientBody(val);
      setShowSuggestions(true);
  };

  const selectContact = (contactIban: string) => {
      triggerHaptic('medium');
      const clean = contactIban.startsWith('PL') ? contactIban.substring(2) : contactIban;
      setRecipientBody(clean);
      setShowSuggestions(false);
      setShowContactDrawer(false);
  };

  const handleVerify = () => {
    triggerHaptic('medium');
    if (recipientBody.length !== 22) {
      addNotification("El IBAN debe tener 22 dígitos (PL...)", 'error');
      return;
    }

    const numericAmount = Number(amount);
    const taxAmount = numericAmount * (currentTaxRate / 100);
    const totalDeduction = numericAmount + taxAmount;

    if (numericAmount <= 0) {
        addNotification("Introduce un monto mayor a 0", 'error');
        return;
    }

    if (totalDeduction > currentAccount.balance) {
      addNotification(`Saldo insuficiente. Total: ${totalDeduction.toLocaleString()} Pts`, 'error');
      return;
    }

    if (numericAmount > SECURITY_THRESHOLD_AMOUNT) {
      setTransferStep('SECURITY');
    } else {
      setTransferStep('CONFIRM');
    }
  };

  const handleConfirm = async () => {
    triggerHaptic('heavy');
    setTransferStep('PROCESSING');
    await new Promise(r => setTimeout(r, 1500)); 
    try {
        await transfer(currentAccount.iban, fullRecipient, Number(amount), 'Transferencia Móvil');
        setTransferStep('SUCCESS');
    } catch (e: any) {
        addNotification(e.message || "Error en la transferencia", 'error');
        setTransferStep('IDLE');
    }
  };

  const resetFlow = () => {
      setTransferStep('IDLE');
      setAmount('');
      setRecipientBody('');
  };

  if (!currentAccount) return <div className="p-8 text-center text-slate-400">Cargando cuentas...</div>;

  const numericAmount = Number(amount) || 0;
  const taxAmount = numericAmount * (currentTaxRate / 100);
  const totalAmount = numericAmount + taxAmount;

  return (
    <div className="pb-safe-nav h-full flex flex-col max-w-lg mx-auto relative animate-fade-in pt-safe px-4 min-h-screen">

      {/* Header */}
      <div className="flex justify-between items-center mb-6">
            <h2 className="text-3xl font-black text-slate-900 tracking-tight">Transferir</h2>
            <div className="bg-brand-50 text-brand-600 border border-brand-100 px-3 py-1 rounded-full text-[10px] font-black uppercase tracking-widest">
                Tasa IRM: {currentTaxRate}%
            </div>
      </div>

      {/* Account Selector Card */}
      <div className="relative mb-6 z-20">
             <button 
                className="w-full p-5 bg-gradient-to-br from-slate-900 to-slate-800 text-white rounded-[2rem] flex items-center justify-between shadow-xl shadow-slate-900/20 active:scale-[0.98] transition-all group relative overflow-hidden"
                onClick={() => setShowAccountDrawer(true)}
             >
                <div className="absolute top-0 right-0 w-32 h-32 bg-white/5 rounded-full blur-2xl -mr-10 -mt-10"></div>
                <div className="flex items-center gap-4 relative z-10">
                    <div className="w-12 h-12 bg-white/10 rounded-2xl flex items-center justify-center backdrop-blur-md border border-white/10 shadow-inner">
                        <Wallet size={24} className="text-white" />
                    </div>
                    <div className="text-left">
                        <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest mb-0.5">Cuenta Origen</p>
                        <p className="font-bold text-lg leading-none">{currentAccount.alias}</p>
                    </div>
                </div>
                <div className="text-right relative z-10">
                    <p className="text-2xl font-black tracking-tight">{currentAccount.balance.toLocaleString()}</p>
                    <p className="text-[10px] text-slate-400 font-bold">Pts Disponibles</p>
                </div>
                <div className="absolute bottom-2 left-1/2 -translate-x-1/2 bg-white/10 backdrop-blur-md px-3 py-0.5 rounded-full text-[9px] font-bold flex items-center gap-1 opacity-0 group-hover:opacity-100 transition-opacity translate-y-1 group-hover:translate-y-0">
                    <ChevronDown size={10}/> Cambiar
                </div>
            </button>
      </div>

      {/* Recipient Input Area */}
      <div className="relative mb-6 z-10">
          <div className="flex justify-between items-end mb-2 ml-1">
              <label className="text-xs font-bold text-slate-400 uppercase tracking-widest">Destinatario</label>
              <button onClick={() => setShowContactDrawer(true)} className="text-[10px] font-black text-brand-600 uppercase tracking-wider flex items-center gap-1 hover:bg-brand-50 px-2 py-0.5 rounded-lg transition-colors">
                  <BookUser size={12}/> Mis Contactos
              </button>
          </div>

          <div className={`bg-white p-2 rounded-[1.5rem] border-2 flex items-center shadow-sm transition-all relative ${showSuggestions ? 'border-brand-500 ring-4 ring-brand-500/10' : 'border-slate-200 focus-within:border-brand-300'}`}>
              <div className="bg-slate-100 w-12 h-12 rounded-2xl flex items-center justify-center text-slate-500 font-black text-sm select-none shrink-0 border border-slate-200">PL</div>
              <input 
                  type="text" 
                  value={recipientBody}
                  onChange={handleRecipientChange}
                  onFocus={() => setShowSuggestions(true)}
                  onBlur={() => setTimeout(() => setShowSuggestions(false), 200)}
                  className="flex-1 bg-transparent px-3 font-mono text-lg font-bold outline-none text-slate-900 placeholder:text-slate-300 tracking-widest min-w-0"
                  placeholder="0000 0000..."
                  inputMode="text"
              />
              <div className="pr-2">
                  {recipientBody.length === 22 ? (
                      <div className="w-8 h-8 bg-emerald-100 text-emerald-600 rounded-full flex items-center justify-center animate-pop-in">
                          <Check size={16} strokeWidth={3}/>
                      </div>
                  ) : (
                      <div className="text-[10px] font-bold text-slate-400 bg-slate-50 px-2 py-1 rounded-lg border border-slate-100">{22 - recipientBody.length}</div>
                  )}
              </div>
          </div>

          {/* Inline Suggestions Dropdown */}
          {showSuggestions && recipientBody.length > 0 && (
              <div className="absolute top-full left-0 right-0 mt-2 bg-white rounded-3xl shadow-xl border border-slate-100 overflow-hidden animate-slide-up z-50 p-2">
                  {suggestions.length > 0 ? (
                      suggestions.map(c => (
                          <button key={c.id} onClick={() => selectContact(c.iban)} className="w-full p-3 flex items-center gap-3 hover:bg-slate-50 rounded-2xl transition-colors group">
                              <div className="w-10 h-10 bg-brand-50 text-brand-600 rounded-xl flex items-center justify-center font-bold text-sm group-hover:bg-brand-600 group-hover:text-white transition-colors">
                                  {c.name.charAt(0)}
                              </div>
                              <div className="text-left flex-1">
                                  <p className="font-bold text-slate-900 text-sm">{c.name}</p>
                                  <p className="text-[10px] text-slate-400 font-mono">...{c.iban.slice(-8)}</p>
                              </div>
                              <ArrowRight size={14} className="text-slate-300 group-hover:text-slate-900"/>
                          </button>
                      ))
                  ) : (
                      <div className="p-4 text-center text-slate-400 text-xs font-bold">Sin coincidencias</div>
                  )}
              </div>
          )}
      </div>

      {/* Amount Display */}
      <div className="flex-1 flex flex-col items-center justify-center min-h-[120px] mb-4">
            <div className="flex flex-col items-center animate-scale-up">
                 <p className="text-xs font-bold text-slate-400 uppercase tracking-widest mb-1">Monto a enviar</p>
                 <div className="flex items-baseline gap-1">
                    <span className={`text-6xl font-black tracking-tighter ${amount ? 'text-slate-900' : 'text-slate-300'}`}>
                        {amount || '0'}
                    </span>
                    <span className="text-2xl text-slate-400 font-bold">Pts</span>
                 </div>
            </div>
            {numericAmount > 0 && (
                <div className="flex items-center gap-2 mt-2 px-4 py-1.5 bg-slate-100 rounded-full border border-slate-200">
                    <span className="text-[10px] font-bold text-slate-500 uppercase tracking-widest">Total (+{taxConfig.transferRate}%):</span>
                    <span className="text-xs font-black text-slate-900">{totalAmount.toLocaleString()} Pts</span>
                </div>
            )}
      </div>

      {/* Keypad */}
      <div className="grid grid-cols-3 gap-3 mb-6">
          {[1,2,3,4,5,6,7,8,9].map(n => (
              <KeypadButton key={n} val={n.toString()} onClick={() => handleKeypad(n.toString())} />
          ))}
          <KeypadButton val="." onClick={() => handleKeypad('.')} />
          <KeypadButton val="0" onClick={() => handleKeypad('0')} />
          <KeypadButton val="DEL" onClick={() => handleKeypad('DEL')} icon={<X size={24} className="text-slate-400"/>} />
      </div>

      <button
          onClick={handleVerify}
          disabled={!amount || recipientBody.length !== 22}
          className="w-full py-4 bg-brand-600 text-white rounded-[2rem] font-black text-lg shadow-xl shadow-brand-500/30 active:scale-95 transition-all disabled:opacity-50 disabled:shadow-none flex items-center justify-center gap-2 mb-safe"
        >
          Revisar y Enviar <ArrowRight size={20} strokeWidth={3} />
      </button>

      {/* Account Selection Drawer */}
      {showAccountDrawer && (
          <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-50 flex flex-col justify-end" onClick={() => setShowAccountDrawer(false)}>
              <div className="bg-white rounded-t-[2.5rem] p-6 pb-safe animate-slide-up max-h-[75vh] overflow-y-auto" onClick={e => e.stopPropagation()}>
                  <div className="w-12 h-1.5 bg-slate-200 rounded-full mx-auto mb-6"></div>
                  <h3 className="text-xl font-black text-slate-900 mb-6 px-2 flex items-center gap-2"><Wallet size={20}/> Seleccionar Cuenta</h3>
                  <div className="space-y-3">
                      {userAccounts.map((acc, idx) => (
                          <button 
                              key={acc.id}
