export const Accounts: React.FC<{ addNotification: any }> = ({ addNotification }) => {
  const { userAccounts, cards = [], currentUser, requestCard, toggleCardStatus, updateCardPin, transactions } = useBank();
  const [showDesigner, setShowDesigner] = useState(false);
  const [selectedAccId, setSelectedAccId] = useState('');
  const [cardPin, setCardPin] = useState('');
  const [copied, setCopied] = useState<string | null>(null);

  // Manage Card State
  const [selectedCardId, setSelectedCardId] = useState<string | null>(cards[0]?.id || null);
  const [showSensitive, setShowSensitive] = useState(false);

  const selectedCard = useMemo(() => cards.find(c => c.id === selectedCardId), [cards, selectedCardId]);

  const cardTransactions = useMemo(() => {
    if (!selectedCard) return [];
    const account = userAccounts.find(a => a.id === selectedCard.accountId);
    return transactions.filter(t => (t.senderIban === account?.iban) && t.type === 'CARD_PAYMENT')
                       .sort((a,b) => new Date(b.date).getTime() - new Date(a.date).getTime());
  }, [transactions, selectedCard, userAccounts]);

  const handleCopy = (text: string) => {
      navigator.clipboard.writeText(text);
      setCopied(text);
      setTimeout(() => setCopied(null), 2000);
  };

  const handleRequestCard = async (designUrl: string) => {
      if (!selectedAccId || !cardPin) {
          addNotification("Selecciona cuenta y define un PIN", "error");
          return;
      }
      await requestCard(selectedAccId, currentUser?.name || '', designUrl, cardPin);
      setShowDesigner(false);
  };

  return (
    <div className="p-4 md:p-10 max-w-6xl mx-auto pb-32 animate-fade-in font-sans">
