            <button 
                onClick={() => setShowDesigner(true)}
                className="w-full md:w-auto px-8 py-4 bg-slate-900 text-white rounded-[2rem] font-black text-[10px] uppercase tracking-[0.2em] shadow-2xl hover:bg-brand-600 transition-all active:scale-95 flex items-center justify-center gap-3 group"
            >
                <Plus size={18} className="group-hover:rotate-90 transition-transform"/> Nueva Tarjeta
            </button>
        </header>

