import React, { useState, useMemo } from 'react';
import { useBank } from '../context/BankContext';
import { SECURITY_THRESHOLD_AMOUNT } from '../constants';
import { Send, ChevronDown, X, CheckCircle2, ShieldCheck, User, Search, BookUser, ArrowRight, Wallet, Check } from 'lucide-react';

interface TransfersProps {
  addNotification: (msg: string, type: 'success' | 'error' | 'info') => void;
}

type TransferStep = 'IDLE' | 'SECURITY' | 'CONFIRM' | 'PROCESSING' | 'SUCCESS';

const KeypadButton: React.FC<{ val: string; onClick: () => void; icon?: React.ReactNode; primary?: boolean }> = ({ val, onClick, icon, primary }) => (
  <button 
    onClick={(e) => {
        const btn = e.currentTarget;
        btn.classList.add('scale-90', 'bg-slate-200');
        setTimeout(() => btn.classList.remove('scale-90', 'bg-slate-200'), 100);
        onClick();
    }}
    className={`h-14 w-full rounded-2xl transition-all duration-150 text-xl font-bold flex items-center justify-center select-none ${primary ? 'bg-brand-600 text-white shadow-lg shadow-brand-500/30 hover:bg-brand-700' : 'bg-white border border-slate-200 text-slate-900 hover:bg-slate-50 shadow-sm'}`}
  >
      {icon ? icon : val}
  </button>
);

export const Transfers: React.FC<TransfersProps> = ({ addNotification }) => {
  const { userAccounts, transfer, taxConfig, contacts, triggerHaptic } = useBank();

  const [selectedAccountIndex, setSelectedAccountIndex] = useState(0);
  const [showAccountDrawer, setShowAccountDrawer] = useState(false); 

  const [recipientBody, setRecipientBody] = useState(''); 
  const [showSuggestions, setShowSuggestions] = useState(false);

  const [amount, setAmount] = useState('');
  const [transferStep, setTransferStep] = useState<TransferStep>('IDLE');

  const currentAccount = userAccounts[selectedAccountIndex];
  const currentTaxRate = taxConfig.transferRate;
  const fullRecipient = 'PL' + recipientBody;

  // Filter contacts based on input
  const filteredContacts = useMemo(() => {
      if (!recipientBody) return contacts.slice(0, 3); // Show recent 3 if empty
      return contacts.filter(c => 
          c.name.toLowerCase().includes(recipientBody.toLowerCase()) || 
          c.iban.includes(recipientBody)
      );
  }, [contacts, recipientBody]);

  const handleKeypad = (val: string) => {
      triggerHaptic('light');
      if (val === 'DEL') {
          setAmount(prev => prev.slice(0, -1));
      } else if (val === '.') {
          if (!amount.includes('.')) setAmount(prev => prev + '.');
      } else {
          if (amount.length < 9) setAmount(prev => prev + val);
      }
  };

  const handleRecipientChange = (e: React.ChangeEvent<HTMLInputElement>) => {
      let val = e.target.value.toUpperCase().replace(/[^A-Z0-9]/g, '');
      // Auto-strip PL prefix if pasted
      if (val.startsWith('PL')) val = val.substring(2);
      // Limit length
      if (val.length <= 22) setRecipientBody(val);
      setShowSuggestions(true);
  };

  const selectContact = (contactIban: string) => {
      triggerHaptic('medium');
      const clean = contactIban.startsWith('PL') ? contactIban.substring(2) : contactIban;
      setRecipientBody(clean);
      setShowSuggestions(false);
  };

  const handleVerify = () => {
    triggerHaptic('medium');
    if (recipientBody.length !== 22) {
      addNotification("El IBAN debe tener 22 dígitos (PL...)", 'error');
      return;
    }

    const numericAmount = Number(amount);
    const taxAmount = numericAmount * (currentTaxRate / 100);
    const totalDeduction = numericAmount + taxAmount;

    if (numericAmount <= 0) {
        addNotification("Introduce un monto mayor a 0", 'error');
        return;
    }

    if (totalDeduction > currentAccount.balance) {
      addNotification(`Saldo insuficiente. Total: ${totalDeduction.toLocaleString()} Pts`, 'error');
      return;
    }

    if (numericAmount > SECURITY_THRESHOLD_AMOUNT) {
      setTransferStep('SECURITY');
    } else {
      setTransferStep('CONFIRM');
    }
  };

  const handleConfirm = async () => {
    triggerHaptic('heavy');
    setTransferStep('PROCESSING');
    await new Promise(r => setTimeout(r, 1500)); 
    try {
        await transfer(currentAccount.iban, fullRecipient, Number(amount), 'Transferencia Móvil');
        setTransferStep('SUCCESS');
    } catch (e: any) {
        addNotification(e.message || "Error en la transferencia", 'error');
        setTransferStep('IDLE');
    }
  };

  const resetFlow = () => {
      setTransferStep('IDLE');
      setAmount('');
      setRecipientBody('');
  };

  if (!currentAccount) return <div className="p-8 text-center text-slate-400">Cargando cuentas...</div>;

  const numericAmount = Number(amount) || 0;
  const taxAmount = numericAmount * (currentTaxRate / 100);
  const totalAmount = numericAmount + taxAmount;

  return (
    <div className="pb-safe-nav h-full flex flex-col max-w-lg mx-auto relative animate-fade-in pt-safe px-4 min-h-screen">

      {/* Header */}
      <div className="flex justify-between items-center mb-6">
            <h2 className="text-3xl font-black text-slate-900 tracking-tight">Transferir</h2>
            <div className="bg-slate-100 px-3 py-1 rounded-full text-[10px] font-bold text-slate-500 uppercase tracking-widest">
                Tasa: {currentTaxRate}%
            </div>
      </div>

      {/* Account Selector Card */}
      <div className="relative mb-6 z-20">
             <button 
                className="w-full p-5 bg-slate-900 text-white rounded-[2rem] flex items-center justify-between shadow-xl shadow-slate-900/20 active:scale-[0.98] transition-all group"
                onClick={() => setShowAccountDrawer(true)}
             >
                <div className="flex items-center gap-4">
                    <div className="w-12 h-12 bg-white/10 rounded-2xl flex items-center justify-center backdrop-blur-md border border-white/10">
                        <Wallet size={24} className="text-brand-300" />
                    </div>
                    <div className="text-left">
                        <p className="text-[10px] text-brand-200 font-bold uppercase tracking-widest mb-0.5">Origen</p>
                        <p className="font-bold text-lg leading-none">{currentAccount.alias}</p>
                    </div>
                </div>
                <div className="text-right">
                    <p className="text-2xl font-black tracking-tight">{currentAccount.balance.toLocaleString()}</p>
                    <p className="text-[10px] text-slate-400 font-bold">Pts Disponibles</p>
                </div>
                <div className="absolute -bottom-3 left-1/2 -translate-x-1/2 bg-white text-slate-900 border border-slate-100 shadow-sm px-3 py-1 rounded-full text-[10px] font-bold flex items-center gap-1 opacity-0 group-hover:opacity-100 transition-opacity translate-y-1 group-hover:translate-y-0">
                    Cambiar <ChevronDown size={10}/>
                </div>
            </button>
      </div>

      {/* Recipient Input Area */}
      <div className="relative mb-6 z-10">
          <label className="text-xs font-bold text-slate-400 uppercase tracking-widest ml-4 mb-2 block">Destinatario</label>
          <div className={`bg-white p-2 rounded-[1.5rem] border-2 flex items-center shadow-sm transition-all relative ${showSuggestions ? 'border-brand-500 ring-4 ring-brand-500/10' : 'border-slate-200'}`}>
              <div className="bg-slate-100 w-12 h-12 rounded-2xl flex items-center justify-center text-slate-500 font-black text-sm select-none shrink-0">PL</div>
              <input 
                  type="text" 
                  value={recipientBody}
                  onChange={handleRecipientChange}
                  onFocus={() => setShowSuggestions(true)}
                  // Don't hide immediately on blur to allow clicking suggestions
                  onBlur={() => setTimeout(() => setShowSuggestions(false), 200)}
                  className="flex-1 bg-transparent px-3 font-mono text-lg font-bold outline-none text-slate-900 placeholder:text-slate-300 tracking-widest min-w-0"
                  placeholder="0000 0000..."
                  inputMode="text"
              />
              <div className="pr-2">
                  {recipientBody.length === 22 ? (
                      <div className="w-8 h-8 bg-emerald-100 text-emerald-600 rounded-full flex items-center justify-center animate-pop-in">
