                  <h3 className="text-xl font-black text-slate-900 mb-6 px-2">Seleccionar Cuenta</h3>
                  <div className="space-y-3">
                      {userAccounts.map((acc, idx) => (
                          <button 
                              key={acc.id}
                              onClick={() => { setSelectedAccountIndex(idx); setShowAccountDrawer(false); }}
                              className={`w-full p-5 rounded-[2rem] flex items-center justify-between border-2 transition-all ${selectedAccountIndex === idx ? 'border-brand-600 bg-brand-50' : 'border-slate-100 hover:border-slate-200'}`}
                          >
                              <div className="flex items-center gap-4">
                                  <div className={`w-12 h-12 rounded-2xl flex items-center justify-center font-bold text-lg ${selectedAccountIndex === idx ? 'bg-brand-600 text-white' : 'bg-slate-100 text-slate-500'}`}>
                                      {acc.alias.charAt(0)}
                                  </div>
                                  <div className="text-left">
                                      <p className={`font-bold text-sm ${selectedAccountIndex === idx ? 'text-brand-900' : 'text-slate-900'}`}>{acc.alias}</p>
                                      <p className="text-xs font-mono text-slate-400">{acc.iban.slice(-8)}</p>
                                  </div>
                              </div>
                              <p className="font-black text-slate-900">{acc.balance.toLocaleString()} Pts</p>
                          </button>
                      ))}
                  </div>
              </div>
          </div>
      )}

      {/* Confirmation Modal */}
      {transferStep === 'CONFIRM' && (
           <div className="fixed inset-0 bg-slate-900/80 backdrop-blur-md z-50 flex items-center justify-center p-6 animate-fade-in">
                <div className="bg-white w-full max-w-sm rounded-[2.5rem] p-8 shadow-2xl animate-scale-up relative">
                    <button onClick={resetFlow} className="absolute top-6 right-6 p-2 bg-slate-50 rounded-full hover:bg-slate-100 transition-colors"><X size={20}/></button>

                    <div className="text-center mb-8">
                        <div className="w-16 h-16 bg-brand-50 text-brand-600 rounded-3xl flex items-center justify-center mx-auto mb-4 shadow-sm">
                            <Send size={32} />
                        </div>
                        <h3 className="text-2xl font-black text-slate-900">Confirmar Envío</h3>
                        <p className="text-slate-400 text-xs font-bold mt-1">Revisa los detalles antes de continuar</p>
                    </div>

                    <div className="space-y-4 mb-8 bg-slate-50 p-6 rounded-[2rem]">
                        <div className="flex justify-between items-center">
                            <span className="text-slate-400 font-bold text-xs uppercase">Envías</span>
                            <span className="font-black text-xl text-slate-900">{numericAmount.toLocaleString()} Pts</span>
                        </div>
                        <div className="flex justify-between items-center border-b border-slate-200 pb-4">
                            <span className="text-slate-400 font-bold text-xs uppercase">Comisión</span>
                            <span className="font-bold text-slate-500 text-sm">{taxAmount.toLocaleString()} Pts</span>
                        </div>
                        <div className="flex justify-between items-center pt-2">
                            <span className="text-slate-900 font-bold text-xs uppercase">Total Cargo</span>
                            <span className="font-black text-2xl text-brand-600">{totalAmount.toLocaleString()}</span>
                        </div>
                    </div>

                    <div className="mb-8 px-2">
                        <div className="flex items-center justify-between mb-2">
                            <div className="flex items-center gap-2">
                                <div className="w-2 h-2 bg-slate-300 rounded-full"></div>
                                <span className="text-xs font-bold text-slate-500">Para</span>
                            </div>
                            <span className="font-mono text-xs font-bold text-slate-900 truncate max-w-[150px]">{fullRecipient}</span>
                        </div>
                        <div className="h-4 border-l-2 border-slate-100 ml-[3px] my-1"></div>
                        <div className="flex items-center justify-between mt-2">
                            <div className="flex items-center gap-2">
                                <div className="w-2 h-2 bg-slate-900 rounded-full"></div>
                                <span className="text-xs font-bold text-slate-500">Desde</span>
                            </div>
                            <span className="text-xs font-bold text-slate-900">{currentAccount.alias}</span>
                        </div>
                    </div>

                    <button onClick={handleConfirm} className="w-full py-4 bg-slate-900 text-white rounded-2xl font-black uppercase text-xs tracking-widest shadow-xl hover:bg-brand-600 transition-all active:scale-95 flex items-center justify-center gap-2">
                        <ShieldCheck size={16}/> Autorizar Operación
                    </button>
                </div>
           </div>
      )}

      {transferStep === 'SUCCESS' && (
           <div className="fixed inset-0 bg-white z-50 flex flex-col items-center justify-center p-6 animate-fade-in text-center">
               <div className="w-28 h-28 bg-emerald-50 text-emerald-500 rounded-full flex items-center justify-center mb-8 shadow-xl shadow-emerald-500/10 animate-pop-in">
                   <CheckCircle2 size={64} strokeWidth={3} />
               </div>
               <h2 className="text-4xl font-black text-slate-900 mb-2 tracking-tight">¡Enviado!</h2>
               <p className="text-slate-400 font-bold mb-12 max-w-xs mx-auto leading-relaxed">
                   Has enviado <span className="text-slate-900">{numericAmount.toLocaleString()} Pts</span> correctamente.
               </p>

               <button onClick={resetFlow} className="px-12 py-5 bg-slate-900 text-white rounded-full font-black text-sm uppercase tracking-widest shadow-2xl active:scale-95 transition-all">
                   Finalizar
               </button>
           </div>
      )}
    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { useBank } from '../context/BankContext';
import { BusinessSidebar } from '../components/BusinessSidebar';
import { BusinessMobileNavbar } from '../components/BusinessMobileNavbar';
import { 
  LayoutDashboard, Wallet, FileText, Users, ShoppingCart, 
  DollarSign, UserPlus, Edit2, Trash2, History, Download, 
  ArrowRightLeft, TrendingUp, ArrowUpRight, ArrowDownLeft,
  Package, Plus, Save, X, Search, CreditCard, Landmark, Check
} from 'lucide-react';
import { Company, Employee, PayrollHistory, Product } from '../types';
import { AreaChart, Area, ResponsiveContainer, Tooltip, CartesianGrid } from 'recharts';

interface BusinessDashboardProps {
  onSwitchView: () => void;
}

export const BusinessDashboard: React.FC<BusinessDashboardProps> = ({ onSwitchView }) => {
  const { 
    currentUser, companies, payPayroll, updateEmployees, 
    generatePDF, getPayrollHistory, companyTransfer, 
    addNotification, updateCatalog, userAccounts, createSubaccount 
  } = useBank();

  const [selectedCompanyId, setSelectedCompanyId] = useState<string | null>(null);
  const [currentView, setCurrentView] = useState('OVERVIEW');

  // States for Modals/Forms
  const [showPayrollModal, setShowPayrollModal] = useState(false);
  const [showEmployeeModal, setShowEmployeeModal] = useState(false);
  const [showProductModal, setShowProductModal] = useState(false);
  const [showTransferModal, setShowTransferModal] = useState(false);
  const [showNewAccountModal, setShowNewAccountModal] = useState(false);

  // Data States
  const [payrollHistory, setPayrollHistory] = useState<PayrollHistory[]>([]);
  const [searchTerm, setSearchTerm] = useState('');
  const [newAccountAlias, setNewAccountAlias] = useState('');

  // Forms
  const [editingEmployee, setEditingEmployee] = useState<Employee | null>(null);
  const [empForm, setEmpForm] = useState({ name: '', dip: '', salary: '', role: '', iban: '' });

  const [editingProduct, setEditingProduct] = useState<Product | null>(null);
  const [prodForm, setProdForm] = useState({ name: '', price: '', description: '' });

  const [transferForm, setTransferForm] = useState({ sourceIban: '', destIban: '', amount: '', concept: '' });

  // Init
  useEffect(() => {
    if (companies.length > 0 && !selectedCompanyId) {
        const myCompanies = companies.filter(c => c.ownerId === currentUser?.id);
        if(myCompanies.length > 0) setSelectedCompanyId(myCompanies[0].id);
    }
  }, [companies, currentUser]);

  const selectedCompany = useMemo(() => companies.find(c => c.id === selectedCompanyId), [companies, selectedCompanyId]);

  // Fetch all accounts belonging to this company
  const companyAccounts = useMemo(() => {
      if(!selectedCompany) return [];
      return userAccounts.filter(a => a.ownerId === currentUser?.id || a.companyId === selectedCompany.id || a.iban === selectedCompany.iban);
  }, [userAccounts, selectedCompany, currentUser]);

  const totalBalance = useMemo(() => companyAccounts.reduce((acc, curr) => acc + curr.balance, 0), [companyAccounts]);

  useEffect(() => {
    if (selectedCompanyId && currentView === 'EMPLOYEES') {
        getPayrollHistory(selectedCompanyId).then(setPayrollHistory);
    }
  }, [selectedCompanyId, currentView]);

  // --- HANDLERS ---

  const handleTransfer = async () => {
      if(!selectedCompany || !transferForm.destIban || !transferForm.amount) return;
      // If sourceIban isn't set, default to main company IBAN
      const source = transferForm.sourceIban || selectedCompany.iban;

      try {
          // Use the general transfer function but originating from company context
          // Note: In a real backend, we'd validate ownership. Here context handles it.
          await companyTransfer(selectedCompany.id, transferForm.destIban, Number(transferForm.amount), transferForm.concept || 'Transferencia Corporativa');
          setShowTransferModal(false);
          setTransferForm({ sourceIban: '', destIban: '', amount: '', concept: '' });
      } catch(e: any) {
          addNotification(e.message, 'error');
      }
  };

  const handleCreateSubaccount = async () => {
      if(!selectedCompany || !newAccountAlias) return;
      try {
          await createSubaccount(selectedCompany.id, newAccountAlias);
          setShowNewAccountModal(false);
          setNewAccountAlias('');
          addNotification("Cuenta operativa creada", "success");
      } catch(e: any) {
          addNotification(e.message, "error");
      }
  };

  const handlePayrollProcess = async () => {
    if (!selectedCompany) return;
    const now = new Date();
    try {
        await payPayroll(selectedCompany.id, (now.getMonth() + 1).toString(), now.getFullYear().toString());
        setShowPayrollModal(false);
        const h = await getPayrollHistory(selectedCompany.id);
        setPayrollHistory(h);
    } catch (e: any) {
        addNotification(e.message, 'error');
    }
  };

  const handleEmployeeSave = async () => {
      if (!selectedCompany) return;
      const salary = parseFloat(empForm.salary);
      if (!empForm.name || !empForm.dip || isNaN(salary)) { addNotification("Datos inválidos", "error"); return; }

      const updatedEmployees = [...selectedCompany.employees];
      if (editingEmployee) {
          const idx = updatedEmployees.findIndex(e => e.id === editingEmployee.id);
          if (idx !== -1) updatedEmployees[idx] = { ...editingEmployee, ...empForm, salary };
      } else {
          updatedEmployees.push({
              id: `emp-${Date.now()}`,
              ...empForm,
              salary,
              hireDate: new Date().toISOString(),
              status: 'ACTIVE'
          });
      }
      await updateEmployees(selectedCompany.id, updatedEmployees);
      setShowEmployeeModal(false);
      setEmpForm({ name: '', dip: '', salary: '', role: '', iban: '' });
  };

  const handleProductSave = async () => {
      if(!selectedCompany) return;
      const price = parseFloat(prodForm.price);
      if(!prodForm.name || isNaN(price)) { addNotification("Producto inválido", "error"); return; }

      const currentCatalog = selectedCompany.catalog?.products || [];
      let newProducts = [...currentCatalog];

      if(editingProduct) {
          const idx = newProducts.findIndex(p => p.id === editingProduct.id);
          if(idx !== -1) newProducts[idx] = { ...editingProduct, ...prodForm, price };
      } else {
          newProducts.push({
              id: `prod-${Date.now()}`,
              ...prodForm,
              price
          });
      }
      await updateCatalog(selectedCompany.id, newProducts);
      setShowProductModal(false);
      setProdForm({ name: '', price: '', description: '' });
  };

  const handleDeleteProduct = async (id: string) => {
      if(!selectedCompany || !confirm("¿Eliminar producto?")) return;
      const newProducts = (selectedCompany.catalog?.products || []).filter(p => p.id !== id);
      await updateCatalog(selectedCompany.id, newProducts);
  };

  if (!selectedCompany) return <div className="p-20 text-center">Cargando empresa...</div>;

  return (
    <div className="min-h-screen bg-slate-50 flex w-full font-sans">
        <BusinessSidebar 
            companyName={selectedCompany.name}
            isPublic={selectedCompany.isPublic}
            currentView={currentView}
            setView={setCurrentView}
            onSwitchToPersonal={onSwitchView}
            onBackToCompanies={() => setSelectedCompanyId(null)}
            onLogout={onSwitchView}
        />

        <BusinessMobileNavbar 
             companyName={selectedCompany.name}
             isPublic={selectedCompany.isPublic}
             currentView={currentView}
             setView={setCurrentView}
             onSwitchToPersonal={onSwitchView}
             onBackToCompanies={() => setSelectedCompanyId(null)}
        />

        <main className="flex-1 md:ml-72 w-full min-h-screen p-4 md:p-10 pb-32">

            {/* --- OVERVIEW --- */}
            {currentView === 'OVERVIEW' && (
                <div className="space-y-8 animate-fade-in">
                    <header className="flex justify-between items-end">
                        <div>
                            <h2 className="text-3xl font-black text-slate-900 tracking-tight">Dashboard</h2>
                            <p className="text-slate-400 text-xs font-bold mt-1 uppercase tracking-widest">Resumen Financiero</p>
                        </div>
                        <div className="text-right">
                            <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Capital Global</p>
                            <p className="text-4xl font-black text-slate-900 tracking-tighter">{totalBalance.toLocaleString()} <span className="text-lg text-slate-400">Pts</span></p>
                        </div>
                    </header>

                    <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                        <div className="bg-white p-8 rounded-[2.5rem] border border-slate-100 shadow-soft">
                             <div className="flex justify-between items-center mb-4">
                                 <div className="p-3 bg-indigo-50 text-indigo-600 rounded-xl"><Users size={20}/></div>
                                 <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">RRHH</span>
                             </div>
                             <p className="text-3xl font-black text-slate-900">{selectedCompany.employees.length}</p>
                             <p className="text-xs text-slate-500 font-bold mt-1">Empleados Activos</p>
                        </div>
                        <div className="bg-white p-8 rounded-[2.5rem] border border-slate-100 shadow-soft">
                             <div className="flex justify-between items-center mb-4">
                                 <div className="p-3 bg-emerald-50 text-emerald-600 rounded-xl"><ShoppingCart size={20}/></div>
                                 <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Ventas</span>
                             </div>
                             <p className="text-3xl font-black text-slate-900">{selectedCompany.catalog.products.length}</p>
                             <p className="text-xs text-slate-500 font-bold mt-1">Productos en Catálogo</p>
                        </div>
                        <div className="bg-white p-8 rounded-[2.5rem] border border-slate-100 shadow-soft">
                             <div className="flex justify-between items-center mb-4">
                                 <div className="p-3 bg-orange-50 text-orange-600 rounded-xl"><TrendingUp size={20}/></div>
                                 <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Valoración</span>
                             </div>
                             <p className="text-3xl font-black text-slate-900">{selectedCompany.stockValue.toLocaleString()}</p>
                             <p className="text-xs text-slate-500 font-bold mt-1">Pts / Acción</p>
                        </div>
                    </div>

                    <div className="bg-white p-8 rounded-[3rem] border border-slate-100 shadow-soft">
                        <h3 className="font-black text-slate-900 mb-6">Flujo de Caja</h3>
                        <div className="h-64 w-full">
                            <ResponsiveContainer width="100%" height="100%">
                                <AreaChart data={[{n:1, v:totalBalance-5000}, {n:2, v:totalBalance-2000}, {n:3, v:totalBalance}]}>
                                    <defs>
                                        <linearGradient id="colorVal" x1="0" y1="0" x2="0" y2="1">
                                            <stop offset="5%" stopColor="#6366f1" stopOpacity={0.1}/>
                                            <stop offset="95%" stopColor="#6366f1" stopOpacity={0}/>
                                        </linearGradient>
                                    </defs>
                                    <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9"/>
                                    <Area type="monotone" dataKey="v" stroke="#6366f1" strokeWidth={3} fillOpacity={1} fill="url(#colorVal)" />
                                </AreaChart>
                            </ResponsiveContainer>
                        </div>
                    </div>
                </div>
            )}

            {/* --- TREASURY (FINANCE) --- */}
            {currentView === 'FINANCE' && (
                <div className="space-y-8 animate-slide-up">
                    <header className="flex justify-between items-center">
                        <div>
                            <h2 className="text-3xl font-black text-slate-900 tracking-tight">Tesorería</h2>
                            <p className="text-slate-400 text-xs font-bold mt-1">Gestión de capital y cuentas operativas</p>
                        </div>
                        <div className="flex gap-2">
                            <button onClick={() => setShowNewAccountModal(true)} className="px-6 py-3 bg-white border border-slate-200 text-slate-900 rounded-2xl font-black text-xs uppercase tracking-widest hover:border-brand-500 transition-all flex items-center gap-2 shadow-sm active:scale-95">
                                <Plus size={16}/> Nueva Cuenta
                            </button>
                            <button onClick={() => setShowTransferModal(true)} className="px-6 py-3 bg-slate-900 text-white rounded-2xl font-black text-xs uppercase tracking-widest hover:bg-brand-600 transition-all flex items-center gap-2 shadow-lg active:scale-95">
                                <ArrowRightLeft size={16}/> Transferir
                            </button>
                        </div>
                    </header>

                    <div className="bg-slate-900 text-white p-10 rounded-[3rem] relative overflow-hidden shadow-2xl">
                        <div className="absolute top-0 right-0 w-64 h-64 bg-brand-500/20 rounded-full blur-3xl"></div>
                        <div className="relative z-10 flex flex-col md:flex-row justify-between gap-8">
                            <div>
                                <p className="text-[10px] font-black uppercase tracking-widest opacity-60 mb-2">IBAN Matriz</p>
                                <p className="font-mono text-xl tracking-wider">{selectedCompany.iban}</p>
                            </div>
                            <div className="text-right">
                                <p className="text-[10px] font-black uppercase tracking-widest opacity-60 mb-2">Saldo Global</p>
                                <p className="text-5xl font-black tracking-tighter">{totalBalance.toLocaleString()} Pts</p>
                            </div>
                        </div>
                    </div>

                    <h3 className="font-black text-xl text-slate-900 mt-8 mb-4">Cuentas Operativas</h3>
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                        {companyAccounts.map(acc => (
                            <div key={acc.id} className="bg-white p-8 rounded-[2.5rem] border border-slate-100 shadow-soft hover:border-brand-200 transition-all">
                                <div className="flex justify-between items-start mb-4">
                                    <div className="flex items-center gap-4">
                                        <div className="w-12 h-12 bg-indigo-50 text-indigo-600 rounded-2xl flex items-center justify-center font-bold text-lg">
                                            {acc.alias.charAt(0)}
                                        </div>
                                        <div>
                                            <p className="font-black text-slate-900 text-lg">{acc.alias}</p>
                                            <p className="text-xs text-slate-400 font-mono tracking-wider">{acc.iban.slice(-8)}</p>
                                        </div>
                                    </div>
                                    <span className="text-[10px] font-black uppercase bg-emerald-50 text-emerald-600 px-3 py-1 rounded-full">Activa</span>
                                </div>
                                <div className="flex items-baseline gap-2 mt-4">
                                    <p className="text-3xl font-black text-slate-900">{acc.balance.toLocaleString()}</p>
                                    <span className="text-sm font-bold text-slate-400">Pts</span>
                                </div>
                            </div>
                        ))}
                    </div>
                </div>
            )}

            {/* --- CATALOG (POS) --- */}
            {currentView === 'CATALOG' && (
                <div className="space-y-8 animate-slide-up">
                    <header className="flex justify-between items-center">
