  buyLootBox: (boxId: string, accountId: string) => Promise<{ success: boolean; wonItem?: LootItem }>;
  redeemCode: (code: string) => Promise<void>;
  buyDesign: (designId: string, accountId: string) => Promise<void>;
  listDesign: (designId: string, price: number) => Promise<void>;
  deleteDesign: (designId: string) => Promise<void>;
  payPayroll: (companyId: string, month: string, year: string) => Promise<void>;
  updateEmployees: (companyId: string, employees: Employee[]) => Promise<void>;
  updateCatalog: (companyId: string, products: Product[]) => Promise<void>;
  rotateApiKey: (companyId: string) => Promise<{apiKey: string}>;
  createSubaccount: (companyId: string, alias: string) => Promise<void>;
  createLottery: (lotteryData: any) => Promise<void>;
  approveLottery: (id: string) => Promise<void>;
  deleteLottery: (id: string) => Promise<void>;
  getPayrollHistory: (companyId: string) => Promise<PayrollHistory[]>;
  triggerHaptic: (pattern?: 'light' | 'medium' | 'heavy' | 'success' | 'error') => void;
  subscribeToPlan: (plan: SubscriptionPlan, accountId: string) => Promise<void>;
  cancelSubscription: (subId: string) => Promise<void>;
}

const BankContext = createContext<BankContextType | undefined>(undefined);

export const BankProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [userAccounts, setUserAccounts] = useState<Account[]>([]);
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [notifications, setNotifications] = useState<AppNotification[]>([]);
  const [companies, setCompanies] = useState<Company[]>([]);
  const [cards, setCards] = useState<Card[]>([]);
  const [contacts, setContacts] = useState<Contact[]>([]);
  const [shareRequests, setShareRequests] = useState<ShareRequest[]>([]);
  const [lootBoxes, setLootBoxes] = useState<LootBox[]>([]);
  const [marketDesigns, setMarketDesigns] = useState<{ store: CardDesign[], inventory: CardDesign[] }>({ store: [], inventory: [] });
  const [userSubscriptions, setUserSubscriptions] = useState<UserSubscription[]>([]);

  const [taxConfig, setTaxConfig] = useState<TaxConfig>({
      vatRate: 12,
      transferRate: 1,
      companyTaxRate: 25,
      lotteryRate: 20
  });

  const lastTxIdRef = useRef<string | null>(null);

  useEffect(() => {
    if ('Notification' in window && Notification.permission !== 'granted') {
      Notification.requestPermission();
    }
  }, []);

  const triggerHaptic = (pattern: 'light' | 'medium' | 'heavy' | 'success' | 'error' = 'light') => {
    if (typeof navigator !== 'undefined' && navigator.vibrate) {
        switch (pattern) {
            case 'light': navigator.vibrate(5); break;
            case 'medium': navigator.vibrate(15); break;
            case 'heavy': navigator.vibrate(30); break;
            case 'success': navigator.vibrate([10, 30, 10]); break;
            case 'error': navigator.vibrate([30, 50, 30, 50, 30]); break;
        }
    }
  };

  const apiCall = async (body: any) => {
    const res = await fetch('/api', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(body)
    });
    const data = await res.json();
    if (!res.ok) throw new Error(data.error || 'Error de Nodo');
    return data;
  };

  const fetchData = useCallback(async (userId: string) => {
    try {
      const data = await apiCall({ action: 'GET_INITIAL_DATA', userId });
      setUserAccounts(data.accounts || []);
      setTransactions(data.transactions || []);
      setCompanies(data.companies || []);
      setCards(data.cards || []);
      setContacts(data.contacts || []);
      setShareRequests(data.shareRequests || []);
      setLootBoxes(data.lootBoxes || []);
      setMarketDesigns(data.marketDesigns || { store: [], inventory: [] });
      setUserSubscriptions(data.userSubscriptions || []);
      if (data.taxConfig) setTaxConfig(data.taxConfig);

      // Check scheduled payments locally for UX (In real app, backend job does this)
      checkScheduledPayments(data.userSubscriptions || [], data.accounts || [], data.companies || []);

    } catch (e: any) {
      console.error("Fetch Data Error:", e.message);
    }
  }, []);

  // --- MOTOR DE COBROS PROGRAMADOS (Simulación Cliente) ---
  // Verifica si hay suscripciones vencidas hoy y ejecuta el cobro
  const checkScheduledPayments = async (subs: UserSubscription[], accounts: Account[], companiesList: Company[]) => {
      const today = new Date();
      today.setHours(0,0,0,0);

      for (const sub of subs) {
          if (sub.status !== 'ACTIVE') continue;
          const paymentDate = new Date(sub.nextPaymentDate);
          paymentDate.setHours(0,0,0,0);

          if (today >= paymentDate) {
              // Time to charge!
              const company = companiesList.find(c => c.id === sub.companyId);
              const plan = company?.subscriptionPlans?.find(p => p.id === sub.planId);
              const account = accounts.find(a => a.id === sub.accountId);

              if (company && plan && account) {
                  console.log(`Ejecutando cobro programado para: ${plan.name}`);
                  try {
                      // Execute Payment
                      await transfer(account.iban, company.iban, plan.price, `Renovación: ${plan.name}`, 'SUBSCRIPTION');

                      // Calculate Next Date
                      const nextDate = new Date(paymentDate);
                      nextDate.setMonth(nextDate.getMonth() + 1); // Assuming monthly

                      // Update Subscription Date in Backend
                      await apiCall({ 
                          action: 'UPDATE_SUBSCRIPTION_DATE', 
                          subscriptionId: sub.id, 
                          nextPaymentDate: nextDate.toISOString() 
                      });
                  } catch (e) {
                      console.error("Fallo cobro automático", e);
                      // In a real app, we would mark subscription as PAST_DUE
                  }
              }
          }
      }
  };

  const subscribeToPlan = async (plan: SubscriptionPlan, accountId: string) => {
      if (!currentUser) return;
      const account = userAccounts.find(a => a.id === accountId);
      if(!account) throw new Error("Cuenta inválida");

      const company = companies.find(c => c.id === plan.companyId);
      if(!company) throw new Error("Empresa no encontrada");

      // 1. Initial Charge
      await transfer(account.iban, company.iban, plan.price, `Alta Suscripción: ${plan.name}`, 'SUBSCRIPTION');

      // 2. Create Subscription Record
      const startDate = new Date();
      const nextPayment = new Date(startDate);
      nextPayment.setMonth(nextPayment.getMonth() + 1); // Next charge in 1 month

      const permanenceEnd = new Date(startDate);
      if(plan.permanenceMonths > 0) {
          permanenceEnd.setMonth(permanenceEnd.getMonth() + plan.permanenceMonths);
      }

      const subData: UserSubscription = {
          id: `sub-${Date.now()}`,
          planId: plan.id,
          userId: currentUser.id,
          accountId: accountId,
          companyId: plan.companyId,
          startDate: startDate.toISOString(),
          nextPaymentDate: nextPayment.toISOString(),
          status: 'ACTIVE',
          permanenceEndDate: plan.permanenceMonths > 0 ? permanenceEnd.toISOString() : undefined
      };

      await apiCall({ action: 'CREATE_SUBSCRIPTION', subscription: subData });
      await fetchData(currentUser.id);
      addNotification(`Suscrito a ${plan.name}`, 'success');
  };

  const cancelSubscription = async (subId: string) => {
      const sub = userSubscriptions.find(s => s.id === subId);
      if (!sub) return;

      if (sub.permanenceEndDate && new Date() < new Date(sub.permanenceEndDate)) {
          const endDate = new Date(sub.permanenceEndDate).toLocaleDateString();
          throw new Error(`Permanencia activa hasta ${endDate}. Cancelación conlleva penalización.`);
          // In a real app, we might ask for confirmation to pay penalty
      }

      await apiCall({ action: 'CANCEL_SUBSCRIPTION', subscriptionId: subId });
      await fetchData(currentUser?.id || '');
      addNotification("Suscripción cancelada", 'info');
  };

  const login = async (dip: string, pass: string) => {
    try {
      const data = await apiCall({ action: 'AUTH', dip, password: pass });
      setCurrentUser(data.user);
      await fetchData(data.user.id);
      return { success: true, user: data.user };
    } catch (e: any) { 
      return { success: false, error: e.message }; 
    }
  };

  const loginWithPlacetaID = async (userData: any) => {
    try {
      const data = await apiCall({ action: 'AUTH_PLACETAID', userData });
      setCurrentUser(data.user);
      await fetchData(data.user.id);
      return { success: true };
    } catch (e: any) {
      return { success: false, error: e.message };
    }
  };

  const logout = () => {
    setCurrentUser(null);
    setUserAccounts([]);
    setTransactions([]);
  };

  const transfer = async (fromIban: string, toIban: string, amount: number, description: string, type = 'TRANSFER') => {
    await apiCall({ action: 'TRANSFER', fromIban, toIban, amount, description, type });
    if (currentUser) await fetchData(currentUser.id);
    addNotification(`Operación completada: ${amount} Pts`, "success");
  };

  const companyTransfer = async (companyId: string, toIban: string, amount: number, description: string) => {
      await apiCall({ action: 'COMPANY_TRANSFER', companyId, toIban, amount, description });
      if (currentUser) await fetchData(currentUser.id);
      addNotification(`Transferencia corporativa enviada`, "success");
  };

  // Replicar resto de métodos básicos con apiCall
  const requestCard = async (accountId: string, holderName: string, design: string, pin: string) => { await apiCall({ action: 'REQUEST_CARD', accountId, holderName, design, pin }); if (currentUser) await fetchData(currentUser.id); addNotification("Tarjeta emitida", "success"); };
  const toggleCardStatus = async (cardId: string, status: string) => { await apiCall({ action: 'TOGGLE_CARD_STATUS', cardId, status }); if (currentUser) await fetchData(currentUser.id); addNotification(`Tarjeta ${status}`, "info"); };
  const updateCardPin = async (cardId: string, newPin: string) => { await apiCall({ action: 'UPDATE_CARD_PIN', cardId, newPin }); addNotification("PIN actualizado", "success"); };
  const payWithCard = async (cardData: any, amount: number, companyId: string, description: string) => { await apiCall({ action: 'PAY_WITH_CARD', ...cardData, amount, companyId, description }); if (currentUser) await fetchData(currentUser.id); addNotification("Pago realizado", "success"); };

  const addNotification = (message: string, type: any) => {
    const id = Date.now().toString();
    setNotifications(prev => [...prev, { id, message, type }]);
    if(!document.hidden) triggerHaptic(type === 'error' ? 'error' : 'light');
    setTimeout(() => setNotifications(prev => prev.filter(n => n.id !== id)), 4000);
  };

  // Stub functions for others to ensure compilation, utilizing apiCall
  const getApiUsageLogs = async (companyId: string) => apiCall({ action: 'GET_API_USAGE_LOGS', companyId });
  const getAge = (birthDate?: string) => 0; // Simplified
  const saveContact = async (name: string, iban: string) => { if(currentUser) { await apiCall({action: 'SAVE_CONTACT', userId: currentUser.id, name, iban}); await fetchData(currentUser.id); }};
  const deleteContact = async (id: string) => { await apiCall({action: 'DELETE_CONTACT', contactId: id}); if(currentUser) await fetchData(currentUser.id); };
  const buyStock = async (companyId: string, accountId: string, amount: number) => { await apiCall({action: 'BUY_STOCK', companyId, accountId, amount}); if(currentUser) await fetchData(currentUser.id); };
  const sellStock = async (companyId: string, accountId: string, amount: number) => { await apiCall({action: 'SELL_STOCK', companyId, accountId, amount}); if(currentUser) await fetchData(currentUser.id); };
  const payCitizenTax = async (accountId: string, amount: number, description: string) => { await apiCall({action: 'PAY_TAX', accountId, amount, description}); if(currentUser) await fetchData(currentUser.id); };
  const getFiscalProjection = async (month: number, year: number) => { if(!currentUser) return []; return apiCall({action: 'GET_FISCAL_PROJECTION', userId: currentUser.id, month, year}); };
  const respondShareRequest = async (id: string, status: string) => { await apiCall({action: 'RESPOND_SHARE_REQUEST', requestId: id, status}); if(currentUser) await fetchData(currentUser.id); };
  const requestShareAccount = async (accountId: string, toDip: string, accessLevel: string) => { await apiCall({action: 'REQUEST_SHARE_ACCOUNT', accountId, toDip, accessLevel}); if(currentUser) await fetchData(currentUser.id); };
  const adminGetState = async () => apiCall({action: 'ADMIN_GET_STATE'});
  const adminRevertTransaction = async (id: string) => apiCall({action: 'ADMIN_REVERT_TX', transactionId: id});
  const adminUpdateUserStatus = async (userId: string, isBlocked: boolean) => apiCall({action: 'ADMIN_UPDATE_USER_STATUS', userId, isBlocked});
  const adminMint = async (amount: number, reason: string) => apiCall({action: 'ADMIN_MINT', amount, reason});
  const adminCreateUser = async (user: any) => apiCall({action: 'ADMIN_CREATE_USER', user});
  const adminGenerateMonthlyTaxes = async (month: number, year: number) => apiCall({action: 'ADMIN_GENERATE_MONTHLY_TAXES', month, year});
  const adminProcessTaxCollection = async () => apiCall({action: 'ADMIN_PROCESS_TAX_COLLECTION'});
  const buyLootBox = async (boxId: string, accountId: string) => { const r = await apiCall({action: 'BUY_LOOTBOX', boxId, accountId}); if(currentUser) await fetchData(currentUser.id); return r; };
  const redeemCode = async (code: string) => { await apiCall({action: 'REDEEM_CODE', code}); if(currentUser) await fetchData(currentUser.id); };
  const buyDesign = async (designId: string, accountId: string) => { await apiCall({action: 'BUY_DESIGN', designId, accountId}); if(currentUser) await fetchData(currentUser.id); };
  const listDesign = async (designId: string, price: number) => { await apiCall({action: 'LIST_DESIGN', designId, price}); if(currentUser) await fetchData(currentUser.id); };
  const deleteDesign = async (designId: string) => { await apiCall({action: 'DELETE_DESIGN', designId}); if(currentUser) await fetchData(currentUser.id); };
  const payPayroll = async (companyId: string, month: string, year: string) => { await apiCall({action: 'PAY_PAYROLL', companyId, month, year}); if(currentUser) await fetchData(currentUser.id); };
  const updateEmployees = async (companyId: string, employees: Employee[]) => { await apiCall({action: 'UPDATE_EMPLOYEES', companyId, employees}); if(currentUser) await fetchData(currentUser.id); };
  const updateCatalog = async (companyId: string, products: Product[]) => { await apiCall({action: 'UPDATE_CATALOG', companyId, products}); if(currentUser) await fetchData(currentUser.id); };
  const rotateApiKey = async (companyId: string) => { const r = await apiCall({action: 'COMPANY_ROTATE_KEY', companyId}); if(currentUser) await fetchData(currentUser.id); return r; };
  const createSubaccount = async (companyId: string, alias: string) => { await apiCall({action: 'CREATE_SUBACCOUNT', companyId, alias}); if(currentUser) await fetchData(currentUser.id); };
  const createLottery = async (lotteryData: any) => { await apiCall({action: 'CREATE_LOTTERY', ...lotteryData}); if(currentUser) await fetchData(currentUser.id); };
  const approveLottery = async (id: string) => { await apiCall({action: 'APPROVE_LOTTERY', lotteryId: id}); if(currentUser) await fetchData(currentUser.id); };
  const deleteLottery = async (id: string) => { await apiCall({action: 'DELETE_LOTTERY', lotteryId: id}); if(currentUser) await fetchData(currentUser.id); };
  const getPayrollHistory = async (companyId: string) => apiCall({action: 'GET_PAYROLL_HISTORY', companyId});

  const generatePDF = (type: string, data: any) => {
      const doc = new jsPDF() as any;
      doc.text("BANCO DE LA PLACETA", 20, 20);
      doc.text(type, 20, 30);
      if (data.amount) doc.text(`Importe: ${data.amount} Pts`, 20, 40);
      if (data.concept) doc.text(`Concepto: ${data.concept}`, 20, 50);
      doc.save(`doc_${Date.now()}.pdf`);
  };

  return (
    <BankContext.Provider value={{
      currentUser, userAccounts, transactions, notifications, companies, cards, contacts, shareRequests, lootBoxes, marketDesigns, userSubscriptions, taxConfig,
      login, loginWithPlacetaID, logout, fetchData, transfer, companyTransfer, requestCard, toggleCardStatus, updateCardPin, payWithCard, getApiUsageLogs, addNotification, generatePDF, getAge,
      saveContact, deleteContact, buyStock, sellStock, payCitizenTax, getFiscalProjection, respondShareRequest, requestShareAccount,
      adminGetState, adminRevertTransaction, adminUpdateUserStatus, adminMint, adminCreateUser, adminGenerateMonthlyTaxes, adminProcessTaxCollection,
      buyLootBox, redeemCode, buyDesign, listDesign, deleteDesign, payPayroll, updateEmployees, updateCatalog, rotateApiKey,
      createSubaccount, createLottery, approveLottery, deleteLottery, getPayrollHistory, triggerHaptic, subscribeToPlan, cancelSubscription
    }}>
      {children}
    </BankContext.Provider>
  );
};

export const useBank = () => {
  const context = useContext(BankContext);
  if (!context) throw new Error('BankContext missing');
  return context;
};

