                <h2 className="text-3xl md:text-4xl font-black text-slate-900 tracking-tighter">Mi Cartera</h2>
                <p className="text-slate-400 font-bold uppercase tracking-[0.2em] text-[10px] mt-2 flex items-center gap-2">
                    <Shield size={12} className="text-brand-600"/> PlacetaPay Wallet v7.0
                </p>
            </div>
            <button 
                onClick={() => setShowDesigner(true)}
                className="w-full md:w-auto px-6 py-3 bg-slate-900 text-white rounded-2xl font-black text-[10px] uppercase tracking-[0.2em] shadow-lg hover:bg-brand-600 transition-all active:scale-95 flex items-center justify-center gap-3 group"
            >
                <Plus size={16} className="group-hover:rotate-90 transition-transform"/> Nueva Tarjeta
            </button>
        </header>

        {/* CARDS CAROUSEL (NO 3D) */}
        <section className="mb-10">
