import React, { useState, useEffect } from 'react';
import { ArrowLeft, Monitor, AlertTriangle, History, ArrowRight, Globe, Loader2, ShieldCheck, Lock, User, Key, ChevronRight } from 'lucide-react';
import { useBank } from '../context/BankContext';

interface LoginProps {
  onLogin: () => void;
  onBack: () => void;
  onATMEnter: () => void;
}

export const Login: React.FC<LoginProps> = ({ onLogin, onBack, onATMEnter }) => {
  const { login, loginWithPlacetaID } = useBank();
  const [dip, setDip] = useState('');
  const [password, setPassword] = useState('');
  const [showLegacy, setShowLegacy] = useState(false);
  const [isLoading, setIsLoading] = useState(false);
  const [errorMessage, setErrorMessage] = useState<string | null>(null);

  useEffect(() => {
    let attempts = 0;
    const maxAttempts = 20;

    const initPlacetaID = () => {
      const SDK = (window as any).PlacetaID;
      const container = document.getElementById('placeta-login');

      if (SDK && container) {
        try {
          new SDK({
            containerId: 'placeta-login',
            apiUrl: 'https://junta.vercel.app/api/placetaid',
            theme: 'dark',
            onSuccess: (userData: any) => handlePlacetaLogin(userData)
          });
        } catch (err) {
          console.error("SDK Error:", err);
          setErrorMessage("Error al conectar con la pasarela de identidad.");
        }
      } else if (attempts < maxAttempts) {
        attempts++;
        setTimeout(initPlacetaID, 300);
      }
    };

    initPlacetaID();
  }, [showLegacy]); // Re-init if switching views potentially

  const handlePlacetaLogin = async (userData: any) => {
    setIsLoading(true);
    setErrorMessage(null);
    try {
        const result = await loginWithPlacetaID(userData);
        if (result.success) {
          onLogin();
        } else {
          setErrorMessage(result.error || 'Sincronización de identidad fallida.');
        }
    } catch (e) {
        setErrorMessage("Error crítico de red con el nodo bancario.");
    } finally {
        setIsLoading(false);
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setErrorMessage(null);
    if (!dip || !password) return;
    setIsLoading(true);
    try {
        const result = await login(dip, password);
        if (result.success) {
            onLogin();
        } else {
            setErrorMessage(result.error || 'Credenciales SIDS no válidas.');
        }
    } catch (e) {
        setErrorMessage("Nodo de autenticación fuera de servicio.");
    } finally {
        setIsLoading(false);
    }
  };

  return (
    <div className="min-h-screen bg-[#020617] flex font-sans overflow-hidden relative selection:bg-brand-500 selection:text-white">
      {/* Background Ambience */}
      <div className="absolute inset-0 z-0">
          <div className="absolute top-[-20%] left-[-10%] w-[70vw] h-[70vw] bg-indigo-900/20 rounded-full blur-[120px] animate-pulse-slow"></div>
          <div className="absolute bottom-[-10%] right-[-10%] w-[50vw] h-[50vw] bg-brand-900/10 rounded-full blur-[100px]"></div>
          <div className="absolute inset-0 bg-[url('https://grainy-gradients.vercel.app/noise.svg')] opacity-20 brightness-100 contrast-150"></div>
      </div>

      {/* Left Column: Brand Hero */}
      <div className="hidden lg:flex w-1/2 relative items-center justify-center z-10 p-12 border-r border-white/5 backdrop-blur-sm">
          <div className="flex flex-col items-center justify-center">
              <div className="relative group">
                  <div className="absolute -inset-10 bg-gradient-to-r from-brand-500 to-indigo-500 rounded-full blur-[60px] opacity-20 group-hover:opacity-30 transition-opacity duration-700"></div>
                  <img 
                    src="https://i.postimg.cc/xd0y9V1t/BANCO-DE.png" 
                    alt="Banco de La Placeta" 
                    className="w-96 h-auto object-contain relative z-10 drop-shadow-2xl transform group-hover:scale-105 transition-transform duration-700"
                  />
              </div>

              <div className="mt-12 text-center max-w-md space-y-6">
                  <div className="inline-flex items-center gap-2 px-4 py-1.5 rounded-full bg-white/5 border border-white/10 text-brand-200 text-[10px] font-black uppercase tracking-[0.2em] backdrop-blur-md">
                      <ShieldCheck size={12}/> Sistema Financiero Oficial
                  </div>
                  <p className="text-slate-400 text-sm font-medium leading-relaxed">
                      Gestione sus activos, realice transferencias y liquide tributos bajo la normativa vigente del Capítulo 1.
                  </p>
              </div>
          </div>

          <div className="absolute bottom-10 left-12 text-[10px] text-slate-600 font-mono flex items-center gap-2">
              <div className="w-2 h-2 bg-emerald-500 rounded-full animate-pulse"></div>
              NODO: BCN-PL-01 • LATENCIA: 24ms
          </div>
      </div>

      {/* Right Column: Auth Form */}
      <div className="flex-1 flex flex-col justify-center px-6 md:px-12 lg:px-24 relative z-10 w-full bg-gradient-to-b from-slate-900/50 to-slate-950/80 backdrop-blur-xl lg:bg-none">

        {/* Mobile Header Logo */}
        <div className="lg:hidden absolute top-8 left-0 right-0 flex justify-center pointer-events-none">
             <img src="https://i.postimg.cc/5t0S5t3p/BANCO-DE.png" className="h-12 w-auto object-contain opacity-50"/>
        </div>

        {/* Navigation Controls */}
        <div className="absolute top-6 left-6 right-6 flex justify-between items-center">
            <button onClick={onBack} className="p-2 rounded-full text-slate-400 hover:text-white hover:bg-white/10 transition-all flex items-center gap-2 group">
                <ArrowLeft size={18} className="group-hover:-translate-x-1 transition-transform"/> <span className="text-xs font-bold uppercase tracking-widest hidden sm:inline">Volver</span>
            </button>
            <button onClick={onATMEnter} className="px-4 py-2 bg-slate-800/50 border border-white/10 rounded-xl text-[10px] font-black text-brand-300 uppercase tracking-widest hover:bg-brand-500 hover:text-white hover:border-brand-500 transition-all flex items-center gap-2 shadow-lg shadow-black/20">
                <Monitor size={14}/> Modo Cajero
            </button>
        </div>

        <div className="w-full max-w-sm mx-auto animate-slide-up relative">

            <div className="mb-8">
                <h2 className="text-2xl font-black text-white tracking-tight mb-2">Bienvenido</h2>
                <p className="text-slate-400 text-sm font-medium">Inicie sesión para acceder a su banca.</p>
            </div>

            {errorMessage && (
                <div className="bg-red-500/10 border border-red-500/20 text-red-200 p-4 rounded-2xl text-xs font-bold mb-6 flex items-start gap-3 animate-slide-up backdrop-blur-md">
                    <AlertTriangle size={16} className="shrink-0 text-red-500 mt-0.5"/> 
                    <span>{errorMessage}</span>
                </div>
