            {isLoading ? (
                <div className="py-20 flex flex-col items-center justify-center space-y-6 bg-slate-900/50 rounded-[2rem] border border-white/5">
                    <div className="relative">
                        <div className="w-16 h-16 border-4 border-brand-500/30 border-t-brand-500 rounded-full animate-spin"></div>
                        <div className="absolute inset-0 flex items-center justify-center">
                            <Lock size={20} className="text-white/50"/>
                        </div>
                    </div>
                    <p className="text-white font-black uppercase text-[10px] tracking-[0.2em] animate-pulse">Autenticando...</p>
                </div>
            ) : (
                <div className="space-y-6">

                    {/* Primary Login: PlacetaID */}
                    {!showLegacy && (
                        <div className="space-y-6">
                            <div id="placeta-login" className="min-h-[64px] animate-fade-in relative z-20">
                                {/* SDK Button renders here */}
                                <div className="h-[64px] w-full bg-slate-800/50 rounded-2xl border border-white/5 flex items-center justify-center text-slate-500 text-[10px] font-black uppercase tracking-widest animate-pulse">
                                    Cargando Pasarela Segura...
                                </div>
                            </div>

                            <div className="relative py-2">
                                <div className="absolute inset-0 flex items-center"><div className="w-full border-t border-white/10"></div></div>
                                <div className="relative flex justify-center text-[10px] uppercase font-black tracking-widest">
                                    <span className="bg-[#0b1021] px-4 text-slate-500">Métodos Alternativos</span>
                                </div>
                            </div>

                            <button onClick={() => setShowLegacy(true)} className="w-full p-4 bg-transparent border border-slate-700 hover:border-slate-500 text-slate-400 hover:text-white rounded-2xl font-bold text-sm transition-all flex items-center justify-between group">
                                <span className="flex items-center gap-3"><History size={18}/> Usar Credenciales Antiguas</span>
                                <ChevronRight size={16} className="text-slate-600 group-hover:text-white transition-colors"/>
                            </button>
                        </div>
                    )}

                    {/* Legacy Login Form */}
                    {showLegacy && (
                        <form onSubmit={handleSubmit} className="space-y-5 animate-slide-up">
                            <div className="space-y-2">
                                 <label className="text-[10px] font-black text-brand-300 uppercase ml-1 tracking-widest flex items-center gap-2"><User size={10}/> Documento (DIP)</label>
                                 <div className="relative group">
                                     <input 
                                        type="text" 
                                        value={dip} 
                                        onChange={(e) => setDip(e.target.value.toUpperCase())} 
                                        className="w-full pl-4 pr-4 py-4 bg-slate-900/80 border border-white/10 rounded-2xl text-white outline-none focus:border-brand-500 focus:ring-1 focus:ring-brand-500 transition-all font-mono font-bold text-lg placeholder:text-slate-600 uppercase tracking-wider" 
                                        placeholder="DIP-XXXXXX" 
                                        autoFocus
                                     />
                                     <div className="absolute inset-0 rounded-2xl bg-brand-500/5 pointer-events-none opacity-0 group-focus-within:opacity-100 transition-opacity"></div>
                                 </div>
                            </div>
                            <div className="space-y-2">
                                 <label className="text-[10px] font-black text-brand-300 uppercase ml-1 tracking-widest flex items-center gap-2"><Key size={10}/> Clave de Acceso</label>
                                 <div className="relative group">
                                     <input 
                                        type="password" 
                                        value={password} 
                                        onChange={(e) => setPassword(e.target.value)} 
                                        className="w-full pl-4 pr-4 py-4 bg-slate-900/80 border border-white/10 rounded-2xl text-white outline-none focus:border-brand-500 focus:ring-1 focus:ring-brand-500 transition-all font-bold text-lg placeholder:text-slate-600 tracking-widest" 
                                        placeholder="••••••••"
                                     />
                                 </div>
                            </div>

                            <button type="submit" disabled={isLoading} className="w-full py-4 bg-gradient-to-r from-brand-600 to-indigo-600 text-white rounded-2xl font-black uppercase text-xs tracking-[0.15em] hover:from-brand-500 hover:to-indigo-500 transition-all shadow-lg shadow-brand-900/40 mt-4 active:scale-95 flex items-center justify-center gap-3 group relative overflow-hidden">
                                <span className="relative z-10 flex items-center gap-2">Acceder al Sistema <ArrowRight size={14} className="group-hover:translate-x-1 transition-transform"/></span>
