                            </button>

                            <button type="button" onClick={() => setShowLegacy(false)} className="w-full text-center text-slate-500 font-bold text-[10px] hover:text-white transition-colors pt-2 uppercase tracking-widest">
                                Cancelar y usar PlacetaID
                            </button>
                        </form>
                    )}
