export const Transfers: React.FC<TransfersProps> = ({ addNotification }) => {
  const { userAccounts, transfer, taxConfig, contacts, transactions, triggerHaptic } = useBank();

  const [selectedAccountIndex, setSelectedAccountIndex] = useState(0);
  const [showAccountDrawer, setShowAccountDrawer] = useState(false); 

  const [recipientInput, setRecipientInput] = useState(''); 
  const [showSuggestions, setShowSuggestions] = useState(false);
  const [detectedBeneficiary, setDetectedBeneficiary] = useState<string | null>(null);

  const [amount, setAmount] = useState('');
  const [transferStep, setTransferStep] = useState<TransferStep>('IDLE');

  const currentAccount = userAccounts[selectedAccountIndex];
  const currentTaxRate = taxConfig.transferRate;

  // --- LOGIC: RECENT & CONTACTS MERGE ---
  const suggestionsList = useMemo(() => {
      // 1. Get contacts formatted
      const contactSuggestions = contacts.map(c => ({
          id: `contact-${c.id}`,
          name: c.name,
          iban: c.iban,
          type: 'CONTACT'
      }));

      // 2. Get recent transactions (unique receivers)
      const recentMap = new Map();
      transactions.forEach(tx => {
          if (tx.senderIban === currentAccount?.iban && tx.receiverIban && !tx.receiverIban.startsWith('PL000000')) { // Exclude system
             // Check if already in contacts to avoid dupes
             if (!contacts.some(c => c.iban === tx.receiverIban)) {
                 if (!recentMap.has(tx.receiverIban)) {
                     recentMap.set(tx.receiverIban, {
                         id: `recent-${tx.id}`,
                         name: tx.receiverIban, // We might not have the name if it wasn't a contact
                         iban: tx.receiverIban,
                         type: 'RECENT'
                     });
                 }
             }
          }
      });
      const recentSuggestions = Array.from(recentMap.values()).slice(0, 3); // Last 3 unique

      return [...contactSuggestions, ...recentSuggestions];
  }, [contacts, transactions, currentAccount]);

  const filteredSuggestions = useMemo(() => {
      if (!recipientInput) return suggestionsList;
      const cleanInput = recipientInput.replace(/\s/g, '').toUpperCase();
      return suggestionsList.filter(s => 
          s.name.toLowerCase().includes(recipientInput.toLowerCase()) || 
          s.iban.includes(cleanInput)
      );
  }, [suggestionsList, recipientInput]);

  // Detect name when input matches a known IBAN exactly
  useEffect(() => {
      const clean = 'PL' + recipientInput.replace(/\s/g, '').toUpperCase();
      const match = suggestionsList.find(s => s.iban === clean);
      setDetectedBeneficiary(match ? match.name : null);
  }, [recipientInput, suggestionsList]);


  // --- HANDLERS ---

  const handleKeypad = (val: string) => {
      triggerHaptic('light');
      if (val === 'DEL') {
          setAmount(prev => prev.slice(0, -1));
      } else if (val === '.') {
          if (!amount.includes('.')) setAmount(prev => prev + '.');
      } else {
          if (amount.length < 9) setAmount(prev => prev + val);
      }
  };

  const formatDisplayIban = (val: string) => {
      // Remove non-alphanumeric
      const clean = val.replace(/[^a-zA-Z0-9]/g, '').toUpperCase();
      // Remove PL prefix if typed manually to avoid PLPL
      const noPrefix = clean.startsWith('PL') ? clean.substring(2) : clean;
      // Add spaces every 4 chars
      return noPrefix.replace(/(.{4})/g, '$1 ').trim();
  };

  const handleRecipientChange = (e: React.ChangeEvent<HTMLInputElement>) => {
      const formatted = formatDisplayIban(e.target.value);
      if (formatted.length <= 26) { // 22 chars + spaces
          setRecipientInput(formatted);
          setShowSuggestions(true);
      }
  };

  const handlePaste = async () => {
      try {
          const text = await navigator.clipboard.readText();
          const formatted = formatDisplayIban(text);
          if (formatted.length <= 26) {
              setRecipientInput(formatted);
              addNotification("IBAN pegado", "info");
              setDetectedBeneficiary(null); // Reset detection to re-verify
          }
      } catch (err) {
          addNotification("No se pudo pegar del portapapeles", "error");
      }
  };

  const selectSuggestion = (item: any) => {
      triggerHaptic('medium');
      // Format: Remove PL, add spaces
      const raw = item.iban.startsWith('PL') ? item.iban.substring(2) : item.iban;
      const formatted = raw.replace(/(.{4})/g, '$1 ').trim();
      setRecipientInput(formatted);
      setDetectedBeneficiary(item.name);
      setShowSuggestions(false);
  };

  const handleVerify = () => {
    triggerHaptic('medium');
    const rawIban = recipientInput.replace(/\s/g, '');

    if (rawIban.length !== 20) { // 22 total - 2 (PL)
      addNotification("El IBAN debe tener 22 caracteres (PL + 20 dígitos)", 'error');
      return;
    }

    const numericAmount = Number(amount);
    const taxAmount = numericAmount * (currentTaxRate / 100);
    const totalDeduction = numericAmount + taxAmount;

    if (numericAmount <= 0) {
        addNotification("Introduce un monto mayor a 0", 'error');
        return;
    }

    if (totalDeduction > currentAccount.balance) {
      addNotification(`Saldo insuficiente. Requerido: ${totalDeduction.toLocaleString()} Pts`, 'error');
      return;
    }

    if (numericAmount > SECURITY_THRESHOLD_AMOUNT) {
      setTransferStep('SECURITY');
    } else {
      setTransferStep('CONFIRM');
    }
  };

  const handleConfirm = async () => {
    triggerHaptic('heavy');
    setTransferStep('PROCESSING');

    const fullRecipient = 'PL' + recipientInput.replace(/\s/g, '');

    // Simulate network delay
    await new Promise(r => setTimeout(r, 1500)); 

    try {
        await transfer(currentAccount.iban, fullRecipient, Number(amount), 'Transferencia Móvil');
        setTransferStep('SUCCESS');
    } catch (e: any) {
        addNotification(e.message || "Error en la transferencia", 'error');
        setTransferStep('IDLE');
    }
  };

  const resetFlow = () => {
      setTransferStep('IDLE');
      setAmount('');
      setRecipientInput('');
      setDetectedBeneficiary(null);
  };

  if (!currentAccount) return <div className="p-8 text-center text-slate-400">Cargando cuentas...</div>;

  const numericAmount = Number(amount) || 0;
  const taxAmount = numericAmount * (currentTaxRate / 100);
  const totalAmount = numericAmount + taxAmount;
  const fullIbanDisplay = 'PL' + recipientInput.replace(/\s/g, '');

  return (
    <div className="pb-safe-nav h-full flex flex-col max-w-lg mx-auto relative animate-fade-in pt-safe px-4 min-h-screen">

      {/* Header */}
      <div className="flex justify-between items-center mb-6">
            <h2 className="text-3xl font-black text-slate-900 tracking-tight">Transferir</h2>
            <div className="bg-slate-100 px-3 py-1 rounded-full text-[10px] font-bold text-slate-500 uppercase tracking-widest flex items-center gap-1">
                <Wallet size={10} className="text-brand-500"/> Saldo Disponible
            </div>
      </div>

      {/* Account Selector Card (Premium UI) */}
      <div className="relative mb-8 z-20">
             <button 
                className="w-full p-6 bg-gradient-to-br from-slate-900 to-slate-800 text-white rounded-[2rem] flex flex-col justify-between shadow-2xl shadow-slate-900/20 active:scale-[0.98] transition-all group relative overflow-hidden h-36"
                onClick={() => setShowAccountDrawer(true)}
             >
                {/* Background Decor */}
                <div className="absolute top-0 right-0 w-32 h-32 bg-white/5 rounded-full blur-2xl -mr-10 -mt-10 pointer-events-none"></div>

                <div className="flex justify-between items-start w-full relative z-10">
                    <div className="flex items-center gap-3">
                        <div className="w-10 h-10 bg-white/10 rounded-xl flex items-center justify-center backdrop-blur-md border border-white/10">
                            {currentAccount.type === 'BUSINESS' ? <Wallet size={20} className="text-brand-300"/> : <User size={20} className="text-brand-300"/>}
                        </div>
                        <div className="text-left">
                            <p className="text-[10px] text-slate-300 font-bold uppercase tracking-widest">Cuenta Origen</p>
                            <p className="font-bold text-md leading-none">{currentAccount.alias}</p>
                        </div>
                    </div>
                    <div className="bg-white/10 px-3 py-1 rounded-lg text-[10px] font-bold flex items-center gap-1 hover:bg-white/20 transition-colors">
                        Cambiar <ChevronDown size={10}/>
                    </div>
                </div>

                <div className="relative z-10 text-left mt-4">
                    <p className="text-3xl font-black tracking-tight">{currentAccount.balance.toLocaleString()} <span className="text-lg opacity-50 font-medium">Pts</span></p>
                    <p className="text-[10px] font-mono text-slate-400 opacity-60">**** {currentAccount.iban.slice(-6)}</p>
                </div>
            </button>
      </div>

      {/* Recipient Input Area (Optimized) */}
      <div className="relative mb-6 z-10 group">
          <div className="flex justify-between items-end mb-2 px-2">
              <label className="text-xs font-bold text-slate-400 uppercase tracking-widest">Destinatario</label>
              {detectedBeneficiary && (
                  <span className="text-[10px] font-black text-emerald-600 bg-emerald-50 px-2 py-0.5 rounded animate-fade-in flex items-center gap-1">
                      <CheckCircle2 size={10}/> {detectedBeneficiary}
                  </span>
              )}
          </div>

          <div className={`bg-white p-2 rounded-[1.8rem] border-2 flex items-center shadow-sm transition-all relative ${showSuggestions ? 'border-brand-500 ring-4 ring-brand-500/10' : 'border-slate-200 hover:border-slate-300'}`}>
              <div className="bg-slate-100 w-14 h-14 rounded-[1.2rem] flex items-center justify-center text-slate-500 font-black text-sm select-none shrink-0 border border-slate-200">PL</div>
              <input 
                  type="text" 
                  value={recipientInput}
                  onChange={handleRecipientChange}
                  onFocus={() => setShowSuggestions(true)}
                  // Delayed blur to allow clicks
                  onBlur={() => setTimeout(() => setShowSuggestions(false), 200)}
                  className="flex-1 bg-transparent px-3 font-mono text-lg font-bold outline-none text-slate-900 placeholder:text-slate-300 tracking-wider min-w-0"
                  placeholder="0000 0000..."
                  inputMode="text"
                  autoComplete="off"
              />

              {recipientInput ? (
                  <button onClick={() => {setRecipientInput(''); setDetectedBeneficiary(null);}} className="p-2 text-slate-300 hover:text-slate-500 transition-colors">
                      <X size={18}/>
                  </button>
              ) : (
                  <div className="flex gap-1 pr-1">
                      <button onClick={handlePaste} className="p-2.5 text-brand-600 bg-brand-50 rounded-xl hover:bg-brand-100 transition-colors" title="Pegar">
                          <Clipboard size={18}/>
                      </button>
                      <button className="p-2.5 text-slate-500 bg-slate-100 rounded-xl hover:bg-slate-200 transition-colors" title="Escanear QR">
                          <QrCode size={18}/>
                      </button>
                  </div>
              )}
          </div>

          {/* Combined Smart Suggestions Dropdown */}
          {showSuggestions && (
              <div className="absolute top-full left-0 right-0 mt-3 bg-white rounded-[2rem] shadow-2xl border border-slate-100 overflow-hidden animate-slide-up z-50 p-2 max-h-72 overflow-y-auto custom-scrollbar">
                  {filteredSuggestions.length > 0 ? (
                      <>
                        <div className="px-4 py-3 flex items-center gap-2">
                            <Search size={12} className="text-brand-500"/>
                            <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Resultados Sugeridos</p>
                        </div>
                        {filteredSuggestions.map((s: any) => (
                            <button key={s.id} onClick={() => selectSuggestion(s)} className="w-full p-3 flex items-center gap-3 hover:bg-slate-50 rounded-2xl transition-all group border border-transparent hover:border-slate-100">
                                <div className={`w-10 h-10 rounded-2xl flex items-center justify-center font-bold text-sm transition-colors ${s.type === 'CONTACT' ? 'bg-brand-100 text-brand-600 group-hover:bg-brand-600 group-hover:text-white' : 'bg-slate-100 text-slate-500 group-hover:bg-slate-800 group-hover:text-white'}`}>
                                    {s.type === 'CONTACT' ? <User size={18}/> : <History size={18}/>}
                                </div>
                                <div className="text-left flex-1 min-w-0">
                                    <p className="font-bold text-slate-900 text-sm truncate">{s.name}</p>
                                    <p className="text-[10px] text-slate-400 font-mono truncate">...{s.iban.slice(-8)}</p>
                                </div>
                                <ArrowRight size={14} className="text-slate-300 group-hover:text-slate-900 -translate-x-2 opacity-0 group-hover:translate-x-0 group-hover:opacity-100 transition-all"/>
                            </button>
                        ))}
                      </>
                  ) : (
                      <div className="p-6 text-center text-slate-400 text-xs font-bold">
                          <p>No se encontraron destinatarios.</p>
                          <p className="text-[10px] font-normal mt-1 opacity-70">Asegúrate de tener el IBAN correcto.</p>
                      </div>
                  )}
              </div>
          )}
      </div>

      {/* Amount Display */}
      <div className="flex-1 flex flex-col items-center justify-center min-h-[140px] mb-4">
            <div className="flex flex-col items-center animate-scale-up">
                 <p className="text-xs font-bold text-slate-400 uppercase tracking-widest mb-2">Monto a enviar</p>
                 <div className="flex items-baseline gap-2 relative">
                    <span className={`text-6xl font-black tracking-tighter ${amount ? 'text-slate-900' : 'text-slate-300'}`}>
                        {amount || '0'}
                    </span>
                    <span className="text-2xl text-slate-400 font-bold absolute -right-10 top-2">Pts</span>
                 </div>
            </div>
            {numericAmount > 0 && (
                <div className="flex items-center gap-2 mt-4 px-4 py-2 bg-slate-100 rounded-full border border-slate-200">
                    <span className="text-[10px] font-bold text-slate-500 uppercase tracking-widest">Total (+{currentTaxRate}%):</span>
                    <span className="text-xs font-black text-slate-900">{totalAmount.toLocaleString()} Pts</span>
                </div>
            )}
      </div>

      {/* Keypad */}
      <div className="grid grid-cols-3 gap-3 mb-6 px-2">
          {[1,2,3,4,5,6,7,8,9].map(n => (
              <KeypadButton key={n} val={n.toString()} onClick={() => handleKeypad(n.toString())} />
          ))}
          <KeypadButton val="." onClick={() => handleKeypad('.')} />
          <KeypadButton val="0" onClick={() => handleKeypad('0')} />
          <KeypadButton val="DEL" onClick={() => handleKeypad('DEL')} icon={<X size={24} className="text-slate-400"/>} />
      </div>

      <button
          onClick={handleVerify}
          disabled={!amount || recipientInput.length < 20}
          className="w-full py-4 bg-brand-600 text-white rounded-[2rem] font-black text-lg shadow-xl shadow-brand-500/30 active:scale-[0.98] transition-all disabled:opacity-50 disabled:shadow-none flex items-center justify-center gap-2 mb-safe"
        >
          Continuar <ArrowRight size={20} strokeWidth={3} />
      </button>

      {/* Account Selection Bottom Sheet */}
      {showAccountDrawer && (
          <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-50 flex flex-col justify-end animate-fade-in" onClick={() => setShowAccountDrawer(false)}>
              <div className="bg-white rounded-t-[2.5rem] p-6 pb-safe animate-slide-up max-h-[70vh] overflow-y-auto relative" onClick={e => e.stopPropagation()}>
                  <div className="w-12 h-1.5 bg-slate-200 rounded-full mx-auto mb-8"></div>
                  <h3 className="text-xl font-black text-slate-900 mb-6 px-2">Seleccionar Cuenta</h3>
                  <div className="space-y-3">
                      {userAccounts.map((acc, idx) => (
                          <button 
                              key={acc.id}
                              onClick={() => { setSelectedAccountIndex(idx); setShowAccountDrawer(false); }}
                              className={`w-full p-5 rounded-[2rem] flex items-center justify-between border-2 transition-all ${selectedAccountIndex === idx ? 'border-brand-600 bg-brand-50 ring-2 ring-brand-500/20' : 'border-slate-100 hover:border-slate-200'}`}
                          >
                              <div className="flex items-center gap-4">
                                  <div className={`w-12 h-12 rounded-2xl flex items-center justify-center font-bold text-lg shadow-sm ${selectedAccountIndex === idx ? 'bg-brand-600 text-white' : 'bg-white text-slate-500 border border-slate-100'}`}>
                                      {acc.alias.charAt(0)}
                                  </div>
                                  <div className="text-left">
                                      <p className={`font-bold text-sm ${selectedAccountIndex === idx ? 'text-brand-900' : 'text-slate-900'}`}>{acc.alias}</p>
                                      <p className="text-xs font-mono text-slate-400">{acc.iban.slice(-8)}</p>
                                  </div>
                              </div>
                              <p className="font-black text-slate-900">{acc.balance.toLocaleString()} Pts</p>
                          </button>
                      ))}
                  </div>
              </div>
          </div>
      )}

      {/* Confirmation Modal */}
      {transferStep === 'CONFIRM' && (
           <div className="fixed inset-0 bg-slate-900/80 backdrop-blur-md z-50 flex items-center justify-center p-6 animate-fade-in">
                <div className="bg-white w-full max-w-sm rounded-[2.5rem] p-8 shadow-2xl animate-scale-up relative">
                    <button onClick={resetFlow} className="absolute top-6 right-6 p-2 bg-slate-50 rounded-full hover:bg-slate-100 transition-colors"><X size={20}/></button>

                    <div className="text-center mb-8">
                        <div className="w-16 h-16 bg-brand-50 text-brand-600 rounded-3xl flex items-center justify-center mx-auto mb-4 shadow-sm">
                            <Send size={32} />
                        </div>
                        <h3 className="text-2xl font-black text-slate-900">Confirmar Envío</h3>
                    </div>

                    <div className="space-y-4 mb-8 bg-slate-50 p-6 rounded-[2rem] border border-slate-100">
                        <div className="flex justify-between items-center">
                            <span className="text-slate-400 font-bold text-xs uppercase">Envías</span>
                            <span className="font-black text-xl text-slate-900">{numericAmount.toLocaleString()} Pts</span>
                        </div>
                        <div className="flex justify-between items-center border-b border-slate-200 pb-4">
                            <span className="text-slate-400 font-bold text-xs uppercase">Tasa ({currentTaxRate}%)</span>
                            <span className="font-bold text-slate-500 text-sm">{taxAmount.toLocaleString()} Pts</span>
                        </div>
                        <div className="flex justify-between items-center pt-2">
                            <span className="text-slate-900 font-bold text-xs uppercase">Total</span>
                            <span className="font-black text-2xl text-brand-600">{totalAmount.toLocaleString()}</span>
                        </div>
                    </div>

                    <div className="mb-8 px-2 space-y-4">
                        <div className="flex items-center justify-between">
                            <div className="flex items-center gap-3">
                                <div className="w-8 h-8 bg-slate-200 rounded-full flex items-center justify-center text-slate-500 font-bold text-xs">
                                    <User size={14}/>
                                </div>
                                <div>
                                    <p className="text-[10px] font-bold text-slate-400 uppercase tracking-wide">Destinatario</p>
                                    <p className="font-bold text-sm text-slate-900 truncate max-w-[150px]">{detectedBeneficiary || 'Desconocido'}</p>
                                </div>
                            </div>
                        </div>
                        <div className="pl-11">
                             <p className="font-mono text-xs font-bold text-slate-500 bg-slate-100 px-2 py-1 rounded inline-block">{fullIbanDisplay}</p>
                        </div>
                    </div>

                    <button onClick={handleConfirm} className="w-full py-4 bg-slate-900 text-white rounded-2xl font-black uppercase text-xs tracking-widest shadow-xl hover:bg-brand-600 transition-all active:scale-95 flex items-center justify-center gap-2">
                        <ShieldCheck size={16}/> Autorizar Operación
                    </button>
                </div>
           </div>
      )}

      {transferStep === 'SUCCESS' && (
           <div className="fixed inset-0 bg-white z-50 flex flex-col items-center justify-center p-6 animate-fade-in text-center">
               <div className="w-28 h-28 bg-emerald-50 text-emerald-500 rounded-full flex items-center justify-center mb-8 shadow-xl shadow-emerald-500/10 animate-pop-in">
                   <CheckCircle2 size={64} strokeWidth={3} />
               </div>
               <h2 className="text-4xl font-black text-slate-900 mb-2 tracking-tight">¡Enviado!</h2>
               <p className="text-slate-400 font-bold mb-12 max-w-xs mx-auto leading-relaxed">
                   Has transferido <span className="text-slate-900">{numericAmount.toLocaleString()} Pts</span> correctamente.
               </p>

               <button onClick={resetFlow} className="px-12 py-5 bg-slate-900 text-white rounded-full font-black text-sm uppercase tracking-widest shadow-2xl active:scale-95 transition-all">
                   Finalizar
               </button>
           </div>
      )}
    </div>
  );
};

import React, { useState, useMemo, useEffect } from 'react';
import { useBank } from '../context/BankContext';
import { SECURITY_THRESHOLD_AMOUNT } from '../constants';
import { Send, ChevronDown, X, CheckCircle2, ShieldCheck, User, Search, QrCode, ArrowRight, Wallet, Check, Clipboard, Clock, History, UserPlus, Star } from 'lucide-react';

interface TransfersProps {
  addNotification: (msg: string, type: 'success' | 'error' | 'info') => void;
}

type TransferStep = 'IDLE' | 'SECURITY' | 'CONFIRM' | 'PROCESSING' | 'SUCCESS';

const KeypadButton: React.FC<{ val: string; onClick: () => void; icon?: React.ReactNode; primary?: boolean; secondary?: boolean }> = ({ val, onClick, icon, primary, secondary }) => (
  <button 
    onClick={(e) => {
        const btn = e.currentTarget;
        btn.classList.add('scale-90', 'bg-slate-200');
        setTimeout(() => btn.classList.remove('scale-90', 'bg-slate-200'), 100);
        onClick();
    }}
    className={`h-14 w-full rounded-2xl transition-all duration-150 text-xl font-bold flex items-center justify-center select-none ${
        primary ? 'bg-brand-600 text-white shadow-lg shadow-brand-500/30 hover:bg-brand-700' : 
        secondary ? 'bg-slate-100 text-slate-500 border border-slate-200 hover:bg-slate-200' :
        'bg-white border border-slate-200 text-slate-900 hover:bg-slate-50 shadow-sm'
    }`}
  >
      {icon ? icon : val}
  </button>
);

export const Transfers: React.FC<TransfersProps> = ({ addNotification }) => {
  const { userAccounts, transfer, taxConfig, contacts, transactions, triggerHaptic } = useBank();

  const [selectedAccountIndex, setSelectedAccountIndex] = useState(0);
  const [showAccountDrawer, setShowAccountDrawer] = useState(false); 

  const [recipientInput, setRecipientInput] = useState(''); 
  const [showSuggestions, setShowSuggestions] = useState(false);
  const [detectedBeneficiary, setDetectedBeneficiary] = useState<string | null>(null);

  const [amount, setAmount] = useState('');
  const [transferStep, setTransferStep] = useState<TransferStep>('IDLE');

  const currentAccount = userAccounts[selectedAccountIndex];
  const currentTaxRate = taxConfig.transferRate;

  // --- LOGIC: RECENT & CONTACTS MERGE ---
  const suggestionsList = useMemo(() => {
      const contactSuggestions = contacts.map(c => ({
          id: `contact-${c.id}`,
          name: c.name,
          iban: c.iban,
          type: 'CONTACT'
      }));

      const recentMap = new Map();
      transactions.forEach(tx => {
          if (tx.senderIban === currentAccount?.iban && tx.receiverIban && !tx.receiverIban.startsWith('PL000000')) {
             if (!contacts.some(c => c.iban === tx.receiverIban)) {
                 if (!recentMap.has(tx.receiverIban)) {
                     recentMap.set(tx.receiverIban, {
                         id: `recent-${tx.id}`,
                         name: tx.receiverIban,
                         iban: tx.receiverIban,
                         type: 'RECENT'
                     });
                 }
             }
          }
      });
      return [...contactSuggestions, ...Array.from(recentMap.values()).slice(0, 3)];
  }, [contacts, transactions, currentAccount]);

  const filteredSuggestions = useMemo(() => {
      if (!recipientInput) return suggestionsList;
      const cleanInput = recipientInput.replace(/\s/g, '').toUpperCase();
      return suggestionsList.filter(s => 
          s.name.toLowerCase().includes(recipientInput.toLowerCase()) || 
          s.iban.includes(cleanInput)
      );
  }, [suggestionsList, recipientInput]);

  useEffect(() => {
      const clean = 'PL' + recipientInput.replace(/\s/g, '').toUpperCase();
      const match = suggestionsList.find(s => s.iban === clean);
      setDetectedBeneficiary(match ? match.name : null);
  }, [recipientInput, suggestionsList]);


  // --- HANDLERS ---

  const handleKeypad = (val: string) => {
      triggerHaptic('light');
      if (val === 'DEL') {
          setAmount(prev => prev.slice(0, -1));
      } else if (val === '.') {
          if (!amount.includes('.')) setAmount(prev => prev + '.');
      } else if (val === '+10') {
          setAmount(prev => (Number(prev) + 10).toString());
      } else if (val === '+50') {
          setAmount(prev => (Number(prev) + 50).toString());
      } else {
          if (amount.length < 9) setAmount(prev => prev + val);
      }
  };

  const formatDisplayIban = (val: string) => {
      const clean = val.replace(/[^a-zA-Z0-9]/g, '').toUpperCase();
      const noPrefix = clean.startsWith('PL') ? clean.substring(2) : clean;
      return noPrefix.replace(/(.{4})/g, '$1 ').trim();
  };

  const handleRecipientChange = (e: React.ChangeEvent<HTMLInputElement>) => {
      const formatted = formatDisplayIban(e.target.value);
      if (formatted.length <= 26) {
          setRecipientInput(formatted);
          setShowSuggestions(true);
      }
  };

  const handlePaste = async () => {
      try {
          const text = await navigator.clipboard.readText();
          const formatted = formatDisplayIban(text);
          if (formatted.length <= 26) {
              setRecipientInput(formatted);
              addNotification("IBAN pegado", "info");
          }
      } catch (err) {
          addNotification("Permiso de portapapeles denegado", "error");
      }
  };

  const selectSuggestion = (item: any) => {
      triggerHaptic('medium');
      const raw = item.iban.startsWith('PL') ? item.iban.substring(2) : item.iban;
      setRecipientInput(raw.replace(/(.{4})/g, '$1 ').trim());
      setDetectedBeneficiary(item.name);
      setShowSuggestions(false);
  };

  const handleVerify = () => {
    triggerHaptic('medium');
    const rawIban = recipientInput.replace(/\s/g, '');
    if (rawIban.length !== 20) {
      addNotification("Formato de IBAN incompleto", 'error');
      return;
    }

    const numericAmount = Number(amount);
    const taxAmount = numericAmount * (currentTaxRate / 100);
    const totalDeduction = numericAmount + taxAmount;

