import React, { useState, useEffect, useRef } from 'react';
import { ArrowLeft, Monitor, AlertTriangle, History, ArrowRight, Globe, ShieldCheck, Lock, User, Key, ChevronRight } from 'lucide-react';
import { useBank } from '../context/BankContext';

interface LoginProps {
  onLogin: () => void;
  onBack: () => void;
  onATMEnter: () => void;
}

export const Login: React.FC<LoginProps> = ({ onLogin, onBack, onATMEnter }) => {
  const { login, loginWithPlacetaID } = useBank();
  const [dip, setDip] = useState('');
  const [password, setPassword] = useState('');
  const [showLegacy, setShowLegacy] = useState(false);
  const [isLoading, setIsLoading] = useState(false);
  const [errorMessage, setErrorMessage] = useState<string | null>(null);

  // Ref para manejar el contenedor del SDK sin interferir con el ciclo de vida de React
  const sdkContainerRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    let attempts = 0;
    const maxAttempts = 20;

    const initPlacetaID = () => {
      const SDK = (window as any).PlacetaID;
      const container = sdkContainerRef.current;

      if (SDK && container) {
        // Limpiamos el contenido manual para evitar el error de removeChild de React
        container.innerHTML = ''; 
        const innerDiv = document.createElement('div');
        innerDiv.id = 'placeta-id-injection-point';
        container.appendChild(innerDiv);

        try {
          new SDK({
            containerId: 'placeta-id-injection-point',
            apiUrl: 'https://junta.vercel.app/api/placetaid',
            theme: 'dark',
            onSuccess: (userData: any) => handlePlacetaLogin(userData)
          });
        } catch (err) {
          console.error("SDK Error:", err);
        }
      } else if (attempts < maxAttempts) {
        attempts++;
        setTimeout(initPlacetaID, 300);
      }
    };

    if (!showLegacy) {
      initPlacetaID();
    }

    // Cleanup robusto al desmontar o cambiar de vista
    return () => {
        if (sdkContainerRef.current) {
            sdkContainerRef.current.innerHTML = '';
        }
    };
  }, [showLegacy]);

  const handlePlacetaLogin = async (userData: any) => {
    setIsLoading(true);
    setErrorMessage(null);
    try {
        const result = await loginWithPlacetaID(userData);
        if (result.success) {
          onLogin();
        } else {
          setErrorMessage(result.error || 'Validación de identidad fallida.');
        }
    } catch (e) {
        setErrorMessage("Error de conexión con el sistema central.");
    } finally {
        setIsLoading(false);
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setErrorMessage(null);
    if (!dip || !password) return;
    setIsLoading(true);
    try {
        const result = await login(dip, password);
        if (result.success) {
            onLogin();
        } else {
            setErrorMessage(result.error || 'Credenciales de acceso no válidas.');
        }
    } catch (e) {
        setErrorMessage("Servicio de autenticación no disponible.");
    } finally {
        setIsLoading(false);
    }
  };

  return (
    <div className="min-h-screen bg-[#020617] flex font-sans overflow-hidden relative selection:bg-brand-500 selection:text-white">
      {/* Background Ambience */}
      <div className="absolute inset-0 z-0 pointer-events-none">
          <div className="absolute top-[-20%] left-[-10%] w-[70vw] h-[70vw] bg-indigo-900/10 rounded-full blur-[120px] animate-pulse-slow"></div>
          <div className="absolute bottom-[-10%] right-[-10%] w-[50vw] h-[50vw] bg-brand-900/10 rounded-full blur-[100px]"></div>
          <div className="absolute inset-0 bg-[url('https://grainy-gradients.vercel.app/noise.svg')] opacity-10 brightness-100 contrast-150"></div>
      </div>

      {/* Left Column: Brand Hero */}
      <div className="hidden lg:flex w-1/2 relative items-center justify-center z-10 p-12 border-r border-white/5 backdrop-blur-sm">
          <div className="flex flex-col items-center justify-center text-center">
              <div className="relative group mb-12">
                  <div className="absolute -inset-10 bg-gradient-to-r from-brand-500 to-indigo-500 rounded-full blur-[60px] opacity-20 group-hover:opacity-30 transition-opacity duration-700"></div>
                  <img 
                    src="https://i.postimg.cc/xd0y9V1t/BANCO-DE.png" 
                    alt="Banco de La Placeta" 
                    className="w-[400px] h-auto object-contain relative z-10 drop-shadow-2xl transform group-hover:scale-105 transition-transform duration-700"
                  />
              </div>

              <div className="max-w-md space-y-6">
                  <div className="inline-flex items-center gap-2 px-4 py-1.5 rounded-full bg-white/5 border border-white/10 text-brand-200 text-[10px] font-black uppercase tracking-[0.2em] backdrop-blur-md">
                      <ShieldCheck size={12}/> Gestión Administrativa Capítulo 1
                  </div>
                  <p className="text-slate-400 text-sm font-medium leading-relaxed">
                      Acceda al Registro Central de Activos. Gestión soberana de capital y liquidación de tributos en tiempo real.
                  </p>
              </div>
          </div>

          <div className="absolute bottom-10 left-12 text-[10px] text-slate-600 font-mono flex items-center gap-2">
              <div className="w-2 h-2 bg-emerald-500 rounded-full animate-pulse"></div>
              CIFRADO DE GRADO MILITAR ACTIVO
          </div>
      </div>

      {/* Right Column: Auth Form */}
      <div className="flex-1 flex flex-col justify-center px-6 md:px-12 lg:px-24 relative z-10 w-full bg-gradient-to-b from-slate-900/50 to-slate-950/80 backdrop-blur-xl lg:bg-none">

        <div className="lg:hidden absolute top-8 left-0 right-0 flex justify-center pointer-events-none">
             <img src="https://i.postimg.cc/5t0S5t3p/BANCO-DE.png" className="h-16 w-auto object-contain opacity-80" alt="Logo"/>
        </div>

        <div className="absolute top-6 left-6 right-6 flex justify-between items-center">
            <button onClick={onBack} className="p-2 rounded-full text-slate-400 hover:text-white hover:bg-white/10 transition-all flex items-center gap-2 group">
                <ArrowLeft size={18} className="group-hover:-translate-x-1 transition-transform"/> <span className="text-xs font-bold uppercase tracking-widest hidden sm:inline">Atrás</span>
            </button>
            <button onClick={onATMEnter} className="px-4 py-2 bg-slate-800/50 border border-white/10 rounded-xl text-[10px] font-black text-brand-300 uppercase tracking-widest hover:bg-brand-500 hover:text-white hover:border-brand-500 transition-all flex items-center gap-2 shadow-lg">
                <Monitor size={14}/> Modo Cajero
            </button>
        </div>

        <div className="w-full max-w-sm mx-auto animate-slide-up relative mt-10 lg:mt-0">

            <div className="mb-10">
                <h2 className="text-3xl font-black text-white tracking-tight mb-2 leading-none">Banca Digital</h2>
                <p className="text-slate-500 font-medium text-sm">Identifíquese en el Nodo para continuar.</p>
            </div>

            {errorMessage && (
                <div className="bg-red-500/10 border border-red-500/20 text-red-300 p-4 rounded-2xl text-xs font-bold mb-8 flex items-start gap-3 animate-slide-up backdrop-blur-md">
                    <AlertTriangle size={16} className="shrink-0 text-red-500 mt-0.5"/> 
                    <span>{errorMessage}</span>
                </div>
            )}

            {isLoading ? (
                <div className="py-20 flex flex-col items-center justify-center space-y-6 bg-slate-900/40 rounded-[3rem] border border-white/5">
                    <div className="relative">
                        <div className="w-16 h-16 border-4 border-brand-500/20 border-t-brand-500 rounded-full animate-spin"></div>
                        <div className="absolute inset-0 flex items-center justify-center">
                            <Lock size={20} className="text-brand-500/50"/>
                        </div>
                    </div>
                    <p className="text-white font-black uppercase text-[10px] tracking-[0.2em] animate-pulse">Sincronizando...</p>
                </div>
            ) : (
                <div className="space-y-8">

                    {/* Primary Login: PlacetaID */}
                    {!showLegacy && (
                        <div className="space-y-8">
                            <div ref={sdkContainerRef} className="min-h-[64px] animate-fade-in relative z-20">
                                {/* SDK Button renders inside here safely via ref */}
                                <div className="h-[64px] w-full bg-slate-800/30 rounded-2xl border border-white/5 flex items-center justify-center text-slate-500 text-[10px] font-black uppercase tracking-widest animate-pulse">
                                    Iniciando Pasarela Segura...
                                </div>
                            </div>

                            <div className="relative py-2">
                                <div className="absolute inset-0 flex items-center"><div className="w-full border-t border-white/5"></div></div>
                                <div className="relative flex justify-center text-[10px] uppercase font-black tracking-widest">
                                    <span className="bg-[#0b1021] px-6 text-slate-600">o accede con</span>
                                </div>
                            </div>

                            <button onClick={() => setShowLegacy(true)} className="w-full p-5 bg-transparent border border-slate-800 hover:border-slate-600 text-slate-400 hover:text-white rounded-2xl font-bold text-sm transition-all flex items-center justify-between group">
                                <span className="flex items-center gap-3"><History size={18}/> Credenciales de Nodo</span>
                                <ChevronRight size={16} className="text-slate-700 group-hover:text-white transition-colors"/>
                            </button>
                        </div>
                    )}

                    {/* Legacy Login Form */}
                    {showLegacy && (
                        <form onSubmit={handleSubmit} className="space-y-6 animate-slide-up">
                            <div className="space-y-3">
                                 <label className="text-[10px] font-black text-brand-300 uppercase ml-1 tracking-widest flex items-center gap-2"><User size={10}/> Identidad (DIP)</label>
                                 <div className="relative group">
                                     <input 
                                        type="text" 
                                        value={dip} 
                                        onChange={(e) => setDip(e.target.value.toUpperCase())} 
                                        className="w-full pl-5 pr-12 py-4 bg-slate-900/60 border border-white/10 rounded-2xl text-white outline-none focus:border-brand-500 focus:ring-1 focus:ring-brand-500 transition-all font-mono font-bold text-lg placeholder:text-slate-700 uppercase tracking-wider" 
                                        placeholder="DIP-XXXXXX" 
                                        autoFocus
                                     />
                                     <div className="absolute top-1/2 right-5 -translate-y-1/2 text-slate-700 pointer-events-none group-focus-within:text-brand-500 transition-colors">
                                         <User size={18}/>
                                     </div>
                                 </div>
                            </div>
                            <div className="space-y-3">
                                 <label className="text-[10px] font-black text-brand-300 uppercase ml-1 tracking-widest flex items-center gap-2"><Key size={10}/> Clave Maestra</label>
                                 <div className="relative group">
                                     <input 
                                        type="password" 
                                        value={password} 
                                        onChange={(e) => setPassword(e.target.value)} 
                                        className="w-full pl-5 pr-12 py-4 bg-slate-900/60 border border-white/10 rounded-2xl text-white outline-none focus:border-brand-500 focus:ring-1 focus:ring-brand-500 transition-all font-bold text-lg placeholder:text-slate-700 tracking-widest" 
                                        placeholder="••••••••"
                                     />
                                     <div className="absolute top-1/2 right-5 -translate-y-1/2 text-slate-700 pointer-events-none group-focus-within:text-brand-500 transition-colors">
                                         <Lock size={18}/>
                                     </div>
                                 </div>
                            </div>

                            <button type="submit" disabled={isLoading} className="w-full py-5 bg-white text-slate-950 rounded-2xl font-black uppercase text-xs tracking-widest hover:bg-brand-500 hover:text-white transition-all shadow-xl mt-4 active:scale-95 flex items-center justify-center gap-3 group overflow-hidden">
                                <span className="relative z-10 flex items-center gap-2">Autorizar Acceso <ArrowRight size={16} className="group-hover:translate-x-1 transition-transform"/></span>
                            </button>

                            <button type="button" onClick={() => setShowLegacy(false)} className="w-full text-center text-slate-600 font-black text-[10px] hover:text-white transition-colors pt-4 uppercase tracking-widest">
                                Volver a PlacetaID
                            </button>
                        </form>
                    )}
                </div>
            )}

            <div className="mt-16 flex flex-col items-center gap-4 text-[9px] font-black text-slate-600 uppercase tracking-[0.2em] text-center border-t border-white/5 pt-8">
                <div className="flex items-center gap-4">
                    <span className="flex items-center gap-1.5"><Globe size={10}/> SSL-256</span>
                    <span className="flex items-center gap-1.5"><ShieldCheck size={10}/> Verificado</span>
                </div>
                <span className="opacity-30">© {new Date().getFullYear()} Junta Administrativa de La Placeta</span>
            </div>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useMemo, useEffect } from 'react';
import { useBank } from '../context/BankContext';
import { SECURITY_THRESHOLD_AMOUNT } from '../constants';
// Added Landmark to the imported icons from lucide-react
import { Send, ChevronDown, X, CheckCircle2, ShieldCheck, User, Search, QrCode, ArrowRight, Wallet, Check, Clipboard, Clock, History, UserPlus, Star, Landmark } from 'lucide-react';

interface TransfersProps {
  addNotification: (msg: string, type: 'success' | 'error' | 'info') => void;
}

type TransferStep = 'IDLE' | 'SECURITY' | 'CONFIRM' | 'PROCESSING' | 'SUCCESS';

const KeypadButton: React.FC<{ val: string; onClick: () => void; icon?: React.ReactNode; primary?: boolean; secondary?: boolean }> = ({ val, onClick, icon, primary, secondary }) => (
  <button 
    onClick={(e) => {
        const btn = e.currentTarget;
        btn.classList.add('scale-90', 'bg-slate-200');
        setTimeout(() => btn.classList.remove('scale-90', 'bg-slate-200'), 100);
        onClick();
    }}
    className={`h-14 w-full rounded-2xl transition-all duration-150 text-xl font-bold flex items-center justify-center select-none ${
        primary ? 'bg-brand-600 text-white shadow-lg shadow-brand-500/30 hover:bg-brand-700' : 
        secondary ? 'bg-slate-100 text-slate-500 border border-slate-200 hover:bg-slate-200' :
        'bg-white border border-slate-200 text-slate-900 hover:bg-slate-50 shadow-sm'
    }`}
  >
      {icon ? icon : val}
  </button>
);

export const Transfers: React.FC<TransfersProps> = ({ addNotification }) => {
  const { userAccounts, transfer, taxConfig, contacts, transactions, triggerHaptic } = useBank();

  const [selectedAccountIndex, setSelectedAccountIndex] = useState(0);
  const [showAccountDrawer, setShowAccountDrawer] = useState(false); 

  const [recipientInput, setRecipientInput] = useState(''); 
  const [showSuggestions, setShowSuggestions] = useState(false);
  const [detectedBeneficiary, setDetectedBeneficiary] = useState<string | null>(null);

  const [amount, setAmount] = useState('');
  const [transferStep, setTransferStep] = useState<TransferStep>('IDLE');

  const currentAccount = userAccounts[selectedAccountIndex];
  const currentTaxRate = taxConfig.transferRate;

  // --- LOGIC: RECENT & CONTACTS MERGE ---
  const suggestionsList = useMemo(() => {
      const contactSuggestions = contacts.map(c => ({
          id: `contact-${c.id}`,
          name: c.name,
          iban: c.iban,
          type: 'CONTACT'
      }));

      const recentMap = new Map();
      transactions.forEach(tx => {
          if (tx.senderIban === currentAccount?.iban && tx.receiverIban && !tx.receiverIban.startsWith('PL000000')) {
             if (!contacts.some(c => c.iban === tx.receiverIban)) {
                 if (!recentMap.has(tx.receiverIban)) {
                     recentMap.set(tx.receiverIban, {
                         id: `recent-${tx.id}`,
                         name: tx.receiverIban,
                         iban: tx.receiverIban,
                         type: 'RECENT'
                     });
                 }
             }
          }
      });
      return [...contactSuggestions, ...Array.from(recentMap.values()).slice(0, 3)];
  }, [contacts, transactions, currentAccount]);

  const filteredSuggestions = useMemo(() => {
      if (!recipientInput) return suggestionsList;
      const cleanInput = recipientInput.replace(/\s/g, '').toUpperCase();
      return suggestionsList.filter(s => 
          s.name.toLowerCase().includes(recipientInput.toLowerCase()) || 
          s.iban.includes(cleanInput)
      );
  }, [suggestionsList, recipientInput]);

  useEffect(() => {
      const clean = 'PL' + recipientInput.replace(/\s/g, '').toUpperCase();
      const match = suggestionsList.find(s => s.iban === clean);
      setDetectedBeneficiary(match ? match.name : null);
  }, [recipientInput, suggestionsList]);


  // --- HANDLERS ---

  const handleKeypad = (val: string) => {
      triggerHaptic('light');
      if (val === 'DEL') {
          setAmount(prev => prev.slice(0, -1));
      } else if (val === '.') {
          if (!amount.includes('.')) setAmount(prev => prev + '.');
      } else if (val === '+10') {
          setAmount(prev => (Number(prev) + 10).toString());
      } else if (val === '+50') {
          setAmount(prev => (Number(prev) + 50).toString());
      } else {
          if (amount.length < 9) setAmount(prev => prev + val);
      }
  };

  const formatDisplayIban = (val: string) => {
      const clean = val.replace(/[^a-zA-Z0-9]/g, '').toUpperCase();
      const noPrefix = clean.startsWith('PL') ? clean.substring(2) : clean;
      return noPrefix.replace(/(.{4})/g, '$1 ').trim();
  };

  const handleRecipientChange = (e: React.ChangeEvent<HTMLInputElement>) => {
      const formatted = formatDisplayIban(e.target.value);
      if (formatted.length <= 26) {
          setRecipientInput(formatted);
          setShowSuggestions(true);
      }
  };

  const handlePaste = async () => {
      try {
          const text = await navigator.clipboard.readText();
          const formatted = formatDisplayIban(text);
          if (formatted.length <= 26) {
              setRecipientInput(formatted);
              addNotification("IBAN pegado", "info");
          }
      } catch (err) {
          addNotification("Permiso de portapapeles denegado", "error");
      }
  };

  const selectSuggestion = (item: any) => {
      triggerHaptic('medium');
      const raw = item.iban.startsWith('PL') ? item.iban.substring(2) : item.iban;
      setRecipientInput(raw.replace(/(.{4})/g, '$1 ').trim());
      setDetectedBeneficiary(item.name);
      setShowSuggestions(false);
  };

  const handleVerify = () => {
    triggerHaptic('medium');
    const rawIban = recipientInput.replace(/\s/g, '');
    if (rawIban.length !== 20) {
      addNotification("Formato de IBAN incompleto", 'error');
      return;
    }

    const numericAmount = Number(amount);
    const taxAmount = numericAmount * (currentTaxRate / 100);
    const totalDeduction = numericAmount + taxAmount;

    if (numericAmount <= 0) {
        addNotification("Introduce un importe válido", 'error');
        return;
    }

    if (totalDeduction > currentAccount.balance) {
      addNotification(`Saldo insuficiente`, 'error');
      return;
    }

    setTransferStep(numericAmount > SECURITY_THRESHOLD_AMOUNT ? 'SECURITY' : 'CONFIRM');
  };

  const handleConfirm = async () => {
    triggerHaptic('heavy');
    setTransferStep('PROCESSING');
    const fullRecipient = 'PL' + recipientInput.replace(/\s/g, '');
    await new Promise(r => setTimeout(r, 1200)); 
    try {
        await transfer(currentAccount.iban, fullRecipient, Number(amount), 'Transferencia Inmediata');
        setTransferStep('SUCCESS');
    } catch (e: any) {
        addNotification(e.message || "Error en el Ledger", 'error');
        setTransferStep('IDLE');
    }
  };

  if (!currentAccount) return null;

  const numericAmount = Number(amount) || 0;
  const taxAmount = numericAmount * (currentTaxRate / 100);
  const totalAmount = numericAmount + taxAmount;
  const fullIbanDisplay = 'PL' + recipientInput.replace(/\s/g, '');

  return (
    <div className="pb-safe-nav h-full flex flex-col max-w-lg mx-auto relative animate-fade-in pt-safe px-4 min-h-screen font-sans">

      {/* Dynamic Header */}
      <div className="flex justify-between items-center mb-6 pt-4">
            <h2 className="text-3xl font-black text-slate-900 tracking-tight">Enviar Pts</h2>
            <div className="bg-white/80 backdrop-blur shadow-sm border border-slate-100 px-4 py-2 rounded-2xl flex items-center gap-2">
                <div className="w-2 h-2 bg-emerald-500 rounded-full animate-pulse"></div>
                <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest">SIDS Direct</span>
            </div>
      </div>

      {/* Account Selector Card */}
      <div className="relative mb-8 group">
             <button 
                className="w-full p-6 bg-slate-900 text-white rounded-[2.5rem] flex flex-col justify-between shadow-2xl shadow-slate-900/20 active:scale-[0.98] transition-all relative overflow-hidden h-40"
                onClick={() => setShowAccountDrawer(true)}
             >
                <div className="absolute top-0 right-0 w-48 h-48 bg-brand-500/10 rounded-full blur-3xl -mr-16 -mt-16 pointer-events-none group-hover:bg-brand-500/20 transition-colors"></div>

                <div className="flex justify-between items-start w-full relative z-10">
                    <div className="flex items-center gap-4">
                        <div className="w-12 h-12 bg-white/10 rounded-2xl flex items-center justify-center backdrop-blur-md border border-white/10">
                            {currentAccount.type === 'BUSINESS' ? <Landmark size={24}/> : <User size={24}/>}
                        </div>
                        <div className="text-left">
                            <p className="text-[10px] text-slate-400 font-bold uppercase tracking-[0.2em]">Cuenta Origen</p>
                            <p className="font-bold text-lg leading-tight">{currentAccount.alias}</p>
                        </div>
                    </div>
                    <div className="bg-white/10 px-3 py-1.5 rounded-xl text-[9px] font-black uppercase tracking-widest flex items-center gap-1 hover:bg-white/20 transition-colors">
                        Cambiar <ChevronDown size={12}/>
                    </div>
                </div>

                <div className="relative z-10 text-left">
                    <p className="text-[10px] font-mono text-slate-500 mb-1">•••• {currentAccount.iban.slice(-8)}</p>
                    <p className="text-3xl font-black tracking-tight">{currentAccount.balance.toLocaleString()} <span className="text-lg opacity-40">Pts</span></p>
                </div>
            </button>
      </div>

      {/* Quick Contacts Bar */}
      <div className="mb-6 px-1">
          <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest mb-4 ml-1">Frecuentes</p>
          <div className="flex gap-4 overflow-x-auto no-scrollbar pb-1">
              <button className="flex flex-col items-center gap-2 shrink-0 group">
                  <div className="w-14 h-14 rounded-2xl bg-slate-100 border-2 border-dashed border-slate-300 flex items-center justify-center text-slate-400 group-hover:border-brand-500 group-hover:text-brand-500 transition-all">
                      <UserPlus size={20}/>
                  </div>
                  <span className="text-[9px] font-bold text-slate-500">Nuevo</span>
              </button>
              {suggestionsList.map((s: any) => (
                  <button key={s.id} onClick={() => selectSuggestion(s)} className="flex flex-col items-center gap-2 shrink-0 group">
                      <div className={`w-14 h-14 rounded-2xl flex items-center justify-center text-lg font-bold transition-all group-hover:scale-105 shadow-sm ${s.type === 'CONTACT' ? 'bg-brand-50 text-brand-600' : 'bg-slate-50 text-slate-500'}`}>
                          {s.name.charAt(0)}
                      </div>
                      <span className="text-[9px] font-bold text-slate-600 truncate w-14 text-center">{s.name.split(' ')[0]}</span>
                  </button>
              ))}
          </div>
      </div>

      {/* Recipient Input Area */}
      <div className="relative mb-6 z-30">
          <div className="flex justify-between items-center mb-2 px-2">
              <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Destinatario</label>
              {detectedBeneficiary && (
                  <div className="flex items-center gap-1.5 px-3 py-1 bg-emerald-50 rounded-full animate-fade-in border border-emerald-100">
                      <CheckCircle2 size={12} className="text-emerald-600"/>
                      <span className="text-[10px] font-black text-emerald-700 uppercase">{detectedBeneficiary}</span>
                  </div>
              )}
          </div>

          <div className={`bg-white p-2 rounded-3xl border-2 flex items-center shadow-soft transition-all relative ${showSuggestions ? 'border-brand-500 ring-4 ring-brand-500/10' : 'border-slate-100 hover:border-slate-200'}`}>
              <div className="bg-slate-50 w-12 h-12 rounded-2xl flex items-center justify-center text-slate-400 font-black text-xs select-none shrink-0 border border-slate-100">PL</div>
              <input 
                  type="text" 
                  value={recipientInput}
                  onChange={handleRecipientChange}
                  onFocus={() => setShowSuggestions(true)}
                  onBlur={() => setTimeout(() => setShowSuggestions(false), 200)}
                  className="flex-1 bg-transparent px-3 font-mono text-lg font-bold outline-none text-slate-900 placeholder:text-slate-200 tracking-wider min-w-0"
                  placeholder="0000 0000..."
                  autoComplete="off"
              />

              {recipientInput ? (
                  <button onClick={() => {setRecipientInput(''); setDetectedBeneficiary(null);}} className="p-3 text-slate-300 hover:text-slate-500 transition-colors">
                      <X size={20}/>
                  </button>
              ) : (
                  <div className="flex gap-1 pr-1">
                      <button onClick={handlePaste} className="p-3 text-brand-600 bg-brand-50 rounded-2xl hover:bg-brand-100 transition-colors" title="Pegar">
                          <Clipboard size={20}/>
                      </button>
                      <button className="p-3 text-slate-400 bg-slate-50 rounded-2xl hover:bg-slate-100 transition-colors">
                          <QrCode size={20}/>
                      </button>
                  </div>
              )}
          </div>

          {/* Combined Smart Suggestions Dropdown */}
          {showSuggestions && (
              <div className="absolute top-full left-0 right-0 mt-3 bg-white rounded-[2rem] shadow-2xl border border-slate-100 overflow-hidden animate-slide-up z-50 p-2 max-h-64 overflow-y-auto">
                  {filteredSuggestions.length > 0 ? (
                        filteredSuggestions.map((s: any) => (
                            <button key={s.id} onClick={() => selectSuggestion(s)} className="w-full p-4 flex items-center gap-4 hover:bg-slate-50 rounded-2xl transition-all group border border-transparent hover:border-slate-100">
                                <div className={`w-11 h-11 rounded-xl flex items-center justify-center font-bold text-sm transition-colors ${s.type === 'CONTACT' ? 'bg-brand-50 text-brand-600 group-hover:bg-brand-600 group-hover:text-white' : 'bg-slate-100 text-slate-500'}`}>
                                    {s.type === 'CONTACT' ? <Star size={18} fill="currentColor"/> : <Clock size={18}/>}
                                </div>
                                <div className="text-left flex-1 min-w-0">
                                    <p className="font-black text-slate-900 text-sm truncate">{s.name}</p>
                                    <p className="text-[10px] text-slate-400 font-mono truncate">{s.iban}</p>
                                </div>
                                <ArrowRight size={14} className="text-slate-300 group-hover:text-slate-900 group-hover:translate-x-1 transition-all"/>
                            </button>
                        ))
                  ) : (
                      <div className="p-8 text-center text-slate-400 text-xs font-bold">
                          Sin coincidencias en el Registro
                      </div>
                  )}
              </div>
          )}
      </div>

      {/* Amount Display */}
      <div className="flex-1 flex flex-col items-center justify-center py-6">
            <div className="flex flex-col items-center">
                 <p className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] mb-4">Importe a enviar</p>
                 <div className="flex items-baseline gap-2 group cursor-default">
                    <span className={`text-7xl font-black tracking-tighter transition-colors ${amount ? 'text-slate-900' : 'text-slate-100'}`}>
                        {amount || '0'}
                    </span>
                    <span className="text-2xl text-slate-400 font-black">Pts</span>
                 </div>
                 {numericAmount > 0 && (
                    <div className="flex items-center gap-2 mt-6 px-5 py-2 bg-slate-100 rounded-full border border-slate-200 animate-fade-in shadow-inner">
                        <span className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Total (+{currentTaxRate}%):</span>
                        <span className="text-xs font-black text-brand-600">{totalAmount.toLocaleString()} Pts</span>
                    </div>
                 )}
            </div>
      </div>

      {/* Keypad */}
      <div className="grid grid-cols-3 gap-3 mb-6 px-2">
          {[1,2,3,4,5,6,7,8,9].map(n => (
              <KeypadButton key={n} val={n.toString()} onClick={() => handleKeypad(n.toString())} />
          ))}
          <KeypadButton val="+10" onClick={() => handleKeypad('+10')} secondary />
          <KeypadButton val="0" onClick={() => handleKeypad('0')} />
          <KeypadButton val="DEL" onClick={() => handleKeypad('DEL')} icon={<X size={20} className="text-slate-400"/>} secondary />
      </div>

      <button
          onClick={handleVerify}
          disabled={!amount || recipientInput.length < 20}
          className="w-full py-5 bg-brand-600 text-white rounded-[2rem] font-black text-sm uppercase tracking-[0.2em] shadow-2xl shadow-brand-500/40 active:scale-[0.98] transition-all disabled:opacity-30 disabled:shadow-none flex items-center justify-center gap-3 mb-safe"
        >
          Continuar <ArrowRight size={20} />
      </button>

      {/* --- MODALS --- */}

      {showAccountDrawer && (
          <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-md z-50 flex flex-col justify-end animate-fade-in" onClick={() => setShowAccountDrawer(false)}>
              <div className="bg-white rounded-t-[3rem] p-8 pb-safe animate-slide-up max-h-[70vh] overflow-y-auto relative shadow-2xl" onClick={e => e.stopPropagation()}>
                  <div className="w-12 h-1.5 bg-slate-200 rounded-full mx-auto mb-8"></div>
                  <h3 className="text-2xl font-black text-slate-900 mb-8 px-2 tracking-tight">Elegir Cuenta</h3>
                  <div className="space-y-4">
                      {userAccounts.map((acc, idx) => (
                          <button 
                              key={acc.id}
                              onClick={() => { setSelectedAccountIndex(idx); setShowAccountDrawer(false); }}
                              className={`w-full p-6 rounded-[2.5rem] flex items-center justify-between border-2 transition-all group ${selectedAccountIndex === idx ? 'border-brand-600 bg-brand-50 shadow-lg shadow-brand-500/10' : 'border-slate-50 hover:border-slate-100 hover:bg-slate-50'}`}
                          >
                              <div className="flex items-center gap-5">
                                  <div className={`w-12 h-12 rounded-2xl flex items-center justify-center font-bold text-lg transition-colors ${selectedAccountIndex === idx ? 'bg-brand-600 text-white' : 'bg-slate-100 text-slate-400'}`}>
                                      {acc.alias.charAt(0)}
                                  </div>
                                  <div className="text-left">
                                      <p className="font-black text-slate-900">{acc.alias}</p>
                                      <p className="text-xs font-mono text-slate-400">{acc.iban}</p>
                                  </div>
                              </div>
                              <p className="font-black text-slate-900 text-lg">{acc.balance.toLocaleString()} Pts</p>
                          </button>
                      ))}
                  </div>
              </div>
          </div>
      )}

      {transferStep === 'CONFIRM' && (
           <div className="fixed inset-0 bg-slate-900/80 backdrop-blur-lg z-50 flex items-center justify-center p-6 animate-fade-in">
                <div className="bg-white w-full max-w-sm rounded-[3.5rem] p-10 shadow-2xl animate-pop-in relative">
                    <button onClick={() => setTransferStep('IDLE')} className="absolute top-8 right-8 p-2 bg-slate-50 rounded-full hover:bg-slate-100 transition-colors"><X size={20}/></button>

                    <div className="text-center mb-10">
                        <div className="w-20 h-20 bg-brand-50 text-brand-600 rounded-[2.5rem] flex items-center justify-center mx-auto mb-4 shadow-inner">
                            <Send size={36} />
                        </div>
                        <h3 className="text-2xl font-black text-slate-900 tracking-tight">Confirmar Envío</h3>
                    </div>

                    <div className="bg-slate-50 p-8 rounded-[2.5rem] mb-10 border border-slate-100 shadow-inner">
                        <div className="flex justify-between items-center mb-4">
                            <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Base</span>
                            <span className="font-black text-xl text-slate-900">{numericAmount.toLocaleString()} Pts</span>
                        </div>
                        <div className="flex justify-between items-center pb-4 border-b border-slate-200">
                            <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Tasa ({currentTaxRate}%)</span>
                            <span className="font-bold text-slate-500">{taxAmount.toLocaleString()} Pts</span>
                        </div>
                        <div className="flex justify-between items-center pt-4">
                            <span className="text-[10px] font-black text-brand-600 uppercase tracking-[0.2em]">Total Final</span>
                            <span className="font-black text-3xl text-brand-600 tracking-tighter">{totalAmount.toLocaleString()}</span>
                        </div>
                    </div>

                    <div className="mb-10 px-2 space-y-4">
                        <div className="flex items-center gap-4">
                            <div className="w-10 h-10 bg-slate-100 rounded-xl flex items-center justify-center text-slate-500 font-bold">
                                {detectedBeneficiary?.charAt(0) || 'D'}
                            </div>
                            <div className="flex-1 min-w-0">
                                <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-0.5">Destinatario</p>
                                <p className="font-black text-slate-900 truncate">{detectedBeneficiary || 'Documento Externo'}</p>
                            </div>
                        </div>
                        <div className="bg-slate-100 p-4 rounded-2xl">
                             <p className="font-mono text-xs font-bold text-slate-500 break-all text-center">{fullIbanDisplay}</p>
                        </div>
                    </div>

                    <button onClick={handleConfirm} className="w-full py-5 bg-slate-900 text-white rounded-3xl font-black uppercase text-[10px] tracking-[0.2em] shadow-xl hover:bg-brand-600 transition-all active:scale-95 flex items-center justify-center gap-2">
                        <ShieldCheck size={18}/> Autorizar con PlacetaID
                    </button>
                </div>
           </div>
      )}

      {transferStep === 'PROCESSING' && (
           <div className="fixed inset-0 bg-slate-900/90 backdrop-blur-xl z-[100] flex flex-col items-center justify-center text-center p-8 animate-fade-in">
                <div className="relative mb-8">
                    <div className="w-24 h-24 border-4 border-white/10 border-t-brand-500 rounded-full animate-spin"></div>
                    <div className="absolute inset-0 flex items-center justify-center">
                        <ShieldCheck size={32} className="text-white opacity-50"/>
                    </div>
                </div>
                <h2 className="text-2xl font-black text-white mb-2 uppercase tracking-widest">Validando Ledger</h2>
                <p className="text-slate-400 font-bold text-sm">Sincronizando con el Registro Central...</p>
           </div>
      )}

      {transferStep === 'SUCCESS' && (
           <div className="fixed inset-0 bg-white z-[100] flex flex-col items-center justify-center p-10 animate-fade-in text-center">
               <div className="w-32 h-32 bg-emerald-50 text-emerald-500 rounded-[3rem] flex items-center justify-center mb-10 shadow-2xl shadow-emerald-500/20 animate-pop-in border-4 border-emerald-100">
                   <CheckCircle2 size={72} strokeWidth={2.5} />
               </div>
               <h2 className="text-5xl font-black text-slate-900 mb-4 tracking-tighter">¡Éxito!</h2>
               <p className="text-slate-500 font-bold mb-14 max-w-xs mx-auto leading-relaxed text-lg">
                   Se han enviado <span className="text-emerald-600">{numericAmount.toLocaleString()} Pts</span> al destinatario.
               </p>

               <button onClick={() => { setTransferStep('IDLE'); setAmount(''); setRecipientInput(''); }} className="w-full max-w-xs py-5 bg-slate-900 text-white rounded-[2.5rem] font-black text-[10px] uppercase tracking-[0.3em] shadow-2xl hover:bg-brand-600 transition-all active:scale-95">
                   Cerrar Operación
               </button>
           </div>
      )}
    </div>
  );
};

import React, { useState, useMemo, useEffect } from 'react';
import { useBank } from '../context/BankContext';
import { SECURITY_THRESHOLD_AMOUNT } from '../constants';
import { 
  Send, ChevronDown, X, CheckCircle2, ShieldCheck, User, 
  Search, QrCode, ArrowRight, Wallet, Check, Clipboard, 
  Clock, History, UserPlus, Star, Landmark 
} from 'lucide-react';

interface TransfersProps {
  addNotification: (msg: string, type: 'success' | 'error' | 'info') => void;
}

type TransferStep = 'IDLE' | 'SECURITY' | 'CONFIRM' | 'PROCESSING' | 'SUCCESS';

const KeypadButton: React.FC<{ val: string; onClick: () => void; icon?: React.ReactNode; primary?: boolean; secondary?: boolean }> = ({ val, onClick, icon, primary, secondary }) => (
  <button 
    onClick={(e) => {
        const btn = e.currentTarget;
        btn.classList.add('scale-90', 'bg-slate-200');
        setTimeout(() => btn.classList.remove('scale-90', 'bg-slate-200'), 100);
        onClick();
    }}
    className={`h-14 w-full rounded-2xl transition-all duration-150 text-xl font-bold flex items-center justify-center select-none ${
        primary ? 'bg-brand-600 text-white shadow-lg shadow-brand-500/30 hover:bg-brand-700' : 
        secondary ? 'bg-slate-100 text-slate-500 border border-slate-200 hover:bg-slate-200' :
        'bg-white border border-slate-200 text-slate-900 hover:bg-slate-50 shadow-sm'
    }`}
  >
      {icon ? icon : val}
  </button>
);

export const Transfers: React.FC<TransfersProps> = ({ addNotification }) => {
  const { userAccounts, transfer, taxConfig, contacts, transactions, triggerHaptic } = useBank();

  const [selectedAccountIndex, setSelectedAccountIndex] = useState(0);
  const [showAccountDrawer, setShowAccountDrawer] = useState(false); 

  const [recipientInput, setRecipientInput] = useState(''); 
  const [showSuggestions, setShowSuggestions] = useState(false);
  const [detectedBeneficiary, setDetectedBeneficiary] = useState<string | null>(null);

  const [amount, setAmount] = useState('');
  const [transferStep, setTransferStep] = useState<TransferStep>('IDLE');

  const currentAccount = userAccounts[selectedAccountIndex];
  const currentTaxRate = taxConfig.transferRate;

  // Combinar contactos y destinatarios recientes para sugerencias
  const suggestionsList = useMemo(() => {
      const contactSuggestions = contacts.map(c => ({
          id: `contact-${c.id}`,
          name: c.name,
          iban: c.iban,
          type: 'CONTACT'
      }));

      const recentMap = new Map();
      transactions.forEach(tx => {
          if (tx.senderIban === currentAccount?.iban && tx.receiverIban && !tx.receiverIban.startsWith('PL000000')) {
             if (!contacts.some(c => c.iban === tx.receiverIban)) {
                 if (!recentMap.has(tx.receiverIban)) {
                     recentMap.set(tx.receiverIban, {
                         id: `recent-${tx.id}`,
                         name: tx.receiverIban,
                         iban: tx.receiverIban,
                         type: 'RECENT'
                     });
                 }
             }
          }
      });
      return [...contactSuggestions, ...Array.from(recentMap.values()).slice(0, 5)];
  }, [contacts, transactions, currentAccount]);

  const filteredSuggestions = useMemo(() => {
      if (!recipientInput) return suggestionsList;
      const cleanInput = recipientInput.replace(/\s/g, '').toUpperCase();
      return suggestionsList.filter(s => 
          s.name.toLowerCase().includes(recipientInput.toLowerCase()) || 
          s.iban.includes(cleanInput)
      );
  }, [suggestionsList, recipientInput]);

  useEffect(() => {
      const clean = 'PL' + recipientInput.replace(/\s/g, '').toUpperCase();
      const match = suggestionsList.find(s => s.iban === clean);
      setDetectedBeneficiary(match ? match.name : null);
  }, [recipientInput, suggestionsList]);

  const handleKeypad = (val: string) => {
      triggerHaptic('light');
      if (val === 'DEL') {
          setAmount(prev => prev.slice(0, -1));
      } else if (val === '.') {
          if (!amount.includes('.')) setAmount(prev => prev + '.');
      } else if (val === '+10') {
          setAmount(prev => (Number(prev) + 10).toString());
      } else if (val === '+50') {
          setAmount(prev => (Number(prev) + 50).toString());
      } else {
          if (amount.length < 9) setAmount(prev => prev + val);
      }
  };

  const formatDisplayIban = (val: string) => {
      const clean = val.replace(/[^a-zA-Z0-9]/g, '').toUpperCase();
      const noPrefix = clean.startsWith('PL') ? clean.substring(2) : clean;
      return noPrefix.replace(/(.{4})/g, '$1 ').trim();
  };

  const handleRecipientChange = (e: React.ChangeEvent<HTMLInputElement>) => {
      const formatted = formatDisplayIban(e.target.value);
      if (formatted.length <= 26) {
          setRecipientInput(formatted);
          setShowSuggestions(true);
      }
  };

  const handlePaste = async () => {
      try {
          const text = await navigator.clipboard.readText();
          const formatted = formatDisplayIban(text);
          if (formatted.length <= 26) {
              setRecipientInput(formatted);
              addNotification("IBAN pegado", "info");
          }
      } catch (err) {
          addNotification("Permiso denegado", "error");
      }
  };

  const selectSuggestion = (item: any) => {
      triggerHaptic('medium');
      const raw = item.iban.startsWith('PL') ? item.iban.substring(2) : item.iban;
      setRecipientInput(raw.replace(/(.{4})/g, '$1 ').trim());
      setDetectedBeneficiary(item.name);
      setShowSuggestions(false);
  };

  const handleVerify = () => {
    triggerHaptic('medium');
    const rawIban = recipientInput.replace(/\s/g, '');
    if (rawIban.length !== 20) {
      addNotification("IBAN incompleto", 'error');
      return;
    }

    const numericAmount = Number(amount);
    const taxAmount = numericAmount * (currentTaxRate / 100);
    const totalDeduction = numericAmount + taxAmount;

    if (numericAmount <= 0) {
        addNotification("Importe no válido", 'error');
        return;
    }

    if (totalDeduction > currentAccount.balance) {
      addNotification(`Saldo insuficiente`, 'error');
      return;
    }

    setTransferStep(numericAmount > SECURITY_THRESHOLD_AMOUNT ? 'SECURITY' : 'CONFIRM');
  };

  const handleConfirm = async () => {
    triggerHaptic('heavy');
    setTransferStep('PROCESSING');
    const fullRecipient = 'PL' + recipientInput.replace(/\s/g, '');
    await new Promise(r => setTimeout(r, 1200)); 
    try {
        await transfer(currentAccount.iban, fullRecipient, Number(amount), 'Transferencia Inmediata SIDS');
        setTransferStep('SUCCESS');
    } catch (e: any) {
        addNotification(e.message || "Error en el Ledger", 'error');
        setTransferStep('IDLE');
    }
  };

  if (!currentAccount) return null;

  const numericAmount = Number(amount) || 0;
  const taxAmount = numericAmount * (currentTaxRate / 100);
  const totalAmount = numericAmount + taxAmount;
  const fullIbanDisplay = 'PL' + recipientInput.replace(/\s/g, '');

  return (
    <div className="pb-safe-nav h-full flex flex-col max-w-lg mx-auto relative animate-fade-in pt-safe px-4 min-h-screen font-sans">

      <div className="flex justify-between items-center mb-6 pt-4">
            <h2 className="text-3xl font-black text-slate-900 tracking-tight">Enviar Fondos</h2>
            <div className="bg-white/80 backdrop-blur shadow-sm border border-slate-100 px-4 py-2 rounded-2xl flex items-center gap-2">
                <div className="w-2 h-2 bg-emerald-500 rounded-full animate-pulse"></div>
                <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Canal Seguro</span>
            </div>
      </div>

      {/* Account Selector Card */}
      <div className="relative mb-6">
             <button 
                className="w-full p-6 bg-slate-900 text-white rounded-[2.5rem] flex flex-col justify-between shadow-2xl active:scale-[0.98] transition-all relative overflow-hidden h-40"
                onClick={() => setShowAccountDrawer(true)}
             >
                <div className="absolute top-0 right-0 w-48 h-48 bg-brand-500/10 rounded-full blur-3xl -mr-16 -mt-16 pointer-events-none"></div>

                <div className="flex justify-between items-start w-full relative z-10">
                    <div className="flex items-center gap-4">
                        <div className="w-12 h-12 bg-white/10 rounded-2xl flex items-center justify-center backdrop-blur-md border border-white/10">
                            {currentAccount.type === 'BUSINESS' ? <Landmark size={24}/> : <User size={24}/>}
                        </div>
                        <div className="text-left">
                            <p className="text-[10px] text-slate-400 font-bold uppercase tracking-[0.2em]">Origen</p>
                            <p className="font-bold text-lg leading-tight">{currentAccount.alias}</p>
                        </div>
                    </div>
                    <div className="bg-white/10 px-3 py-1.5 rounded-xl text-[9px] font-black uppercase tracking-widest flex items-center gap-1 hover:bg-white/20 transition-colors">
                        Cambiar <ChevronDown size={12}/>
                    </div>
                </div>

                <div className="relative z-10 text-left">
                    <p className="text-[10px] font-mono text-slate-500 mb-1">{currentAccount.iban.slice(0, 4)} •••• {currentAccount.iban.slice(-4)}</p>
                    <p className="text-3xl font-black tracking-tight">{currentAccount.balance.toLocaleString()} <span className="text-lg opacity-40">Pts</span></p>
                </div>
            </button>
      </div>

      {/* Quick Contacts Bar */}
      <div className="mb-6 px-1">
          <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest mb-4 ml-1">Sugeridos</p>
          <div className="flex gap-4 overflow-x-auto no-scrollbar pb-1">
              <button className="flex flex-col items-center gap-2 shrink-0 group">
                  <div className="w-14 h-14 rounded-2xl bg-slate-100 border-2 border-dashed border-slate-300 flex items-center justify-center text-slate-400 group-hover:border-brand-500 group-hover:text-brand-500 transition-all">
                      <UserPlus size={20}/>
                  </div>
                  <span className="text-[9px] font-bold text-slate-500">Nuevo</span>
              </button>
              {suggestionsList.map((s: any) => (
                  <button key={s.id} onClick={() => selectSuggestion(s)} className="flex flex-col items-center gap-2 shrink-0 group">
                      <div className={`w-14 h-14 rounded-2xl flex items-center justify-center text-lg font-bold transition-all group-hover:scale-105 shadow-sm ${s.type === 'CONTACT' ? 'bg-brand-50 text-brand-600' : 'bg-slate-50 text-slate-500'}`}>
                          {s.name.charAt(0)}
                      </div>
                      <span className="text-[9px] font-bold text-slate-600 truncate w-14 text-center">{s.name.split(' ')[0]}</span>
                  </button>
              ))}
          </div>
      </div>

      {/* Recipient Input Area */}
      <div className="relative mb-6 z-30">
          <div className="flex justify-between items-center mb-2 px-2">
              <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Destinatario</label>
              {detectedBeneficiary && (
                  <div className="flex items-center gap-1.5 px-3 py-1 bg-emerald-50 rounded-full animate-fade-in border border-emerald-100">
                      <CheckCircle2 size={12} className="text-emerald-600"/>
                      <span className="text-[10px] font-black text-emerald-700 uppercase">{detectedBeneficiary}</span>
                  </div>
              )}
          </div>

          <div className={`bg-white p-2 rounded-3xl border-2 flex items-center shadow-soft transition-all relative ${showSuggestions ? 'border-brand-500 ring-4 ring-brand-500/10' : 'border-slate-100 hover:border-slate-200'}`}>
              <div className="bg-slate-50 w-12 h-12 rounded-2xl flex items-center justify-center text-slate-400 font-black text-xs select-none shrink-0 border border-slate-100">PL</div>
              <input 
                  type="text" 
                  value={recipientInput}
                  onChange={handleRecipientChange}
                  onFocus={() => setShowSuggestions(true)}
                  onBlur={() => setTimeout(() => setShowSuggestions(false), 200)}
                  className="flex-1 bg-transparent px-3 font-mono text-lg font-bold outline-none text-slate-900 placeholder:text-slate-200 tracking-wider min-w-0"
                  placeholder="0000 0000..."
                  autoComplete="off"
              />

              {recipientInput ? (
                  <button onClick={() => {setRecipientInput(''); setDetectedBeneficiary(null);}} className="p-3 text-slate-300 hover:text-slate-500 transition-colors">
                      <X size={20}/>
                  </button>
              ) : (
                  <div className="flex gap-1 pr-1">
                      <button onClick={handlePaste} className="p-3 text-brand-600 bg-brand-50 rounded-2xl hover:bg-brand-100 transition-colors">
                          <Clipboard size={20}/>
                      </button>
                      <button className="p-3 text-slate-400 bg-slate-50 rounded-2xl hover:bg-slate-100 transition-colors">
                          <QrCode size={20}/>
                      </button>
                  </div>
              )}
          </div>

          {showSuggestions && (
              <div className="absolute top-full left-0 right-0 mt-3 bg-white rounded-[2rem] shadow-2xl border border-slate-100 overflow-hidden animate-slide-up z-50 p-2 max-h-64 overflow-y-auto">
                  {filteredSuggestions.length > 0 ? (
                        filteredSuggestions.map((s: any) => (
                            <button key={s.id} onClick={() => selectSuggestion(s)} className="w-full p-4 flex items-center gap-4 hover:bg-slate-50 rounded-2xl transition-all group border border-transparent hover:border-slate-100">
                                <div className={`w-11 h-11 rounded-xl flex items-center justify-center font-bold text-sm transition-colors ${s.type === 'CONTACT' ? 'bg-brand-50 text-brand-600 group-hover:bg-brand-600 group-hover:text-white' : 'bg-slate-100 text-slate-500'}`}>
                                    {s.type === 'CONTACT' ? <Star size={18} fill="currentColor"/> : <Clock size={18}/>}
                                </div>
                                <div className="text-left flex-1 min-w-0">
                                    <p className="font-black text-slate-900 text-sm truncate">{s.name}</p>
                                    <p className="text-[10px] text-slate-400 font-mono truncate">{s.iban}</p>
                                </div>
                                <ArrowRight size={14} className="text-slate-300 group-hover:text-slate-900 group-hover:translate-x-1 transition-all"/>
                            </button>
                        ))
                  ) : (
                      <div className="p-8 text-center text-slate-400 text-xs font-bold">
                          Sin coincidencias en el Nodo
                      </div>
                  )}
              </div>
          )}
      </div>

      {/* Amount Display */}
      <div className="flex-1 flex flex-col items-center justify-center py-4">
            <div className="flex flex-col items-center">
                 <p className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] mb-4">Monto de la Operación</p>
                 <div className="flex items-baseline gap-2 group cursor-default">
                    <span className={`text-7xl font-black tracking-tighter transition-colors ${amount ? 'text-slate-900' : 'text-slate-100'}`}>
                        {amount || '0'}
                    </span>
                    <span className="text-2xl text-slate-400 font-black">Pts</span>
                 </div>
                 {numericAmount > 0 && (
                    <div className="flex items-center gap-2 mt-6 px-5 py-2 bg-slate-100 rounded-full border border-slate-200 animate-fade-in shadow-inner">
                        <span className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Total (+{currentTaxRate}%):</span>
                        <span className="text-xs font-black text-brand-600">{totalAmount.toLocaleString()} Pts</span>
                    </div>
                 )}
            </div>
      </div>

      {/* Keypad */}
      <div className="grid grid-cols-3 gap-3 mb-6 px-2">
          {[1,2,3,4,5,6,7,8,9].map(n => (
              <KeypadButton key={n} val={n.toString()} onClick={() => handleKeypad(n.toString())} />
          ))}
          <KeypadButton val="+10" onClick={() => handleKeypad('+10')} secondary />
          <KeypadButton val="0" onClick={() => handleKeypad('0')} />
          <KeypadButton val="DEL" onClick={() => handleKeypad('DEL')} icon={<X size={20} className="text-slate-400"/>} secondary />
      </div>

      <button
          onClick={handleVerify}
          disabled={!amount || recipientInput.length < 20}
          className="w-full py-5 bg-brand-600 text-white rounded-[2rem] font-black text-sm uppercase tracking-[0.2em] shadow-2xl shadow-brand-500/40 active:scale-[0.98] transition-all disabled:opacity-30 flex items-center justify-center gap-3 mb-safe"
        >
          Confirmar Envío <ArrowRight size={20} />
      </button>

      {/* --- MODALS --- */}

      {showAccountDrawer && (
          <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-md z-50 flex flex-col justify-end animate-fade-in" onClick={() => setShowAccountDrawer(false)}>
              <div className="bg-white rounded-t-[3rem] p-8 pb-safe animate-slide-up max-h-[70vh] overflow-y-auto relative shadow-2xl" onClick={e => e.stopPropagation()}>
                  <div className="w-12 h-1.5 bg-slate-200 rounded-full mx-auto mb-8"></div>
                  <h3 className="text-2xl font-black text-slate-900 mb-8 px-2 tracking-tight">Elegir Cuenta Origen</h3>
                  <div className="space-y-4">
                      {userAccounts.map((acc, idx) => (
                          <button 
                              key={acc.id}
                              onClick={() => { setSelectedAccountIndex(idx); setShowAccountDrawer(false); }}
                              className={`w-full p-6 rounded-[2.5rem] flex items-center justify-between border-2 transition-all group ${selectedAccountIndex === idx ? 'border-brand-600 bg-brand-50 shadow-lg' : 'border-slate-50 hover:border-slate-100 hover:bg-slate-50'}`}
                          >
                              <div className="flex items-center gap-5">
                                  <div className={`w-12 h-12 rounded-2xl flex items-center justify-center font-bold text-lg transition-colors ${selectedAccountIndex === idx ? 'bg-brand-600 text-white' : 'bg-slate-100 text-slate-400'}`}>
                                      {acc.alias.charAt(0)}
                                  </div>
                                  <div className="text-left">
                                      <p className="font-black text-slate-900">{acc.alias}</p>
                                      <p className="text-xs font-mono text-slate-400">{acc.iban.slice(0, 10)}...</p>
                                  </div>
                              </div>
                              <p className="font-black text-slate-900 text-lg">{acc.balance.toLocaleString()} Pts</p>
                          </button>
                      ))}
                  </div>
              </div>
          </div>
      )}

      {transferStep === 'CONFIRM' && (
