      if (SDK && container) {
        // Limpiamos el contenido manual del contenedor "sacrifical" 
        // para evitar el error de removeChild de React al desmontar
        container.innerHTML = ''; 
        const innerDiv = document.createElement('div');
        innerDiv.id = 'placeta-id-mount-point';
        container.appendChild(innerDiv);

        try {
          new SDK({
            containerId: 'placeta-id-mount-point',
            apiUrl: 'https://junta.vercel.app/api/placetaid',
            theme: 'dark',
            onSuccess: (userData: any) => handlePlacetaLogin(userData)
