        attempts++;
        setTimeout(initPlacetaID, 300);
      }
    };

    if (!showLegacy) {
      initPlacetaID();
    }

    // Limpieza robusta para prevenir errores de nodos fantasmas
    return () => {
        if (sdkContainerRef.current) {
            sdkContainerRef.current.innerHTML = '';
        }
    };
  }, [showLegacy]);

  const handlePlacetaLogin = async (userData: any) => {
    setIsLoading(true);
    setErrorMessage(null);
    try {
        const result = await loginWithPlacetaID(userData);
        if (result.success) {
          onLogin();
        } else {
          setErrorMessage(result.error || 'Identidad no verificada.');
        }
    } catch (e) {
        setErrorMessage("Error de conexión con el Nodo Central.");
    } finally {
        setIsLoading(false);
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setErrorMessage(null);
    if (!dip || !password) return;
    setIsLoading(true);
    try {
        const result = await login(dip, password);
        if (result.success) {
            onLogin();
        } else {
            setErrorMessage(result.error || 'Credenciales no válidas.');
