const AppContent: React.FC = () => {
  const { currentUser, notifications, logout, addNotification, fetchData, updateSelfBirthDate } = useBank();
  const [currentView, setView] = useState('dashboard');
  const [showLogin, setShowLogin] = useState(false);
  const [showATM, setShowATM] = useState(false);
  const [isBusinessView, setIsBusinessView] = useState(false);
  const [birthDateInput, setBirthDateInput] = useState('');

  const isEntityAccount = currentUser?.role === 'COMPANY';

  useEffect(() => {
    if (isEntityAccount) {
      setIsBusinessView(true);
    }
  }, [currentUser, isEntityAccount]);

  useEffect(() => {
    if (currentUser?.id) {
        fetchData(currentUser.id);
    }
  }, [currentUser, fetchData]);


  if (!currentUser) {
    if (showATM) return <ATM onExit={() => setShowATM(false)} />;
    if (showLogin) return <Login onLogin={() => setView('dashboard')} onBack={() => setShowLogin(false)} onATMEnter={() => setShowATM(true)} />;
    return <Landing onEnter={() => setShowLogin(true)} />;
  }

  // PANTALLA DE BLOQUEO: VALIDACIÓN DE IDENTIDAD SIDS
  if (!currentUser.birthDate) {
      return (
          <div className="min-h-screen bg-[#020617] flex items-center justify-center p-6 font-sans">
              <div className="max-w-md w-full bg-slate-900 border border-white/10 rounded-[2.5rem] p-10 shadow-2xl text-center animate-pop-in">
                  <div className="w-20 h-20 bg-brand-500/20 text-brand-400 rounded-3xl flex items-center justify-center mx-auto mb-8">
                      <ShieldAlert size={40} />
                  </div>
                  <h2 className="text-3xl font-black text-white mb-4 tracking-tight">Validación SIDS</h2>
                  <p className="text-slate-400 font-medium mb-8 leading-relaxed">
                      Debe completar su perfil de identidad digital. Introduzca su fecha de nacimiento para habilitar las funciones bancarias según el Capítulo 1.
                  </p>

                  <div className="space-y-6">
                      <div className="text-left">
                          <label className="text-[10px] font-black text-brand-300 uppercase tracking-widest ml-1 mb-2 block">Fecha de Nacimiento</label>
                          <div className="relative">
                              <Calendar className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-500" size={20}/>
                              <input 
                                  type="date" 
                                  value={birthDateInput}
                                  onChange={(e) => setBirthDateInput(e.target.value)}
                                  className="w-full pl-12 pr-6 py-4 bg-slate-800 border border-white/5 rounded-2xl text-white font-bold outline-none focus:border-brand-500 transition-all"
                              />
                          </div>
                      </div>
                      <button 
                        onClick={() => birthDateInput && updateSelfBirthDate(birthDateInput)}
                        disabled={!birthDateInput}
                        className="w-full py-5 bg-white text-slate-950 rounded-2xl font-black uppercase text-xs tracking-widest hover:bg-brand-500 hover:text-white transition-all shadow-xl flex items-center justify-center gap-3 disabled:opacity-30 active:scale-95"
                      >
                          Finalizar Identificación <ArrowRight size={18}/>
                      </button>
                      <button onClick={logout} className="text-slate-600 font-bold text-xs uppercase tracking-widest hover:text-white transition-colors">Salir del Sistema</button>
                  </div>
              </div>
          </div>
      );
  }

  if (isBusinessView) {
      return <BusinessDashboard onSwitchView={() => !isEntityAccount && setIsBusinessView(false)} />;
  }

  const renderView = () => {
    switch (currentView) {
      case 'dashboard': return <Dashboard onNavigate={setView} onSwitchToBusiness={() => setIsBusinessView(true)} />;
      case 'accounts': return <Accounts addNotification={addNotification} />;
      case 'transfers': return <Transfers addNotification={addNotification} />;
      case 'payments': return <Payments addNotification={addNotification} />;
      case 'investments': return <Investments addNotification={addNotification} />;
      case 'taxes': return <Taxes />;
      case 'sede': return <SedeElectronica />;
      case 'family': return <Family />;
      case 'lottery': return <Lottery addNotification={addNotification} />;
      case 'market': return <Market />;
      case 'admin': return <Admin />;
      default: return <Dashboard onNavigate={setView} onSwitchToBusiness={() => setIsBusinessView(true)} />;
    }
  };

  return (
    <div className="min-h-screen bg-slate-50 flex w-full">
      <Sidebar currentView={currentView} setView={setView} onLogout={logout} />
      <MobileNavbar currentView={currentView} setView={setView} />

      <main className="flex-1 md:ml-72 w-full min-h-screen transition-all duration-300">
         {renderView()}
      </main>

      <div className="fixed top-4 right-4 z-[200] flex flex-col gap-3 pointer-events-none">
        {notifications.map(n => (
          <div key={n.id} className={`pointer-events-auto min-w-[320px] p-4 rounded-2xl shadow-2xl text-white font-bold flex justify-between items-center animate-slide-up backdrop-blur-md ${
            n.type === 'success' ? 'bg-green-500/90' : 
            n.type === 'error' ? 'bg-red-500/90' : 
            'bg-slate-800/90'
          }`}>
            <span className="text-sm">{n.message}</span>
            <X size={18} className="cursor-pointer opacity-80 hover:opacity-100" onClick={() => {}} />
          </div>
        ))}
      </div>
    </div>
  );
};

