import { BusinessDashboard } from './pages/BusinessDashboard';
import { Admin } from './pages/Admin';
import { Accounts } from './pages/Accounts';
import { Transfers } from './pages/Transfers';
import { Payments } from './pages/Payments';
import { Investments } from './pages/Investments';
import { Taxes } from './pages/Taxes';
import { SedeElectronica } from './pages/Sede';
import { Family } from './pages/Family';
import { Lottery } from './pages/Lottery';
import { Market } from './pages/Market';
import { ATM } from './pages/ATM';
import { useBank } from './context/BankContext';
import { X, ShieldAlert, Calendar, ArrowRight, Lock } from 'lucide-react';

const AppContent: React.FC = () => {
  const { currentUser, notifications, logout, addNotification, fetchData, updateSelfBirthDate } = useBank();
  const [currentView, setView] = useState('dashboard');
  const [showLogin, setShowLogin] = useState(false);
  const [showATM, setShowATM] = useState(false);
  const [isBusinessView, setIsBusinessView] = useState(false);
  const [birthDateInput, setBirthDateInput] = useState('');

  const isEntityAccount = currentUser?.role === 'COMPANY';

  useEffect(() => {
    if (isEntityAccount) {
      setIsBusinessView(true);
    }
  }, [currentUser, isEntityAccount]);

  useEffect(() => {
    if (currentUser?.id) {
        fetchData(currentUser.id).catch(console.error);
    }
  }, [currentUser?.id, fetchData]);


  if (!currentUser) {
    if (showATM) return <ATM onExit={() => setShowATM(false)} />;
    if (showLogin) return <Login onLogin={() => setView('dashboard')} onBack={() => setShowLogin(false)} onATMEnter={() => setShowATM(true)} />;
    return <Landing onEnter={() => setShowLogin(true)} />;
  }

  // PANTALLA DE BLOQUEO: VALIDACIÓN DE IDENTIDAD SIDS (RESPONSIVE)
  if (!currentUser.birthDate) {
      return (
          <div className="min-h-screen bg-[#020617] flex items-center justify-center p-4 font-sans relative overflow-hidden">
              <div className="absolute inset-0 bg-gradient-to-br from-brand-900/20 to-indigo-900/20 pointer-events-none"></div>
              <div className="max-w-md w-full bg-slate-900/80 backdrop-blur-2xl border border-white/10 rounded-[3rem] p-8 md:p-12 shadow-2xl text-center animate-pop-in relative z-10">
                  <div className="w-20 h-20 bg-brand-500/20 text-brand-400 rounded-[2rem] flex items-center justify-center mx-auto mb-8 shadow-glow">
                      <ShieldAlert size={40} />
                  </div>
                  <h2 className="text-3xl font-black text-white mb-4 tracking-tight leading-none">Validación SIDS</h2>
                  <p className="text-slate-400 font-medium mb-10 leading-relaxed text-sm">
                      Capítulo 1, Art. 3.2: La fecha de nacimiento es requerida para habilitar la custodia de activos digitales en el Nodo Central.
                  </p>

                  <div className="space-y-6">
                      <div className="text-left">
                          <label className="text-[10px] font-black text-brand-300 uppercase tracking-[0.2em] ml-2 mb-3 block">Fecha de Nacimiento</label>
                          <div className="relative group">
                              <Calendar className="absolute left-5 top-1/2 -translate-y-1/2 text-slate-500 group-focus-within:text-brand-400 transition-colors" size={20}/>
                              <input 
                                  type="date" 
                                  value={birthDateInput}
                                  onChange={(e) => setBirthDateInput(e.target.value)}
                                  className="w-full pl-14 pr-6 py-5 bg-slate-800/50 border border-white/5 rounded-2xl text-white font-bold outline-none focus:border-brand-500 focus:ring-4 focus:ring-brand-500/10 transition-all text-lg"
                              />
                          </div>
                      </div>
                      <button 
                        onClick={() => birthDateInput && updateSelfBirthDate(birthDateInput)}
                        disabled={!birthDateInput}
                        className="w-full py-5 bg-white text-slate-950 rounded-2xl font-black uppercase text-xs tracking-widest hover:bg-brand-500 hover:text-white transition-all shadow-xl flex items-center justify-center gap-3 disabled:opacity-20 active:scale-95 group"
                      >
                          Completar Identificación <ArrowRight size={18} className="group-hover:translate-x-1 transition-transform"/>
                      </button>
                      <button onClick={logout} className="text-slate-500 font-black text-[10px] uppercase tracking-[0.2em] hover:text-white transition-colors pt-4">Cancelar y Salir</button>
                  </div>
              </div>
          </div>
      );
  }

  if (isBusinessView) {
      return <BusinessDashboard onSwitchView={() => !isEntityAccount && setIsBusinessView(false)} />;
  }

  const renderView = () => {
    switch (currentView) {
      case 'dashboard': return <Dashboard onNavigate={setView} onSwitchToBusiness={() => setIsBusinessView(true)} />;
      case 'accounts': return <Accounts addNotification={addNotification} />;
      case 'transfers': return <Transfers addNotification={addNotification} />;
      case 'payments': return <Payments addNotification={addNotification} />;
      case 'investments': return <Investments addNotification={addNotification} />;
      case 'taxes': return <Taxes />;
      case 'sede': return <SedeElectronica />;
      case 'family': return <Family />;
      case 'lottery': return <Lottery addNotification={addNotification} />;
      case 'market': return <Market />;
      case 'admin': return <Admin />;
      default: return <Dashboard onNavigate={setView} onSwitchToBusiness={() => setIsBusinessView(true)} />;
    }
  };

  return (
    <div className="min-h-screen bg-slate-50 flex w-full overflow-hidden">
      <Sidebar currentView={currentView} setView={setView} onLogout={logout} />
      <MobileNavbar currentView={currentView} setView={setView} />

      <main className="flex-1 md:ml-72 w-full min-h-screen transition-all duration-300 relative overflow-y-auto overflow-x-hidden">
         {renderView()}
      </main>

      <div className="fixed top-4 right-4 z-[300] flex flex-col gap-3 pointer-events-none w-[calc(100%-2rem)] md:w-auto">
        {notifications.map(n => (
          <div key={n.id} className={`pointer-events-auto w-full md:min-w-[320px] p-5 rounded-2xl shadow-2xl text-white font-bold flex justify-between items-center animate-slide-up backdrop-blur-md border border-white/10 ${
            n.type === 'success' ? 'bg-emerald-600/90' : 
            n.type === 'error' ? 'bg-rose-600/90' : 
            'bg-slate-900/90'
          }`}>
            <span className="text-sm tracking-tight">{n.message}</span>
            <X size={18} className="cursor-pointer opacity-60 hover:opacity-100" onClick={() => {}} />
          </div>
        ))}
      </div>
    </div>
  );
};

export default () => <AppContent />;

import React, { useMemo, useState } from 'react';
import { useBank } from '../context/BankContext';
import { 
  Wallet, ArrowRightLeft, TrendingUp, Bell, 
  Building2, ArrowUpRight, ArrowDownLeft, ShieldCheck, 
  CreditCard, Zap, Plus, User, X, ChevronRight,
  QrCode, Ticket, ShoppingBag, Send
} from 'lucide-react';
import { AreaChart, Area, ResponsiveContainer, Tooltip } from 'recharts';

interface DashboardProps { onNavigate: (view: string) => void; onSwitchToBusiness?: () => void; }

export const Dashboard: React.FC<DashboardProps> = ({ onNavigate, onSwitchToBusiness }) => {
  const { currentUser, userAccounts, transactions, companies, contacts, transfer, triggerHaptic, addNotification } = useBank();
  const [showBalance, setShowBalance] = useState(true);
  const [showPlaceZum, setShowPlaceZum] = useState(false);
  const [placeZumAmount, setPlaceZumAmount] = useState('');
  const [selectedContact, setSelectedContact] = useState<any>(null);
  const [customIban, setCustomIban] = useState('');

  if (!currentUser) return null;

  const totalBalance = userAccounts?.reduce((acc, curr) => acc + parseFloat(curr.balance.toString()), 0) || 0;
  const mainAccount = userAccounts?.[0];

  const frequentContacts = useMemo(() => {
      const freqMap = new Map();
      if (!transactions || !mainAccount) return [];
      transactions.forEach(tx => {
          if (tx.senderIban === mainAccount.iban && tx.receiverIban) {
              const contact = contacts?.find(c => c.iban === tx.receiverIban);
              const name = contact ? contact.name : tx.receiverIban;
              const id = tx.receiverIban;
              if (!freqMap.has(id)) {
                  freqMap.set(id, { id, name, iban: tx.receiverIban, count: 1 });
              } else {
                  freqMap.get(id).count++;
              }
          }
      });
      return Array.from(freqMap.values()).sort((a, b) => b.count - a.count).slice(0, 5);
  }, [transactions, mainAccount, contacts]);

  const handleNav = (view: string) => {
      triggerHaptic('light');
      onNavigate(view);
  }

  const handlePlaceZumSend = async () => {
      if (!mainAccount) return;
      const targetIban = selectedContact ? selectedContact.iban : (customIban.startsWith('PL') ? customIban : 'PL' + customIban);
      const amount = Number(placeZumAmount);

      if (!targetIban || amount <= 0) {
          addNotification("Datos incompletos", "error");
          return;
      }
      if (mainAccount.balance < amount) {
          addNotification("Saldo insuficiente", "error");
          return;
      }

      setShowPlaceZum(false);
      triggerHaptic('heavy');

      try {
          await transfer(mainAccount.iban, targetIban, amount, "PlaceZum Instantáneo", "PLACEZUM");
          setPlaceZumAmount('');
          setSelectedContact(null);
          setCustomIban('');
      } catch (e: any) {
          addNotification(e.message, "error");
      }
  };

  const getGreeting = () => {
      const hour = new Date().getHours();
      if (hour < 12) return 'Buenos días';
      if (hour < 20) return 'Buenas tardes';
      return 'Buenas noches';
  };

  return (
    <div className="pb-40 w-full max-w-7xl mx-auto px-4 md:px-8 pt-safe font-sans animate-fade-in overflow-x-hidden">

      {/* Top Bar */}
      <header className="flex justify-between items-center mb-8 pt-4">
        <div className="flex items-center gap-4">
            <div className="relative">
                <div className="w-12 h-12 rounded-full bg-slate-900 text-white flex items-center justify-center font-bold text-lg shadow-lg border-2 border-slate-800 shrink-0 overflow-hidden">
                    {currentUser.avatarUrl ? <img src={currentUser.avatarUrl} className="w-full h-full object-cover" alt="Avatar"/> : currentUser.name.charAt(0)}
                </div>
                <div className="absolute -bottom-1 -right-1 w-5 h-5 bg-emerald-500 border-4 border-slate-50 rounded-full"></div>
            </div>
            <div className="min-w-0">
                <p className="text-slate-400 text-[10px] font-black uppercase tracking-widest">{getGreeting()}</p>
                <h1 className="text-xl md:text-2xl font-black text-slate-900 leading-none tracking-tight truncate">{currentUser.name.split(' ')[0]}</h1>
            </div>
        </div>
        <div className="flex gap-2">
            {companies?.some(c => c.ownerId === currentUser.id) && (
                <button onClick={() => { triggerHaptic('medium'); onSwitchToBusiness?.(); }} className="p-3 bg-indigo-50 text-indigo-600 rounded-2xl hover:bg-indigo-600 hover:text-white transition-all shadow-sm active:scale-95">
                    <Building2 size={20}/>
                </button>
            )}
            <button className="p-3 bg-white border border-slate-200 rounded-2xl text-slate-400 hover:text-slate-900 transition-all shadow-sm active:scale-95 relative">
                <Bell size={20} />
                <span className="absolute top-3 right-3 w-2 h-2 bg-red-500 rounded-full"></span>
            </button>
        </div>
      </header>

      {/* Main Grid */}
      <div className="grid grid-cols-1 lg:grid-cols-12 gap-6">

          {/* Left Column: Balance & PlaceZum */}
          <div className="lg:col-span-8 flex flex-col gap-6">

              {/* Balance Card "Holographic" */}
              <div className="relative overflow-hidden rounded-[2.5rem] bg-slate-900 text-white p-8 shadow-2xl shadow-brand-900/20 group min-h-[220px] flex flex-col justify-center">
                  <div className="absolute top-0 right-0 w-[400px] h-[400px] bg-brand-600/30 rounded-full blur-[120px] -mr-20 -mt-40 group-hover:bg-brand-500/40 transition-colors duration-700"></div>
                  <div className="absolute bottom-0 left-0 w-[300px] h-[300px] bg-indigo-600/20 rounded-full blur-[100px] -ml-20 -mb-20"></div>

                  <div className="relative z-10">
                      <div className="flex justify-between items-start mb-6">
                          <div>
                              <p className="text-brand-200 font-bold text-[10px] uppercase tracking-[0.2em] mb-3 flex items-center gap-2">
                                  <Wallet size={12}/> Patrimonio Total
                              </p>
                              <div onClick={() => setShowBalance(!showBalance)} className="cursor-pointer active:scale-95 transition-transform">
                                <h2 className={`font-black tracking-tighter transition-all ${showBalance ? (totalBalance > 1000000 ? 'text-4xl md:text-6xl' : 'text-5xl md:text-7xl') : 'text-5xl'}`}>
                                    {showBalance ? totalBalance.toLocaleString('es-ES') : '••••••'} <span className="text-xl md:text-2xl text-slate-500 font-bold">Pts</span>
                                </h2>
                              </div>
                          </div>
                          <div className="flex flex-col gap-2">
                              <button className="w-10 h-10 bg-white/10 backdrop-blur-md rounded-xl flex items-center justify-center hover:bg-white/20 transition-all active:scale-95">
                                  <QrCode size={18}/>
                              </button>
                          </div>
                      </div>

                      <div className="flex gap-3 overflow-x-auto no-scrollbar">
                          <div className="bg-white/5 border border-white/10 backdrop-blur-sm px-4 py-2.5 rounded-2xl flex items-center gap-3 shrink-0">
                              <div className="w-7 h-7 rounded-full bg-emerald-500/20 flex items-center justify-center text-emerald-400"><ArrowDownLeft size={14}/></div>
                              <div>
                                  <p className="text-[8px] text-slate-500 uppercase font-black tracking-widest">Ingresos</p>
                                  <p className="text-xs font-bold text-white">+12.4%</p>
                              </div>
                          </div>
                          <div className="bg-white/5 border border-white/10 backdrop-blur-sm px-4 py-2.5 rounded-2xl flex items-center gap-3 shrink-0">
                              <div className="w-7 h-7 rounded-full bg-red-500/20 flex items-center justify-center text-red-400"><ArrowUpRight size={14}/></div>
                              <div>
                                  <p className="text-[8px] text-slate-500 uppercase font-black tracking-widest">Gastos</p>
                                  <p className="text-xs font-bold text-white">-4.2%</p>
                              </div>
                          </div>
                      </div>
                  </div>
              </div>

              {/* PlaceZum Widget */}
              <div className="bg-gradient-to-br from-brand-600 to-indigo-700 rounded-[2.5rem] p-1 shadow-lg overflow-hidden relative">
                  <div className="bg-white rounded-[2.3rem] p-6">
                      <div className="flex justify-between items-center mb-6">
                          <div className="flex items-center gap-2">
                              <div className="w-8 h-8 bg-brand-100 text-brand-600 rounded-full flex items-center justify-center">
                                  <Zap size={16} fill="currentColor"/>
                              </div>
                              <h3 className="font-black text-slate-900 text-base uppercase tracking-tight">PlaceZum</h3>
                          </div>
                          <button onClick={() => { setSelectedContact(null); setShowPlaceZum(true); }} className="text-[10px] font-black uppercase tracking-widest text-brand-600 hover:bg-brand-50 px-3 py-1.5 rounded-xl transition-colors border border-brand-100">
                              Nuevo Envío
                          </button>
                      </div>

                      <div className="flex gap-5 overflow-x-auto no-scrollbar pb-2">
                          <button onClick={() => { setSelectedContact(null); setShowPlaceZum(true); }} className="flex flex-col items-center gap-3 min-w-[64px] group">
                              <div className="w-14 h-14 rounded-2xl bg-slate-50 border-2 border-dashed border-slate-200 flex items-center justify-center text-slate-300 group-hover:border-brand-500 group-hover:text-brand-500 transition-all">
                                  <Plus size={24}/>
                              </div>
                              <span className="text-[9px] font-black text-slate-400 uppercase">Añadir</span>
                          </button>

                          {frequentContacts.map((contact, i) => (
                              <button key={i} onClick={() => { setSelectedContact(contact); setShowPlaceZum(true); }} className="flex flex-col items-center gap-3 min-w-[64px] group">
                                  <div className="w-14 h-14 rounded-2xl bg-slate-900 border-2 border-white shadow-lg flex items-center justify-center text-white font-black text-xl group-hover:scale-110 transition-all relative overflow-hidden">
                                      {contact.name.charAt(0)}
                                  </div>
                                  <span className="text-[10px] font-bold text-slate-600 truncate w-full text-center">{contact.name.split(' ')[0]}</span>
                              </button>
                          ))}
                      </div>
                  </div>
              </div>

              {/* Functional Shortcuts */}
              <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                  <button onClick={() => handleNav('transfers')} className="bg-white p-5 rounded-[2rem] shadow-soft border border-slate-100 flex flex-col items-center gap-3 hover:border-brand-200 hover:-translate-y-1 transition-all group">
                      <div className="w-12 h-12 bg-blue-50 text-blue-600 rounded-2xl flex items-center justify-center group-hover:bg-blue-600 group-hover:text-white transition-colors shadow-sm"><ArrowRightLeft size={20}/></div>
                      <span className="text-[10px] font-black uppercase tracking-widest text-slate-500">Girar</span>
                  </button>
                  <button onClick={() => handleNav('payments')} className="bg-white p-5 rounded-[2rem] shadow-soft border border-slate-100 flex flex-col items-center gap-3 hover:border-brand-200 hover:-translate-y-1 transition-all group">
                      <div className="w-12 h-12 bg-orange-50 text-orange-600 rounded-2xl flex items-center justify-center group-hover:bg-orange-600 group-hover:text-white transition-colors shadow-sm"><CreditCard size={20}/></div>
                      <span className="text-[10px] font-black uppercase tracking-widest text-slate-500">Pagar</span>
                  </button>
                  <button onClick={() => handleNav('sede')} className="bg-white p-5 rounded-[2rem] shadow-soft border border-slate-100 flex flex-col items-center gap-3 hover:border-brand-200 hover:-translate-y-1 transition-all group">
                      <div className="w-12 h-12 bg-emerald-50 text-emerald-600 rounded-2xl flex items-center justify-center group-hover:bg-emerald-600 group-hover:text-white transition-colors shadow-sm"><Landmark size={20}/></div>
                      <span className="text-[10px] font-black uppercase tracking-widest text-slate-500">Sede</span>
                  </button>
                  <button onClick={() => handleNav('accounts')} className="bg-white p-5 rounded-[2rem] shadow-soft border border-slate-100 flex flex-col items-center gap-3 hover:border-brand-200 hover:-translate-y-1 transition-all group">
                      <div className="w-12 h-12 bg-purple-50 text-purple-600 rounded-2xl flex items-center justify-center group-hover:bg-purple-600 group-hover:text-white transition-colors shadow-sm"><Wallet size={20}/></div>
                      <span className="text-[10px] font-black uppercase tracking-widest text-slate-500">Wallet</span>
                  </button>
              </div>

          </div>

          {/* Right Column: Promos & Activity */}
          <div className="lg:col-span-4 space-y-6">

              {/* Promo Carousel */}
              <div className="snap-x snap-mandatory flex overflow-x-auto gap-4 no-scrollbar pb-2">
                  <div onClick={() => handleNav('lottery')} className="snap-start shrink-0 w-full bg-gradient-to-br from-pink-500 to-rose-600 rounded-[2.5rem] p-6 text-white relative overflow-hidden cursor-pointer hover:scale-[1.02] transition-transform shadow-xl">
                      <div className="absolute top-0 right-0 w-32 h-32 bg-white/20 rounded-full blur-2xl -mr-10 -mt-10"></div>
                      <div className="relative z-10">
                          <div className="flex justify-between items-start mb-8">
                              <div className="p-3 bg-white/20 backdrop-blur-md rounded-2xl"><Ticket size={24} className="text-white"/></div>
                              <span className="bg-white text-rose-600 text-[10px] font-black px-3 py-1 rounded-full uppercase tracking-widest">Bote SIDS</span>
                          </div>
                          <p className="text-[9px] font-black text-rose-100 uppercase tracking-[0.2em] mb-1">Acumulado Especial</p>
                          <h3 className="text-4xl font-black mb-4 tracking-tighter">50.000 Pts</h3>
                          <div className="flex items-center gap-2 text-[10px] font-black uppercase tracking-widest bg-white/10 w-fit px-3 py-1.5 rounded-xl border border-white/20">
                              Participar <ChevronRight size={14}/>
                          </div>
                      </div>
                  </div>
              </div>

              {/* Recent Activity List */}
              <div className="bg-white p-7 rounded-[2.5rem] border border-slate-100 shadow-soft h-full max-h-[440px] flex flex-col">
                  <div className="flex justify-between items-center mb-6 px-1">
                      <h3 className="font-black text-slate-900 text-lg tracking-tight">Actividad</h3>
                      <button onClick={() => handleNav('accounts')} className="text-brand-600 text-[10px] font-black uppercase tracking-widest hover:underline">Auditoría</button>
                  </div>

                  <div className="flex-1 overflow-y-auto custom-scrollbar space-y-4 pr-1">
                      {transactions?.slice(0, 5).map(tx => {
                          const isIncoming = userAccounts?.some(a => a.iban === tx.receiverIban);
                          return (
                              <div key={tx.id} className="flex items-center justify-between p-3.5 hover:bg-slate-50 rounded-2xl transition-all border border-transparent hover:border-slate-100 group">
                                  <div className="flex items-center gap-4 min-w-0">
                                      <div className={`w-11 h-11 rounded-xl flex items-center justify-center shadow-sm shrink-0 transition-transform group-hover:scale-105 ${isIncoming ? 'bg-emerald-50 text-emerald-600' : 'bg-slate-50 text-slate-600'}`}>
                                          {isIncoming ? <ArrowDownLeft size={18}/> : <ArrowUpRight size={18}/>}
                                      </div>
                                      <div className="min-w-0">
                                          <p className="font-bold text-slate-900 text-xs truncate pr-2">{tx.description}</p>
                                          <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest mt-0.5">{new Date(tx.date).toLocaleDateString()}</p>
                                      </div>
                                  </div>
                                  <span className={`font-black text-sm whitespace-nowrap shrink-0 tracking-tight ${isIncoming ? 'text-emerald-600' : 'text-slate-900'}`}>
                                      {isIncoming ? '+' : '-'}{tx.amount.toLocaleString()}
                                  </span>
                              </div>
                          );
                      })}
                      {(!transactions || transactions.length === 0) && (
                        <div className="flex flex-col items-center justify-center py-12 text-slate-300">
                            <History size={32} className="mb-2 opacity-50"/>
                            <p className="text-[10px] font-black uppercase tracking-widest">Sin movimientos</p>
                        </div>
                      )}
                  </div>
              </div>
          </div>
      </div>

      {/* PlaceZum Quick Send Drawer (Mobile Ready) */}
      {showPlaceZum && (
          <div className="fixed inset-0 bg-slate-950/60 backdrop-blur-md z-[250] flex items-end md:items-center justify-center p-0 md:p-4 animate-fade-in" onClick={() => setShowPlaceZum(false)}>
              <div className="bg-white w-full max-w-sm md:rounded-[3rem] rounded-t-[3rem] p-8 md:p-10 shadow-2xl animate-slide-up relative" onClick={e => e.stopPropagation()}>
                  <div className="w-12 h-1.5 bg-slate-200 rounded-full mx-auto mb-6 md:hidden"></div>
                  <button onClick={() => setShowPlaceZum(false)} className="absolute top-6 right-6 p-2.5 bg-slate-100 rounded-full text-slate-400 hover:text-slate-900 transition-all"><X size={20}/></button>

                  <div className="flex flex-col items-center mb-8">
                      <div className="w-16 h-16 bg-brand-50 text-brand-600 rounded-[1.5rem] flex items-center justify-center mb-4 shadow-sm">
                          <Zap size={32} fill="currentColor"/>
                      </div>
                      <h3 className="text-2xl font-black text-slate-900 tracking-tight">Giro PlaceZum</h3>
                      <p className="text-slate-400 font-black text-[10px] uppercase tracking-[0.2em] mt-2">Liquidación Instantánea</p>
                  </div>

                  <div className="space-y-6">
                      <div className="bg-slate-50 p-5 rounded-3xl border border-slate-100">
                          <label className="text-[9px] font-black text-slate-400 uppercase tracking-[0.2em] mb-3 block ml-1">Destinatario SIDS</label>
                          {selectedContact ? (
                              <div className="flex items-center gap-4 bg-white p-3.5 rounded-2xl border border-brand-200 shadow-sm animate-pop-in">
