import React, { createContext, useContext, useState, ReactNode, useEffect, useCallback } from 'react';
import { User, Account, Transaction, Company, AppNotification, Product, Employee, Card, Contact, TaxConfig, ShareRequest, LootBox, LootItem, CardDesign, ApiUsageLog, PayrollHistory, UserSubscription, SubscriptionPlan } from '../types';
import { jsPDF } from 'jspdf';
import 'jspdf-autotable';

interface BankContextType {
  currentUser: User | null;
  userAccounts: Account[];
  transactions: Transaction[];
  notifications: AppNotification[];
  companies: Company[];
  cards: Card[];
  contacts: Contact[];
  shareRequests: ShareRequest[];
  lootBoxes: LootBox[];
  marketDesigns: { store: CardDesign[], inventory: CardDesign[] };
  userSubscriptions: UserSubscription[];
  taxConfig: TaxConfig;
  login: (dip: string, pass: string) => Promise<{ success: boolean; error?: string }>;
  loginWithPlacetaID: (userData: any) => Promise<{ success: boolean; error?: string }>;
  logout: () => void;
  fetchData: (userId: string) => Promise<void>;
  transfer: (fromIban: string, toIban: string, amount: number, description: string, type?: string) => Promise<void>;
  companyTransfer: (companyId: string, toIban: string, amount: number, description: string) => Promise<void>;
  requestCard: (accountId: string, holderName: string, design: string, pin: string) => Promise<void>;
  toggleCardStatus: (cardId: string, status: 'ACTIVE' | 'FROZEN') => Promise<void>;
  updateCardPin: (cardId: string, newPin: string) => Promise<void>;
  payWithCard: (cardData: {pan: string, cvv: string, pin: string}, amount: number, companyId: string, description: string) => Promise<void>;
  getApiUsageLogs: (companyId: string) => Promise<ApiUsageLog[]>;
  addNotification: (message: string, type: 'success' | 'error' | 'info') => void;
  generatePDF: (type: string, data: any) => void;
  getAge: (birthDate?: string) => number;
  saveContact: (name: string, iban: string) => Promise<void>;
  deleteContact: (id: string) => Promise<void>;
  buyStock: (companyId: string, accountId: string, amount: number) => Promise<void>;
  sellStock: (companyId: string, accountId: string, amount: number) => Promise<void>;
  payCitizenTax: (accountId: string, amount: number, description: string) => Promise<void>;
  getFiscalProjection: (month: number, year: number) => Promise<any[]>;
  respondShareRequest: (id: string, status: 'ACCEPTED' | 'REJECTED') => Promise<void>;
  requestShareAccount: (accountId: string, toDip: string, accessLevel: string) => Promise<void>;
  adminGetState: () => Promise<any>;
  adminRevertTransaction: (id: string) => Promise<void>;
  adminUpdateUserStatus: (userId: string, isBlocked: boolean) => Promise<void>;
  adminUpdateUserBirthDate: (userId: string, birthDate: string) => Promise<void>;
  adminMint: (amount: number, reason: string) => Promise<void>;
  adminCreateUser: (user: any) => Promise<void>;
  adminGenerateMonthlyTaxes: (month: number, year: number) => Promise<any>;
  adminProcessTaxCollection: () => Promise<any>;
  buyLootBox: (boxId: string, accountId: string) => Promise<{ success: boolean; wonItem?: LootItem }>;
  redeemCode: (code: string) => Promise<void>;
  buyDesign: (designId: string, accountId: string) => Promise<void>;
  listDesign: (designId: string, price: number) => Promise<void>;
  deleteDesign: (designId: string) => Promise<void>;
  payPayroll: (companyId: string, month: string, year: string) => Promise<void>;
  updateEmployees: (companyId: string, employees: Employee[]) => Promise<void>;
  updateCatalog: (companyId: string, products: Product[]) => Promise<void>;
  rotateApiKey: (companyId: string) => Promise<{apiKey: string}>;
  createSubaccount: (companyId: string, alias: string) => Promise<void>;
  createLottery: (lotteryData: any) => Promise<void>;
  approveLottery: (id: string) => Promise<void>;
  deleteLottery: (id: string) => Promise<void>;
  getPayrollHistory: (companyId: string) => Promise<PayrollHistory[]>;
  triggerHaptic: (pattern?: 'light' | 'medium' | 'heavy' | 'success' | 'error') => void;
  subscribeToPlan: (plan: SubscriptionPlan, accountId: string) => Promise<void>;
  cancelSubscription: (subId: string) => Promise<void>;
  updateSelfBirthDate: (birthDate: string) => Promise<void>;
}

const BankContext = createContext<BankContextType | undefined>(undefined);

export const BankProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [userAccounts, setUserAccounts] = useState<Account[]>([]);
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [notifications, setNotifications] = useState<AppNotification[]>([]);
  const [companies, setCompanies] = useState<Company[]>([]);
  const [cards, setCards] = useState<Card[]>([]);
  const [contacts, setContacts] = useState<Contact[]>([]);
  const [shareRequests, setShareRequests] = useState<ShareRequest[]>([]);
  const [lootBoxes, setLootBoxes] = useState<LootBox[]>([]);
  const [marketDesigns, setMarketDesigns] = useState<{ store: CardDesign[], inventory: CardDesign[] }>({ store: [], inventory: [] });
  const [userSubscriptions, setUserSubscriptions] = useState<UserSubscription[]>([]);

  const [taxConfig, setTaxConfig] = useState<TaxConfig>({
      vatRate: 12,
      transferRate: 1,
      companyTaxRate: 25,
      lotteryRate: 20
  });

  useEffect(() => {
    if ('Notification' in window && Notification.permission !== 'granted') {
      Notification.requestPermission();
    }
  }, []);

  const triggerHaptic = (pattern: 'light' | 'medium' | 'heavy' | 'success' | 'error' = 'light') => {
    if (typeof navigator !== 'undefined' && navigator.vibrate) {
        switch (pattern) {
            case 'light': navigator.vibrate(5); break;
            case 'medium': navigator.vibrate(15); break;
            case 'heavy': navigator.vibrate(30); break;
            case 'success': navigator.vibrate([10, 30, 10]); break;
            case 'error': navigator.vibrate([30, 50, 30, 50, 30]); break;
        }
    }
  };

  const apiCall = async (body: any) => {
    const res = await fetch('/api', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(body)
    });
    const data = await res.json();
    if (!res.ok) throw new Error(data.error || 'Error de Nodo');
    return data;
  };

  const fetchData = useCallback(async (userId: string) => {
    if (!userId) return;
    try {
      const data = await apiCall({ action: 'GET_INITIAL_DATA', userId });
      setUserAccounts(data.accounts || []);
      setTransactions(data.transactions || []);
      setCompanies(data.companies || []);
      setCards(data.cards || []);
      setContacts(data.contacts || []);
      setShareRequests(data.shareRequests || []);
      setLootBoxes(data.lootBoxes || []);
      setMarketDesigns(data.marketDesigns || { store: [], inventory: [] });
      setUserSubscriptions(data.userSubscriptions || []);
      if (data.taxConfig) setTaxConfig(data.taxConfig);
    } catch (e: any) {
      console.error("Nodo Central Fetch Error:", e.message);
    }
  }, []);

  const getAge = (birthDate?: string) => {
    if (!birthDate) return 0;
    const today = new Date();
    const birth = new Date(birthDate);
    if (isNaN(birth.getTime())) return 0;
    let age = today.getFullYear() - birth.getFullYear();
    const m = today.getMonth() - birth.getMonth();
    if (m < 0 || (m === 0 && today.getDate() < birth.getDate())) {
        age--;
    }
    return age;
  };

  const updateSelfBirthDate = async (birthDate: string) => {
      if (!currentUser?.id) return;
      await apiCall({ action: 'ADMIN_UPDATE_USER_BIRTHDATE', userId: currentUser.id, birthDate });
      setCurrentUser(prev => prev ? { ...prev, birthDate } : null);
      addNotification("Identidad SIDS sincronizada", "success");
  };

  const login = async (dip: string, pass: string) => {
    try {
      const data = await apiCall({ action: 'AUTH', dip, password: pass });
      if (data.user) {
        setCurrentUser(data.user);
        await fetchData(data.user.id);
        return { success: true, user: data.user };
      }
      return { success: false, error: "Respuesta de Nodo vacía" };
    } catch (e: any) { 
      return { success: false, error: e.message }; 
    }
  };

  const loginWithPlacetaID = async (userData: any) => {
    try {
      const data = await apiCall({ action: 'AUTH_PLACETAID', userData });
      if (data.user) {
        setCurrentUser(data.user);
        await fetchData(data.user.id);
        return { success: true };
      }
      return { success: false, error: "Fallo en pasarela SIDS" };
    } catch (e: any) {
      return { success: false, error: e.message };
    }
  };

  const logout = () => {
    setCurrentUser(null);
    setUserAccounts([]);
    setTransactions([]);
    setNotifications([]);
  };

  const transfer = async (fromIban: string, toIban: string, amount: number, description: string, type = 'TRANSFER') => {
    await apiCall({ action: 'TRANSFER', fromIban, toIban, amount, description, type });
    if (currentUser?.id) await fetchData(currentUser.id);
    addNotification(`Firma digital confirmada: ${amount} Pts`, "success");
  };

  const companyTransfer = async (companyId: string, toIban: string, amount: number, description: string) => {
      await apiCall({ action: 'COMPANY_TRANSFER', companyId, toIban, amount, description });
      if (currentUser?.id) await fetchData(currentUser.id);
      addNotification(`Giro corporativo procesado`, "success");
  };

  const requestCard = async (accountId: string, holderName: string, design: string, pin: string) => { await apiCall({ action: 'REQUEST_CARD', accountId, holderName, design, pin }); if (currentUser?.id) await fetchData(currentUser.id); addNotification("PlacetaPay emitida", "success"); };
  const toggleCardStatus = async (cardId: string, status: string) => { await apiCall({ action: 'TOGGLE_CARD_STATUS', cardId, status }); if (currentUser?.id) await fetchData(currentUser.id); addNotification(`Estado: ${status}`, "info"); };
  const updateCardPin = async (cardId: string, newPin: string) => { await apiCall({ action: 'UPDATE_CARD_PIN', cardId, newPin }); addNotification("PIN sincronizado", "success"); };
  const payWithCard = async (cardData: any, amount: number, companyId: string, description: string) => { await apiCall({ action: 'PAY_WITH_CARD', ...cardData, amount, companyId, description }); if (currentUser?.id) await fetchData(currentUser.id); addNotification("Pago liquidado", "success"); };
  const getApiUsageLogs = async (companyId: string) => apiCall({ action: 'GET_API_USAGE_LOGS', companyId });

  const addNotification = (message: string, type: any) => {
    const id = Date.now().toString();
    setNotifications(prev => [...prev, { id, message, type }]);
    if(!document.hidden) triggerHaptic(type === 'error' ? 'error' : 'light');
    setTimeout(() => setNotifications(prev => prev.filter(n => n.id !== id)), 4000);
  };

  const saveContact = async (name: string, iban: string) => { if(currentUser?.id) { await apiCall({action: 'SAVE_CONTACT', userId: currentUser.id, name, iban}); await fetchData(currentUser.id); }};
  const deleteContact = async (id: string) => { await apiCall({action: 'DELETE_CONTACT', contactId: id}); if(currentUser?.id) await fetchData(currentUser.id); };
  const buyStock = async (companyId: string, accountId: string, amount: number) => { await apiCall({action: 'BUY_STOCK', companyId, accountId, amount}); if(currentUser?.id) await fetchData(currentUser.id); };
  const sellStock = async (companyId: string, accountId: string, amount: number) => { await apiCall({action: 'SELL_STOCK', companyId, accountId, amount}); if(currentUser?.id) await fetchData(currentUser.id); };
  const payCitizenTax = async (accountId: string, amount: number, description: string) => { await apiCall({action: 'PAY_TAX', accountId, amount, description}); if(currentUser?.id) await fetchData(currentUser.id); };
  const getFiscalProjection = async (month: number, year: number) => { if(!currentUser?.id) return []; return apiCall({action: 'GET_FISCAL_PROJECTION', userId: currentUser.id, month, year}); };
  const respondShareRequest = async (id: string, status: string) => { await apiCall({action: 'RESPOND_SHARE_REQUEST', requestId: id, status}); if(currentUser?.id) await fetchData(currentUser.id); };
  const requestShareAccount = async (accountId: string, toDip: string, accessLevel: string) => { await apiCall({action: 'REQUEST_SHARE_ACCOUNT', accountId, toDip, accessLevel}); if(currentUser?.id) await fetchData(currentUser.id); };
  const adminGetState = async () => apiCall({action: 'ADMIN_GET_STATE'});
  const adminRevertTransaction = async (id: string) => apiCall({action: 'ADMIN_REVERT_TX', transactionId: id});
  const adminUpdateUserStatus = async (userId: string, isBlocked: boolean) => apiCall({action: 'ADMIN_UPDATE_USER_STATUS', userId, isBlocked});
  const adminUpdateUserBirthDate = async (userId: string, birthDate: string) => apiCall({action: 'ADMIN_UPDATE_USER_BIRTHDATE', userId, birthDate});
  const adminMint = async (amount: number, reason: string) => apiCall({action: 'ADMIN_MINT', amount, reason});
  const adminCreateUser = async (user: any) => apiCall({action: 'ADMIN_CREATE_USER', user});
  const adminGenerateMonthlyTaxes = async (month: number, year: number) => apiCall({action: 'ADMIN_GENERATE_MONTHLY_TAXES', month, year});
  const adminProcessTaxCollection = async () => apiCall({action: 'ADMIN_PROCESS_TAX_COLLECTION'});
  const buyLootBox = async (boxId: string, accountId: string) => { const r = await apiCall({action: 'BUY_LOOTBOX', boxId, accountId}); if(currentUser?.id) await fetchData(currentUser.id); return r; };
  const redeemCode = async (code: string) => { await apiCall({action: 'REDEEM_CODE', code}); if(currentUser?.id) await fetchData(currentUser.id); };
  const buyDesign = async (designId: string, accountId: string) => { await apiCall({action: 'BUY_DESIGN', designId, accountId}); if(currentUser?.id) await fetchData(currentUser.id); };
  const listDesign = async (designId: string, price: number) => { await apiCall({action: 'LIST_DESIGN', designId, price}); if(currentUser?.id) await fetchData(currentUser.id); };
  const deleteDesign = async (designId: string) => { await apiCall({action: 'DELETE_DESIGN', designId}); if(currentUser?.id) await fetchData(currentUser.id); };
  const payPayroll = async (companyId: string, month: string, year: string) => { await apiCall({action: 'PAY_PAYROLL', companyId, month, year}); if(currentUser?.id) await fetchData(currentUser.id); };
  const updateEmployees = async (companyId: string, employees: Employee[]) => { await apiCall({action: 'UPDATE_EMPLOYEES', companyId, employees}); if(currentUser?.id) await fetchData(currentUser.id); };
  const updateCatalog = async (companyId: string, products: Product[]) => { await apiCall({action: 'UPDATE_CATALOG', companyId, products}); if(currentUser?.id) await fetchData(currentUser.id); };
  const rotateApiKey = async (companyId: string) => { const r = await apiCall({action: 'COMPANY_ROTATE_KEY', companyId}); if(currentUser?.id) await fetchData(currentUser.id); return r; };
  const createSubaccount = async (companyId: string, alias: string) => { await apiCall({action: 'CREATE_SUBACCOUNT', companyId, alias}); if(currentUser?.id) await fetchData(currentUser.id); };
  const createLottery = async (lotteryData: any) => { await apiCall({action: 'CREATE_LOTTERY', ...lotteryData}); if(currentUser?.id) await fetchData(currentUser.id); };
  const approveLottery = async (id: string) => { await apiCall({action: 'APPROVE_LOTTERY', lotteryId: id}); if(currentUser?.id) await fetchData(currentUser.id); };
  const deleteLottery = async (id: string) => { await apiCall({action: 'DELETE_LOTTERY', lotteryId: id}); if(currentUser?.id) await fetchData(currentUser.id); };
  const getPayrollHistory = async (companyId: string) => apiCall({action: 'GET_PAYROLL_HISTORY', companyId});
  const subscribeToPlan = async (plan: SubscriptionPlan, accountId: string) => { 
      await apiCall({ action: 'CREATE_SUBSCRIPTION', planId: plan.id, accountId, companyId: plan.companyId });
      if(currentUser?.id) await fetchData(currentUser.id);
  };
  const cancelSubscription = async (subId: string) => {
      await apiCall({ action: 'CANCEL_SUBSCRIPTION', subscriptionId: subId });
      if(currentUser?.id) await fetchData(currentUser.id);
  };

  const generatePDF = (type: string, data: any) => {
      const doc = new jsPDF() as any;
      doc.text("BANCO DE LA PLACETA", 20, 20);
      doc.text(type, 20, 30);
      if (data.amount) doc.text(`Importe: ${data.amount} Pts`, 20, 40);
      if (data.concept) doc.text(`Concepto: ${data.concept}`, 20, 50);
      doc.save(`doc_${Date.now()}.pdf`);
  };

  return (
    <BankContext.Provider value={{
      currentUser, userAccounts, transactions, notifications, companies, cards, contacts, shareRequests, lootBoxes, marketDesigns, userSubscriptions, taxConfig,
      login, loginWithPlacetaID, logout, fetchData, transfer, companyTransfer, requestCard, toggleCardStatus, updateCardPin, payWithCard, getApiUsageLogs, addNotification, generatePDF, getAge,
      saveContact, deleteContact, buyStock, sellStock, payCitizenTax, getFiscalProjection, respondShareRequest, requestShareAccount,
      adminGetState, adminRevertTransaction, adminUpdateUserStatus, adminUpdateUserBirthDate, adminMint, adminCreateUser, adminGenerateMonthlyTaxes, adminProcessTaxCollection,
      buyLootBox, redeemCode, buyDesign, listDesign, deleteDesign, payPayroll, updateEmployees, updateCatalog, rotateApiKey,
      createSubaccount, createLottery, approveLottery, deleteLottery, getPayrollHistory, triggerHaptic, subscribeToPlan, cancelSubscription, updateSelfBirthDate
    }}>
      {children}
    </BankContext.Provider>
  );
};

export const useBank = () => {
  const context = useContext(BankContext);
  if (!context) throw new Error('BankContext missing');
  return context;
};

import React, { useMemo, useState } from 'react';
import { useBank } from '../context/BankContext';
import { 
  Wallet, ArrowRightLeft, TrendingUp, Bell, 
  Building2, ArrowUpRight, ArrowDownLeft, ShieldCheck, 
  CreditCard, Zap, Plus, User, X, ChevronRight,
  QrCode, Ticket, ShoppingBag, Send, Landmark, History
} from 'lucide-react';
import { AreaChart, Area, ResponsiveContainer, Tooltip } from 'recharts';

interface DashboardProps { onNavigate: (view: string) => void; onSwitchToBusiness?: () => void; }

export const Dashboard: React.FC<DashboardProps> = ({ onNavigate, onSwitchToBusiness }) => {
  const { currentUser, userAccounts, transactions, companies, contacts, transfer, triggerHaptic, addNotification } = useBank();
  const [showBalance, setShowBalance] = useState(true);
  const [showPlaceZum, setShowPlaceZum] = useState(false);
  const [placeZumAmount, setPlaceZumAmount] = useState('');
  const [selectedContact, setSelectedContact] = useState<any>(null);
  const [customIban, setCustomIban] = useState('');

  if (!currentUser) return null;

  const totalBalance = userAccounts?.reduce((acc, curr) => acc + parseFloat(curr.balance.toString()), 0) || 0;
  const mainAccount = userAccounts?.[0];

  const frequentContacts = useMemo(() => {
      const freqMap = new Map();
      if (!transactions || !mainAccount) return [];
      transactions.forEach(tx => {
          if (tx.senderIban === mainAccount.iban && tx.receiverIban) {
              const contact = contacts?.find(c => c.iban === tx.receiverIban);
              const name = contact ? contact.name : tx.receiverIban;
              const id = tx.receiverIban;
              if (!freqMap.has(id)) {
                  freqMap.set(id, { id, name, iban: tx.receiverIban, count: 1 });
              } else {
                  freqMap.get(id).count++;
              }
          }
      });
      return Array.from(freqMap.values()).sort((a, b) => b.count - a.count).slice(0, 5);
  }, [transactions, mainAccount, contacts]);

  const handleNav = (view: string) => {
      triggerHaptic('light');
      onNavigate(view);
  }

  const handlePlaceZumSend = async () => {
      if (!mainAccount) return;
      const targetIban = selectedContact ? selectedContact.iban : (customIban.startsWith('PL') ? customIban : 'PL' + customIban);
      const amount = Number(placeZumAmount);

      if (!targetIban || amount <= 0) {
          addNotification("Datos incompletos", "error");
          return;
      }
      if (mainAccount.balance < amount) {
          addNotification("Saldo insuficiente", "error");
          return;
      }

      setShowPlaceZum(false);
      triggerHaptic('heavy');

      try {
          await transfer(mainAccount.iban, targetIban, amount, "PlaceZum Instantáneo", "PLACEZUM");
          setPlaceZumAmount('');
          setSelectedContact(null);
          setCustomIban('');
      } catch (e: any) {
          addNotification(e.message, "error");
      }
  };

  const getGreeting = () => {
      const hour = new Date().getHours();
      if (hour < 12) return 'Buenos días';
      if (hour < 20) return 'Buenas tardes';
      return 'Buenas noches';
  };

  return (
    <div className="pb-40 w-full max-w-7xl mx-auto px-4 md:px-8 pt-safe font-sans animate-fade-in overflow-x-hidden">

      {/* Top Bar */}
      <header className="flex justify-between items-center mb-8 pt-4">
        <div className="flex items-center gap-4">
            <div className="relative">
                <div className="w-12 h-12 rounded-full bg-slate-900 text-white flex items-center justify-center font-bold text-lg shadow-lg border-2 border-slate-800 shrink-0 overflow-hidden">
                    {currentUser.avatarUrl ? <img src={currentUser.avatarUrl} className="w-full h-full object-cover" alt="Avatar"/> : currentUser.name.charAt(0)}
                </div>
                <div className="absolute -bottom-1 -right-1 w-5 h-5 bg-emerald-500 border-4 border-slate-50 rounded-full"></div>
            </div>
