import { Pool } from '@neondatabase/serverless';

let pool: any = null;
const getPool = () => {
  if (!pool) {
    if (!process.env.DATABASE_URL) throw new Error('DATABASE_URL is missing');
    pool = new (Pool as any)({ connectionString: process.env.DATABASE_URL });
  }
  return pool;
};

const BANK_IBAN = 'PL0000000000000000000000';

const formatResponse = (obj: any): any => {
    if (obj === null || obj === undefined) return obj;
    if (obj instanceof Date) return obj.toISOString();
    if (Array.isArray(obj)) return obj.map(formatResponse);
    if (typeof obj !== 'object') return obj;
    const newObj: any = {};
    for (const key in obj) {
        const newKey = key.replace(/_([a-z])/g, (g) => g[1].toUpperCase());
        let value = obj[key];
        const numericFields = ['balance', 'amount', 'price', 'capital', 'stockValue', 'salary', 'tax', 'prizeValue'];
        if (numericFields.includes(newKey) && (typeof value === 'string' || value === null)) {
            value = parseFloat(value || '0');
        }
        newObj[newKey] = formatResponse(value);
    }
    return newObj;
};

export default async function handler(req: any, res: any) {
    let client: any;
    res.setHeader('Content-Type', 'application/json');
    res.setHeader('Access-Control-Allow-Origin', '*');
    res.setHeader('Access-Control-Allow-Methods', 'POST, OPTIONS');

    if (req.method === 'OPTIONS') return res.status(200).end();

    try {
        const { action, ...params } = req.body || {};
        client = await getPool().connect();

        if (action === 'AUTH') {
            const { dip, password } = params;
            const userRes = await client.query("SELECT * FROM users WHERE UPPER(dip) = $1 AND password_hash = $2", [dip.toUpperCase().trim(), password]);
            if (userRes.rows.length === 0) return res.status(401).json({ error: "Credenciales no encontradas" });
            return res.status(200).json({ success: true, user: formatResponse(userRes.rows[0]) });
        }

        if (action === 'AUTH_PLACETAID') {
            const { userData } = params;
            // El SDK de PlacetaID envía habitualmente 'dni' o 'id'
            const dip = (userData.dni || userData.dip || userData.id || '').toUpperCase().trim();
            if (!dip) return res.status(400).json({ error: "Identidad SIDS no válida" });

            const userRes = await client.query("SELECT * FROM users WHERE UPPER(dip) = $1", [dip]);
            if (userRes.rows.length === 0) return res.status(404).json({ error: "Ciudadano no registrado en el Nodo Bancario" });

            return res.status(200).json({ success: true, user: formatResponse(userRes.rows[0]) });
        }

        if (action === 'GET_INITIAL_DATA') {
            const { userId } = params;
            const accounts = (await client.query("SELECT * FROM accounts WHERE owner_id = $1 OR $1 = ANY(shared_with)", [userId])).rows;
            const companies = (await client.query("SELECT * FROM companies")).rows;
            const cards = (await client.query("SELECT * FROM cards WHERE account_id IN (SELECT id FROM accounts WHERE owner_id = $1)", [userId])).rows;
            const contacts = (await client.query("SELECT * FROM contacts WHERE user_id = $1", [userId])).rows;
            const shareRequests = (await client.query("SELECT sr.*, u1.name as from_user_name, u2.name as to_user_name FROM share_requests sr LEFT JOIN users u1 ON sr.from_user_id = u1.id LEFT JOIN users u2 ON sr.to_user_dip = u2.dip WHERE sr.from_user_id = $1 OR sr.to_user_dip = (SELECT dip FROM users WHERE id = $1)", [userId])).rows;
            const lootBoxes = (await client.query("SELECT * FROM loot_boxes")).rows;
            const userSubs = (await client.query("SELECT * FROM user_subscriptions WHERE user_id = $1", [userId])).rows;
            const allDesigns = (await client.query("SELECT * FROM card_designs")).rows;

            const ibans = accounts.map((a: any) => a.iban);
            let txs = [];
            if (ibans.length > 0) {
                const placeholders = ibans.map((_, i) => `$${i + 1}`).join(',');
                txs = (await client.query(`SELECT * FROM transactions WHERE sender_iban IN (${placeholders}) OR receiver_iban IN (${placeholders}) ORDER BY date DESC LIMIT 50`, ibans)).rows;
            }

            return res.status(200).json(formatResponse({ accounts, companies, cards, transactions: txs, contacts, shareRequests, lootBoxes, userSubscriptions: userSubs, marketDesigns: { store: allDesigns.filter((d:any)=>!d.owner_id), inventory: allDesigns.filter((d:any)=>d.owner_id===userId) } }));
        }

        if (action === 'TRANSFER') {
            const { fromIban, toIban, amount, description } = params;
            const total = amount * 1.01;
            await client.query("BEGIN");
            const sender = await client.query("SELECT balance FROM accounts WHERE iban = $1 FOR UPDATE", [fromIban]);
            if (sender.rows.length === 0 || parseFloat(sender.rows[0].balance) < total) { await client.query("ROLLBACK"); return res.status(400).json({ error: "Fondos insuficientes" }); }
            await client.query("UPDATE accounts SET balance = balance - $1 WHERE iban = $2", [total, fromIban]);
            await client.query("UPDATE accounts SET balance = balance + $1 WHERE iban = $2", [amount, toIban]);
            await client.query("UPDATE accounts SET balance = balance + $1 WHERE iban = $2", [amount * 0.01, BANK_IBAN]);
            await client.query("INSERT INTO transactions (id, amount, sender_iban, receiver_iban, description, type, tax, status, date) VALUES ($1, $2, $3, $4, $5, 'TRANSFER', $6, 'COMPLETED', NOW())", [`tx-${Date.now()}`, amount, fromIban, toIban, description, amount * 0.01]);
            await client.query("COMMIT");
            return res.status(200).json({ success: true });
        }

        if (action === 'ADMIN_UPDATE_USER_BIRTHDATE') {
            const { userId, birthDate } = params;
            await client.query("UPDATE users SET birth_date = $1 WHERE id = $2", [birthDate, userId]);
            return res.status(200).json({ success: true });
        }

        if (action === 'ADMIN_UPDATE_USER_STATUS') {
            const { userId, isBlocked } = params;
            await client.query("UPDATE users SET is_blocked = $1 WHERE id = $2", [isBlocked, userId]);
            return res.status(200).json({ success: true });
        }

        if (action === 'ADMIN_GET_STATE') {
             const users = (await client.query("SELECT * FROM users ORDER BY created_at DESC")).rows;
             const txs = (await client.query("SELECT * FROM transactions ORDER BY date DESC LIMIT 200")).rows;
             const accounts = (await client.query("SELECT * FROM accounts")).rows;
             const m0 = accounts.reduce((acc: number, curr: any) => acc + parseFloat(curr.balance), 0);
             return res.status(200).json(formatResponse({ users, transactions: txs, allAccounts: accounts, m0 }));
        }

        // Catch all for mocks
        return res.status(200).json({ success: true });

    } catch (e: any) {
        return res.status(500).json({ error: e.message });
    } finally {
        if (client) client.release();
    }
}

import { Pool } from '@neondatabase/serverless';

let pool: any = null;
const getPool = () => {
  if (!pool) {
    if (!process.env.DATABASE_URL) throw new Error('DATABASE_URL is missing');
    pool = new (Pool as any)({ connectionString: process.env.DATABASE_URL });
  }
  return pool;
};

const BANK_IBAN = 'PL0000000000000000000000';

const formatResponse = (obj: any): any => {
    if (obj === null || obj === undefined) return obj;
    if (obj instanceof Date) return obj.toISOString();
    if (Array.isArray(obj)) return obj.map(formatResponse);
    if (typeof obj !== 'object') return obj;
    const newObj: any = {};
    for (const key in obj) {
        const newKey = key.replace(/_([a-z])/g, (g) => g[1].toUpperCase());
        let value = obj[key];
        const numericFields = ['balance', 'amount', 'price', 'capital', 'stockValue', 'salary', 'tax', 'prizeValue'];
        if (numericFields.includes(newKey) && (typeof value === 'string' || value === null)) {
            value = parseFloat(value || '0');
        }
        newObj[newKey] = formatResponse(value);
    }
    return newObj;
};

