import { Pool } from '@neondatabase/serverless';

let pool: any = null;
const getPool = () => {
  if (!pool) {
    if (!process.env.DATABASE_URL) throw new Error('DATABASE_URL is missing');
    pool = new (Pool as any)({ connectionString: process.env.DATABASE_URL });
  }
  return pool;
};

const BANK_IBAN = 'PL0000000000000000000000';

const formatResponse = (obj: any): any => {
    if (obj === null || obj === undefined) return obj;
    if (obj instanceof Date) return obj.toISOString();
    if (Array.isArray(obj)) return obj.map(formatResponse);
    if (typeof obj !== 'object') return obj;
    const newObj: any = {};
    for (const key in obj) {
        const newKey = key.replace(/_([a-z])/g, (g) => g[1].toUpperCase());
        let value = obj[key];
        const numericFields = ['balance', 'amount', 'price', 'capital', 'stockValue', 'salary', 'tax', 'prizeValue'];
        if (numericFields.includes(newKey) && (typeof value === 'string' || value === null)) {
            value = parseFloat(value || '0');
        }
        newObj[newKey] = formatResponse(value);
    }
    return newObj;
};

export default async function handler(req: any, res: any) {
    let client: any;
    res.setHeader('Content-Type', 'application/json');
    res.setHeader('Access-Control-Allow-Origin', '*');
    res.setHeader('Access-Control-Allow-Methods', 'POST, OPTIONS');
    res.setHeader('Access-Control-Allow-Headers', 'Content-Type');

    if (req.method === 'OPTIONS') return res.status(200).end();

    try {
        const { action, ...params } = req.body || {};
        client = await getPool().connect();

        if (action === 'AUTH') {
            const { dip, password } = params;
            const userRes = await client.query("SELECT * FROM users WHERE UPPER(dip) = $1 AND password_hash = $2", [dip.toUpperCase().trim(), password]);
            if (userRes.rows.length === 0) return res.status(401).json({ error: "Credenciales no encontradas" });
            return res.status(200).json({ success: true, user: formatResponse(userRes.rows[0]) });
        }

        if (action === 'AUTH_PLACETAID') {
            const { userData } = params;
            const dip = (userData?.dni || userData?.dip || userData?.id || userData?.username || '').toUpperCase().trim();
            if (!dip) return res.status(400).json({ error: "Identidad SIDS no válida" });

            const userRes = await client.query("SELECT * FROM users WHERE UPPER(dip) = $1", [dip]);
            if (userRes.rows.length === 0) return res.status(404).json({ error: "Ciudadano no registrado en el Banco" });

            return res.status(200).json({ success: true, user: formatResponse(userRes.rows[0]) });
        }

        if (action === 'GET_INITIAL_DATA') {
            const { userId } = params;

            // Consultas Core: Si fallan, el sistema no puede operar (son tablas base del Cap 1)
            let accounts = []; try { accounts = (await client.query("SELECT * FROM accounts WHERE owner_id = $1 OR $1 = ANY(shared_with)", [userId])).rows; } catch(e) { accounts = []; }
            let companies = []; try { companies = (await client.query("SELECT * FROM companies")).rows; } catch(e) { companies = []; }

            // Consultas Secundarias: Silenciamos errores si las tablas no existen
            let cards = []; try { cards = (await client.query("SELECT * FROM cards WHERE account_id IN (SELECT id FROM accounts WHERE owner_id = $1)", [userId])).rows; } catch(e) {}
            let contacts = []; try { contacts = (await client.query("SELECT * FROM contacts WHERE user_id = $1", [userId])).rows; } catch(e) {}
            let shareRequests = []; try { shareRequests = (await client.query("SELECT sr.*, u1.name as from_user_name, u2.name as to_user_name FROM share_requests sr LEFT JOIN users u1 ON sr.from_user_id = u1.id LEFT JOIN users u2 ON sr.to_user_dip = u2.dip WHERE sr.from_user_id = $1 OR sr.to_user_dip = (SELECT dip FROM users WHERE id = $1)", [userId])).rows; } catch(e) {}
            let lootBoxes = []; try { lootBoxes = (await client.query("SELECT * FROM loot_boxes")).rows; } catch(e) {}
            let userSubscriptions = []; try { userSubscriptions = (await client.query("SELECT * FROM user_subscriptions WHERE user_id = $1", [userId])).rows; } catch(e) {}
            let allDesigns = []; try { allDesigns = (await client.query("SELECT * FROM card_designs")).rows; } catch(e) {}

            const ibans = (accounts || []).map((a: any) => a.iban);
            let txs = [];
            if (ibans.length > 0) {
                try {
                    const placeholders = ibans.map((_, i) => `$${i + 1}`).join(',');
                    txs = (await client.query(`SELECT * FROM transactions WHERE sender_iban IN (${placeholders}) OR receiver_iban IN (${placeholders}) ORDER BY date DESC LIMIT 50`, ibans)).rows;
                } catch(e) { txs = []; }
            }

            // RESPUESTA GARANTIZADA: Si alguna query falló, devolvemos array vacío pero nunca undefined/null
            return res.status(200).json(formatResponse({ 
                accounts: accounts || [], 
                companies: companies || [], 
                cards: cards || [], 
                transactions: txs || [], 
                contacts: contacts || [], 
                shareRequests: shareRequests || [], 
                lootBoxes: lootBoxes || [], 
                userSubscriptions: userSubscriptions || [], 
                marketDesigns: { 
                    store: (allDesigns || []).filter((d:any)=>!d.owner_id), 
                    inventory: (allDesigns || []).filter((d:any)=>d.owner_id===userId) 
                } 
            }));
        }

        // Acciones administrativas básicas
        if (action === 'ADMIN_GET_STATE') {
             let users = []; try { users = (await client.query("SELECT * FROM users ORDER BY created_at DESC")).rows; } catch(e) {}
             let txs = []; try { txs = (await client.query("SELECT * FROM transactions ORDER BY date DESC LIMIT 200")).rows; } catch(e) {}
             let accounts = []; try { accounts = (await client.query("SELECT * FROM accounts")).rows; } catch(e) {}
             const m0 = (accounts || []).reduce((acc: number, curr: any) => acc + parseFloat(curr.balance || '0'), 0);
             return res.status(200).json(formatResponse({ users: users || [], transactions: txs || [], allAccounts: accounts || [], m0 }));
        }

        return res.status(200).json({ success: true });

    } catch (e: any) {
        return res.status(500).json({ error: e.message });
    } finally {
        if (client) client.release();
    }
}

