  const [contacts, setContacts] = useState<Contact[]>([]);
  const [shareRequests, setShareRequests] = useState<ShareRequest[]>([]);
  const [lootBoxes, setLootBoxes] = useState<LootBox[]>([]);
  const [marketDesigns, setMarketDesigns] = useState<{ store: CardDesign[], inventory: CardDesign[] }>({ store: [], inventory: [] });
  const [userSubscriptions, setUserSubscriptions] = useState<UserSubscription[]>([]);

  const [taxConfig, setTaxConfig] = useState<TaxConfig>({
      vatRate: 12,
      transferRate: 1,
      companyTaxRate: 25,
      lotteryRate: 20
  });

  const triggerHaptic = (pattern: 'light' | 'medium' | 'heavy' | 'success' | 'error' = 'light') => {
    if (typeof navigator !== 'undefined' && navigator.vibrate) {
        switch (pattern) {
            case 'light': navigator.vibrate(5); break;
            case 'medium': navigator.vibrate(15); break;
            case 'heavy': navigator.vibrate(30); break;
            case 'success': navigator.vibrate([10, 30, 10]); break;
            case 'error': navigator.vibrate([30, 50, 30, 50, 30]); break;
        }
    }
  };

  const apiCall = async (body: any) => {
    try {
        const res = await fetch('/api', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify(body)
        });
        const data = await res.json();
        if (!res.ok) throw new Error(data.error || 'Fallo en conexión');
        return data;
    } catch (e: any) {
        console.error("API Call Error:", e.message);
        throw e;
    }
  };

  const fetchData = useCallback(async (userId: string) => {
    if (!userId) return;
    try {
      const data = await apiCall({ action: 'GET_INITIAL_DATA', userId });
      // Asegurar que siempre actualizamos con arrays para evitar errores de renderizado
      setUserAccounts(Array.isArray(data.accounts) ? data.accounts : []);
      setTransactions(Array.isArray(data.transactions) ? data.transactions : []);
      setCompanies(Array.isArray(data.companies) ? data.companies : []);
      setCards(Array.isArray(data.cards) ? data.cards : []);
      setContacts(Array.isArray(data.contacts) ? data.contacts : []);
      setShareRequests(Array.isArray(data.shareRequests) ? data.shareRequests : []);
      setLootBoxes(Array.isArray(data.lootBoxes) ? data.lootBoxes : []);
      setUserSubscriptions(Array.isArray(data.userSubscriptions) ? data.userSubscriptions : []);
