import { Pool } from '@neondatabase/serverless';

let pool: any = null;
const getPool = () => {
  if (!pool) {
    if (!process.env.DATABASE_URL) throw new Error('DATABASE_URL is missing');
    pool = new (Pool as any)({ connectionString: process.env.DATABASE_URL });
  }
  return pool;
};

const BANK_IBAN = 'PL0000000000000000000000';

const formatResponse = (obj: any): any => {
    if (obj === null || obj === undefined) return obj;
    if (obj instanceof Date) return obj.toISOString();
    if (Array.isArray(obj)) return obj.map(formatResponse);
    if (typeof obj !== 'object') return obj;
    const newObj: any = {};
    for (const key in obj) {
        const newKey = key.replace(/_([a-z])/g, (g) => g[1].toUpperCase());
        let value = obj[key];
        const numericFields = ['balance', 'amount', 'price', 'capital', 'stockValue', 'salary', 'tax', 'prizeValue'];
        if (numericFields.includes(newKey) && (typeof value === 'string' || value === null)) {
            value = parseFloat(value || '0');
        }
        newObj[newKey] = formatResponse(value);
    }
    return newObj;
};

export default async function handler(req: any, res: any) {
    let client: any;
    res.setHeader('Content-Type', 'application/json');
    res.setHeader('Access-Control-Allow-Origin', '*');
    res.setHeader('Access-Control-Allow-Methods', 'POST, OPTIONS');
    res.setHeader('Access-Control-Allow-Headers', 'Content-Type');

    if (req.method === 'OPTIONS') return res.status(200).end();

    try {
        const { action, ...params } = req.body || {};
        client = await getPool().connect();

        // --- AUTH ---
        if (action === 'AUTH') {
            const { dip, password } = params;
            const userRes = await client.query("SELECT * FROM users WHERE UPPER(dip) = $1 AND password_hash = $2", [dip.toUpperCase().trim(), password]);
            if (userRes.rows.length === 0) return res.status(401).json({ error: "Credenciales SIDS incorrectas" });
            return res.status(200).json({ success: true, user: formatResponse(userRes.rows[0]) });
        }

        // --- CORE DATA ---
        if (action === 'GET_INITIAL_DATA') {
            const { userId } = params;
            const accounts = (await client.query("SELECT * FROM accounts WHERE owner_id = $1 OR $1 = ANY(shared_with)", [userId])).rows;
            const companies = (await client.query("SELECT * FROM companies")).rows;

            let cards = []; try { cards = (await client.query("SELECT * FROM cards WHERE account_id IN (SELECT id FROM accounts WHERE owner_id = $1)", [userId])).rows; } catch(e) {}
            let contacts = []; try { contacts = (await client.query("SELECT * FROM contacts WHERE user_id = $1", [userId])).rows; } catch(e) {}
            let lootBoxes = []; try { lootBoxes = (await client.query("SELECT * FROM loot_boxes")).rows; } catch(e) {}

            const ibans = (accounts || []).map((a: any) => a.iban);
            let txs = [];
            if (ibans.length > 0) {
                const placeholders = ibans.map((_, i) => `$${i + 1}`).join(',');
                txs = (await client.query(`SELECT * FROM transactions WHERE sender_iban IN (${placeholders}) OR receiver_iban IN (${placeholders}) ORDER BY date DESC LIMIT 50`, ibans)).rows;
            }

            return res.status(200).json(formatResponse({ accounts, companies, cards, transactions: txs, contacts, lootBoxes }));
        }

        // --- CONTACTS ---
        if (action === 'SAVE_CONTACT') {
            const { userId, name, iban } = params;
            await client.query(
                "INSERT INTO contacts (id, user_id, name, iban) VALUES ($1, $2, $3, $4) ON CONFLICT (user_id, iban) DO UPDATE SET name = $3",
                [`cnt-${Date.now()}`, userId, name, iban.toUpperCase().replace(/\s/g, '')]
            );
            return res.status(200).json({ success: true });
        }

        if (action === 'DELETE_CONTACT') {
            await client.query("DELETE FROM contacts WHERE id = $1", [params.contactId]);
            return res.status(200).json({ success: true });
        }

        // --- TRANSFERS ---
        if (action === 'TRANSFER') {
            const { fromIban, toIban, amount, description, type } = params;
            const tax = amount * 0.01;
            const total = amount + tax;

            await client.query("BEGIN");
            const sender = await client.query("SELECT balance FROM accounts WHERE iban = $1 FOR UPDATE", [fromIban]);
            if (!sender.rows[0] || parseFloat(sender.rows[0].balance) < total) {
                await client.query("ROLLBACK");
                return res.status(400).json({ error: "Fondos insuficientes (Importe + 1% Tasas)" });
            }

            await client.query("UPDATE accounts SET balance = balance - $1 WHERE iban = $2", [total, fromIban]);
            await client.query("UPDATE accounts SET balance = balance + $1 WHERE iban = $2", [amount, toIban]);
            await client.query("UPDATE accounts SET balance = balance + $1 WHERE iban = $2", [tax, BANK_IBAN]);
            await client.query("INSERT INTO transactions (id, amount, sender_iban, receiver_iban, description, type, tax, status, date) VALUES ($1, $2, $3, $4, $5, $6, $7, 'COMPLETED', NOW())", 
                [`tx-${Date.now()}`, amount, fromIban, toIban, description, type || 'TRANSFER', tax]);

            await client.query("COMMIT");
            return res.status(200).json({ success: true });
        }

        // --- PAYROLL ---
        if (action === 'PAY_PAYROLL') {
            const { companyId, month, year } = params;
            await client.query("BEGIN");

            const company = (await client.query("SELECT * FROM companies WHERE id = $1", [companyId])).rows[0];
            const employees = (await client.query("SELECT * FROM employees WHERE company_id = $1 AND status = 'ACTIVE'", [companyId])).rows;

            if (!company || employees.length === 0) { await client.query("ROLLBACK"); return res.status(400).json({ error: "No hay empleados activos para procesar" }); }

            let totalCompanyCost = 0;
            for (const emp of employees) {
                const base = parseFloat(emp.salary);
                const employerTax = base * 0.075;
                const employeeRet = base * 0.075;
                const net = base - employeeRet;
                const cost = base + employerTax;
                totalCompanyCost += cost;

                // Pago al empleado
                await client.query("UPDATE accounts SET balance = balance + $1 WHERE iban = $2", [net, emp.iban]);
                // Pago al estado (ambas partes)
                await client.query("UPDATE accounts SET balance = balance + $1 WHERE iban = $2", [employerTax + employeeRet, BANK_IBAN]);
                // Registro TX
                await client.query("INSERT INTO transactions (id, amount, sender_iban, receiver_iban, description, type, tax, status) VALUES ($1, $2, $3, $4, $5, 'PAYROLL', $6, 'COMPLETED')",
                    [`pay-${Date.now()}-${emp.id}`, net, company.iban, emp.iban, `Nómina ${month}/${year}`, employerTax + employeeRet]);
            }

            const companyAcc = await client.query("SELECT balance FROM accounts WHERE iban = $1 FOR UPDATE", [company.iban]);
            if (parseFloat(companyAcc.rows[0].balance) < totalCompanyCost) {
                await client.query("ROLLBACK");
                return res.status(400).json({ error: "Saldo insuficiente para liquidar todas las nóminas" });
            }

            await client.query("UPDATE accounts SET balance = balance - $1 WHERE iban = $2", [totalCompanyCost, company.iban]);
            await client.query("INSERT INTO payroll_history (id, company_id, month, year, total_amount, employee_count, processed_at, total_taxes) VALUES ($1, $2, $3, $4, $5, $6, NOW(), $7)",
                [`ph-${Date.now()}`, companyId, month, year, totalCompanyCost, employees.length, totalCompanyCost * 0.15]);

            await client.query("COMMIT");
            return res.status(200).json({ success: true });
        }

        // --- ADMIN ACTIONS ---
        if (action === 'ADMIN_GET_STATE') {
            const users = (await client.query("SELECT * FROM users ORDER BY created_at DESC")).rows;
            const txs = (await client.query("SELECT * FROM transactions ORDER BY date DESC LIMIT 200")).rows;
            const accounts = (await client.query("SELECT * FROM accounts")).rows;
            const m0 = accounts.reduce((acc: number, curr: any) => acc + parseFloat(curr.balance), 0);
            return res.status(200).json(formatResponse({ users, transactions: txs, allAccounts: accounts, m0 }));
        }

        if (action === 'ADMIN_REVERT_TX') {
            const { transactionId } = params;
            await client.query("BEGIN");
            const tx = (await client.query("SELECT * FROM transactions WHERE id = $1", [transactionId])).rows[0];
            if (!tx || tx.status === 'REVERTED') { await client.query("ROLLBACK"); return res.status(400).json({ error: "TX no válida o ya revertida" }); }

            const totalAmount = parseFloat(tx.amount) + parseFloat(tx.tax);
            // Devolver al emisor
            await client.query("UPDATE accounts SET balance = balance + $1 WHERE iban = $2", [totalAmount, tx.sender_iban]);
            // Retirar del receptor
            await client.query("UPDATE accounts SET balance = balance - $1 WHERE iban = $2", [tx.amount, tx.receiver_iban]);
            // Retirar del estado (la tasa)
            await client.query("UPDATE accounts SET balance = balance - $1 WHERE iban = $2", [tx.tax, BANK_IBAN]);
            // Marcar como revertida
            await client.query("UPDATE transactions SET status = 'REVERTED', description = '[REVERTIDA] ' || description WHERE id = $1", [transactionId]);

            await client.query("COMMIT");
            return res.status(200).json({ success: true });
        }

        if (action === 'ADMIN_MINT') {
            const { amount, reason } = params;
            // El minting inyecta dinero en la cuenta del estado (Tesoro)
            await client.query("UPDATE accounts SET balance = balance + $1 WHERE iban = $2", [amount, BANK_IBAN]);
            await client.query("INSERT INTO transactions (id, amount, sender_iban, receiver_iban, description, type, status) VALUES ($1, $2, 'SYSTEM', $3, $4, 'MINT', 'COMPLETED')",
                [`mint-${Date.now()}`, amount, BANK_IBAN, `Emisión Monetaria: ${reason}`]);
            return res.status(200).json({ success: true });
        }

        if (action === 'ADMIN_GENERATE_MONTHLY_TAXES') {
            const { month, year } = params;
            // Simulador de recaudación IRM masiva basada en saldos medios/actuales
            const accounts = (await client.query("SELECT * FROM accounts WHERE balance > 1000")).rows;
            let total = 0;
            for (const acc of accounts) {
                const tax = parseFloat(acc.balance) * 0.02; // Tasa fija del 2% para la recaudación masiva
                await client.query("UPDATE accounts SET balance = balance - $1 WHERE id = $2", [tax, acc.id]);
                await client.query("UPDATE accounts SET balance = balance + $1 WHERE iban = $2", [tax, BANK_IBAN]);
                await client.query("INSERT INTO transactions (id, amount, sender_iban, receiver_iban, description, type, status) VALUES ($1, $2, $3, $4, $5, 'IRM_TAX', 'COMPLETED')",
                    [`tax-${Date.now()}-${acc.id}`, tax, acc.iban, BANK_IBAN, `IRM Mensual ${month}/${year}`]);
                total += tax;
            }
            return res.status(200).json({ success: true, total });
        }

        return res.status(200).json({ success: true });

    } catch (e: any) {
        if (client) await client.query("ROLLBACK");
        return res.status(500).json({ error: e.message });
    } finally {
        if (client) client.release();
    }
}

import React, { createContext, useContext, useState, ReactNode, useEffect, useCallback } from 'react';
import { User, Account, Transaction, Company, AppNotification, Product, Employee, Card, Contact, TaxConfig, ShareRequest, LootBox, LootItem, CardDesign, ApiUsageLog, PayrollHistory, UserSubscription, SubscriptionPlan } from '../types';
import { jsPDF } from 'jspdf';
import 'jspdf-autotable';

interface BankContextType {
  currentUser: User | null;
  userAccounts: Account[];
  transactions: Transaction[];
  notifications: AppNotification[];
  companies: Company[];
  cards: Card[];
  contacts: Contact[];
  lootBoxes: LootBox[];
  taxConfig: TaxConfig;
  login: (dip: string, pass: string) => Promise<{ success: boolean; error?: string }>;
  loginWithPlacetaID: (userData: any) => Promise<{ success: boolean; error?: string }>;
  logout: () => void;
  fetchData: (userId: string) => Promise<void>;
  transfer: (fromIban: string, toIban: string, amount: number, description: string, type?: string) => Promise<void>;
  companyTransfer: (companyId: string, toIban: string, amount: number, description: string) => Promise<void>;
  addNotification: (message: string, type: 'success' | 'error' | 'info') => void;
  generatePDF: (type: string, data: any) => void;
  getAge: (birthDate?: string) => number;
  saveContact: (name: string, iban: string) => Promise<void>;
  deleteContact: (id: string) => Promise<void>;
  adminGetState: () => Promise<any>;
  adminRevertTransaction: (id: string) => Promise<void>;
  adminUpdateUserStatus: (userId: string, isBlocked: boolean) => Promise<void>;
  adminUpdateUserBirthDate: (userId: string, birthDate: string) => Promise<void>;
  adminMint: (amount: number, reason: string) => Promise<void>;
  adminGenerateMonthlyTaxes: (month: number, year: number) => Promise<any>;
  payPayroll: (companyId: string, month: string, year: string) => Promise<void>;
  updateEmployees: (companyId: string, employees: Employee[]) => Promise<void>;
  updateCatalog: (companyId: string, products: Product[]) => Promise<void>;
  getPayrollHistory: (companyId: string) => Promise<PayrollHistory[]>;
  triggerHaptic: (pattern?: 'light' | 'medium' | 'heavy' | 'success' | 'error') => void;
  updateSelfBirthDate: (birthDate: string) => Promise<void>;
}

const BankContext = createContext<BankContextType | undefined>(undefined);

export const BankProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [userAccounts, setUserAccounts] = useState<Account[]>([]);
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [notifications, setNotifications] = useState<AppNotification[]>([]);
  const [companies, setCompanies] = useState<Company[]>([]);
  const [cards, setCards] = useState<Card[]>([]);
  const [contacts, setContacts] = useState<Contact[]>([]);
  const [lootBoxes, setLootBoxes] = useState<LootBox[]>([]);

  const [taxConfig] = useState<TaxConfig>({ vatRate: 12, transferRate: 1, companyTaxRate: 25, lotteryRate: 20 });

  const triggerHaptic = (pattern: 'light' | 'medium' | 'heavy' | 'success' | 'error' = 'light') => {
    if (typeof navigator !== 'undefined' && navigator.vibrate) {
        switch (pattern) {
            case 'light': navigator.vibrate(5); break;
            case 'medium': navigator.vibrate(15); break;
            case 'heavy': navigator.vibrate(30); break;
            case 'success': navigator.vibrate([10, 30, 10]); break;
            case 'error': navigator.vibrate([30, 50, 30, 50, 30]); break;
        }
    }
  };

  const apiCall = async (body: any) => {
    const res = await fetch('/api', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(body)
    });
    const data = await res.json();
    if (!res.ok) throw new Error(data.error || 'Fallo en la conexión');
    return data;
  };

  const fetchData = useCallback(async (userId: string) => {
    if (!userId) return;
    try {
      const data = await apiCall({ action: 'GET_INITIAL_DATA', userId });
      setUserAccounts(data.accounts);
      setTransactions(data.transactions);
      setCompanies(data.companies);
      setCards(data.cards || []);
      setContacts(data.contacts || []);
      setLootBoxes(data.lootBoxes || []);
    } catch (e) { console.error(e); }
  }, []);

  const login = async (dip: string, pass: string) => {
    try {
      const data = await apiCall({ action: 'AUTH', dip, password: pass });
      if (data.user) {
        setCurrentUser(data.user);
        await fetchData(data.user.id);
        return { success: true };
      }
      return { success: false, error: "Identidad no válida" };
    } catch (e: any) { return { success: false, error: e.message }; }
  };

  const loginWithPlacetaID = async (userData: any) => {
    try {
      const data = await apiCall({ action: 'AUTH_PLACETAID', userData });
      if (data.user) {
        setCurrentUser(data.user);
        await fetchData(data.user.id);
        return { success: true };
      }
      return { success: false, error: "Fallo SIDS" };
    } catch (e: any) { return { success: false, error: e.message }; }
  };

  const logout = () => { setCurrentUser(null); setUserAccounts([]); setTransactions([]); setNotifications([]); };

  const transfer = async (fromIban: string, toIban: string, amount: number, description: string, type = 'TRANSFER') => {
    await apiCall({ action: 'TRANSFER', fromIban, toIban, amount, description, type });
    if (currentUser?.id) await fetchData(currentUser.id);
    addNotification(`Operación firmada con éxito`, "success");
  };

  const companyTransfer = async (companyId: string, toIban: string, amount: number, description: string) => {
      await apiCall({ action: 'COMPANY_TRANSFER', companyId, toIban, amount, description });
      if (currentUser?.id) await fetchData(currentUser.id);
      addNotification(`Giro corporativo ejecutado`, "success");
  };

  const addNotification = (message: string, type: any) => {
    const id = Date.now().toString();
    setNotifications(prev => [...prev, { id, message, type }]);
    if(!document.hidden) triggerHaptic(type === 'error' ? 'error' : 'light');
    setTimeout(() => setNotifications(prev => prev.filter(n => n.id !== id)), 4000);
  };

  const saveContact = async (name: string, iban: string) => { 
      if(currentUser?.id) { 
          await apiCall({action: 'SAVE_CONTACT', userId: currentUser.id, name, iban}); 
          await fetchData(currentUser.id); 
          addNotification("Contacto actualizado en agenda", "success");
      }
  };
  const deleteContact = async (id: string) => { 
      await apiCall({action: 'DELETE_CONTACT', contactId: id}); 
      if(currentUser?.id) await fetchData(currentUser.id); 
      addNotification("Contacto eliminado", "info");
  };

  const adminGetState = () => apiCall({ action: 'ADMIN_GET_STATE' });
  const adminRevertTransaction = async (transactionId: string) => {
      await apiCall({ action: 'ADMIN_REVERT_TX', transactionId });
      addNotification("Transacción revertida", "success");
  };
  const adminUpdateUserStatus = async (userId: string, isBlocked: boolean) => {
      await apiCall({ action: 'ADMIN_UPDATE_USER_STATUS', userId, isBlocked });
      addNotification(`Ciudadano ${isBlocked ? 'Bloqueado' : 'Desbloqueado'}`, "info");
  };
  const adminUpdateUserBirthDate = (userId: string, birthDate: string) => apiCall({ action: 'ADMIN_UPDATE_USER_BIRTHDATE', userId, birthDate });
  const adminMint = async (amount: number, reason: string) => {
      await apiCall({ action: 'ADMIN_MINT', amount, reason });
      addNotification("Masa monetaria actualizada", "success");
  };
  const adminGenerateMonthlyTaxes = (month: number, year: number) => apiCall({ action: 'ADMIN_GENERATE_MONTHLY_TAXES', month, year });

  const payPayroll = async (companyId: string, month: string, year: string) => {
      await apiCall({ action: 'PAY_PAYROLL', companyId, month, year });
      if (currentUser?.id) await fetchData(currentUser.id);
      addNotification("Nóminas liquidadas", "success");
  };
  const updateEmployees = async (companyId: string, employees: Employee[]) => {
      await apiCall({ action: 'UPDATE_EMPLOYEES', companyId, employees });
      if (currentUser?.id) await fetchData(currentUser.id);
  };
  const updateCatalog = async (companyId: string, products: Product[]) => {
      await apiCall({ action: 'UPDATE_CATALOG', companyId, products });
      if (currentUser?.id) await fetchData(currentUser.id);
  };
  const getPayrollHistory = (companyId: string) => apiCall({ action: 'GET_PAYROLL_HISTORY', companyId });

  const updateSelfBirthDate = async (birthDate: string) => {
      if (!currentUser?.id) return;
      await apiCall({ action: 'ADMIN_UPDATE_USER_BIRTHDATE', userId: currentUser.id, birthDate });
      setCurrentUser(prev => prev ? { ...prev, birthDate } : null);
      addNotification("Identidad sincronizada", "success");
  };

  const getAge = (birthDate?: string) => {
    if (!birthDate) return 0;
    const today = new Date();
    const birth = new Date(birthDate);
    if (isNaN(birth.getTime())) return 0;
    let age = today.getFullYear() - birth.getFullYear();
    const m = today.getMonth() - birth.getMonth();
    if (m < 0 || (m === 0 && today.getDate() < birth.getDate())) age--;
    return age;
  };

  const generatePDF = (type: string, data: any) => {
      const doc = new jsPDF() as any;
      const primaryColor = [15, 23, 42]; // Slate 900

      // Header Institucional
      doc.setFillColor(...primaryColor);
      doc.rect(0, 0, 210, 40, 'F');
      doc.setTextColor(255, 255, 255);
      doc.setFont("helvetica", "bold");
      doc.setFontSize(22);
      doc.text("BANCO DE LA PLACETA", 20, 25);
      doc.setFontSize(10);
      doc.text("REGISTRO CENTRAL SIDS — CAPÍTULO 1", 20, 32);

      doc.setTextColor(...primaryColor);
      doc.setFontSize(14);
      doc.text(type.replace(/_/g, ' '), 20, 55);
      doc.setDrawColor(200, 200, 200);
      doc.line(20, 58, 190, 58);

      doc.setFontSize(10);
      doc.setFont("helvetica", "normal");

      let y = 70;
      Object.entries(data).forEach(([key, val]: [string, any]) => {
          doc.setFont("helvetica", "bold");
          doc.text(`${key.toUpperCase()}:`, 20, y);
          doc.setFont("helvetica", "normal");
          doc.text(String(val), 70, y);
          y += 10;
      });

      doc.setFontSize(8);
      doc.setTextColor(150, 150, 150);
      doc.text(`Documento verificado digitalmente el ${new Date().toLocaleString()}`, 20, 280);
      doc.text(`ID de Operación: ${Math.random().toString(36).substring(2, 15).toUpperCase()}`, 20, 285);

      doc.save(`banco_placeta_${type.toLowerCase()}_${Date.now()}.pdf`);
  };

  return (
    <BankContext.Provider value={{
      currentUser, userAccounts, transactions, notifications, companies, cards, contacts, lootBoxes, taxConfig,
      login, loginWithPlacetaID, logout, fetchData, transfer, companyTransfer, addNotification, generatePDF, getAge,
      saveContact, deleteContact, adminGetState, adminRevertTransaction, adminUpdateUserStatus, adminUpdateUserBirthDate, adminMint, adminGenerateMonthlyTaxes,
      payPayroll, updateEmployees, updateCatalog, getPayrollHistory, triggerHaptic, updateSelfBirthDate
    }}>
      {children}
    </BankContext.Provider>
  );
};

export const useBank = () => {
  const context = useContext(BankContext);
  if (!context) throw new Error('BankContext missing');
  return context;
};

import React, { useState, useMemo, useEffect } from 'react';
import { useBank } from '../context/BankContext';
