import { Pool } from '@neondatabase/serverless';

let pool: any = null;
const getPool = () => {
  if (!pool) {
    if (!process.env.DATABASE_URL) throw new Error('DATABASE_URL is missing');
    pool = new (Pool as any)({ connectionString: process.env.DATABASE_URL });
  }
  return pool;
};

const BANK_IBAN = 'PL0000000000000000000000';

const formatResponse = (obj: any): any => {
    if (obj === null || obj === undefined) return obj;
    if (obj instanceof Date) return obj.toISOString();
    if (Array.isArray(obj)) return obj.map(formatResponse);
    if (typeof obj !== 'object') return obj;
    const newObj: any = {};
    for (const key in obj) {
        const newKey = key.replace(/_([a-z])/g, (g) => g[1].toUpperCase());
        let value = obj[key];
        const numericFields = ['balance', 'amount', 'price', 'capital', 'stockValue', 'salary', 'tax', 'prizeValue'];
        if (numericFields.includes(newKey) && (typeof value === 'string' || value === null)) {
            value = parseFloat(value || '0');
        }
        newObj[newKey] = formatResponse(value);
    }
    return newObj;
};

export default async function handler(req: any, res: any) {
    let client: any;
    res.setHeader('Content-Type', 'application/json');
    res.setHeader('Access-Control-Allow-Origin', '*');
    res.setHeader('Access-Control-Allow-Methods', 'POST, OPTIONS');
    res.setHeader('Access-Control-Allow-Headers', 'Content-Type');

    if (req.method === 'OPTIONS') return res.status(200).end();

    try {
        const { action, ...params } = req.body || {};
        client = await getPool().connect();

        // AUTH & SYNC
        if (action === 'AUTH') {
            const { dip, password } = params;
            const userRes = await client.query("SELECT * FROM users WHERE UPPER(dip) = $1 AND password_hash = $2", [dip.toUpperCase().trim(), password]);
            if (userRes.rows.length === 0) return res.status(401).json({ error: "Identidad SIDS no válida" });
            return res.status(200).json({ success: true, user: formatResponse(userRes.rows[0]) });
        }

        if (action === 'GET_INITIAL_DATA') {
            const { userId } = params;
            const accounts = (await client.query("SELECT * FROM accounts WHERE owner_id = $1 OR $1 = ANY(shared_with)", [userId])).rows;
            const companies = (await client.query("SELECT * FROM companies")).rows;
            let contacts = []; try { contacts = (await client.query("SELECT * FROM contacts WHERE user_id = $1", [userId])).rows; } catch(e){}
            const ibans = accounts.map((a: any) => a.iban);
            let txs = [];
            if (ibans.length > 0) {
                const placeholders = ibans.map((_, i) => `$${i + 1}`).join(',');
                txs = (await client.query(`SELECT * FROM transactions WHERE sender_iban IN (${placeholders}) OR receiver_iban IN (${placeholders}) ORDER BY date DESC LIMIT 50`, ibans)).rows;
            }
            return res.status(200).json(formatResponse({ accounts, companies, transactions: txs, contacts }));
        }

        // CONTACTS
        if (action === 'SAVE_CONTACT') {
            const { userId, name, iban } = params;
            await client.query("INSERT INTO contacts (id, user_id, name, iban) VALUES ($1, $2, $3, $4) ON CONFLICT (user_id, iban) DO UPDATE SET name = $3", 
                [`cnt-${Date.now()}`, userId, name, iban.toUpperCase()]);
            return res.status(200).json({ success: true });
        }
        if (action === 'DELETE_CONTACT') {
            await client.query("DELETE FROM contacts WHERE id = $1", [params.contactId]);
            return res.status(200).json({ success: true });
        }

        // ADMIN CORE
        if (action === 'ADMIN_GET_STATE') {
            const users = (await client.query("SELECT * FROM users ORDER BY created_at DESC")).rows;
            const txs = (await client.query("SELECT * FROM transactions ORDER BY date DESC LIMIT 200")).rows;
            const accounts = (await client.query("SELECT * FROM accounts")).rows;
            const m0 = accounts.reduce((acc: number, curr: any) => acc + parseFloat(curr.balance), 0);
            return res.status(200).json(formatResponse({ users, transactions: txs, allAccounts: accounts, m0 }));
        }

        if (action === 'ADMIN_REVERT_TX') {
            const { transactionId } = params;
            await client.query("BEGIN");
            const txRes = await client.query("SELECT * FROM transactions WHERE id = $1", [transactionId]);
            if (txRes.rows.length === 0) { await client.query("ROLLBACK"); return res.status(404).json({ error: "TX no encontrada" }); }
            const tx = txRes.rows[0];
            if (tx.status === 'REVERTED') { await client.query("ROLLBACK"); return res.status(400).json({ error: "TX ya revertida" }); }

            const amount = parseFloat(tx.amount);
            const tax = parseFloat(tx.tax || '0');

            // Revertir saldos
            await client.query("UPDATE accounts SET balance = balance + $1 WHERE iban = $2", [amount + tax, tx.sender_iban]);
            await client.query("UPDATE accounts SET balance = balance - $1 WHERE iban = $2", [amount, tx.receiver_iban]);
            await client.query("UPDATE accounts SET balance = balance - $1 WHERE iban = $2", [tax, BANK_IBAN]);
            await client.query("UPDATE transactions SET status = 'REVERTED', description = '[REVERTIDA] ' || description WHERE id = $1", [transactionId]);

            await client.query("COMMIT");
            return res.status(200).json({ success: true });
        }

        if (action === 'ADMIN_MINT') {
            const { amount, reason } = params;
            await client.query("UPDATE accounts SET balance = balance + $1 WHERE iban = $2", [amount, BANK_IBAN]);
            await client.query("INSERT INTO transactions (id, amount, sender_iban, receiver_iban, description, type, status) VALUES ($1, $2, 'SYSTEM', $3, $4, 'MINT', 'COMPLETED')",
                [`mint-${Date.now()}`, amount, BANK_IBAN, `EMISIÓN GUBERNAMENTAL: ${reason}`]);
            return res.status(200).json({ success: true });
        }

        // FISCAL & PAYROLL
        if (action === 'PAY_PAYROLL') {
            const { companyId, month, year } = params;
            await client.query("BEGIN");
            const employees = (await client.query("SELECT * FROM employees WHERE company_id = $1 AND status = 'ACTIVE'", [companyId])).rows;
            const company = (await client.query("SELECT iban FROM companies WHERE id = $1", [companyId])).rows[0];

            let totalCost = 0;
            for (const emp of employees) {
                const base = parseFloat(emp.salary);
                const empTax = base * 0.075; // Cuota patronal
                const net = base * 0.925; // Retención empleado
                totalCost += (base + empTax);

                await client.query("UPDATE accounts SET balance = balance + $1 WHERE iban = $2", [net, emp.iban]);
                await client.query("UPDATE accounts SET balance = balance + $1 WHERE iban = $2", [empTax + (base * 0.075), BANK_IBAN]);
                await client.query("INSERT INTO transactions (id, amount, sender_iban, receiver_iban, description, type, tax) VALUES ($1, $2, $3, $4, $5, 'PAYROLL', $6)",
                    [`pay-${Date.now()}-${emp.id}`, net, company.iban, emp.iban, `Nómina ${month}/${year}`, empTax * 2]);
            }
            await client.query("UPDATE accounts SET balance = balance - $1 WHERE iban = $2", [totalCost, company.iban]);
            await client.query("INSERT INTO payroll_history (id, company_id, month, year, total_amount, employee_count) VALUES ($1, $2, $3, $4, $5, $6)",
                [`ph-${Date.now()}`, companyId, month, year, totalCost, employees.length]);
            await client.query("COMMIT");
            return res.status(200).json({ success: true });
        }

        if (action === 'GET_FISCAL_PROJECTION') {
            const { userId, month, year } = params;
            const accounts = (await client.query("SELECT * FROM accounts WHERE owner_id = $1", [userId])).rows;
            const results = [];
            for (const acc of accounts) {
                const income = (await client.query("SELECT SUM(amount) FROM transactions WHERE receiver_iban = $1 AND EXTRACT(MONTH FROM date) = $2 AND EXTRACT(YEAR FROM date) = $3", [acc.iban, month, year])).rows[0].sum || 0;
                const expenses = (await client.query("SELECT SUM(amount) FROM transactions WHERE sender_iban = $1 AND EXTRACT(MONTH FROM date) = $2 AND EXTRACT(YEAR FROM date) = $3", [acc.iban, month, year])).rows[0].sum || 0;
                const flow = parseFloat(income) - parseFloat(expenses);
                const ia = acc.balance > 0 ? flow / parseFloat(acc.balance) : 0;
                results.push({ accountId: acc.id, alias: acc.alias, iban: acc.iban, income: parseFloat(income), expenses: parseFloat(expenses), ia, projectedTax: Math.max(0, ia * 100), currentDebt: 0 });
            }
            return res.status(200).json(formatResponse(results));
        }

        return res.status(200).json({ success: true });
    } catch (e: any) {
        if (client) await client.query("ROLLBACK");
        return res.status(500).json({ error: e.message });
    } finally {
        if (client) client.release();
    }
}

import React, { createContext, useContext, useState, ReactNode, useEffect, useCallback } from 'react';
import { User, Account, Transaction, Company, AppNotification, Product, Employee, Card, Contact, TaxConfig, ShareRequest, LootBox, LootItem, CardDesign, ApiUsageLog, PayrollHistory, UserSubscription, SubscriptionPlan } from '../types';
import { jsPDF } from 'jspdf';
import 'jspdf-autotable';

interface BankContextType {
  currentUser: User | null;
  userAccounts: Account[];
  transactions: Transaction[];
  notifications: AppNotification[];
  companies: Company[];
  cards: Card[];
  contacts: Contact[];
  lootBoxes: LootBox[];
  taxConfig: TaxConfig;
  login: (dip: string, pass: string) => Promise<{ success: boolean; error?: string }>;
  loginWithPlacetaID: (userData: any) => Promise<{ success: boolean; error?: string }>;
  logout: () => void;
  fetchData: (userId: string) => Promise<void>;
  transfer: (fromIban: string, toIban: string, amount: number, description: string, type?: string) => Promise<void>;
  companyTransfer: (companyId: string, toIban: string, amount: number, description: string) => Promise<void>;
  addNotification: (message: string, type: 'success' | 'error' | 'info') => void;
  generatePDF: (type: string, data: any) => void;
  getAge: (birthDate?: string) => number;
  saveContact: (name: string, iban: string) => Promise<void>;
  deleteContact: (id: string) => Promise<void>;
