  adminUpdateUserBirthDate: (userId: string, birthDate: string) => Promise<void>;
  adminMint: (amount: number, reason: string) => Promise<void>;
  adminGenerateMonthlyTaxes: (month: number, year: number) => Promise<any>;
  payPayroll: (companyId: string, month: string, year: string) => Promise<void>;
  updateEmployees: (companyId: string, employees: Employee[]) => Promise<void>;
  updateCatalog: (companyId: string, products: Product[]) => Promise<void>;
  getPayrollHistory: (companyId: string) => Promise<PayrollHistory[]>;
  triggerHaptic: (pattern?: 'light' | 'medium' | 'heavy' | 'success' | 'error') => void;
  updateSelfBirthDate: (birthDate: string) => Promise<void>;
  payCitizenTax: (accountId: string, amount: number, description: string) => Promise<void>;
  getFiscalProjection: (month: number, year: number) => Promise<any[]>;
}

const BankContext = createContext<BankContextType | undefined>(undefined);

export const BankProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [userAccounts, setUserAccounts] = useState<Account[]>([]);
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [notifications, setNotifications] = useState<AppNotification[]>([]);
  const [companies, setCompanies] = useState<Company[]>([]);
  const [cards, setCards] = useState<Card[]>([]);
  const [contacts, setContacts] = useState<Contact[]>([]);
  const [lootBoxes, setLootBoxes] = useState<LootBox[]>([]);

  const [taxConfig] = useState<TaxConfig>({ vatRate: 12, transferRate: 1, companyTaxRate: 25, lotteryRate: 20 });

  const triggerHaptic = (pattern: 'light' | 'medium' | 'heavy' | 'success' | 'error' = 'light') => {
    if (typeof navigator !== 'undefined' && navigator.vibrate) {
        switch (pattern) {
            case 'light': navigator.vibrate(5); break;
            case 'medium': navigator.vibrate(15); break;
            case 'heavy': navigator.vibrate(30); break;
            case 'success': navigator.vibrate([10, 30, 10]); break;
            case 'error': navigator.vibrate([30, 50, 30, 50, 30]); break;
        }
    }
  };

  const apiCall = async (body: any) => {
    const res = await fetch('/api', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(body)
    });
    const data = await res.json();
    if (!res.ok) throw new Error(data.error || 'Fallo en la comunicación con el Nodo Central');
    return data;
  };

  const fetchData = useCallback(async (userId: string) => {
    if (!userId) return;
    try {
      const data = await apiCall({ action: 'GET_INITIAL_DATA', userId });
      setUserAccounts(data.accounts || []);
      setTransactions(data.transactions || []);
      setCompanies(data.companies || []);
      setCards(data.cards || []);
      setContacts(data.contacts || []);
      setLootBoxes(data.lootBoxes || []);
    } catch (e) { console.error(e); }
  }, []);

  const login = async (dip: string, pass: string) => {
    try {
      const data = await apiCall({ action: 'AUTH', dip, password: pass });
      if (data.user) {
        setCurrentUser(data.user);
        await fetchData(data.user.id);
        return { success: true };
      }
      return { success: false, error: "Identidad no reconocida" };
    } catch (e: any) { return { success: false, error: e.message }; }
  };

  const loginWithPlacetaID = async (userData: any) => {
    try {
      const data = await apiCall({ action: 'AUTH_PLACETAID', userData });
      if (data.user) {
        setCurrentUser(data.user);
        await fetchData(data.user.id);
        return { success: true };
      }
      return { success: false, error: "Fallo en pasarela SIDS" };
    } catch (e: any) { return { success: false, error: e.message }; }
  };

  const logout = () => { setCurrentUser(null); setUserAccounts([]); setTransactions([]); setNotifications([]); };

  const transfer = async (fromIban: string, toIban: string, amount: number, description: string, type = 'TRANSFER') => {
    await apiCall({ action: 'TRANSFER', fromIban, toIban, amount, description, type });
    if (currentUser?.id) await fetchData(currentUser.id);
    addNotification(`Operación firmada en Ledger`, "success");
  };

  const companyTransfer = async (companyId: string, toIban: string, amount: number, description: string) => {
      await apiCall({ action: 'COMPANY_TRANSFER', companyId, toIban, amount, description });
      if (currentUser?.id) await fetchData(currentUser.id);
      addNotification(`Giro corporativo ejecutado`, "success");
  };

  const addNotification = (message: string, type: any) => {
    const id = Date.now().toString();
    setNotifications(prev => [...prev, { id, message, type }]);
    if(!document.hidden) triggerHaptic(type === 'error' ? 'error' : 'light');
    setTimeout(() => setNotifications(prev => prev.filter(n => n.id !== id)), 4000);
  };

  const saveContact = async (name: string, iban: string) => { 
      if(currentUser?.id) { 
          await apiCall({action: 'SAVE_CONTACT', userId: currentUser.id, name, iban}); 
          await fetchData(currentUser.id); 
          addNotification("Agenda actualizada", "success");
      }
  };
  const deleteContact = async (id: string) => { 
      await apiCall({action: 'DELETE_CONTACT', contactId: id}); 
      if(currentUser?.id) await fetchData(currentUser.id); 
      addNotification("Contacto eliminado", "info");
  };

  const adminGetState = () => apiCall({ action: 'ADMIN_GET_STATE' });
  const adminRevertTransaction = async (transactionId: string) => {
      await apiCall({ action: 'ADMIN_REVERT_TX', transactionId });
      addNotification("Operación revertida con éxito", "success");
  };
  const adminUpdateUserStatus = async (userId: string, isBlocked: boolean) => {
      await apiCall({ action: 'ADMIN_UPDATE_USER_STATUS', userId, isBlocked });
      addNotification(`Estado de ciudadano actualizado`, "info");
  };
  const adminUpdateUserBirthDate = (userId: string, birthDate: string) => apiCall({ action: 'ADMIN_UPDATE_USER_BIRTHDATE', userId, birthDate });
  const adminMint = async (amount: number, reason: string) => {
      await apiCall({ action: 'ADMIN_MINT', amount, reason });
      addNotification("Masa monetaria inyectada", "success");
  };
  const adminGenerateMonthlyTaxes = (month: number, year: number) => apiCall({ action: 'ADMIN_GENERATE_MONTHLY_TAXES', month, year });

  const payPayroll = async (companyId: string, month: string, year: string) => {
      await apiCall({ action: 'PAY_PAYROLL', companyId, month, year });
      if (currentUser?.id) await fetchData(currentUser.id);
  };
  const updateEmployees = async (companyId: string, employees: Employee[]) => {
      await apiCall({ action: 'UPDATE_EMPLOYEES', companyId, employees });
      if (currentUser?.id) await fetchData(currentUser.id);
  };
  const updateCatalog = async (companyId: string, products: Product[]) => {
      await apiCall({ action: 'UPDATE_CATALOG', companyId, products });
      if (currentUser?.id) await fetchData(currentUser.id);
  };
  const getPayrollHistory = (companyId: string) => apiCall({ action: 'GET_PAYROLL_HISTORY', companyId });
  const getFiscalProjection = (month: number, year: number) => apiCall({ action: 'GET_FISCAL_PROJECTION', userId: currentUser?.id, month, year });
  const payCitizenTax = async (accountId: string, amount: number, description: string) => {
      await apiCall({ action: 'TRANSFER', fromIban: userAccounts.find(a=>a.id===accountId)?.iban, toIban: 'PL0000000000000000000000', amount, description, type: 'TAX' });
      if (currentUser?.id) await fetchData(currentUser.id);
  };

  const updateSelfBirthDate = async (birthDate: string) => {
      if (!currentUser?.id) return;
      await apiCall({ action: 'ADMIN_UPDATE_USER_BIRTHDATE', userId: currentUser.id, birthDate });
      setCurrentUser(prev => prev ? { ...prev, birthDate } : null);
  };

  const getAge = (birthDate?: string) => {
    if (!birthDate) return 0;
    const today = new Date();
    const birth = new Date(birthDate);
    if (isNaN(birth.getTime())) return 0;
    let age = today.getFullYear() - birth.getFullYear();
    const m = today.getMonth() - birth.getMonth();
    if (m < 0 || (m === 0 && today.getDate() < birth.getDate())) age--;
    return age;
  };

  const generatePDF = (type: string, data: any) => {
      const doc = new jsPDF() as any;
      const primaryColor = [15, 23, 42]; 

      doc.setFillColor(...primaryColor);
      doc.rect(0, 0, 210, 45, 'F');
      doc.setTextColor(255, 255, 255);
      doc.setFont("helvetica", "bold");
      doc.setFontSize(24);
      doc.text("BANCO DE LA PLACETA", 20, 28);
      doc.setFontSize(10);
      doc.text("DOCUMENTO OFICIAL REGISTRADO — NODO CENTRAL SIDS", 20, 36);

      doc.setTextColor(...primaryColor);
      doc.setFontSize(16);
      doc.text(type.replace(/_/g, ' '), 20, 65);
      doc.setDrawColor(220, 220, 220);
      doc.line(20, 68, 190, 68);

      doc.setFontSize(11);
      doc.setFont("helvetica", "normal");

      let y = 85;
      Object.entries(data).forEach(([key, val]: [string, any]) => {
          if (typeof val === 'object') return;
          doc.setFont("helvetica", "bold");
          doc.text(`${key.toUpperCase()}:`, 20, y);
          doc.setFont("helvetica", "normal");
          doc.text(String(val), 75, y);
          y += 12;
      });

      doc.setFontSize(8);
      doc.setTextColor(180, 180, 180);
      doc.text(`Hash de Verificación: ${Math.random().toString(36).substring(2, 15).toUpperCase()}`, 20, 275);
      doc.text(`Emitido el ${new Date().toLocaleString()} por la Autoridad Bancaria Competente.`, 20, 280);

      doc.save(`Placeta_Certificado_${type}_${Date.now()}.pdf`);
  };

  return (
    <BankContext.Provider value={{
      currentUser, userAccounts, transactions, notifications, companies, cards, contacts, lootBoxes, taxConfig,
      login, loginWithPlacetaID, logout, fetchData, transfer, companyTransfer, addNotification, generatePDF, getAge,
      saveContact, deleteContact, adminGetState, adminRevertTransaction, adminUpdateUserStatus, adminUpdateUserBirthDate, adminMint, adminGenerateMonthlyTaxes,
      payPayroll, updateEmployees, updateCatalog, getPayrollHistory, triggerHaptic, updateSelfBirthDate, getFiscalProjection, payCitizenTax
    }}>
      {children}
    </BankContext.Provider>
  );
};

export const useBank = () => {
  const context = useContext(BankContext);
  if (!context) throw new Error('BankContext missing');
  return context;
};

