import { Pool } from '@neondatabase/serverless';

let pool: any = null;
const getPool = () => {
  if (!pool) {
    if (!process.env.DATABASE_URL) throw new Error('DATABASE_URL is missing');
    pool = new (Pool as any)({ connectionString: process.env.DATABASE_URL });
  }
  return pool;
};

const BANK_IBAN = 'PL0000000000000000000000';

const formatResponse = (obj: any): any => {
    if (obj === null || obj === undefined) return obj;
    if (obj instanceof Date) return obj.toISOString();
    if (Array.isArray(obj)) return obj.map(formatResponse);
    if (typeof obj !== 'object') return obj;
    const newObj: any = {};
    for (const key in obj) {
        const newKey = key.replace(/_([a-z])/g, (g) => g[1].toUpperCase());
        let value = obj[key];
        const numericFields = ['balance', 'amount', 'price', 'capital', 'stockValue', 'salary', 'tax', 'prizeValue'];
        if (numericFields.includes(newKey) && (typeof value === 'string' || value === null)) {
            value = parseFloat(value || '0');
        }
        newObj[newKey] = formatResponse(value);
    }
    return newObj;
};

export default async function handler(req: any, res: any) {
    let client: any;
    res.setHeader('Content-Type', 'application/json');
    res.setHeader('Access-Control-Allow-Origin', '*');
    res.setHeader('Access-Control-Allow-Methods', 'POST, OPTIONS');
    res.setHeader('Access-Control-Allow-Headers', 'Content-Type');

    if (req.method === 'OPTIONS') return res.status(200).end();

    try {
        const { action, ...params } = req.body || {};
        client = await getPool().connect();

        // --- AUTH ACTIONS ---
        if (action === 'AUTH') {
            const { dip, password } = params;
            const userRes = await client.query("SELECT * FROM users WHERE UPPER(dip) = $1 AND password_hash = $2", [dip.toUpperCase().trim(), password]);
            if (userRes.rows.length === 0) return res.status(401).json({ error: "Credenciales SIDS no válidas" });
            return res.status(200).json({ success: true, user: formatResponse(userRes.rows[0]) });
        }

        if (action === 'AUTH_PLACETAID') {
            const { userData } = params;
            const dip = (userData.dni || userData.dip || userData.id || '').toUpperCase().trim();
            const userRes = await client.query("SELECT * FROM users WHERE UPPER(dip) = $1", [dip]);
            if (userRes.rows.length === 0) return res.status(404).json({ error: "Usuario verificado pero no registrado en el Banco" });
            return res.status(200).json({ success: true, user: formatResponse(userRes.rows[0]) });
        }

        // --- DATA RETRIEVAL ---
        if (action === 'GET_INITIAL_DATA') {
            const { userId } = params;
            const accounts = (await client.query("SELECT * FROM accounts WHERE owner_id = $1 OR $1 = ANY(shared_with)", [userId])).rows;
            const companies = (await client.query("SELECT * FROM companies WHERE owner_id = $1", [userId])).rows;
            const contacts = (await client.query("SELECT * FROM contacts WHERE user_id = $1", [userId])).rows;
            const ibans = (accounts || []).map((a: any) => a.iban);
            let txs = [];
            if (ibans.length > 0) {
                const placeholders = ibans.map((_, i) => `$${i + 1}`).join(',');
                txs = (await client.query(`SELECT * FROM transactions WHERE sender_iban IN (${placeholders}) OR receiver_iban IN (${placeholders}) ORDER BY date DESC LIMIT 50`, ibans)).rows;
            }
            return res.status(200).json(formatResponse({ accounts: accounts || [], companies: companies || [], transactions: txs || [], contacts: contacts || [] }));
        }

        // --- TRANSACTIONAL ACTIONS ---
        if (action === 'TRANSFER') {
            const { fromIban, toIban, amount, description, type } = params;
            await client.query("BEGIN");

            const senderRes = await client.query("SELECT * FROM accounts WHERE iban = $1 FOR UPDATE", [fromIban]);
            if (senderRes.rows.length === 0) throw new Error("Cuenta origen no existe");

            const taxRate = type === 'IRM_TAX' || type === 'TAX' ? 0 : 0.01;
            const totalToDeduct = amount * (1 + taxRate);

            if (senderRes.rows[0].balance < totalToDeduct) throw new Error("Saldo insuficiente (incluyendo tasas)");

            await client.query("UPDATE accounts SET balance = balance - $1 WHERE iban = $2", [totalToDeduct, fromIban]);
            await client.query("UPDATE accounts SET balance = balance + $1 WHERE iban = $2", [amount, toIban]);
            if (taxRate > 0) await client.query("UPDATE accounts SET balance = balance + $1 WHERE iban = $2", [amount * taxRate, BANK_IBAN]);

            const txId = 'TX-' + Math.random().toString(36).substr(2, 9).toUpperCase();
            await client.query("INSERT INTO transactions (id, sender_iban, receiver_iban, amount, description, type, tax, status) VALUES ($1, $2, $3, $4, $5, $6, $7, 'COMPLETED')", 
                [txId, fromIban, toIban, amount, description, type || 'TRANSFER', amount * taxRate]);

            await client.query("COMMIT");
            return res.status(200).json({ success: true, txId });
        }

        if (action === 'COMPANY_TRANSFER') {
            const { companyId, toIban, amount, description } = params;
            const company = (await client.query("SELECT iban FROM companies WHERE id = $1", [companyId])).rows[0];
            if (!company) throw new Error("Empresa no registrada");

            // Reutilizar lógica de transferencia usando el IBAN de la empresa
            return handler({ ...req, body: { action: 'TRANSFER', fromIban: company.iban, toIban, amount, description, type: 'TRANSFER' } }, res);
        }

        // --- PAYROLL (CAP 1) ---
        if (action === 'PAY_PAYROLL') {
            const { companyId, month, year } = params;
            await client.query("BEGIN");
            const companyRes = await client.query("SELECT * FROM companies WHERE id = $1", [companyId]);
            const company = companyRes.rows[0];
            const employees = company.employees;

            let totalCost = 0;
            let totalTaxes = 0;

            for (const emp of employees) {
                const base = parseFloat(emp.salary);
                const employerExtra = base * 0.075;
                const employeeDiscount = base * 0.075;
                const net = base - employeeDiscount;
                const cost = base + employerExtra;
                const stateTax = employerExtra + employeeDiscount;

                // Deducciones y Pagos
                await client.query("UPDATE accounts SET balance = balance - $1 WHERE iban = $2", [cost, company.iban]);
                await client.query("UPDATE accounts SET balance = balance + $1 WHERE iban = $2", [net, emp.iban]);
                await client.query("UPDATE accounts SET balance = balance + $1 WHERE iban = $2", [stateTax, BANK_IBAN]);

                totalCost += cost;
                totalTaxes += stateTax;
            }

            const hId = 'PAY-' + Date.now();
            await client.query("INSERT INTO payroll_history (id, company_id, month, year, total_amount, employee_count, total_taxes) VALUES ($1, $2, $3, $4, $5, $6, $7)",
                [hId, companyId, month, year, totalCost, employees.length, totalTaxes]);

            await client.query("COMMIT");
            return res.status(200).json({ success: true });
        }

        // --- CONTACTS ---
        if (action === 'SAVE_CONTACT') {
            const { userId, name, iban } = params;
            await client.query("INSERT INTO contacts (id, user_id, name, iban) VALUES ($1, $2, $3, $4) ON CONFLICT (user_id, iban) DO UPDATE SET name = $3", 
                ['CON-'+Date.now(), userId, name, iban]);
            return res.status(200).json({ success: true });
        }

        if (action === 'DELETE_CONTACT') {
            const { contactId } = params;
            await client.query("DELETE FROM contacts WHERE id = $1", [contactId]);
            return res.status(200).json({ success: true });
        }

        // --- FISCAL ---
        if (action === 'GET_FISCAL_PROJECTION') {
            const { userId, month, year } = params;
            const accounts = (await client.query("SELECT * FROM accounts WHERE owner_id = $1", [userId])).rows;
            const results = [];
            for (const acc of accounts) {
                const inc = (await client.query("SELECT SUM(amount) FROM transactions WHERE receiver_iban = $1 AND EXTRACT(MONTH FROM date) = $2 AND EXTRACT(YEAR FROM date) = $3", [acc.iban, month, year])).rows[0].sum || 0;
                const exp = (await client.query("SELECT SUM(amount) FROM transactions WHERE sender_iban = $1 AND EXTRACT(MONTH FROM date) = $2 AND EXTRACT(YEAR FROM date) = $3", [acc.iban, month, year])).rows[0].sum || 0;
                const balance = parseFloat(acc.balance);
                const ia = balance > 0 ? (Math.max(0, (parseFloat(inc) - parseFloat(exp)) / balance)) : 0;
                results.push({ accountId: acc.id, alias: acc.alias, iban: acc.iban, income: parseFloat(inc), expenses: parseFloat(exp), ia, projectedTax: ia * balance * 0.05, currentDebt: 0 });
            }
            return res.status(200).json(formatResponse(results));
        }

        if (action === 'LINK_ACCOUNT_TO_COMPANY') {
            const { accountId, companyId } = params;
            await client.query("UPDATE accounts SET company_id = $1, type = 'BUSINESS' WHERE id = $2", [companyId, accountId]);
            return res.status(200).json({ success: true });
        }

        return res.status(400).json({ error: `Acción '${action}' no reconocida por el Nodo SIDS` });
    } catch (e: any) {
        if (client) await client.query("ROLLBACK");
        console.error("CRITICAL SIDS ERROR:", e.message);
        return res.status(500).json({ error: e.message });
    } finally {
        if (client) client.release();
    }
}

