                    <div className="space-y-8"><div className="grid grid-cols-1 md:grid-cols-2 gap-6"><div><label className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-3 block ml-1">Vincular a Cuenta</label><select value={selectedAccId} onChange={e => setSelectedAccId(e.target.value)} className="w-full p-4.5 bg-slate-50 border-2 border-transparent focus:border-brand-500 rounded-2xl font-bold text-sm outline-none transition-all"><option value="">Elegir fondos...</option>{userAccounts.map(a => <option key={a.id} value={a.id}>{a.alias} ({a.balance} Pz)</option>)}</select></div><div><label className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-3 block ml-1">PIN</label><input type="password" maxLength={4} placeholder="4 dígitos" value={cardPin} onChange={e => setCardPin(e.target.value.replace(/\D/g, ''))} className="w-full p-4.5 bg-slate-50 border-2 border-transparent focus:border-brand-500 rounded-2xl font-mono text-center text-2xl font-black outline-none transition-all"/></div></div><div className="pt-6 border-t border-slate-100"><CardDesigner holderName={currentUser?.name || ''} onSave={(d) => { if(selectedAccId && cardPin) requestCard(selectedAccId, currentUser?.name||'', d, cardPin); setShowDesigner(false); }} /></div></div>
                </div>
            </div>
        )}
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { useBank } from '../context/BankContext';
