        {/* EDUCATIONAL MODAL */}
        {showInfo && (
            <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-md z-50 flex items-center justify-center p-4 animate-fade-in" onClick={() => setShowInfo(false)}>
