                <div>
                    <p className="font-black text-emerald-900 text-sm">Mercado Activo</p>
                    <p className="text-[10px] text-emerald-600/80 font-bold uppercase tracking-wider">Actualizado en tiempo real</p>
                </div>
            </div>
