                                  <p className="text-lg font-black text-slate-900">{acc.expenses.toLocaleString()}</p>
                              </div>
                              <div className="bg-slate-50 p-4 rounded-2xl border border-slate-100">
                                  <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest mb-1">IA Calculado</p>
                                  <p className="text-2xl font-black text-slate-900">{ia.toFixed(4)}</p>
                              </div>
                              <div className="bg-brand-600 p-4 rounded-2xl text-white">
