                                  <p className="text-xs font-bold text-slate-700 mt-0.5">IA = (Ingresos Mensuales - Gastos Mensuales) / Saldo Promedio</p>
                              </div>
                          </div>
                      </div>

                      <div className={`lg:w-80 rounded-[2.5rem] p-8 flex flex-col justify-between ${acc.currentDebt > 0 ? 'bg-red-50 border border-red-100' : 'bg-slate-50 border border-slate-100'}`}>
