  // Forms
  const [editingEmployee, setEditingEmployee] = useState<Employee | null>(null);
  const [empForm, setEmpForm] = useState({ name: '', dip: '', salary: '', role: '', iban: '' });

  const [editingProduct, setEditingProduct] = useState<Product | null>(null);
  const [prodForm, setProdForm] = useState({ name: '', price: '', description: '' });

  const [transferForm, setTransferForm] = useState({ sourceIban: '', destIban: '', amount: '', concept: '' });

  // Init
  useEffect(() => {
    if (myCompanies.length > 0 && !selectedCompanyId) {
        // Auto-select first if only one, otherwise keep null to show grid
        if (myCompanies.length === 1) setSelectedCompanyId(myCompanies[0].id);
    }
  }, [myCompanies, selectedCompanyId]);

  const selectedCompany = useMemo(() => companies.find(c => c.id === selectedCompanyId), [companies, selectedCompanyId]);

  // Fetch only accounts explicitly linked to this company
  const companyAccounts = useMemo(() => {
      if(!selectedCompany) return [];
      return userAccounts.filter(a => a.companyId === selectedCompany.id || a.iban === selectedCompany.iban);
  }, [userAccounts, selectedCompany]);

  const totalBalance = useMemo(() => companyAccounts.reduce((acc, curr) => acc + curr.balance, 0), [companyAccounts]);

  useEffect(() => {
    if (selectedCompanyId && currentView === 'EMPLOYEES') {
        getPayrollHistory(selectedCompanyId).then(setPayrollHistory);
    }
  }, [selectedCompanyId, currentView]);

  // --- HANDLERS ---

  const handleTransfer = async () => {
      if(!selectedCompany || !transferForm.destIban || !transferForm.amount) return;
      const source = transferForm.sourceIban || selectedCompany.iban;

      try {
          await companyTransfer(selectedCompany.id, transferForm.destIban, Number(transferForm.amount), transferForm.concept || 'Transferencia Corporativa');
          setShowTransferModal(false);
          setTransferForm({ sourceIban: '', destIban: '', amount: '', concept: '' });
      } catch(e: any) {
          addNotification(e.message, 'error');
      }
  };

  const handlePayrollProcess = async () => {
    if (!selectedCompany) return;
    const now = new Date();
    try {
        await payPayroll(selectedCompany.id, (now.getMonth() + 1).toString(), now.getFullYear().toString());
        setShowPayrollModal(false);
        const h = await getPayrollHistory(selectedCompany.id);
        setPayrollHistory(h);
    } catch (e: any) {
        addNotification(e.message, 'error');
    }
  };

  const handleEmployeeSave = async () => {
      if (!selectedCompany) return;
      const salary = parseFloat(empForm.salary);
      if (!empForm.name || !empForm.dip || isNaN(salary)) { addNotification("Datos inválidos", "error"); return; }

      const updatedEmployees = [...selectedCompany.employees];
      if (editingEmployee) {
          const idx = updatedEmployees.findIndex(e => e.id === editingEmployee.id);
          if (idx !== -1) updatedEmployees[idx] = { ...editingEmployee, ...empForm, salary };
      } else {
          updatedEmployees.push({
              id: `emp-${Date.now()}`,
              ...empForm,
              salary,
              hireDate: new Date().toISOString(),
              status: 'ACTIVE'
          });
      }
      await updateEmployees(selectedCompany.id, updatedEmployees);
      setShowEmployeeModal(false);
      setEmpForm({ name: '', dip: '', salary: '', role: '', iban: '' });
  };

  const handleProductSave = async () => {
      if(!selectedCompany) return;
      const price = parseFloat(prodForm.price);
      if(!prodForm.name || isNaN(price)) { addNotification("Producto inválido", "error"); return; }

      const currentCatalog = selectedCompany.catalog?.products || [];
      let newProducts = [...currentCatalog];

      if(editingProduct) {
          const idx = newProducts.findIndex(p => p.id === editingProduct.id);
          if(idx !== -1) newProducts[idx] = { ...editingProduct, ...prodForm, price };
      } else {
          newProducts.push({
              id: `prod-${Date.now()}`,
              ...prodForm,
              price
          });
      }
      await updateCatalog(selectedCompany.id, newProducts);
      setShowProductModal(false);
      setProdForm({ name: '', price: '', description: '' });
  };

  const handleDeleteProduct = async (id: string) => {
      if(!selectedCompany || !confirm("¿Eliminar producto?")) return;
      const newProducts = (selectedCompany.catalog?.products || []).filter(p => p.id !== id);
      await updateCatalog(selectedCompany.id, newProducts);
  };

  if (!selectedCompany) {
      return (
          <div className="min-h-screen bg-slate-50 flex items-center justify-center p-6 md:p-10 font-sans animate-fade-in">
              <div className="max-w-4xl w-full">
                  <header className="mb-10 flex justify-between items-center">
                    <div>
                        <h2 className="text-3xl md:text-4xl font-black text-slate-900 mb-2 flex items-center gap-3">
                            <Building2 className="text-brand-600" size={36}/> Mis Sociedades
                        </h2>
                        <p className="text-slate-400 font-bold uppercase tracking-widest text-[10px]">Gestión centralizada de activos jurídicos</p>
                    </div>
                    <button 
                        onClick={onSwitchView}
                        className="px-6 py-2.5 bg-white border border-slate-200 rounded-xl font-black text-[10px] uppercase tracking-widest text-slate-500 hover:text-brand-600 hover:border-brand-100 transition-all flex items-center gap-2"
                    >
                        <User size={14}/> Vista Personal
                    </button>
                  </header>

                  <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                      {myCompanies.map(c => (
                          <button 
                            key={c.id} 
                            onClick={() => setSelectedCompanyId(c.id)}
                            className="bg-white p-8 rounded-[2.5rem] border border-slate-100 shadow-soft hover:shadow-xl hover:border-brand-300 transition-all text-left group relative overflow-hidden"
                          >
                                <div className="absolute top-0 right-0 w-32 h-32 bg-slate-50 rounded-full -mr-16 -mt-16 group-hover:bg-brand-50 transition-colors"></div>
                                <div className={`w-14 h-14 rounded-2xl flex items-center justify-center text-white font-black text-2xl mb-6 shadow-lg relative z-10 ${c.isPublic ? 'bg-indigo-600 shadow-indigo-500/20' : 'bg-slate-900 shadow-slate-900/10'}`}>
                                    {c.name.charAt(0)}
                                </div>
                                <h3 className="font-black text-xl text-slate-900 mb-1 truncate relative z-10">{c.name}</h3>
                                <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest relative z-10">{c.isPublic ? 'Sociedad Pública' : 'Sociedad Privada'}</p>
                                <div className="mt-8 flex items-center justify-between relative z-10">
                                    <div className="flex items-center gap-2 text-brand-600 font-bold text-[10px] uppercase tracking-wider">
                                        Gestionar <ChevronRight size={14} />
                                    </div>
                                    <span className="text-[9px] font-mono text-slate-300">{c.nif}</span>
                                </div>
                          </button>
                      ))}
                      <button onClick={onSwitchView} className="p-8 rounded-[2.5rem] border-4 border-dashed border-slate-200 flex flex-col items-center justify-center text-slate-300 hover:text-slate-900 hover:border-slate-300 transition-all gap-4 group">
                          <Plus size={32} className="group-hover:scale-110 transition-transform"/>
                          <span className="font-black text-xs uppercase tracking-widest">Nueva Sociedad</span>
                      </button>
                  </div>
              </div>
          </div>
      );
  }

  return (
    <div className="min-h-screen bg-slate-50 flex w-full font-sans">
        <BusinessSidebar 
            selectedCompany={selectedCompany}
            myCompanies={myCompanies}
            currentView={currentView}
            setView={setCurrentView}
            onSelectCompany={setSelectedCompanyId}
            onSwitchToPersonal={onSwitchToPersonal}
            onLogout={onSwitchView}
        />

        <BusinessMobileNavbar 
             companyName={selectedCompany.name}
             isPublic={selectedCompany.isPublic}
             currentView={currentView}
             setView={setCurrentView}
             onSwitchToPersonal={onSwitchToPersonal}
             onBackToCompanies={() => setSelectedCompanyId(null)}
        />

        <main className="flex-1 md:ml-72 w-full min-h-screen p-4 md:p-10 pb-32">

            {/* --- OVERVIEW --- */}
            {currentView === 'OVERVIEW' && (
                <div className="space-y-8 animate-fade-in">
                    <header className="flex justify-between items-end">
                        <div>
                            <div className="flex items-center gap-3 mb-1">
                                <h2 className="text-3xl font-black text-slate-900 tracking-tight">Dashboard</h2>
                                {myCompanies.length > 1 && (
                                    <button 
                                        onClick={() => setSelectedCompanyId(null)}
                                        className="p-2 hover:bg-white rounded-xl text-slate-400 hover:text-brand-600 transition-all shadow-sm border border-transparent hover:border-slate-100 group"
                                        title="Cambiar de Empresa"
                                    >
                                        <ArrowRightLeft size={16} className="group-hover:rotate-180 transition-transform duration-500" />
                                    </button>
                                )}
                            </div>
                            <p className="text-slate-400 text-[10px] font-bold uppercase tracking-widest">{selectedCompany.name}</p>
                        </div>
                        <div className="text-right">
                            <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Capital Global</p>
                            <p className="text-4xl font-black text-slate-900 tracking-tighter">{totalBalance.toLocaleString()} <span className="text-lg text-slate-400 font-bold">Pz</span></p>
                        </div>
                    </header>

                    <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                        <div className="bg-white p-8 rounded-[2.5rem] border border-slate-100 shadow-soft">
                             <div className="flex justify-between items-center mb-4">
                                 <div className="p-3 bg-indigo-50 text-indigo-600 rounded-xl"><Users size={20}/></div>
                                 <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">RRHH</span>
                             </div>
                             <p className="text-3xl font-black text-slate-900">{selectedCompany.employees.length}</p>
                             <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest mt-1">Nóminas Activas</p>
                        </div>
                        <div className="bg-white p-8 rounded-[2.5rem] border border-slate-100 shadow-soft">
                             <div className="flex justify-between items-center mb-4">
                                 <div className="p-3 bg-emerald-50 text-emerald-600 rounded-xl"><ShoppingCart size={20}/></div>
                                 <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Ventas</span>
                             </div>
                             <p className="text-3xl font-black text-slate-900">{selectedCompany.catalog.products.length}</p>
                             <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest mt-1">Catálogo SIDS</p>
                        </div>
                        <div className="bg-white p-8 rounded-[2.5rem] border border-slate-100 shadow-soft">
                             <div className="flex justify-between items-center mb-4">
                                 <div className="p-3 bg-orange-50 text-orange-600 rounded-xl"><TrendingUp size={20}/></div>
                                 <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Valoración</span>
                             </div>
                             <p className="text-3xl font-black text-slate-900">{selectedCompany.stockValue.toLocaleString()}</p>
                             <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest mt-1">Pz / Acción</p>
                        </div>
                    </div>

                    <div className="bg-white p-8 rounded-[3rem] border border-slate-100 shadow-soft">
                        <div className="flex justify-between items-center mb-8">
                            <h3 className="font-black text-slate-900 text-lg">Flujo de Tesorería</h3>
                            <span className="text-[10px] font-black uppercase text-brand-600 bg-brand-50 px-3 py-1 rounded-full">Tiempo Real</span>
                        </div>
                        <div className="h-64 w-full">
                            <ResponsiveContainer width="100%" height="100%">
                                <AreaChart data={[{n:1, v:totalBalance-5000}, {n:2, v:totalBalance-2000}, {n:3, v:totalBalance}]}>
                                    <defs>
                                        <linearGradient id="colorVal" x1="0" y1="0" x2="0" y2="1">
                                            <stop offset="5%" stopColor="#6366f1" stopOpacity={0.1}/>
                                            <stop offset="95%" stopColor="#6366f1" stopOpacity={0}/>
                                        </linearGradient>
                                    </defs>
                                    <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9"/>
                                    <Area type="monotone" dataKey="v" stroke="#6366f1" strokeWidth={3} fillOpacity={1} fill="url(#colorVal)" />
                                </AreaChart>
                            </ResponsiveContainer>
                        </div>
                    </div>
                </div>
            )}

            {/* --- TREASURY (FINANCE) --- */}
            {currentView === 'FINANCE' && (
                <div className="space-y-8 animate-slide-up">
                    <header className="flex justify-between items-center">
                        <div>
                            <h2 className="text-3xl font-black text-slate-900 tracking-tight">Tesorería</h2>
                            <p className="text-slate-400 text-[10px] font-bold uppercase tracking-widest mt-1">Gestión operativa de fondos</p>
                        </div>
                        <div className="flex gap-2">
                            <button onClick={() => setShowTransferModal(true)} className="px-6 py-3 bg-slate-900 text-white rounded-2xl font-black text-xs uppercase tracking-widest hover:bg-brand-600 transition-all flex items-center gap-2 shadow-lg active:scale-95">
                                <ArrowRightLeft size={16}/> Girar Fondos
                            </button>
                        </div>
                    </header>

                    <div className="bg-slate-900 text-white p-10 rounded-[3rem] relative overflow-hidden shadow-2xl">
                        <div className="absolute top-0 right-0 w-64 h-64 bg-brand-500/20 rounded-full blur-3xl -mr-20 -mt-20"></div>
                        <div className="relative z-10 flex flex-col md:flex-row justify-between gap-8">
                            <div>
                                <p className="text-[10px] font-black uppercase tracking-widest opacity-60 mb-2">IBAN de Facturación</p>
                                <p className="font-mono text-xl tracking-wider">{selectedCompany.iban}</p>
                            </div>
                            <div className="text-right">
                                <p className="text-[10px] font-black uppercase tracking-widest opacity-60 mb-2">Balance Consolidado</p>
                                <p className="text-5xl font-black tracking-tighter">{totalBalance.toLocaleString()} <span className="text-xl font-bold opacity-30">Pz</span></p>
                            </div>
                        </div>
                    </div>

                    <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-widest mt-12 mb-6 ml-2">Cuentas Vinculadas a la Sociedad</h3>
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                        {companyAccounts.map(acc => (
                            <div key={acc.id} className="bg-white p-8 rounded-[2.5rem] border border-slate-100 shadow-soft hover:border-brand-200 transition-all group">
                                <div className="flex justify-between items-start mb-6">
                                    <div className="flex items-center gap-4">
                                        <div className="w-12 h-12 bg-slate-50 text-slate-400 group-hover:bg-brand-50 group-hover:text-brand-600 rounded-2xl flex items-center justify-center font-bold text-lg transition-colors">
                                            {acc.alias.charAt(0)}
                                        </div>
                                        <div>
                                            <p className="font-black text-slate-900 text-lg leading-tight">{acc.alias}</p>
                                            <p className="text-[10px] text-slate-400 font-mono tracking-widest mt-0.5">{acc.iban.slice(0,4)} •••• {acc.iban.slice(-4)}</p>
                                        </div>
                                    </div>
                                    <span className="text-[9px] font-black uppercase bg-emerald-50 text-emerald-600 px-3 py-1 rounded-full border border-emerald-100">Operativa</span>
                                </div>
                                <div className="flex items-baseline gap-2">
                                    <p className="text-4xl font-black text-slate-900 tracking-tighter">{acc.balance.toLocaleString()}</p>
                                    <span className="text-sm font-bold text-slate-400">Pz</span>
                                </div>
                            </div>
                        ))}
                    </div>
                </div>
            )}

            {/* --- CATALOG (POS) --- */}
            {currentView === 'CATALOG' && (
                <div className="space-y-8 animate-slide-up">
                    <header className="flex justify-between items-center">
                        <div>
                            <h2 className="text-3xl font-black text-slate-900 tracking-tight">Catálogo</h2>
                            <p className="text-slate-400 text-[10px] font-bold uppercase tracking-widest mt-1">Servicios ofrecidos en PlacetaPay</p>
                        </div>
                        <button onClick={() => { setEditingProduct(null); setProdForm({name:'', price:'', description:''}); setShowProductModal(true); }} className="px-6 py-3 bg-brand-600 text-white rounded-2xl font-black text-xs uppercase tracking-widest hover:bg-brand-500 transition-all flex items-center gap-2 shadow-lg active:scale-95">
                            <Plus size={16}/> Nuevo Producto
                        </button>
                    </header>

                    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                        {(selectedCompany.catalog?.products || []).map(p => (
                            <div key={p.id} className="bg-white p-6 rounded-[2.5rem] border border-slate-100 shadow-soft group hover:border-brand-200 transition-all">
                                <div className="flex justify-between items-start mb-4">
                                    <div className="p-3 bg-slate-50 text-slate-400 rounded-2xl group-hover:bg-brand-50 group-hover:text-brand-600 transition-colors">
                                        <Package size={24}/>
                                    </div>
                                    <div className="flex gap-2">
                                        <button onClick={() => { setEditingProduct(p); setProdForm({name: p.name, price: p.price.toString(), description: p.description||''}); setShowProductModal(true); }} className="p-2 bg-slate-50 text-slate-400 rounded-xl hover:text-indigo-600 transition-colors"><Edit2 size={16}/></button>
                                        <button onClick={() => handleDeleteProduct(p.id)} className="p-2 bg-slate-50 text-slate-400 rounded-xl hover:text-red-600 transition-colors"><Trash2 size={16}/></button>
                                    </div>
                                </div>
                                <h3 className="font-black text-lg text-slate-900 mb-1">{p.name}</h3>
                                <p className="text-xs text-slate-500 font-medium mb-4 line-clamp-2 h-8">{p.description || 'Sin descripción'}</p>
                                <div className="flex justify-between items-center pt-4 border-t border-slate-50">
                                    <span className="text-2xl font-black text-slate-900">{p.price} Pz</span>
                                    <span className="text-[10px] font-black uppercase bg-slate-100 text-slate-500 px-2 py-1 rounded">Activo</span>
                                </div>
                            </div>
                        ))}
                        {(!selectedCompany.catalog?.products || selectedCompany.catalog.products.length === 0) && (
                            <div className="col-span-full py-20 text-center border-2 border-dashed border-slate-200 rounded-[3rem]">
                                <Package size={48} className="mx-auto text-slate-300 mb-4"/>
                                <p className="text-slate-400 font-bold uppercase tracking-widest text-xs">Catálogo vacío</p>
                            </div>
                        )}
                    </div>
                </div>
            )}

            {/* --- HR (EMPLOYEES) --- */}
            {currentView === 'EMPLOYEES' && (
                <div className="space-y-8 animate-slide-up">
                    <header className="flex justify-between items-center flex-wrap gap-4">
                        <div>
                            <h3 className="text-3xl font-black text-slate-900 tracking-tight">Recursos Humanos</h3>
                            <p className="text-slate-400 text-[10px] font-bold uppercase tracking-widest mt-1">Plantilla y procesamiento salarial</p>
                        </div>
                        <div className="flex gap-3">
                            <button onClick={() => setShowPayrollModal(true)} className="px-6 py-3 bg-emerald-600 text-white rounded-2xl font-black text-[10px] uppercase tracking-widest shadow-xl hover:bg-emerald-500 transition-all flex items-center gap-2 active:scale-95">
                                <DollarSign size={16}/> Pagar Nóminas
                            </button>
                            <button onClick={() => { setEditingEmployee(null); setEmpForm({name:'', dip:'', salary:'', role:'', iban:''}); setShowEmployeeModal(true); }} className="px-6 py-3 bg-slate-900 text-white rounded-2xl font-black text-[10px] uppercase tracking-widest shadow-xl hover:bg-brand-600 transition-all flex items-center gap-2 active:scale-95">
                                <UserPlus size={16}/> Contratar
                            </button>
                        </div>
                    </header>

                    <div className="bg-white rounded-[3rem] border border-slate-100 shadow-soft overflow-hidden">
                        <div className="overflow-x-auto">
                            <table className="w-full text-left min-w-[700px]">
                                <thead className="bg-slate-50 border-b border-slate-100">
                                    <tr>
                                        <th className="p-6 text-[10px] font-black uppercase text-slate-400 tracking-widest">Empleado</th>
                                        <th className="p-6 text-[10px] font-black uppercase text-slate-400 tracking-widest">Cargo</th>
                                        <th className="p-6 text-[10px] font-black uppercase text-slate-400 tracking-widest">Salario Bruto</th>
                                        <th className="p-6 text-[10px] font-black uppercase text-slate-400 tracking-widest text-right">Acciones</th>
                                    </tr>
                                </thead>
                                <tbody className="divide-y divide-slate-50">
                                    {selectedCompany.employees.length === 0 ? (
                                        <tr><td colSpan={4} className="p-10 text-center text-slate-400 text-sm font-bold">No hay empleados registrados</td></tr>
                                    ) : selectedCompany.employees.map(emp => (
                                        <tr key={emp.id} className="hover:bg-slate-50 transition-colors">
                                            <td className="p-6">
                                                <p className="font-bold text-slate-900">{emp.name}</p>
                                                <p className="text-xs text-slate-400 font-mono tracking-widest uppercase">{emp.dip}</p>
                                            </td>
                                            <td className="p-6"><span className="bg-indigo-50 text-indigo-600 px-3 py-1 rounded-lg text-[10px] font-black uppercase">{emp.role}</span></td>
                                            <td className="p-6 font-mono font-bold text-slate-700 tracking-tighter">{emp.salary.toLocaleString()} Pz</td>
                                            <td className="p-6 text-right space-x-2 whitespace-nowrap">
                                                <button onClick={() => { setEditingEmployee(emp); setEmpForm({name:emp.name, dip:emp.dip, salary:emp.salary.toString(), role:emp.role, iban:emp.iban}); setShowEmployeeModal(true); }} className="p-2 text-slate-400 hover:text-brand-600 transition-colors"><Edit2 size={16}/></button>
                                            </td>
                                        </tr>
                                    ))}
                                </tbody>
                            </table>
                        </div>
                    </div>

                    <div className="mt-12">
                        <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] mb-4 ml-2 flex items-center gap-2"><History size={14}/> Registro de Liquidaciones</h4>
                        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                             {payrollHistory.map(h => (
                                 <div key={h.id} className="bg-white p-6 rounded-[2rem] border border-slate-100 shadow-soft flex justify-between items-center hover:border-brand-100 transition-colors">
                                     <div>
                                         <p className="font-black text-slate-900 text-sm">Nómina {h.month}/{h.year}</p>
                                         <p className="text-[9px] text-slate-400 font-bold uppercase tracking-widest mt-1">Procesada: {new Date(h.processedAt).toLocaleDateString()}</p>
                                     </div>
                                     <div className="text-right">
                                         <p className="font-black text-slate-900 tracking-tighter">{h.totalAmount.toLocaleString()} Pz</p>
                                         <p className="text-[9px] font-bold text-red-500 uppercase tracking-widest mt-1">Impuestos: {h.totalTaxes.toLocaleString()} Pz</p>
                                     </div>
                                 </div>
                             ))}
                             {payrollHistory.length === 0 && <div className="col-span-full p-10 text-center text-xs text-slate-300 font-bold uppercase tracking-widest bg-slate-50 rounded-[2rem] border border-dashed border-slate-200">Sin historial de pagos</div>}
                        </div>
                    </div>
                </div>
            )}

            {/* --- INVOICING --- */}
            {currentView === 'INVOICING' && (
                <div className="space-y-8 animate-fade-in">
                    <header className="flex justify-between items-center">
                        <h2 className="text-3xl font-black text-slate-900 tracking-tight">Facturación</h2>
                        <button onClick={() => addNotification("Módulo de facturación en desarrollo", "info")} className="px-6 py-3 bg-slate-900 text-white rounded-2xl font-black text-xs uppercase tracking-widest hover:bg-brand-600 transition-all flex items-center gap-2 shadow-lg active:scale-95">
                            <Plus size={16}/> Emitir Factura
                        </button>
