import { Pool } from '@neondatabase/serverless';

let pool: any = null;
const getPool = () => {
  if (!pool) {
    if (!process.env.DATABASE_URL) throw new Error('DATABASE_URL is missing');
    pool = new (Pool as any)({ connectionString: process.env.DATABASE_URL });
  }
  return pool;
};

const BANK_IBAN = 'PL0000000000000000000000';

const formatResponse = (obj: any): any => {
    if (obj === null || obj === undefined) return obj;
    if (obj instanceof Date) return obj.toISOString();
    if (Array.isArray(obj)) return obj.map(formatResponse);
    if (typeof obj !== 'object') return obj;
    const newObj: any = {};
    for (const key in obj) {
        const newKey = key.replace(/_([a-z])/g, (g) => g[1].toUpperCase());
        let value = obj[key];
        const numericFields = ['balance', 'amount', 'price', 'capital', 'stockValue', 'salary', 'tax', 'prizeValue'];
        if (numericFields.includes(newKey) && (typeof value === 'string' || value === null)) {
            value = parseFloat(value || '0');
        }
        newObj[newKey] = formatResponse(value);
    }
    return newObj;
};

export default async function handler(req: any, res: any) {
    let client: any;
    res.setHeader('Content-Type', 'application/json');
    res.setHeader('Access-Control-Allow-Origin', '*');
    res.setHeader('Access-Control-Allow-Methods', 'POST, OPTIONS');
    res.setHeader('Access-Control-Allow-Headers', 'Content-Type');

    if (req.method === 'OPTIONS') return res.status(200).end();

    try {
        const { action, ...params } = req.body || {};
        client = await getPool().connect();

        // --- AUTH ACTIONS ---
        if (action === 'AUTH') {
            const { dip, password } = params;
            const userRes = await client.query("SELECT * FROM users WHERE UPPER(dip) = $1 AND password_hash = $2", [dip.toUpperCase().trim(), password]);
            if (userRes.rows.length === 0) return res.status(401).json({ error: "Credenciales SIDS no válidas" });
            return res.status(200).json({ success: true, user: formatResponse(userRes.rows[0]) });
        }

        if (action === 'AUTH_PLACETAID') {
            const { userData } = params;
            const dip = (userData.dni || userData.dip || userData.id || '').toUpperCase().trim();
            const userRes = await client.query("SELECT * FROM users WHERE UPPER(dip) = $1", [dip]);
            if (userRes.rows.length === 0) return res.status(404).json({ error: "Usuario verificado pero no registrado en el Banco" });
            return res.status(200).json({ success: true, user: formatResponse(userRes.rows[0]) });
        }

        // --- DATA RETRIEVAL ---
        if (action === 'GET_INITIAL_DATA') {
            const { userId } = params;
            const accounts = (await client.query("SELECT * FROM accounts WHERE owner_id = $1 OR $1 = ANY(shared_with)", [userId])).rows;
            const companies = (await client.query("SELECT * FROM companies WHERE owner_id = $1", [userId])).rows;
            const contacts = (await client.query("SELECT * FROM contacts WHERE user_id = $1", [userId])).rows;
            const lootBoxes = (await client.query("SELECT * FROM loot_boxes WHERE status = 'APPROVED' OR owner_id = $1", [userId])).rows;
            const ibans = (accounts || []).map((a: any) => a.iban);
            let txs = [];
            if (ibans.length > 0) {
                const placeholders = ibans.map((_, i) => `$${i + 1}`).join(',');
                txs = (await client.query(`SELECT * FROM transactions WHERE sender_iban IN (${placeholders}) OR receiver_iban IN (${placeholders}) ORDER BY date DESC LIMIT 50`, ibans)).rows;
            }
            return res.status(200).json(formatResponse({ accounts: accounts || [], companies: companies || [], transactions: txs || [], contacts: contacts || [], lootBoxes: lootBoxes || [] }));
        }

        // --- BUSINESS ACTIONS ---
        if (action === 'COMPANY_GO_PUBLIC') {
            const { companyId } = params;
            await client.query("UPDATE companies SET is_public = true, stock_value = 100.00 WHERE id = $1", [companyId]);
            return res.status(200).json({ success: true });
        }

        if (action === 'COMPANY_CREATE_LOTTERY') {
            const { companyId, name, description, price, prizeValue, color } = params;
            await client.query("BEGIN");
            const company = (await client.query("SELECT iban, balance FROM accounts WHERE company_id = $1 OR iban = (SELECT iban FROM companies WHERE id = $1)", [companyId])).rows[0];

            if (!company || company.balance < prizeValue) {
                throw new Error("Saldo insuficiente para garantizar el premio del sorteo");
            }

            // Bloquear fondos del premio en la cuenta estatal (Escrow)
            await client.query("UPDATE accounts SET balance = balance - $1 WHERE iban = $2", [prizeValue, company.iban]);
            await client.query("UPDATE accounts SET balance = balance + $1 WHERE iban = $2", [prizeValue, BANK_IBAN]);

            const id = 'LOOT-' + Date.now();
            await client.query("INSERT INTO loot_boxes (id, owner_id, name, description, price, prize_value, color, status) VALUES ($1, $2, $3, $4, $5, $6, $7, 'APPROVED')",
                [id, companyId, name, description, price, prizeValue, color]);

            await client.query("COMMIT");
            return res.status(200).json({ success: true });
        }

        // --- TRANSACTIONAL ACTIONS ---
        if (action === 'TRANSFER') {
            const { fromIban, toIban, amount, description, type } = params;
            await client.query("BEGIN");

            const senderRes = await client.query("SELECT * FROM accounts WHERE iban = $1 FOR UPDATE", [fromIban]);
            if (senderRes.rows.length === 0) throw new Error("Cuenta origen no existe");

            const taxRate = type === 'IRM_TAX' || type === 'TAX' || type === 'ADMIN' ? 0 : 0.01;
            const totalToDeduct = amount * (1 + taxRate);

            if (senderRes.rows[0].balance < totalToDeduct) throw new Error("Saldo insuficiente (incluyendo tasas)");

            await client.query("UPDATE accounts SET balance = balance - $1 WHERE iban = $2", [totalToDeduct, fromIban]);
            await client.query("UPDATE accounts SET balance = balance + $1 WHERE iban = $2", [amount, toIban]);
            if (taxRate > 0) await client.query("UPDATE accounts SET balance = balance + $1 WHERE iban = $2", [amount * taxRate, BANK_IBAN]);

            const txId = 'TX-' + Math.random().toString(36).substr(2, 9).toUpperCase();
            await client.query("INSERT INTO transactions (id, sender_iban, receiver_iban, amount, description, type, tax, status) VALUES ($1, $2, $3, $4, $5, $6, $7, 'COMPLETED')", 
                [txId, fromIban, toIban, amount, description, type || 'TRANSFER', amount * taxRate]);

            await client.query("COMMIT");
            return res.status(200).json({ success: true, txId });
        }

        // ... resto de acciones existentes ...
        return res.status(400).json({ error: `Acción '${action}' no reconocida` });
    } catch (e: any) {
        if (client) await client.query("ROLLBACK");
        return res.status(500).json({ error: e.message });
    } finally {
        if (client) client.release();
    }
}

import React, { createContext, useContext, useState, ReactNode, useEffect, useCallback } from 'react';
import { User, Account, Transaction, Company, AppNotification, Product, Employee, Card, Contact, TaxConfig, ShareRequest, LootBox, LootItem, CardDesign, ApiUsageLog, PayrollHistory, UserSubscription, SubscriptionPlan } from '../types';
import { BANK_IBAN } from '../constants';
import { jsPDF } from 'jspdf';
import 'jspdf-autotable';

interface BankContextType {
  currentUser: User | null;
  userAccounts: Account[];
  transactions: Transaction[];
  notifications: AppNotification[];
  companies: Company[];
  cards: Card[];
  contacts: Contact[];
  lootBoxes: LootBox[];
  taxConfig: TaxConfig;
  login: (dip: string, pass: string) => Promise<{ success: boolean; error?: string }>;
  loginWithPlacetaID: (userData: any) => Promise<{ success: boolean; error?: string }>;
  logout: () => void;
  fetchData: (userId: string) => Promise<void>;
  transfer: (fromIban: string, toIban: string, amount: number, description: string, type?: string) => Promise<void>;
  companyTransfer: (companyId: string, toIban: string, amount: number, description: string) => Promise<void>;
  linkAccountToCompany: (accountId: string, companyId: string) => Promise<void>;
  addNotification: (message: string, type: 'success' | 'error' | 'info') => void;
  generatePDF: (type: string, data: any) => void;
  getAge: (birthDate?: string) => number;
  saveContact: (name: string, iban: string) => Promise<void>;
  deleteContact: (id: string) => Promise<void>;
  adminGetState: () => Promise<any>;
  adminRevertTransaction: (id: string) => Promise<void>;
  adminUpdateUserStatus: (userId: string, isBlocked: boolean) => Promise<void>;
  adminUpdateUserBirthDate: (userId: string, birthDate: string) => Promise<void>;
  adminMint: (amount: number, reason: string) => Promise<void>;
  adminGenerateMonthlyTaxes: (month: number, year: number) => Promise<any>;
  payPayroll: (companyId: string, month: string, year: string) => Promise<void>;
  updateEmployees: (companyId: string, employees: Employee[]) => Promise<void>;
  updateCatalog: (companyId: string, products: Product[]) => Promise<void>;
  getPayrollHistory: (companyId: string) => Promise<PayrollHistory[]>;
  triggerHaptic: (pattern?: 'light' | 'medium' | 'heavy' | 'success' | 'error') => void;
  updateSelfBirthDate: (birthDate: string) => Promise<void>;
  payCitizenTax: (accountId: string, amount: number, description: string) => Promise<void>;
  getFiscalProjection: (month: number, year: number) => Promise<any[]>;
  goPublic: (companyId: string) => Promise<void>;
  createLottery: (companyId: string, data: any) => Promise<void>;
  buyLootBox: (boxId: string, accountId: string) => Promise<any>;
  redeemCode: (code: string) => Promise<void>;
}

const BankContext = createContext<BankContextType | undefined>(undefined);

export const BankProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [userAccounts, setUserAccounts] = useState<Account[]>([]);
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [notifications, setNotifications] = useState<AppNotification[]>([]);
  const [companies, setCompanies] = useState<Company[]>([]);
  const [cards, setCards] = useState<Card[]>([]);
  const [contacts, setContacts] = useState<Contact[]>([]);
  const [lootBoxes, setLootBoxes] = useState<LootBox[]>([]);

  const [taxConfig] = useState<TaxConfig>({ vatRate: 12, transferRate: 1, companyTaxRate: 25, lotteryRate: 20 });

  const triggerHaptic = (pattern: 'light' | 'medium' | 'heavy' | 'success' | 'error' = 'light') => {
    if (typeof navigator !== 'undefined' && navigator.vibrate) {
        switch (pattern) {
            case 'light': navigator.vibrate(5); break;
            case 'medium': navigator.vibrate(15); break;
            case 'heavy': navigator.vibrate(30); break;
            case 'success': navigator.vibrate([10, 30, 10]); break;
            case 'error': navigator.vibrate([30, 50, 30, 50, 30]); break;
        }
    }
  };

  const apiCall = async (body: any) => {
    const res = await fetch('/api', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(body)
    });
    const data = await res.json();
    if (!res.ok) throw new Error(data.error || 'Fallo SIDS');
    return data;
  };

  const fetchData = useCallback(async (userId: string) => {
    if (!userId) return;
    try {
      const data = await apiCall({ action: 'GET_INITIAL_DATA', userId });
      setUserAccounts(Array.isArray(data.accounts) ? data.accounts : []);
      setTransactions(Array.isArray(data.transactions) ? data.transactions : []);
      setCompanies(Array.isArray(data.companies) ? data.companies : []);
      setCards(Array.isArray(data.cards) ? data.cards : []);
      setContacts(Array.isArray(data.contacts) ? data.contacts : []);
      setLootBoxes(Array.isArray(data.lootBoxes) ? data.lootBoxes : []);
    } catch (e) { console.error(e); }
  }, []);

  const login = async (dip: string, pass: string) => {
    try {
      const data = await apiCall({ action: 'AUTH', dip, password: pass });
      if (data.user) {
        setCurrentUser(data.user);
        await fetchData(data.user.id);
        return { success: true };
      }
      return { success: false, error: "Credenciales no válidas" };
    } catch (e: any) { return { success: false, error: e.message }; }
  };

  const loginWithPlacetaID = async (userData: any) => {
    try {
      const data = await apiCall({ action: 'AUTH_PLACETAID', userData });
      if (data.user) {
        setCurrentUser(data.user);
        await fetchData(data.user.id);
        return { success: true };
      }
      return { success: false, error: "Fallo SIDS" };
    } catch (e: any) { return { success: false, error: e.message }; }
  };

  const logout = () => { setCurrentUser(null); setUserAccounts([]); setTransactions([]); setNotifications([]); };

  const transfer = async (fromIban: string, toIban: string, amount: number, description: string, type = 'TRANSFER') => {
    await apiCall({ action: 'TRANSFER', fromIban, toIban, amount, description, type });
    if (currentUser?.id) await fetchData(currentUser.id);
    addNotification(`Giro firmado`, "success");
  };

  const companyTransfer = async (companyId: string, toIban: string, amount: number, description: string) => {
      await apiCall({ action: 'COMPANY_TRANSFER', companyId, toIban, amount, description });
      if (currentUser?.id) await fetchData(currentUser.id);
  };

  const linkAccountToCompany = async (accountId: string, companyId: string) => {
      await apiCall({ action: 'LINK_ACCOUNT_TO_COMPANY', accountId, companyId });
      if (currentUser?.id) await fetchData(currentUser.id);
      addNotification("Cuenta vinculada a sociedad", "success");
  };

  const goPublic = async (companyId: string) => {
      await apiCall({ action: 'COMPANY_GO_PUBLIC', companyId });
      if (currentUser?.id) await fetchData(currentUser.id);
      addNotification("Sociedad ahora cotiza en Bolsa SIDS", "success");
  };

  const createLottery = async (companyId: string, data: any) => {
      await apiCall({ action: 'COMPANY_CREATE_LOTTERY', companyId, ...data });
      if (currentUser?.id) await fetchData(currentUser.id);
      addNotification("Sorteo creado y garantizado", "success");
  };

  const buyLootBox = async (boxId: string, accountId: string) => {
      const res = await apiCall({ action: 'BUY_LOOTBOX', boxId, accountId });
      if (currentUser?.id) await fetchData(currentUser.id);
      return res;
  };

  const redeemCode = async (code: string) => {
      await apiCall({ action: 'REDEEM_CODE', code, userId: currentUser?.id });
      if (currentUser?.id) await fetchData(currentUser.id);
      addNotification("Código canjeado", "success");
  };

  const addNotification = (message: string, type: any) => {
    const id = Date.now().toString();
    setNotifications(prev => [...prev, { id, message, type }]);
    if(!document.hidden) triggerHaptic(type === 'error' ? 'error' : 'light');
    setTimeout(() => setNotifications(prev => prev.filter(n => n.id !== id)), 4000);
  };

  const saveContact = async (name: string, iban: string) => { 
      if(currentUser?.id) { 
          await apiCall({action: 'SAVE_CONTACT', userId: currentUser.id, name, iban}); 
          await fetchData(currentUser.id); 
      }
  };
  const deleteContact = async (id: string) => { 
      await apiCall({action: 'DELETE_CONTACT', contactId: id}); 
      if(currentUser?.id) await fetchData(currentUser.id); 
  };

  const adminGetState = () => apiCall({ action: 'ADMIN_GET_STATE' });
  const adminRevertTransaction = async (transactionId: string) => {
      await apiCall({ action: 'ADMIN_REVERT_TX', transactionId });
      addNotification("TX Revertida", "success");
  };
  const adminUpdateUserStatus = (userId: string, isBlocked: boolean) => apiCall({ action: 'ADMIN_UPDATE_USER_STATUS', userId, isBlocked });
  const adminUpdateUserBirthDate = (userId: string, birthDate: string) => apiCall({ action: 'ADMIN_UPDATE_USER_BIRTHDATE', userId, birthDate });
  const adminMint = (amount: number, reason: string) => apiCall({ action: 'ADMIN_MINT', amount, reason });
  const adminGenerateMonthlyTaxes = (month: number, year: number) => apiCall({ action: 'ADMIN_GENERATE_MONTHLY_TAXES', month, year });

  const payPayroll = async (companyId: string, month: string, year: string) => {
      await apiCall({ action: 'PAY_PAYROLL', companyId, month, year });
      if (currentUser?.id) await fetchData(currentUser.id);
  };
  const updateEmployees = async (companyId: string, employees: Employee[]) => {
      await apiCall({ action: 'UPDATE_EMPLOYEES', companyId, employees });
      if (currentUser?.id) await fetchData(currentUser.id);
  };
  const updateCatalog = async (companyId: string, products: Product[]) => {
      await apiCall({ action: 'UPDATE_CATALOG', companyId, products });
      if (currentUser?.id) await fetchData(currentUser.id);
  };
  const getPayrollHistory = (companyId: string) => apiCall({ action: 'GET_PAYROLL_HISTORY', companyId });
  const getFiscalProjection = (month: number, year: number) => apiCall({ action: 'GET_FISCAL_PROJECTION', userId: currentUser?.id, month, year });
  const payCitizenTax = (accountId: string, amount: number, description: string) => apiCall({ action: 'TRANSFER', fromIban: userAccounts.find(a=>a.id===accountId)?.iban, toIban: BANK_IBAN, amount, description, type: 'TAX' });

  const updateSelfBirthDate = async (birthDate: string) => {
      if (!currentUser?.id) return;
      await apiCall({ action: 'ADMIN_UPDATE_USER_BIRTHDATE', userId: currentUser.id, birthDate });
      setCurrentUser(prev => prev ? { ...prev, birthDate } : null);
  };

  const getAge = (birthDate?: string) => {
    if (!birthDate) return 0;
    const today = new Date();
    const birth = new Date(birthDate);
    if (isNaN(birth.getTime())) return 0;
    let age = today.getFullYear() - birth.getFullYear();
    const m = today.getMonth() - birth.getMonth();
    if (m < 0 || (m === 0 && today.getDate() < birth.getDate())) age--;
    return age;
  };

  const generatePDF = (type: string, data: any) => {
      const doc = new jsPDF() as any;
      doc.setFillColor(15, 23, 42);
      doc.rect(0, 0, 210, 40, 'F');
      doc.setTextColor(255, 255, 255);
      doc.setFontSize(20);
      doc.text("BANCO DE LA PLACETA", 20, 25);
      doc.setFontSize(8);
      doc.text("CAPÍTULO 1 — GESTIÓN ADMINISTRATIVA CENTRALIZADA", 20, 32);
      doc.setTextColor(15, 23, 42);
      doc.setFontSize(14);
      doc.text(type.replace(/_/g, ' '), 20, 60);
      let y = 80;
      Object.entries(data).forEach(([k, v]) => {
          doc.setFontSize(10);
          doc.text(`${k.toUpperCase()}: ${String(v)}`, 20, y);
          y += 10;
      });
      doc.save(`Placeta_${type}_${Date.now()}.pdf`);
  };

  return (
    <BankContext.Provider value={{
      currentUser, userAccounts, transactions, notifications, companies, cards, contacts, lootBoxes, taxConfig,
      login, loginWithPlacetaID, logout, fetchData, transfer, companyTransfer, linkAccountToCompany, addNotification, generatePDF, getAge,
      saveContact, deleteContact, adminGetState, adminRevertTransaction, adminUpdateUserStatus, adminUpdateUserBirthDate, adminMint, adminGenerateMonthlyTaxes,
      payPayroll, updateEmployees, updateCatalog, getPayrollHistory, triggerHaptic, updateSelfBirthDate, getFiscalProjection, payCitizenTax,
      goPublic, createLottery, buyLootBox, redeemCode
    }}>
      {children}
    </BankContext.Provider>
  );
};

export const useBank = () => {
  const context = useContext(BankContext);
  if (!context) throw new Error('BankContext missing');
  return context;
};

