import { Pool } from '@neondatabase/serverless';

let pool: any = null;
const getPool = () => {
  if (!pool) {
    if (!process.env.DATABASE_URL) throw new Error('DATABASE_URL is missing');
    pool = new (Pool as any)({ connectionString: process.env.DATABASE_URL });
  }
  return pool;
};

const BANK_IBAN = 'PL0000000000000000000000';

const formatResponse = (obj: any): any => {
    if (obj === null || obj === undefined) return obj;
    if (obj instanceof Date) return obj.toISOString();
    if (Array.isArray(obj)) return obj.map(formatResponse);
    if (typeof obj !== 'object') return obj;
    const newObj: any = {};
    for (const key in obj) {
        const newKey = key.replace(/_([a-z])/g, (g) => g[1].toUpperCase());
        let value = obj[key];
        const numericFields = ['balance', 'amount', 'price', 'capital', 'stockValue', 'salary', 'tax', 'prizeValue'];
        if (numericFields.includes(newKey) && (typeof value === 'string' || value === null)) {
            value = parseFloat(value || '0');
        }
        newObj[newKey] = formatResponse(value);
    }
    return newObj;
};

export default async function handler(req: any, res: any) {
    let client: any;
    res.setHeader('Content-Type', 'application/json');
    res.setHeader('Access-Control-Allow-Origin', '*');
    res.setHeader('Access-Control-Allow-Methods', 'POST, OPTIONS');
    res.setHeader('Access-Control-Allow-Headers', 'Content-Type');

    if (req.method === 'OPTIONS') return res.status(200).end();

    try {
        const { action, ...params } = req.body || {};
        client = await getPool().connect();

        // --- AUTH ---
        if (action === 'AUTH') {
            const { dip, password } = params;
            const userRes = await client.query("SELECT * FROM users WHERE UPPER(dip) = $1 AND password_hash = $2", [dip.toUpperCase().trim(), password]);
            if (userRes.rows.length === 0) return res.status(401).json({ error: "Credenciales SIDS no válidas" });
            return res.status(200).json({ success: true, user: formatResponse(userRes.rows[0]) });
        }

        if (action === 'AUTH_PLACETAID') {
            const { userData } = params;
            const dip = (userData.dni || userData.dip || userData.id || '').toUpperCase().trim();
            const userRes = await client.query("SELECT * FROM users WHERE UPPER(dip) = $1", [dip]);
            if (userRes.rows.length === 0) return res.status(404).json({ error: "Usuario verificado pero no registrado en el Banco" });
            return res.status(200).json({ success: true, user: formatResponse(userRes.rows[0]) });
        }

        // --- DATA RETRIEVAL ---
        if (action === 'GET_INITIAL_DATA') {
            const { userId } = params;
            const accounts = (await client.query("SELECT * FROM accounts WHERE owner_id = $1 OR $1 = ANY(shared_with)", [userId])).rows;
            const companies = (await client.query("SELECT * FROM companies WHERE owner_id = $1", [userId])).rows;
            const contacts = (await client.query("SELECT * FROM contacts WHERE user_id = $1", [userId])).rows;
            const lootBoxes = (await client.query("SELECT * FROM loot_boxes WHERE status = 'APPROVED' OR owner_id IN (SELECT id FROM companies WHERE owner_id = $1)", [userId])).rows;
            const ibans = (accounts || []).map((a: any) => a.iban);
            let txs = [];
            if (ibans.length > 0) {
                const placeholders = ibans.map((_, i) => `$${i + 1}`).join(',');
                txs = (await client.query(`SELECT * FROM transactions WHERE sender_iban IN (${placeholders}) OR receiver_iban IN (${placeholders}) ORDER BY date DESC LIMIT 50`, ibans)).rows;
            }
            return res.status(200).json(formatResponse({ accounts, companies, transactions: txs, contacts, lootBoxes }));
        }

        // --- BUSINESS ACTIONS ---
        if (action === 'COMPANY_GO_PUBLIC') {
            const { companyId } = params;
            await client.query("UPDATE companies SET is_public = true, stock_value = 100.00 WHERE id = $1", [companyId]);
            return res.status(200).json({ success: true });
        }

        if (action === 'COMPANY_CREATE_LOTTERY') {
            const { companyId, name, description, price, prizeValue, color } = params;
            await client.query("BEGIN");
            const accRes = await client.query("SELECT iban, balance FROM accounts WHERE company_id = $1 OR iban = (SELECT iban FROM companies WHERE id = $1) LIMIT 1", [companyId]);
            const companyAcc = accRes.rows[0];

            if (!companyAcc || companyAcc.balance < prizeValue) throw new Error("Saldo insuficiente para garantizar el premio");

            await client.query("UPDATE accounts SET balance = balance - $1 WHERE iban = $2", [prizeValue, companyAcc.iban]);
            await client.query("UPDATE accounts SET balance = balance + $1 WHERE iban = $2", [prizeValue, BANK_IBAN]);

            const id = 'LOOT-' + Date.now();
            await client.query("INSERT INTO loot_boxes (id, owner_id, name, description, price, prize_value, color, status) VALUES ($1, $2, $3, $4, $5, $6, $7, 'APPROVED')",
                [id, companyId, name, description, price, prizeValue, color]);

            await client.query("COMMIT");
            return res.status(200).json({ success: true });
        }

        // --- LOTTERY ACTIONS ---
        if (action === 'BUY_LOOTBOX') {
            const { boxId, accountId } = params;
            await client.query("BEGIN");
            const boxRes = await client.query("SELECT * FROM loot_boxes WHERE id = $1", [boxId]);
            const accRes = await client.query("SELECT * FROM accounts WHERE id = $1", [accountId]);
            const box = boxRes.rows[0];
            const acc = accRes.rows[0];

            if (acc.balance < box.price) throw new Error("Saldo insuficiente");

            await client.query("UPDATE accounts SET balance = balance - $1 WHERE id = $2", [box.price, accountId]);

            // Lógica de Sorteo (Simulada para demo: 10% de probabilidad de ganar)
            const won = Math.random() < 0.10;
            let wonItem = null;

            if (won) {
                const prize = parseFloat(box.prize_value);
                const tax = prize * 0.20; // 20% impuesto lotería
                const net = prize - tax;
                await client.query("UPDATE accounts SET balance = balance - $1 WHERE iban = $2", [prize, BANK_IBAN]);
                await client.query("UPDATE accounts SET balance = balance + $1 WHERE id = $2", [net, accountId]);
                await client.query("UPDATE accounts SET balance = balance + $1 WHERE iban = $2", [tax, BANK_IBAN]);

                wonItem = { id: 'PRIZE-'+Date.now(), name: `Premio de ${box.name}`, value: prize };

                await client.query("INSERT INTO transactions (id, sender_iban, receiver_iban, amount, description, type, status, tax) VALUES ($1, $2, $3, $4, $5, 'LOTTERY', 'COMPLETED', $6)",
                    ['TX-WIN-'+Date.now(), BANK_IBAN, acc.iban, prize, `Premio Lotería: ${box.name}`, tax]);
            } else {
                // Si no gana, el coste del ticket va al dueño del sorteo (o al estado si es oficial)
                const ownerRes = await client.query("SELECT iban FROM companies WHERE id = $1", [box.owner_id]);
                const ownerIban = ownerRes.rows[0]?.iban || BANK_IBAN;
                await client.query("UPDATE accounts SET balance = balance + $1 WHERE iban = $2", [box.price, ownerIban]);
            }

            await client.query("COMMIT");
            return res.status(200).json({ success: true, won, wonItem });
        }

        // --- ADMIN ---
        if (action === 'ADMIN_GET_STATE') {
            const users = (await client.query("SELECT * FROM users ORDER BY created_at DESC")).rows;
            const txs = (await client.query("SELECT * FROM transactions ORDER BY date DESC LIMIT 100")).rows;
            const accounts = (await client.query("SELECT * FROM accounts")).rows;
            const m0Res = await client.query("SELECT SUM(balance) as m0 FROM accounts");
            return res.status(200).json(formatResponse({ users, transactions: txs, allAccounts: accounts, m0: m0Res.rows[0].m0 || 0 }));
        }

        // --- GENERAL TRANSACTIONS ---
        if (action === 'TRANSFER') {
            const { fromIban, toIban, amount, description, type } = params;
            await client.query("BEGIN");
            const senderRes = await client.query("SELECT balance FROM accounts WHERE iban = $1 FOR UPDATE", [fromIban]);
            if (senderRes.rows.length === 0) throw new Error("Cuenta origen no existe");

            const taxRate = type === 'TAX' || type === 'ADMIN' ? 0 : 0.01;
            const total = amount * (1 + taxRate);
            if (senderRes.rows[0].balance < total) throw new Error("Saldo insuficiente");

            await client.query("UPDATE accounts SET balance = balance - $1 WHERE iban = $2", [total, fromIban]);
            await client.query("UPDATE accounts SET balance = balance + $1 WHERE iban = $2", [amount, toIban]);
            if (taxRate > 0) await client.query("UPDATE accounts SET balance = balance + $1 WHERE iban = $2", [amount * taxRate, BANK_IBAN]);

            await client.query("INSERT INTO transactions (id, sender_iban, receiver_iban, amount, description, type, status, tax) VALUES ($1, $2, $3, $4, $5, $6, 'COMPLETED', $7)",
                ['TX-'+Math.random().toString(36).substr(2,9).toUpperCase(), fromIban, toIban, amount, description, type || 'TRANSFER', amount * taxRate]);

            await client.query("COMMIT");
            return res.status(200).json({ success: true });
        }

        return res.status(400).json({ error: `Acción '${action}' no reconocida` });
    } catch (e: any) {
        if (client) await client.query("ROLLBACK");
        return res.status(500).json({ error: e.message });
    } finally {
        if (client) client.release();
    }
}

