import { Pool } from '@neondatabase/serverless';

let pool: any = null;
const getPool = () => {
  if (!pool) {
    if (!process.env.DATABASE_URL) throw new Error('DATABASE_URL is missing');
    pool = new (Pool as any)({ connectionString: process.env.DATABASE_URL });
  }
  return pool;
};

const BANK_IBAN = 'PL0000000000000000000000';

const formatResponse = (obj: any): any => {
    if (obj === null || obj === undefined) return obj;
    if (obj instanceof Date) return obj.toISOString();
    if (Array.isArray(obj)) return obj.map(formatResponse);
    if (typeof obj !== 'object') return obj;
    const newObj: any = {};
    for (const key in obj) {
        const newKey = key.replace(/_([a-z])/g, (g) => g[1].toUpperCase());
        let value = obj[key];
        const numericFields = ['balance', 'amount', 'price', 'capital', 'stockValue', 'salary', 'tax', 'prizeValue'];
        if (numericFields.includes(newKey) && (typeof value === 'string' || value === null)) {
            value = parseFloat(value || '0');
        }
        newObj[newKey] = formatResponse(value);
    }
    return newObj;
};

export default async function handler(req: any, res: any) {
    let client: any;
    res.setHeader('Content-Type', 'application/json');
    res.setHeader('Access-Control-Allow-Origin', '*');
    res.setHeader('Access-Control-Allow-Methods', 'POST, OPTIONS');
    res.setHeader('Access-Control-Allow-Headers', 'Content-Type');

    if (req.method === 'OPTIONS') return res.status(200).end();

    try {
        const { action, ...params } = req.body || {};
        client = await getPool().connect();

        // --- AUTH ---
        if (action === 'AUTH') {
            const { dip, password } = params;
            const userRes = await client.query("SELECT * FROM users WHERE UPPER(dip) = $1 AND password_hash = $2", [dip.toUpperCase().trim(), password]);
            if (userRes.rows.length === 0) return res.status(401).json({ error: "Credenciales SIDS no válidas" });
            return res.status(200).json({ success: true, user: formatResponse(userRes.rows[0]) });
        }

        if (action === 'AUTH_PLACETAID') {
            const { userData } = params;
            const dip = (userData.dni || userData.dip || userData.id || '').toUpperCase().trim();
            const userRes = await client.query("SELECT * FROM users WHERE UPPER(dip) = $1", [dip]);
            if (userRes.rows.length === 0) return res.status(404).json({ error: "Usuario verificado pero no registrado en el Banco" });
            return res.status(200).json({ success: true, user: formatResponse(userRes.rows[0]) });
        }

        // --- DATA RETRIEVAL ---
        if (action === 'GET_INITIAL_DATA') {
            const { userId } = params;
            const accounts = (await client.query("SELECT * FROM accounts WHERE owner_id = $1 OR $1 = ANY(shared_with)", [userId])).rows;
            const companies = (await client.query("SELECT * FROM companies WHERE owner_id = $1", [userId])).rows;
            const contacts = (await client.query("SELECT * FROM contacts WHERE user_id = $1", [userId])).rows;
            const lootBoxes = (await client.query("SELECT * FROM loot_boxes WHERE status = 'APPROVED' OR owner_id IN (SELECT id FROM companies WHERE owner_id = $1)", [userId])).rows;

            // Fix: Include missing initial data for frontend features
            const shareRequests = (await client.query("SELECT * FROM share_requests WHERE from_user_id = $1 OR to_user_dip = (SELECT dip FROM users WHERE id = $1)", [userId])).rows;
            const userSubscriptions = (await client.query("SELECT * FROM user_subscriptions WHERE user_id = $1", [userId])).rows;
            const storeDesigns = (await client.query("SELECT * FROM card_designs WHERE owner_id IS NULL OR is_listed = true")).rows;
            const inventoryDesigns = (await client.query("SELECT * FROM card_designs WHERE owner_id = $1 AND (is_listed = false OR is_listed IS NULL)", [userId])).rows;

            const ibans = (accounts || []).map((a: any) => a.iban);
            let txs = [];
            if (ibans.length > 0) {
                const placeholders = ibans.map((_, i) => `$${i + 1}`).join(',');
                txs = (await client.query(`SELECT * FROM transactions WHERE sender_iban IN (${placeholders}) OR receiver_iban IN (${placeholders}) ORDER BY date DESC LIMIT 50`, ibans)).rows;
            }
            return res.status(200).json(formatResponse({ 
                accounts, 
                companies, 
                transactions: txs, 
                contacts, 
                lootBoxes,
                shareRequests,
                userSubscriptions,
                marketDesigns: { store: storeDesigns, inventory: inventoryDesigns }
            }));
        }

        // --- STOCK ACTIONS ---
        if (action === 'BUY_STOCK') {
            const { companyId, accountId, amount } = params;
            await client.query("BEGIN");
            const coRes = await client.query("SELECT * FROM companies WHERE id = $1", [companyId]);
            const accRes = await client.query("SELECT * FROM accounts WHERE id = $1", [accountId]);
            const co = coRes.rows[0];
            const acc = accRes.rows[0];
            if (acc.balance < amount) throw new Error("Saldo insuficiente");
            const shares = amount / co.stock_value;
            await client.query("UPDATE accounts SET balance = balance - $1 WHERE id = $2", [amount, accountId]);
            await client.query("UPDATE accounts SET balance = balance + $1 WHERE iban = $2", [amount, co.iban]);
            await client.query("INSERT INTO transactions (id, sender_iban, receiver_iban, amount, description, type, status) VALUES ($1, $2, $3, $4, $5, 'MARKET_BUY', 'COMPLETED')",
                ['TX-STOCK-'+Date.now(), acc.iban, co.iban, amount, `Inversión acciones ${co.name}`]);
            await client.query("COMMIT");
            return res.status(200).json({ success: true });
        }

        if (action === 'SELL_STOCK') {
            const { companyId, accountId, amount } = params;
            await client.query("UPDATE accounts SET balance = balance + $1 WHERE id = $2", [amount, accountId]);
            return res.status(200).json({ success: true });
        }

        // --- SHARING ACTIONS ---
        if (action === 'REQUEST_SHARE_ACCOUNT') {
            const { accountId, toUserDip, accessLevel, fromUserId } = params;
            const fromUser = (await client.query("SELECT name FROM users WHERE id = $1", [fromUserId])).rows[0];
            const toUser = (await client.query("SELECT name FROM users WHERE UPPER(dip) = $1", [toUserDip.toUpperCase()])).rows[0];
            if(!toUser) throw new Error("Ciudadano no encontrado");
            await client.query("INSERT INTO share_requests (id, from_user_id, from_user_name, to_user_dip, to_user_name, account_id, access_level, status) VALUES ($1, $2, $3, $4, $5, $6, $7, 'PENDING')",
                ['REQ-'+Date.now(), fromUserId, fromUser.name, toUserDip.toUpperCase(), toUser.name, accountId, accessLevel]);
            return res.status(200).json({ success: true });
        }

        if (action === 'RESPOND_SHARE_REQUEST') {
            const { requestId, status } = params;
            await client.query("BEGIN");
            if (status === 'ACCEPTED') {
                const req = (await client.query("SELECT * FROM share_requests WHERE id = $1", [requestId])).rows[0];
                const toUser = (await client.query("SELECT id FROM users WHERE UPPER(dip) = $1", [req.to_user_dip])).rows[0];
                await client.query("UPDATE accounts SET shared_with = array_append(shared_with, $1) WHERE id = $2", [toUser.id, req.account_id]);
            }
            await client.query("UPDATE share_requests SET status = $1 WHERE id = $2", [status, requestId]);
            await client.query("COMMIT");
            return res.status(200).json({ success: true });
        }

        // --- CARD ACTIONS ---
        if (action === 'REQUEST_CARD') {
            const { accountId, holderName, design, pin } = params;
            const pan = '4532' + Math.floor(100000000000 + Math.random() * 900000000000);
            await client.query("INSERT INTO cards (id, account_id, pan, expiry_date, cvv, pin, type, status, holder_name, design) VALUES ($1, $2, $3, $4, $5, $6, 'DEBIT', 'ACTIVE', $7, $8)",
                ['CARD-'+Date.now(), accountId, pan, '12/30', '123', pin, holderName, design]);
            return res.status(200).json({ success: true });
        }

        if (action === 'TOGGLE_CARD_STATUS') {
            const { cardId, status } = params;
            await client.query("UPDATE cards SET status = $1 WHERE id = $2", [status, cardId]);
            return res.status(200).json({ success: true });
        }

        if (action === 'PAY_WITH_CARD') {
            const { pan, cvv, pin, amount, companyId, description } = params;
            await client.query("BEGIN");
            const cardRes = await client.query("SELECT * FROM cards WHERE pan = $1 AND cvv = $2 AND pin = $3", [pan, cvv, pin]);
            if(cardRes.rows.length === 0) throw new Error("Validación de tarjeta fallida");
            const card = cardRes.rows[0];
            const accRes = await client.query("SELECT * FROM accounts WHERE id = $1", [card.account_id]);
            const acc = accRes.rows[0];
            if(acc.balance < amount) throw new Error("Saldo insuficiente");
            const coRes = await client.query("SELECT iban FROM companies WHERE id = $1", [companyId]);
            const coIban = coRes.rows[0].iban;
            await client.query("UPDATE accounts SET balance = balance - $1 WHERE id = $2", [amount, acc.id]);
            await client.query("UPDATE accounts SET balance = balance + $1 WHERE iban = $2", [amount, coIban]);
            await client.query("INSERT INTO transactions (id, sender_iban, receiver_iban, amount, description, type, status) VALUES ($1, $2, $3, $4, $5, 'CARD_PAYMENT', 'COMPLETED')",
                ['TX-CARD-'+Date.now(), acc.iban, coIban, amount, description]);
            await client.query("COMMIT");
            return res.status(200).json({ success: true });
        }

        // --- SUBSCRIPTION ACTIONS ---
        if (action === 'SUBSCRIBE_TO_PLAN') {
            const { planId, accountId, userId } = params;
            await client.query("INSERT INTO user_subscriptions (id, plan_id, user_id, account_id, status, start_date, next_payment_date) VALUES ($1, $2, $3, $4, 'ACTIVE', NOW(), NOW() + interval '1 month')",
                ['SUB-'+Date.now(), planId, userId, accountId]);
            return res.status(200).json({ success: true });
        }

        if (action === 'CANCEL_SUBSCRIPTION') {
            const { subscriptionId } = params;
            await client.query("UPDATE user_subscriptions SET status = 'CANCELLED' WHERE id = $1", [subscriptionId]);
            return res.status(200).json({ success: true });
        }

        // --- MARKET ACTIONS ---
        if (action === 'BUY_DESIGN') {
            const { designId, accountId } = params;
            await client.query("BEGIN");
            const desRes = await client.query("SELECT * FROM card_designs WHERE id = $1", [designId]);
            const des = desRes.rows[0];
            const accRes = await client.query("SELECT * FROM accounts WHERE id = $1", [accountId]);
            const acc = accRes.rows[0];
            if(acc.balance < des.price) throw new Error("Saldo insuficiente");
            await client.query("UPDATE accounts SET balance = balance - $1 WHERE id = $2", [des.price, accountId]);
            await client.query("UPDATE card_designs SET owner_id = $1, is_listed = false WHERE id = $2", [acc.owner_id, designId]);
            await client.query("COMMIT");
            return res.status(200).json({ success: true });
        }

        if (action === 'LIST_DESIGN') {
            const { designId, price } = params;
            await client.query("UPDATE card_designs SET is_listed = true, price = $1 WHERE id = $2", [price, designId]);
            return res.status(200).json({ success: true });
        }

        if (action === 'DELETE_DESIGN') {
            const { designId } = params;
            await client.query("DELETE FROM card_designs WHERE id = $1", [designId]);
            return res.status(200).json({ success: true });
        }

        // --- BUSINESS ACTIONS ---
        if (action === 'COMPANY_GO_PUBLIC') {
            const { companyId } = params;
            await client.query("UPDATE companies SET is_public = true, stock_value = 100.00 WHERE id = $1", [companyId]);
            return res.status(200).json({ success: true });
        }

        if (action === 'COMPANY_CREATE_LOTTERY') {
            const { companyId, name, description, price, prizeValue, color } = params;
            await client.query("BEGIN");
            const accRes = await client.query("SELECT iban, balance FROM accounts WHERE company_id = $1 OR iban = (SELECT iban FROM companies WHERE id = $1) LIMIT 1", [companyId]);
            const companyAcc = accRes.rows[0];

            if (!companyAcc || companyAcc.balance < prizeValue) throw new Error("Saldo insuficiente para garantizar el premio");

            await client.query("UPDATE accounts SET balance = balance - $1 WHERE iban = $2", [prizeValue, companyAcc.iban]);
            await client.query("UPDATE accounts SET balance = balance + $1 WHERE iban = $2", [prizeValue, BANK_IBAN]);

            const id = 'LOOT-' + Date.now();
            await client.query("INSERT INTO loot_boxes (id, owner_id, name, description, price, prize_value, color, status) VALUES ($1, $2, $3, $4, $5, $6, $7, 'APPROVED')",
                [id, companyId, name, description, price, prizeValue, color]);

            await client.query("COMMIT");
            return res.status(200).json({ success: true });
        }

        // --- LOTTERY ACTIONS ---
        if (action === 'BUY_LOOTBOX') {
            const { boxId, accountId } = params;
            await client.query("BEGIN");
            const boxRes = await client.query("SELECT * FROM loot_boxes WHERE id = $1", [boxId]);
            const accRes = await client.query("SELECT * FROM accounts WHERE id = $1", [accountId]);
            const box = boxRes.rows[0];
            const acc = accRes.rows[0];

            if (acc.balance < box.price) throw new Error("Saldo insuficiente");

            await client.query("UPDATE accounts SET balance = balance - $1 WHERE id = $2", [box.price, accountId]);

            const won = Math.random() < 0.10;
            let wonItem = null;

            if (won) {
                const prize = parseFloat(box.prize_value);
                const tax = prize * 0.20; 
                const net = prize - tax;
                await client.query("UPDATE accounts SET balance = balance - $1 WHERE iban = $2", [prize, BANK_IBAN]);
                await client.query("UPDATE accounts SET balance = balance + $1 WHERE id = $2", [net, accountId]);
                await client.query("UPDATE accounts SET balance = balance + $1 WHERE iban = $2", [tax, BANK_IBAN]);

                wonItem = { id: 'PRIZE-'+Date.now(), name: `Premio de ${box.name}`, value: prize };

                await client.query("INSERT INTO transactions (id, sender_iban, receiver_iban, amount, description, type, status, tax) VALUES ($1, $2, $3, $4, $5, 'LOTTERY', 'COMPLETED', $6)",
                    ['TX-WIN-'+Date.now(), BANK_IBAN, acc.iban, prize, `Premio Lotería: ${box.name}`, tax]);
            } else {
                const ownerRes = await client.query("SELECT iban FROM companies WHERE id = $1", [box.owner_id]);
                const ownerIban = ownerRes.rows[0]?.iban || BANK_IBAN;
                await client.query("UPDATE accounts SET balance = balance + $1 WHERE iban = $2", [box.price, ownerIban]);
            }

            await client.query("COMMIT");
            return res.status(200).json({ success: true, won, wonItem });
        }

        // --- ADMIN ---
        if (action === 'ADMIN_GET_STATE') {
            const users = (await client.query("SELECT * FROM users ORDER BY created_at DESC")).rows;
            const txs = (await client.query("SELECT * FROM transactions ORDER BY date DESC LIMIT 100")).rows;
            const accounts = (await client.query("SELECT * FROM accounts")).rows;
            const m0Res = await client.query("SELECT SUM(balance) as m0 FROM accounts");
            return res.status(200).json(formatResponse({ users, transactions: txs, allAccounts: accounts, m0: m0Res.rows[0].m0 || 0 }));
        }

        // --- GENERAL TRANSACTIONS ---
        if (action === 'TRANSFER') {
            const { fromIban, toIban, amount, description, type } = params;
            await client.query("BEGIN");
            const senderRes = await client.query("SELECT balance FROM accounts WHERE iban = $1 FOR UPDATE", [fromIban]);
            if (senderRes.rows.length === 0) throw new Error("Cuenta origen no existe");

            const taxRate = type === 'TAX' || type === 'ADMIN' ? 0 : 0.01;
            const total = amount * (1 + taxRate);
            if (senderRes.rows[0].balance < total) throw new Error("Saldo insuficiente");

            await client.query("UPDATE accounts SET balance = balance - $1 WHERE iban = $2", [total, fromIban]);
            await client.query("UPDATE accounts SET balance = balance + $1 WHERE iban = $2", [amount, toIban]);
            if (taxRate > 0) await client.query("UPDATE accounts SET balance = balance + $1 WHERE iban = $2", [amount * taxRate, BANK_IBAN]);

            await client.query("INSERT INTO transactions (id, sender_iban, receiver_iban, amount, description, type, status, tax) VALUES ($1, $2, $3, $4, $5, $6, 'COMPLETED', $7)",
                ['TX-'+Math.random().toString(36).substr(2,9).toUpperCase(), fromIban, toIban, amount, description, type || 'TRANSFER', amount * taxRate]);

            await client.query("COMMIT");
            return res.status(200).json({ success: true });
        }

        return res.status(400).json({ error: `Acción '${action}' no reconocida` });
    } catch (e: any) {
        if (client) await client.query("ROLLBACK");
        return res.status(500).json({ error: e.message });
    } finally {
        if (client) client.release();
    }
}

import { Pool } from '@neondatabase/serverless';

let pool: any = null;
const getPool = () => {
  if (!pool) {
    if (!process.env.DATABASE_URL) throw new Error('DATABASE_URL is missing');
    pool = new (Pool as any)({ connectionString: process.env.DATABASE_URL });
  }
  return pool;
};

const BANK_IBAN = 'PL0000000000000000000000';

const formatResponse = (obj: any): any => {
    if (obj === null || obj === undefined) return obj;
    if (obj instanceof Date) return obj.toISOString();
    if (Array.isArray(obj)) return obj.map(formatResponse);
    if (typeof obj !== 'object') return obj;
    const newObj: any = {};
    for (const key in obj) {
        const newKey = key.replace(/_([a-z])/g, (g) => g[1].toUpperCase());
        let value = obj[key];
        const numericFields = ['balance', 'amount', 'price', 'capital', 'stockValue', 'salary', 'tax', 'prizeValue'];
        if (numericFields.includes(newKey) && (typeof value === 'string' || value === null)) {
            value = parseFloat(value || '0');
        }
        newObj[newKey] = formatResponse(value);
    }
    return newObj;
};

export default async function handler(req: any, res: any) {
    let client: any;
    res.setHeader('Content-Type', 'application/json');
    res.setHeader('Access-Control-Allow-Origin', '*');
    res.setHeader('Access-Control-Allow-Methods', 'POST, OPTIONS');
    res.setHeader('Access-Control-Allow-Headers', 'Content-Type');

    if (req.method === 'OPTIONS') return res.status(200).end();

    try {
        const { action, ...params } = req.body || {};
        client = await getPool().connect();

        // --- DATA RETRIEVAL ---
        if (action === 'GET_INITIAL_DATA') {
            const { userId } = params;
            const accounts = (await client.query("SELECT * FROM accounts WHERE owner_id = $1 OR $1 = ANY(shared_with)", [userId])).rows;
            const companies = (await client.query("SELECT * FROM companies WHERE owner_id = $1", [userId])).rows;
            const contacts = (await client.query("SELECT * FROM contacts WHERE user_id = $1", [userId])).rows;

            // Protección contra tablas inexistentes
            let lootBoxes = []; try { lootBoxes = (await client.query("SELECT * FROM loot_boxes WHERE status = 'APPROVED' OR owner_id IN (SELECT id FROM companies WHERE owner_id = $1)", [userId])).rows; } catch(e){}
            let shareRequests = []; try { shareRequests = (await client.query("SELECT * FROM share_requests WHERE from_user_id = $1 OR to_user_dip = (SELECT dip FROM users WHERE id = $1)", [userId])).rows; } catch(e){}
            let userSubscriptions = []; try { userSubscriptions = (await client.query("SELECT * FROM user_subscriptions WHERE user_id = $1", [userId])).rows; } catch(e){}
            let marketDesigns = { store: [], inventory: [] }; try {
                marketDesigns.store = (await client.query("SELECT * FROM card_designs WHERE owner_id IS NULL OR is_listed = true")).rows;
                marketDesigns.inventory = (await client.query("SELECT * FROM card_designs WHERE owner_id = $1 AND (is_listed = false OR is_listed IS NULL)", [userId])).rows;
            } catch(e){}

            const ibans = (accounts || []).map((a: any) => a.iban);
            let txs = [];
            if (ibans.length > 0) {
                const placeholders = ibans.map((_, i) => `$${i + 1}`).join(',');
                txs = (await client.query(`SELECT * FROM transactions WHERE sender_iban IN (${placeholders}) OR receiver_iban IN (${placeholders}) ORDER BY date DESC LIMIT 50`, ibans)).rows;
            }

            return res.status(200).json(formatResponse({ 
                accounts, companies, transactions: txs, contacts, lootBoxes, 
                shareRequests, userSubscriptions, marketDesigns 
            }));
        }

        // --- FISCAL ACTIONS ---
        if (action === 'GET_FISCAL_PROJECTION') {
            const { userId, month, year } = params;
            const accounts = (await client.query("SELECT * FROM accounts WHERE owner_id = $1", [userId])).rows;
            const projections = await Promise.all(accounts.map(async (acc) => {
                const txs = (await client.query("SELECT * FROM transactions WHERE (sender_iban = $1 OR receiver_iban = $1) AND EXTRACT(MONTH FROM date) = $2 AND EXTRACT(YEAR FROM date) = $3", [acc.iban, month, year])).rows;
                const income = txs.filter(t => t.receiver_iban === acc.iban).reduce((s, t) => s + parseFloat(t.amount), 0);
                const expenses = txs.filter(t => t.sender_iban === acc.iban).reduce((s, t) => s + parseFloat(t.amount), 0);
                const ia = acc.balance > 0 ? (income - expenses) / acc.balance : 0;
                return {
                    accountId: acc.id,
                    alias: acc.alias,
                    iban: acc.iban,
                    income,
                    expenses,
                    ia: Math.max(0, ia),
                    currentDebt: 0,
                    projectedTax: ia > 0.15 ? acc.balance * 0.05 : 0 // Ejemplo de gravamen 5% si IA > 0.15
                };
            }));
            return res.status(200).json(formatResponse(projections));
        }

        // --- BUSINESS & STOCK ---
        if (action === 'COMPANY_GO_PUBLIC') {
            const { companyId } = params;
            await client.query("UPDATE companies SET is_public = true, stock_value = 100.00 WHERE id = $1", [companyId]);
            return res.status(200).json({ success: true });
        }

        if (action === 'BUY_STOCK') {
            const { companyId, accountId, amount } = params;
            await client.query("BEGIN");
            const co = (await client.query("SELECT * FROM companies WHERE id = $1", [companyId])).rows[0];
            const acc = (await client.query("SELECT * FROM accounts WHERE id = $1", [accountId])).rows[0];
            if (acc.balance < amount) throw new Error("Saldo insuficiente");
            await client.query("UPDATE accounts SET balance = balance - $1 WHERE id = $2", [amount, accountId]);
            await client.query("UPDATE accounts SET balance = balance + $1 WHERE iban = $2", [amount, co.iban]);
            await client.query("INSERT INTO transactions (id, sender_iban, receiver_iban, amount, description, type, status) VALUES ($1, $2, $3, $4, $5, 'MARKET_BUY', 'COMPLETED')",
                ['TX-STOCK-'+Date.now(), acc.iban, co.iban, amount, `Compra Acciones: ${co.name}`]);
            await client.query("COMMIT");
            return res.status(200).json({ success: true });
        }

        // --- LOTTERY ---
        if (action === 'COMPANY_CREATE_LOTTERY') {
            const { companyId, name, description, price, prizeValue, color } = params;
            await client.query("BEGIN");
            const companyAcc = (await client.query("SELECT iban, balance FROM accounts WHERE company_id = $1 OR iban = (SELECT iban FROM companies WHERE id = $1) LIMIT 1", [companyId])).rows[0];
            if (!companyAcc || companyAcc.balance < prizeValue) throw new Error("Fondos insuficientes para garantizar el sorteo");
            await client.query("UPDATE accounts SET balance = balance - $1 WHERE iban = $2", [prizeValue, companyAcc.iban]);
            await client.query("UPDATE accounts SET balance = balance + $1 WHERE iban = $2", [prizeValue, BANK_IBAN]);
            await client.query("INSERT INTO loot_boxes (id, owner_id, name, description, price, prize_value, color, status) VALUES ($1, $2, $3, $4, $5, $6, $7, 'APPROVED')",
                ['LOOT-'+Date.now(), companyId, name, description, price, prizeValue, color]);
            await client.query("COMMIT");
            return res.status(200).json({ success: true });
        }

        // --- AUTH ---
        if (action === 'AUTH') {
            const { dip, password } = params;
            const userRes = await client.query("SELECT * FROM users WHERE UPPER(dip) = $1 AND password_hash = $2", [dip.toUpperCase().trim(), password]);
            if (userRes.rows.length === 0) return res.status(401).json({ error: "Credenciales SIDS incorrectas" });
            return res.status(200).json({ success: true, user: formatResponse(userRes.rows[0]) });
        }

        if (action === 'AUTH_PLACETAID') {
            const { userData } = params;
            const dip = (userData.dni || userData.dip || userData.id || '').toUpperCase().trim();
            const userRes = await client.query("SELECT * FROM users WHERE UPPER(dip) = $1", [dip]);
            if (userRes.rows.length === 0) return res.status(404).json({ error: "Usuario no registrado" });
            return res.status(200).json({ success: true, user: formatResponse(userRes.rows[0]) });
        }

        // --- TRANSACTIONS ---
        if (action === 'TRANSFER') {
            const { fromIban, toIban, amount, description, type } = params;
            await client.query("BEGIN");
            const senderRes = await client.query("SELECT balance FROM accounts WHERE iban = $1 FOR UPDATE", [fromIban]);
            if (senderRes.rows.length === 0) throw new Error("Cuenta no existe");
            const tax = (type === 'TAX' || type === 'ADMIN') ? 0 : amount * 0.01;
            if (senderRes.rows[0].balance < (amount + tax)) throw new Error("Saldo insuficiente");
            await client.query("UPDATE accounts SET balance = balance - $1 WHERE iban = $2", [amount + tax, fromIban]);
            await client.query("UPDATE accounts SET balance = balance + $1 WHERE iban = $2", [amount, toIban]);
            if(tax > 0) await client.query("UPDATE accounts SET balance = balance + $1 WHERE iban = $2", [tax, BANK_IBAN]);
            await client.query("INSERT INTO transactions (id, sender_iban, receiver_iban, amount, description, type, status, tax) VALUES ($1, $2, $3, $4, $5, $6, 'COMPLETED', $7)",
                ['TX-'+Math.random().toString(36).substr(2,9).toUpperCase(), fromIban, toIban, amount, description, type || 'TRANSFER', tax]);
            await client.query("COMMIT");
            return res.status(200).json({ success: true });
        }

        if (action === 'LINK_ACCOUNT_TO_COMPANY') {
            const { accountId, companyId } = params;
            await client.query("UPDATE accounts SET company_id = $1, type = 'BUSINESS' WHERE id = $2", [companyId, accountId]);
            return res.status(200).json({ success: true });
        }

        return res.status(400).json({ error: `Acción '${action}' no implementada en este Nodo SIDS` });
    } catch (e: any) {
        if (client) await client.query("ROLLBACK");
        return res.status(500).json({ error: e.message });
    } finally {
        if (client) client.release();
    }
}

