                    <div className="grid grid-cols-1 xl:grid-cols-2 gap-8">
                        <div className="bg-white p-10 rounded-[3.5rem] border border-slate-100 shadow-soft relative overflow-hidden group">
                            <div className="absolute top-0 right-0 w-64 h-64 bg-indigo-50 rounded-full blur-3xl -mr-20 -mt-20 group-hover:bg-indigo-100 transition-colors"></div>
                            <div className="relative z-10">
                                <div className="w-16 h-16 bg-indigo-600 text-white rounded-2xl flex items-center justify-center mb-8 shadow-lg">
                                    <TrendingUp size={32}/>
                                </div>
                                <h3 className="text-2xl font-black text-slate-900 mb-4 tracking-tight">Apertura a Bolsa SIDS</h3>
                                <p className="text-slate-500 text-sm leading-relaxed mb-10 font-medium">
                                    Transforme su sociedad limitada en una entidad pública. Capte capital de los ciudadanos permitiendo la compraventa de participaciones en el Mercado de Valores.
                                </p>

                                {selectedCompany.isPublic ? (
                                    <div className="bg-emerald-50 border border-emerald-100 p-6 rounded-3xl flex items-center gap-4">
                                        <div className="w-12 h-12 bg-white text-emerald-600 rounded-2xl flex items-center justify-center shadow-sm"><Check size={24} strokeWidth={3}/></div>
                                        <div>
                                            <p className="font-black text-emerald-900 text-sm">Empresa Pública Activa</p>
                                            <p className="text-[10px] text-emerald-600 font-bold uppercase tracking-wider">Valoración: {selectedCompany.stockValue} Pz / Acción</p>
                                        </div>
                                    </div>
                                ) : (
                                    <button onClick={() => setShowIpoModal(true)} className="w-full py-5 bg-slate-900 text-white rounded-2xl font-black uppercase text-xs tracking-widest hover:bg-indigo-600 transition-all shadow-xl active:scale-95">
                                        Iniciar Oferta Pública (IPO)
                                    </button>
                                )}
                            </div>
                        </div>

                        <div className="bg-white p-10 rounded-[3.5rem] border border-slate-100 shadow-soft relative overflow-hidden group">
                            <div className="absolute top-0 right-0 w-64 h-64 bg-amber-50 rounded-full blur-3xl -mr-20 -mt-20 group-hover:bg-amber-100 transition-colors"></div>
                            <div className="relative z-10">
                                <div className="w-16 h-16 bg-amber-500 text-white rounded-2xl flex items-center justify-center mb-8 shadow-lg">
                                    <Gift size={32}/>
                                </div>
                                <h3 className="text-2xl font-black text-slate-900 mb-4 tracking-tight">Sorteos Corporativos</h3>
                                <p className="text-slate-500 text-sm leading-relaxed mb-10 font-medium">
                                    Incentive el uso de su marca creando "Cajas de Botín" o Sorteos. El Banco garantiza la entrega del premio bloqueando los fondos por adelantado.
                                </p>
                                <button onClick={() => setShowLotteryModal(true)} className="w-full py-5 bg-white border-2 border-amber-500 text-amber-600 rounded-2xl font-black uppercase text-xs tracking-widest hover:bg-amber-500 hover:text-white transition-all shadow-lg active:scale-95">
                                    Configurar Nueva Lotería
                                </button>
                            </div>
                        </div>
                    </div>
                </div>
            )}
        </main>

        {/* MODAL IPO RIESGOS */}
        {showIpoModal && (
            <div className="fixed inset-0 bg-slate-900/80 backdrop-blur-md z-[500] flex items-center justify-center p-4">
                <div className="bg-white w-full max-w-xl rounded-[3.5rem] p-10 shadow-2xl animate-scale-up relative">
                    <button onClick={() => setShowIpoModal(false)} className="absolute top-8 right-8 p-2.5 bg-slate-50 rounded-full hover:bg-slate-100 transition-colors"><X size={20}/></button>
                    <div className="flex items-center gap-4 mb-8">
                        <div className="w-16 h-16 bg-red-50 text-red-600 rounded-2xl flex items-center justify-center shadow-inner"><ShieldAlert size={32}/></div>
                        <div>
                            <h3 className="text-2xl font-black text-slate-900">Aviso Legal de IPO</h3>
                            <p className="text-[10px] font-black text-red-500 uppercase tracking-widest">Protocolo Legislativo Cap. 2</p>
                        </div>
                    </div>

                    <div className="space-y-4 mb-10">
                        <div className="flex gap-4 p-5 bg-slate-50 rounded-3xl border border-slate-100">
                            <Scale size={24} className="text-indigo-600 shrink-0"/>
                            <p className="text-xs text-slate-600 leading-relaxed font-bold"><strong>Dilución de Control</strong>: Al emitir acciones públicas, usted cede la propiedad parcial de la empresa. Las decisiones críticas podrían requerir consenso de accionistas.</p>
                        </div>
                        <div className="flex gap-4 p-5 bg-slate-50 rounded-3xl border border-slate-100">
                            <BarChart3 size={24} className="text-indigo-600 shrink-0"/>
                            <p className="text-xs text-slate-600 leading-relaxed font-bold"><strong>Transparencia Administrativa</strong>: Sus estados financieros serán públicos y auditables desde cualquier Nodo SIDS por cualquier inversor.</p>
                        </div>
                        <div className="flex gap-4 p-5 bg-slate-50 rounded-3xl border border-slate-100">
                            <Info size={24} className="text-indigo-600 shrink-0"/>
                            <p className="text-xs text-slate-600 leading-relaxed font-bold"><strong>Valor de Mercado</strong>: El precio de su acción fluctuará según la confianza del sistema. Una mala gestión puede reducir drásticamente el valor patrimonial.</p>
                        </div>
                    </div>

                    <div className="flex gap-3">
                        <button onClick={() => setShowIpoModal(false)} className="flex-1 py-4 bg-slate-100 text-slate-500 rounded-2xl font-black uppercase text-[10px] tracking-widest">Cancelar</button>
                        <button onClick={handleIpo} className="flex-[2] py-4 bg-indigo-600 text-white rounded-2xl font-black uppercase text-[10px] tracking-widest shadow-xl hover:bg-indigo-700 active:scale-95 transition-all">Acepto los Riesgos y Salgo a Bolsa</button>
                    </div>
                </div>
            </div>
        )}

        {/* MODAL LOTTERY */}
        {showLotteryModal && (
            <div className="fixed inset-0 bg-slate-900/80 backdrop-blur-md z-[500] flex items-center justify-center p-4">
                <div className="bg-white w-full max-w-md rounded-[3.5rem] p-10 shadow-2xl animate-scale-up relative">
                    <button onClick={() => setShowLotteryModal(false)} className="absolute top-8 right-8 p-2.5 bg-slate-50 rounded-full hover:bg-slate-100 transition-colors"><X size={20}/></button>
                    <h3 className="text-2xl font-black text-slate-900 mb-8 tracking-tight">Crear Sorteo Corporativo</h3>
                    <div className="space-y-5">
                        <div>
                            <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-2 mb-2 block">Nombre del Evento</label>
                            <input className="w-full p-4 bg-slate-50 rounded-2xl font-bold text-sm outline-none border-2 border-transparent focus:border-brand-500" placeholder="Ej: Gran Sorteo Aniversario" value={lotteryForm.name} onChange={e => setLotteryForm({...lotteryForm, name: e.target.value})} />
                        </div>
                        <div>
                            <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-2 mb-2 block">Fondo del Premio (Pz)</label>
                            <input type="number" className="w-full p-4 bg-slate-50 rounded-2xl font-black text-2xl outline-none border-2 border-transparent focus:border-brand-500" placeholder="0.00" value={lotteryForm.prizeValue} onChange={e => setLotteryForm({...lotteryForm, prizeValue: e.target.value})} />
                            <p className="text-[9px] text-slate-400 mt-2 ml-2">Importe a bloquear como garantía estatal.</p>
                        </div>
                        <div className="grid grid-cols-2 gap-4">
                             <div>
                                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-2 mb-2 block">Precio Ticket</label>
                                <input type="number" className="w-full p-4 bg-slate-50 rounded-2xl font-bold text-sm outline-none" value={lotteryForm.price} onChange={e => setLotteryForm({...lotteryForm, price: e.target.value})} />
                             </div>
                             <div>
                                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-2 mb-2 block">Diseño Caja</label>
                                <select className="w-full p-4 bg-slate-50 rounded-2xl font-bold text-[10px] uppercase outline-none" value={lotteryForm.color} onChange={e => setLotteryForm({...lotteryForm, color: e.target.value})}>
                                    <option value="from-indigo-600 to-indigo-800">Nocturno</option>
                                    <option value="from-amber-400 to-orange-600">Dorado (VIP)</option>
                                    <option value="from-emerald-400 to-teal-700">Corporativo</option>
                                </select>
                             </div>
                        </div>
                        <button onClick={handleCreateLottery} className="w-full py-5 bg-slate-900 text-white rounded-3xl font-black uppercase text-xs tracking-widest hover:bg-brand-600 shadow-xl active:scale-95 mt-4">Garantizar y Lanzar Sorteo</button>
                    </div>
                </div>
            </div>
        )}
    </div>
  );
};
